INSERT INTO meals
  (id, title, title_es, image, calories, protein, carbs, fat, prep_time, tag, tag_es, category, difficulty, difficulty_es, serves, ingredients, steps, steps_es, is_active)
VALUES
  ('r433', 'Tuscan Herb Baked Chicken', 'Pollo al Horno con Hierbas Toscanas', NULL, 456, 48, 30, 16, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','olive_oil','garlic','tomato','spinach','oregano','cheese'], ARRAY['Preheat oven to 425°F (220°C) and pat chicken breast dry.','Rub chicken with olive oil, minced garlic, and oregano; season with salt and pepper.','Top with halved tomatoes and bake 20-22 minutes until internal temp reaches 165°F (74°C).','Stir in spinach and a sprinkle of cheese during the last 3 minutes, then serve.'], ARRAY['Precalienta el horno a 220°C (425°F) y seca la pechuga de pollo.','Unta el pollo con aceite de oliva, ajo picado y orégano; sazona con sal y pimienta.','Cubre con tomates en mitades y hornea 20-22 minutos hasta que alcance 74°C (165°F).','Agrega la espinaca y un poco de queso en los últimos 3 minutos y sirve.'], TRUE),
  ('r434', 'Chipotle Lime Grilled Chicken', 'Pollo a la Parrilla con Chipotle y Limón', NULL, 432, 46, 35, 12, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','chipotle','lime','garlic','olive_oil','cilantro'], ARRAY['Whisk chipotle, lime juice, garlic, and olive oil into a marinade.','Coat chicken breast and marinate at least 15 minutes.','Grill over medium-high heat 6-7 minutes per side until 165°F (74°C).','Rest 5 minutes, top with cilantro, and serve.'], ARRAY['Bate el chipotle, el jugo de limón, el ajo y el aceite de oliva para la marinada.','Cubre la pechuga de pollo y marina al menos 15 minutos.','Asa a fuego medio-alto 6-7 minutos por lado hasta 74°C (165°F).','Deja reposar 5 minutos, cubre con cilantro y sirve.'], TRUE),
  ('r435', 'Lemon Oregano Chicken Skewers', 'Brochetas de Pollo con Limón y Orégano', NULL, 423, 44, 28, 15, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','olive_oil','lemon','garlic','oregano','bell_pepper','onion'], ARRAY['Marinate cubed chicken in olive oil, lemon, garlic, and oregano for 20 minutes.','Thread chicken onto skewers with bell pepper and onion chunks.','Grill over medium-high heat, turning, 10-12 minutes until 165°F (74°C).','Squeeze fresh lemon over the skewers and serve.'], ARRAY['Marina el pollo en cubos con aceite de oliva, limón, ajo y orégano por 20 minutos.','Ensarta el pollo en brochetas con trozos de pimiento y cebolla.','Asa a fuego medio-alto, girando, 10-12 minutos hasta 74°C (165°F).','Exprime limón fresco sobre las brochetas y sirve.'], TRUE),
  ('r436', 'Cajun Sheet-Pan Chicken & Peppers', 'Pollo Cajún con Pimientos al Horno', NULL, 429, 45, 33, 13, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','bell_pepper','onion','cajun_seasoning','olive_oil','garlic'], ARRAY['Preheat oven to 425°F (220°C) and line a sheet pan.','Toss chicken, bell pepper, and onion with olive oil, garlic, and Cajun seasoning.','Spread on the pan and bake 22-25 minutes until chicken hits 165°F (74°C).','Serve straight from the pan.'], ARRAY['Precalienta el horno a 220°C (425°F) y forra una bandeja.','Mezcla el pollo, el pimiento y la cebolla con aceite, ajo y sazón Cajún.','Extiende en la bandeja y hornea 22-25 minutos hasta que el pollo llegue a 74°C (165°F).','Sirve directo de la bandeja.'], TRUE),
  ('r437', 'Za''atar Roasted Chicken Breast', 'Pechuga de Pollo Asada con Za''atar', NULL, 422, 47, 27, 14, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','za_atar','olive_oil','lemon','garlic','sweet_potato'], ARRAY['Preheat oven to 425°F (220°C).','Rub chicken with olive oil, za''atar, garlic, and lemon zest.','Roast alongside cubed sweet potato 22-25 minutes until 165°F (74°C).','Finish with a squeeze of lemon and serve.'], ARRAY['Precalienta el horno a 220°C (425°F).','Unta el pollo con aceite de oliva, za''atar, ajo y ralladura de limón.','Asa junto con batata en cubos 22-25 minutos hasta 74°C (165°F).','Termina con un toque de limón y sirve.'], TRUE),
  ('r438', 'Honey Mustard Baked Chicken', 'Pollo al Horno con Miel y Mostaza', NULL, 432, 43, 38, 12, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','honey','dijon_mustard','garlic','olive_oil','broccoli'], ARRAY['Preheat oven to 400°F (205°C).','Whisk honey, dijon mustard, garlic, and olive oil; coat the chicken.','Bake with broccoli florets 22-25 minutes until 165°F (74°C).','Spoon pan juices over the top and serve.'], ARRAY['Precalienta el horno a 205°C (400°F).','Bate miel, mostaza Dijon, ajo y aceite; cubre el pollo.','Hornea con floretes de brócoli 22-25 minutos hasta 74°C (165°F).','Baña con los jugos de la bandeja y sirve.'], TRUE),
  ('r439', 'Pesto Chicken & Cherry Tomatoes', 'Pollo al Pesto con Tomates Cherry', NULL, 450, 46, 26, 18, 28, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','pesto','tomato','olive_oil','garlic','spinach'], ARRAY['Preheat oven to 425°F (220°C).','Spread pesto over chicken breast and scatter cherry tomatoes around it.','Bake 20-22 minutes until chicken reaches 165°F (74°C).','Toss in spinach off the heat and serve.'], ARRAY['Precalienta el horno a 220°C (425°F).','Cubre la pechuga con pesto y reparte tomates cherry alrededor.','Hornea 20-22 minutos hasta que el pollo llegue a 74°C (165°F).','Mezcla la espinaca fuera del fuego y sirve.'], TRUE),
  ('r440', 'Moroccan Spiced Chicken Breast', 'Pechuga de Pollo Especiada Marroquí', NULL, 453, 44, 40, 13, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','cumin','paprika','garlic','olive_oil','couscous','lemon'], ARRAY['Rub chicken with cumin, paprika, garlic, and olive oil.','Grill over medium-high heat 6-7 minutes per side until 165°F (74°C).','Meanwhile prepare couscous per package directions.','Slice chicken over couscous and finish with lemon.'], ARRAY['Unta el pollo con comino, paprika, ajo y aceite de oliva.','Asa a fuego medio-alto 6-7 minutos por lado hasta 74°C (165°F).','Mientras, prepara el cuscús según el paquete.','Rebana el pollo sobre el cuscús y termina con limón.'], TRUE),
  ('r441', 'Balsamic Chicken & Zucchini Bake', 'Pollo Balsámico con Calabacín al Horno', NULL, 422, 45, 29, 14, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','balsamic_vinegar','zucchini','tomato','olive_oil','garlic'], ARRAY['Preheat oven to 425°F (220°C).','Toss chicken and zucchini with balsamic vinegar, garlic, and olive oil.','Add halved tomatoes and bake 22-24 minutes until 165°F (74°C).','Drizzle with pan glaze and serve.'], ARRAY['Precalienta el horno a 220°C (425°F).','Mezcla el pollo y el calabacín con balsámico, ajo y aceite.','Añade tomates en mitades y hornea 22-24 minutos hasta 74°C (165°F).','Rocía con el glaseado de la bandeja y sirve.'], TRUE),
  ('r442', 'Buffalo Baked Chicken Breast', 'Pechuga de Pollo Buffalo al Horno', NULL, 431, 49, 25, 15, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','buffalo_sauce','garlic','olive_oil','carrot','celery'], ARRAY['Preheat oven to 400°F (205°C).','Coat chicken breast in buffalo sauce, garlic, and olive oil.','Bake 22-25 minutes until internal temp reaches 165°F (74°C).','Serve with carrot and celery sticks.'], ARRAY['Precalienta el horno a 205°C (400°F).','Cubre la pechuga con salsa buffalo, ajo y aceite.','Hornea 22-25 minutos hasta alcanzar 74°C (165°F).','Sirve con palitos de zanahoria y apio.'], TRUE),
  ('r443', 'Lemon Pepper Grilled Chicken', 'Pollo a la Parrilla con Limón y Pimienta', NULL, 411, 47, 31, 11, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','lemon','black_pepper','garlic','olive_oil','asparagus'], ARRAY['Season chicken with lemon zest, cracked black pepper, garlic, and olive oil.','Grill over medium-high heat 6-7 minutes per side until 165°F (74°C).','Grill asparagus alongside until tender-crisp.','Squeeze lemon over both and serve.'], ARRAY['Sazona el pollo con ralladura de limón, pimienta negra, ajo y aceite.','Asa a fuego medio-alto 6-7 minutos por lado hasta 74°C (165°F).','Asa los espárragos al lado hasta que estén tiernos.','Exprime limón sobre ambos y sirve.'], TRUE),
  ('r444', 'Smoky BBQ Baked Chicken Breast', 'Pechuga de Pollo BBQ Ahumada', NULL, 456, 45, 42, 12, 32, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','bbq_sauce','paprika','garlic','olive_oil','sweet_potato'], ARRAY['Preheat oven to 400°F (205°C).','Rub chicken with paprika and garlic, then coat in BBQ sauce.','Bake with cubed sweet potato 24-26 minutes until 165°F (74°C).','Brush with extra sauce and serve.'], ARRAY['Precalienta el horno a 205°C (400°F).','Unta el pollo con paprika y ajo, luego cubre con salsa BBQ.','Hornea con batata en cubos 24-26 minutos hasta 74°C (165°F).','Pincela con más salsa y sirve.'], TRUE),
  ('r445', 'Herb Butter Roasted Chicken', 'Pollo Asado con Mantequilla de Hierbas', NULL, 463, 46, 27, 19, 28, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','butter','garlic','parsley','olive_oil','asparagus'], ARRAY['Preheat oven to 425°F (220°C).','Mash butter with garlic and parsley; rub over chicken breast.','Roast with asparagus 20-22 minutes until 165°F (74°C).','Spoon melted herb butter over the top and serve.'], ARRAY['Precalienta el horno a 220°C (425°F).','Mezcla mantequilla con ajo y perejil; unta sobre la pechuga.','Asa con espárragos 20-22 minutos hasta 74°C (165°F).','Baña con la mantequilla de hierbas derretida y sirve.'], TRUE),
  ('r446', 'Tex-Mex Sheet-Pan Chicken Fajitas', 'Fajitas de Pollo Tex-Mex al Horno', NULL, 473, 44, 45, 13, 28, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','bell_pepper','onion','cumin','chili_powder','lime','tortilla'], ARRAY['Preheat oven to 425°F (220°C).','Toss sliced chicken, bell pepper, and onion with cumin, chili powder, and lime.','Roast 20-22 minutes until chicken reaches 165°F (74°C).','Serve in warm tortillas.'], ARRAY['Precalienta el horno a 220°C (425°F).','Mezcla el pollo en tiras, pimiento y cebolla con comino, chile en polvo y limón.','Asa 20-22 minutos hasta que el pollo llegue a 74°C (165°F).','Sirve en tortillas calientes.'], TRUE),
  ('r447', 'Garlic Butter Grilled Sirloin', 'Sirloin a la Parrilla con Mantequilla de Ajo', NULL, 475, 50, 26, 19, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['sirloin_steak','butter','garlic','olive_oil','asparagus','rosemary'], ARRAY['Bring sirloin to room temperature and season with garlic, salt, and pepper.','Grill over high heat 4-5 minutes per side for medium (135°F/57°C).','Rest 5 minutes, then top with garlic-herb butter.','Serve with grilled asparagus.'], ARRAY['Deja el sirloin a temperatura ambiente y sazona con ajo, sal y pimienta.','Asa a fuego alto 4-5 minutos por lado para término medio (57°C/135°F).','Reposa 5 minutos y cubre con mantequilla de ajo y hierbas.','Sirve con espárragos a la parrilla.'], TRUE),
  ('r448', 'Cajun Grilled Flank Steak', 'Falda a la Parrilla Cajún', NULL, 465, 48, 30, 17, 22, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['flank_steak','cajun_seasoning','olive_oil','garlic','bell_pepper'], ARRAY['Rub flank steak with Cajun seasoning, garlic, and olive oil.','Grill over high heat 4-5 minutes per side for medium (135°F/57°C).','Rest 5 minutes and slice thinly against the grain.','Serve with charred bell pepper.'], ARRAY['Unta la falda con sazón Cajún, ajo y aceite de oliva.','Asa a fuego alto 4-5 minutos por lado para término medio (57°C/135°F).','Reposa 5 minutos y corta fino contra la fibra.','Sirve con pimiento asado.'], TRUE),
  ('r449', 'Mediterranean Grilled Steak Plate', 'Plato de Bistec Mediterráneo a la Parrilla', NULL, 486, 47, 34, 18, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['steak','olive_oil','lemon','oregano','tomato','cucumber','feta'], ARRAY['Season steak with olive oil, oregano, salt, and pepper.','Grill over high heat 4-5 minutes per side to medium (135°F/57°C); rest 5 minutes.','Toss tomato and cucumber with lemon and crumbled feta.','Slice steak over the salad and serve.'], ARRAY['Sazona el bistec con aceite, orégano, sal y pimienta.','Asa a fuego alto 4-5 minutos por lado a término medio (57°C/135°F); reposa 5 minutos.','Mezcla tomate y pepino con limón y feta desmenuzado.','Rebana el bistec sobre la ensalada y sirve.'], TRUE),
  ('r450', 'Balsamic Grilled Flank Steak', 'Falda a la Parrilla con Balsámico', NULL, 452, 49, 28, 16, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['flank_steak','balsamic_vinegar','garlic','olive_oil','spinach'], ARRAY['Marinate flank steak in balsamic vinegar, garlic, and olive oil 20 minutes.','Grill over high heat 4-5 minutes per side to medium (135°F/57°C).','Rest 5 minutes and slice against the grain.','Serve over fresh spinach.'], ARRAY['Marina la falda en balsámico, ajo y aceite 20 minutos.','Asa a fuego alto 4-5 minutos por lado a término medio (57°C/135°F).','Reposa 5 minutos y corta contra la fibra.','Sirve sobre espinaca fresca.'], TRUE),
  ('r451', 'Steak & Pepper Fajita Sheet-Pan', 'Fajitas de Bistec y Pimiento al Horno', NULL, 497, 46, 40, 17, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['steak','bell_pepper','onion','cumin','lime','olive_oil'], ARRAY['Preheat oven to 450°F (230°C).','Toss sliced steak, bell pepper, and onion with cumin, lime, and olive oil.','Roast 12-15 minutes until steak is medium and peppers char.','Serve hot from the pan.'], ARRAY['Precalienta el horno a 230°C (450°F).','Mezcla el bistec en tiras, pimiento y cebolla con comino, limón y aceite.','Asa 12-15 minutos hasta que el bistec esté medio y los pimientos se doren.','Sirve caliente de la bandeja.'], TRUE),
  ('r452', 'Coffee-Rubbed Grilled Steak', 'Bistec a la Parrilla con Café', NULL, 466, 51, 25, 18, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['steak','coffee','paprika','garlic','olive_oil','sweet_potato'], ARRAY['Mix ground coffee, paprika, and garlic into a dry rub.','Press rub onto the steak and let sit 10 minutes.','Grill over high heat 4-5 minutes per side to medium (135°F/57°C); rest 5 minutes.','Serve with roasted sweet potato.'], ARRAY['Mezcla café molido, paprika y ajo para un adobo seco.','Presiona el adobo sobre el bistec y deja reposar 10 minutos.','Asa a fuego alto 4-5 minutos por lado a término medio (57°C/135°F); reposa 5 minutos.','Sirve con batata asada.'], TRUE),
  ('r453', 'Rosemary Garlic Grilled Sirloin', 'Sirloin a la Parrilla con Romero y Ajo', NULL, 461, 50, 27, 17, 22, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['sirloin_steak','rosemary','garlic','olive_oil','potato'], ARRAY['Rub sirloin with rosemary, garlic, and olive oil; season with salt.','Grill over high heat 4-5 minutes per side to medium (135°F/57°C).','Rest 5 minutes before slicing.','Serve with roasted potato.'], ARRAY['Unta el sirloin con romero, ajo y aceite; sazona con sal.','Asa a fuego alto 4-5 minutos por lado a término medio (57°C/135°F).','Reposa 5 minutos antes de rebanar.','Sirve con papa asada.'], TRUE),
  ('r454', 'Montreal Grilled Steak & Broccoli', 'Bistec Montreal con Brócoli a la Parrilla', NULL, 470, 48, 29, 18, 22, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['steak','garlic','olive_oil','broccoli','black_pepper'], ARRAY['Season steak generously with Montreal-style pepper-garlic rub.','Grill over high heat 4-5 minutes per side to medium (135°F/57°C); rest 5 minutes.','Grill or steam broccoli until tender-crisp.','Slice steak and serve with the broccoli.'], ARRAY['Sazona el bistec con abundante adobo de pimienta y ajo estilo Montreal.','Asa a fuego alto 4-5 minutos por lado a término medio (57°C/135°F); reposa 5 minutos.','Asa o cocina el brócoli al vapor hasta que esté tierno.','Rebana el bistec y sirve con el brócoli.'], TRUE),
  ('r455', 'Herb-Crusted Roast Pork Tenderloin', 'Lomo de Cerdo Asado con Hierbas', NULL, 418, 47, 26, 14, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','rosemary','thyme','garlic','olive_oil','potato'], ARRAY['Preheat oven to 425°F (220°C).','Rub pork tenderloin with rosemary, thyme, garlic, and olive oil.','Roast with cubed potato 22-25 minutes until pork reaches 145°F (63°C).','Rest 5 minutes, slice, and serve.'], ARRAY['Precalienta el horno a 220°C (425°F).','Unta el lomo de cerdo con romero, tomillo, ajo y aceite.','Asa con papa en cubos 22-25 minutos hasta que el cerdo llegue a 63°C (145°F).','Reposa 5 minutos, rebana y sirve.'], TRUE),
  ('r456', 'Balsamic Glazed Pork Tenderloin', 'Lomo de Cerdo Glaseado con Balsámico', NULL, 433, 45, 34, 13, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','balsamic_vinegar','honey','garlic','olive_oil','broccoli'], ARRAY['Preheat oven to 425°F (220°C).','Sear pork tenderloin, then brush with balsamic-honey glaze.','Roast with broccoli 20-24 minutes until pork reaches 145°F (63°C).','Rest 5 minutes, slice, and drizzle with more glaze.'], ARRAY['Precalienta el horno a 220°C (425°F).','Sella el lomo de cerdo y pincela con glaseado de balsámico y miel.','Asa con brócoli 20-24 minutos hasta que el cerdo llegue a 63°C (145°F).','Reposa 5 minutos, rebana y baña con más glaseado.'], TRUE),
  ('r457', 'Cajun Sheet-Pan Pork Tenderloin', 'Lomo de Cerdo Cajún al Horno', NULL, 462, 46, 38, 14, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','cajun_seasoning','bell_pepper','onion','olive_oil','sweet_potato'], ARRAY['Preheat oven to 425°F (220°C).','Rub pork with Cajun seasoning and olive oil; add bell pepper, onion, and sweet potato.','Roast 24-26 minutes until pork reaches 145°F (63°C).','Rest 5 minutes, slice, and serve from the pan.'], ARRAY['Precalienta el horno a 220°C (425°F).','Unta el cerdo con sazón Cajún y aceite; añade pimiento, cebolla y batata.','Asa 24-26 minutos hasta que el cerdo llegue a 63°C (145°F).','Reposa 5 minutos, rebana y sirve de la bandeja.'], TRUE),
  ('r458', 'Maple Dijon Roasted Pork Tenderloin', 'Lomo de Cerdo Asado con Arce y Dijon', NULL, 444, 44, 40, 12, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','maple_syrup','dijon_mustard','garlic','olive_oil','brussels_sprouts'], ARRAY['Preheat oven to 425°F (220°C).','Whisk maple syrup, dijon mustard, and garlic; coat the pork.','Roast with halved brussels sprouts 22-25 minutes until 145°F (63°C).','Rest 5 minutes, slice, and serve.'], ARRAY['Precalienta el horno a 220°C (425°F).','Bate sirope de arce, mostaza Dijon y ajo; cubre el cerdo.','Asa con coles de Bruselas en mitades 22-25 minutos hasta 63°C (145°F).','Reposa 5 minutos, rebana y sirve.'], TRUE),
  ('r459', 'Cuban Mojo Pork Tenderloin', 'Lomo de Cerdo al Mojo Cubano', NULL, 447, 46, 32, 15, 45, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['pork_tenderloin','orange','lime','garlic','cumin','olive_oil','rice'], ARRAY['Blend orange juice, lime, garlic, and cumin into a mojo marinade.','Marinate pork tenderloin at least 30 minutes.','Roast at 425°F (220°C) for 22-25 minutes until 145°F (63°C); rest 5 minutes.','Slice and serve over rice with pan juices.'], ARRAY['Licúa jugo de naranja, limón, ajo y comino para la marinada mojo.','Marina el lomo de cerdo al menos 30 minutos.','Asa a 220°C (425°F) por 22-25 minutos hasta 63°C (145°F); reposa 5 minutos.','Rebana y sirve sobre arroz con los jugos.'], TRUE),
  ('r460', 'Garlic Rosemary Pork Tenderloin', 'Lomo de Cerdo con Ajo y Romero', NULL, 421, 48, 28, 13, 32, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','garlic','rosemary','olive_oil','asparagus'], ARRAY['Preheat oven to 425°F (220°C).','Rub pork with garlic, rosemary, and olive oil.','Roast with asparagus 20-24 minutes until pork reaches 145°F (63°C).','Rest 5 minutes, slice, and serve.'], ARRAY['Precalienta el horno a 220°C (425°F).','Unta el cerdo con ajo, romero y aceite de oliva.','Asa con espárragos 20-24 minutos hasta que el cerdo llegue a 63°C (145°F).','Reposa 5 minutos, rebana y sirve.'], TRUE),
  ('r461', 'Chili-Lime Grilled Pork Tenderloin', 'Lomo de Cerdo a la Parrilla con Chile y Limón', NULL, 426, 45, 30, 14, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','chili_powder','lime','garlic','olive_oil','black_beans'], ARRAY['Rub pork tenderloin with chili powder, lime, and garlic.','Grill over medium-high heat, turning, 18-20 minutes until 145°F (63°C).','Rest 5 minutes and slice.','Serve with warm black beans.'], ARRAY['Unta el lomo de cerdo con chile en polvo, limón y ajo.','Asa a fuego medio-alto, girando, 18-20 minutos hasta 63°C (145°F).','Reposa 5 minutos y rebana.','Sirve con habichuelas negras calientes.'], TRUE),
  ('r462', 'Harissa Roasted Pork Tenderloin', 'Lomo de Cerdo Asado con Harissa', NULL, 463, 46, 36, 15, 33, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','harissa','garlic','olive_oil','couscous','lemon'], ARRAY['Preheat oven to 425°F (220°C).','Coat pork tenderloin with harissa, garlic, and olive oil.','Roast 22-25 minutes until pork reaches 145°F (63°C); rest 5 minutes.','Slice and serve over couscous with lemon.'], ARRAY['Precalienta el horno a 220°C (425°F).','Cubre el lomo de cerdo con harissa, ajo y aceite.','Asa 22-25 minutos hasta que el cerdo llegue a 63°C (145°F); reposa 5 minutos.','Rebana y sirve sobre cuscús con limón.'], TRUE),
  ('r463', 'Lemon Dill Baked Cod', 'Bacalao al Horno con Limón y Eneldo', NULL, 416, 43, 34, 12, 22, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cod','lemon','dill','garlic','olive_oil','rice'], ARRAY['Preheat oven to 400°F (205°C).','Top cod fillet with lemon, dill, garlic, and olive oil.','Bake 12-15 minutes until fish flakes easily (145°F/63°C).','Serve over rice with extra lemon.'], ARRAY['Precalienta el horno a 205°C (400°F).','Cubre el filete de bacalao con limón, eneldo, ajo y aceite.','Hornea 12-15 minutos hasta que el pescado se desmenuce (63°C/145°F).','Sirve sobre arroz con más limón.'], TRUE),
  ('r464', 'Mediterranean Baked Tilapia', 'Tilapia Mediterránea al Horno', NULL, 397, 40, 30, 13, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['tilapia','olive_oil','tomato','olive','garlic','oregano','lemon'], ARRAY['Preheat oven to 400°F (205°C).','Top tilapia with tomato, olives, garlic, and oregano; drizzle with olive oil.','Bake 12-14 minutes until fish flakes easily (145°F/63°C).','Finish with lemon and serve.'], ARRAY['Precalienta el horno a 205°C (400°F).','Cubre la tilapia con tomate, aceitunas, ajo y orégano; rocía con aceite.','Hornea 12-14 minutos hasta que el pescado se desmenuce (63°C/145°F).','Termina con limón y sirve.'], TRUE),
  ('r465', 'Lemon Garlic Baked Halibut', 'Halibut al Horno con Ajo y Limón', NULL, 410, 44, 27, 14, 22, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['halibut','lemon','garlic','olive_oil','asparagus','parsley'], ARRAY['Preheat oven to 400°F (205°C).','Drizzle halibut with olive oil, lemon juice, and minced garlic.','Bake with asparagus 13-15 minutes until fish flakes (145°F/63°C).','Garnish with parsley and serve.'], ARRAY['Precalienta el horno a 205°C (400°F).','Rocía el halibut con aceite, jugo de limón y ajo picado.','Hornea con espárragos 13-15 minutos hasta que el pescado se desmenuce (63°C/145°F).','Decora con perejil y sirve.'], TRUE),
  ('r466', 'Sheet-Pan Cod Caprese', 'Bacalao Caprese al Horno', NULL, 424, 42, 28, 16, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cod','tomato','cheese','basil','olive_oil','garlic'], ARRAY['Preheat oven to 400°F (205°C).','Place cod on a sheet pan and top with sliced tomato and cheese.','Drizzle with olive oil and garlic; bake 14-16 minutes until fish flakes (145°F/63°C).','Scatter fresh basil over the top and serve.'], ARRAY['Precalienta el horno a 205°C (400°F).','Coloca el bacalao en una bandeja y cubre con tomate en rodajas y queso.','Rocía con aceite y ajo; hornea 14-16 minutos hasta que se desmenuce (63°C/145°F).','Esparce albahaca fresca encima y sirve.'], TRUE),
  ('r467', 'Blackened Tilapia Plate', 'Plato de Tilapia Ennegrecida', NULL, 412, 43, 33, 12, 18, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['tilapia','paprika','cayenne','garlic','olive_oil','rice','lime'], ARRAY['Mix paprika, cayenne, and garlic into a blackening spice.','Coat tilapia and sear in a hot skillet 3 minutes per side until charred and cooked.','Squeeze lime over the fish.','Serve over rice.'], ARRAY['Mezcla paprika, cayena y ajo para el condimento ennegrecido.','Cubre la tilapia y sella en sartén caliente 3 minutos por lado hasta dorar y cocinar.','Exprime limón sobre el pescado.','Sirve sobre arroz.'], TRUE),
  ('r468', 'Caribbean Jerk Tilapia', 'Tilapia Jerk Caribeña', NULL, 411, 41, 37, 11, 22, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['tilapia','jerk_seasoning','lime','garlic','olive_oil','rice'], ARRAY['Rub tilapia with jerk seasoning, garlic, and olive oil.','Bake at 400°F (205°C) for 12-14 minutes until fish flakes (145°F/63°C).','Squeeze lime over the fish.','Serve over rice.'], ARRAY['Unta la tilapia con condimento jerk, ajo y aceite de oliva.','Hornea a 205°C (400°F) por 12-14 minutos hasta que se desmenuce (63°C/145°F).','Exprime limón sobre el pescado.','Sirve sobre arroz.'], TRUE),
  ('r469', 'Greek Baked Cod & Tomatoes', 'Bacalao Griego al Horno con Tomate', NULL, 410, 42, 29, 14, 24, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cod','tomato','olive_oil','garlic','oregano','feta','lemon'], ARRAY['Preheat oven to 400°F (205°C).','Place cod in a dish with tomato, garlic, oregano, and olive oil.','Bake 14-16 minutes until fish flakes easily (145°F/63°C).','Crumble feta over top, add lemon, and serve.'], ARRAY['Precalienta el horno a 205°C (400°F).','Coloca el bacalao en un molde con tomate, ajo, orégano y aceite.','Hornea 14-16 minutos hasta que el pescado se desmenuce (63°C/145°F).','Desmenuza feta encima, añade limón y sirve.'], TRUE),
  ('r470', 'Herb-Crusted Baked Halibut', 'Halibut al Horno con Costra de Hierbas', NULL, 419, 45, 26, 15, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['halibut','parsley','thyme','garlic','olive_oil','whole_grain_bread'], ARRAY['Preheat oven to 400°F (205°C).','Combine breadcrumbs, parsley, thyme, and garlic; press onto the halibut.','Drizzle with olive oil and bake 14-16 minutes until fish flakes (145°F/63°C).','Serve warm.'], ARRAY['Precalienta el horno a 205°C (400°F).','Combina pan rallado, perejil, tomillo y ajo; presiona sobre el halibut.','Rocía con aceite y hornea 14-16 minutos hasta que el pescado se desmenuce (63°C/145°F).','Sirve caliente.'], TRUE),
  ('r471', 'Pesto Baked Cod', 'Bacalao al Pesto al Horno', NULL, 437, 43, 28, 17, 24, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cod','pesto','zucchini','tomato','olive_oil','garlic'], ARRAY['Preheat oven to 400°F (205°C).','Spread pesto over cod and surround with zucchini and tomato.','Drizzle with olive oil and bake 14-16 minutes until fish flakes (145°F/63°C).','Serve hot.'], ARRAY['Precalienta el horno a 205°C (400°F).','Cubre el bacalao con pesto y rodea con calabacín y tomate.','Rocía con aceite y hornea 14-16 minutos hasta que el pescado se desmenuce (63°C/145°F).','Sirve caliente.'], TRUE),
  ('r472', 'Herb Roasted Turkey Breast', 'Pechuga de Pavo Asada con Hierbas', NULL, 408, 50, 25, 12, 50, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['turkey_breast','rosemary','thyme','garlic','olive_oil','potato'], ARRAY['Preheat oven to 375°F (190°C).','Rub turkey breast with rosemary, thyme, garlic, and olive oil.','Roast with potato 35-40 minutes until turkey reaches 165°F (74°C).','Rest 10 minutes, slice, and serve.'], ARRAY['Precalienta el horno a 190°C (375°F).','Unta la pechuga de pavo con romero, tomillo, ajo y aceite.','Asa con papa 35-40 minutos hasta que el pavo llegue a 74°C (165°F).','Reposa 10 minutos, rebana y sirve.'], TRUE),
  ('r473', 'BBQ Turkey Meatloaf', 'Pastel de Carne de Pavo BBQ', NULL, 484, 45, 40, 16, 55, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['ground_turkey','bbq_sauce','onion','garlic','eggs','oats'], ARRAY['Preheat oven to 375°F (190°C).','Mix ground turkey, oats, egg, onion, and garlic; press into a loaf pan.','Top with BBQ sauce and bake 40-45 minutes until 165°F (74°C).','Rest 10 minutes, slice, and serve.'], ARRAY['Precalienta el horno a 190°C (375°F).','Mezcla pavo molido, avena, huevo, cebolla y ajo; presiona en un molde.','Cubre con salsa BBQ y hornea 40-45 minutos hasta 74°C (165°F).','Reposa 10 minutos, rebana y sirve.'], TRUE),
  ('r474', 'Mediterranean Turkey Burgers', 'Hamburguesas de Pavo Mediterráneas', NULL, 458, 44, 30, 18, 22, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','feta','spinach','garlic','olive_oil','oregano'], ARRAY['Mix ground turkey with feta, chopped spinach, garlic, and oregano.','Form into patties.','Grill over medium heat 5-6 minutes per side until 165°F (74°C).','Serve with a drizzle of olive oil.'], ARRAY['Mezcla el pavo molido con feta, espinaca picada, ajo y orégano.','Forma las hamburguesas.','Asa a fuego medio 5-6 minutos por lado hasta 74°C (165°F).','Sirve con un chorrito de aceite de oliva.'], TRUE),
  ('r475', 'Cajun Turkey Cutlets', 'Filetes de Pavo Cajún', NULL, 417, 48, 27, 13, 18, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['turkey_breast','cajun_seasoning','olive_oil','garlic','bell_pepper'], ARRAY['Season turkey breast cutlets with Cajun seasoning and garlic.','Sear in olive oil over medium-high heat 3-4 minutes per side until 165°F (74°C).','Add sliced bell pepper to the pan and cook until soft.','Serve the cutlets topped with peppers.'], ARRAY['Sazona los filetes de pechuga de pavo con sazón Cajún y ajo.','Sella en aceite a fuego medio-alto 3-4 minutos por lado hasta 74°C (165°F).','Añade pimiento en tiras a la sartén y cocina hasta ablandar.','Sirve los filetes cubiertos con los pimientos.'], TRUE),
  ('r476', 'Italian Baked Turkey Meatballs', 'Albóndigas de Pavo Italianas al Horno', NULL, 477, 46, 35, 17, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','tomato','garlic','oregano','eggs','cheese'], ARRAY['Preheat oven to 400°F (205°C).','Mix ground turkey, egg, garlic, oregano, and cheese; roll into meatballs.','Bake 18-20 minutes until 165°F (74°C).','Simmer in tomato sauce 5 minutes and serve.'], ARRAY['Precalienta el horno a 205°C (400°F).','Mezcla pavo molido, huevo, ajo, orégano y queso; forma albóndigas.','Hornea 18-20 minutos hasta 74°C (165°F).','Cocina en salsa de tomate 5 minutos y sirve.'], TRUE),
  ('r477', 'Southwest Turkey Sheet-Pan', 'Pavo Estilo Suroeste al Horno', NULL, 474, 43, 44, 14, 28, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','bell_pepper','onion','black_beans','cumin','corn'], ARRAY['Preheat oven to 400°F (205°C).','Toss ground turkey, bell pepper, onion, black beans, and corn with cumin.','Spread on a sheet pan and bake 18-20 minutes until turkey is cooked through (165°F/74°C).','Serve warm.'], ARRAY['Precalienta el horno a 205°C (400°F).','Mezcla pavo molido, pimiento, cebolla, habichuelas negras y maíz con comino.','Extiende en una bandeja y hornea 18-20 minutos hasta cocinar el pavo (74°C/165°F).','Sirve caliente.'], TRUE),
  ('r478', 'Greek Turkey Kofta Skewers', 'Brochetas de Kofta de Pavo Griega', NULL, 436, 45, 28, 16, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['ground_turkey','cumin','garlic','onion','parsley','olive_oil'], ARRAY['Mix ground turkey with cumin, garlic, grated onion, and parsley.','Shape the mixture around skewers into kofta logs.','Grill over medium-high heat, turning, 10-12 minutes until 165°F (74°C).','Drizzle with olive oil and serve.'], ARRAY['Mezcla el pavo molido con comino, ajo, cebolla rallada y perejil.','Moldea la mezcla alrededor de brochetas en forma de kofta.','Asa a fuego medio-alto, girando, 10-12 minutos hasta 74°C (165°F).','Rocía con aceite de oliva y sirve.'], TRUE),
  ('r479', 'Teriyaki Glazed Baked Cod', 'Bacalao Glaseado Teriyaki al Horno', NULL, 415, 41, 38, 11, 22, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cod','soy_sauce','honey','garlic','sesame_oil','rice'], ARRAY['Preheat oven to 400°F (205°C).','Whisk soy sauce, honey, garlic, and sesame oil into a teriyaki glaze.','Brush over cod and bake 12-15 minutes until fish flakes (145°F/63°C).','Serve over rice with extra glaze.'], ARRAY['Precalienta el horno a 205°C (400°F).','Bate salsa de soya, miel, ajo y aceite de sésamo para el glaseado teriyaki.','Pincela sobre el bacalao y hornea 12-15 minutos hasta que se desmenuce (63°C/145°F).','Sirve sobre arroz con más glaseado.'], TRUE),
  ('r480', 'BBQ Glazed Pork Tenderloin', 'Lomo de Cerdo Glaseado BBQ', NULL, 478, 46, 42, 14, 33, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','bbq_sauce','garlic','paprika','olive_oil','sweet_potato'], ARRAY['Preheat oven to 425°F (220°C).','Rub pork tenderloin with paprika and garlic, then brush with BBQ sauce.','Roast with sweet potato 22-25 minutes until pork reaches 145°F (63°C).','Rest 5 minutes, slice, and brush with more sauce.'], ARRAY['Precalienta el horno a 220°C (425°F).','Unta el lomo de cerdo con paprika y ajo, luego pincela con salsa BBQ.','Asa con batata 22-25 minutos hasta que el cerdo llegue a 63°C (145°F).','Reposa 5 minutos, rebana y pincela con más salsa.'], TRUE),
  ('r481', 'Chicken Teriyaki Donburi', 'Donburi de Pollo Teriyaki', NULL, 492, 48, 48, 12, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','rice','broccoli','soy_sauce','honey','sesame_oil','onion'], ARRAY['Simmer soy sauce, honey, and a splash of water into a glossy teriyaki glaze, 3 minutes.','Sear sliced chicken thigh in sesame oil over medium-high until cooked through, 6-7 minutes.','Toss the chicken in the glaze while you steam the broccoli, 3 minutes.','Serve over hot rice, topped with broccoli and sliced green onion.'], ARRAY['Cocina a fuego lento la salsa de soya, la miel y un chorrito de agua hasta formar un glaseado teriyaki brillante, 3 minutos.','Dora el muslo de pollo en rodajas en aceite de sésamo a fuego medio-alto hasta cocinar, 6-7 minutos.','Mezcla el pollo con el glaseado mientras cocinas el brócoli al vapor, 3 minutos.','Sirve sobre arroz caliente, con el brócoli y cebollín encima.'], TRUE),
  ('r482', 'Korean Chicken Bulgogi Bowl', 'Bowl de Pollo Bulgogi Coreano', NULL, 478, 46, 42, 14, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','carrot','spinach','soy_sauce','sesame_oil','garlic'], ARRAY['Marinate sliced chicken in soy sauce, grated garlic, sesame oil, and a little honey, 15 minutes.','Stir-fry the chicken over high heat until caramelized, 5-6 minutes.','Quickly wilt the spinach and julienned carrot in the same pan.','Pile over rice and finish with sesame seeds.'], ARRAY['Marina el pollo en rodajas con salsa de soya, ajo rallado, aceite de sésamo y un poco de miel, 15 minutos.','Saltea el pollo a fuego alto hasta caramelizar, 5-6 minutos.','Marchita rápidamente la espinaca y la zanahoria en juliana en la misma sartén.','Sirve sobre arroz y termina con semillas de sésamo.'], TRUE),
  ('r483', 'Pad Krapow Chicken', 'Pollo a la Albahaca Tailandesa (Pad Krapow)', NULL, 480, 44, 40, 16, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','bell_pepper','garlic','soy_sauce','eggs','onion'], ARRAY['Fry minced garlic and chili in oil, then add ground chicken over high heat, 5 minutes.','Add sliced bell pepper and onion; season with soy sauce and a pinch of sugar.','Stir in a big handful of Thai basil until just wilted.','Fry an egg crispy and serve over rice with the basil chicken.'], ARRAY['Sofríe ajo picado y chile en aceite, luego agrega el pollo molido a fuego alto, 5 minutos.','Añade el pimiento y la cebolla en rodajas; sazona con salsa de soya y una pizca de azúcar.','Incorpora un puñado grande de albahaca tailandesa hasta marchitar.','Fríe un huevo crujiente y sirve sobre arroz con el pollo a la albahaca.'], TRUE),
  ('r484', 'Japanese Salmon Teriyaki Bowl', 'Bowl de Salmón Teriyaki', NULL, 510, 42, 45, 18, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','broccoli','soy_sauce','honey','sesame_oil','onion'], ARRAY['Pan-sear salmon skin-side down in sesame oil, 4 minutes, then flip for 2 minutes.','Add soy sauce and honey to the pan and spoon the glaze over the fish.','Steam the broccoli until bright green, 3 minutes.','Serve salmon and broccoli over rice, drizzled with pan glaze and green onion.'], ARRAY['Sella el salmón con la piel hacia abajo en aceite de sésamo, 4 minutos, y voltea 2 minutos.','Agrega salsa de soya y miel a la sartén y baña el pescado con el glaseado.','Cocina el brócoli al vapor hasta que esté verde brillante, 3 minutos.','Sirve el salmón y el brócoli sobre arroz, con el glaseado y cebollín.'], TRUE),
  ('r485', 'Shrimp Pad Thai Protein Bowl', 'Bowl Proteico de Pad Thai con Camarón', NULL, 486, 40, 50, 14, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['shrimp','rice_noodles','eggs','bean_sprouts','peanuts','soy_sauce','lemon'], ARRAY['Soak the rice noodles in hot water until pliable, then drain.','Stir-fry shrimp until pink, push aside, and scramble the eggs in the pan.','Add noodles, soy sauce, tamarind or lemon, and a pinch of sugar; toss to coat.','Fold in bean sprouts and top with crushed peanuts.'], ARRAY['Remoja los fideos de arroz en agua caliente hasta que estén flexibles y escurre.','Saltea los camarones hasta que estén rosados, aparta y revuelve los huevos en la sartén.','Agrega los fideos, salsa de soya, tamarindo o limón y una pizca de azúcar; mezcla bien.','Incorpora los germinados y cubre con maní triturado.'], TRUE),
  ('r486', 'Beef Bulgogi Rice Bowl', 'Bowl de Carne Bulgogi', NULL, 505, 45, 43, 17, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['lean_beef','rice','onion','carrot','soy_sauce','sesame_oil','garlic'], ARRAY['Marinate thin-sliced beef in soy sauce, garlic, sesame oil, and honey, 20 minutes.','Sear the beef in a screaming-hot pan, 2-3 minutes, so it caramelizes.','Stir-fry the onion and carrot until just tender.','Serve over rice with a sprinkle of sesame seeds and green onion.'], ARRAY['Marina la carne en lonjas finas con salsa de soya, ajo, aceite de sésamo y miel, 20 minutos.','Sella la carne en una sartén bien caliente, 2-3 minutos, para caramelizar.','Saltea la cebolla y la zanahoria hasta que estén tiernas.','Sirve sobre arroz con semillas de sésamo y cebollín.'], TRUE),
  ('r487', 'Japanese Chicken Curry Bowl', 'Bowl de Curry Japonés de Pollo', NULL, 499, 43, 48, 15, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','carrot','onion','potato','curry_paste'], ARRAY['Brown cubed chicken in a pot, then remove.','Saute onion, carrot, and potato until the edges soften, 5 minutes.','Add water and Japanese curry roux; simmer until thick and the vegetables are tender, 15 minutes.','Return the chicken to warm through and serve over rice.'], ARRAY['Dora el pollo en cubos en una olla y retíralo.','Sofríe la cebolla, la zanahoria y la papa hasta ablandar los bordes, 5 minutos.','Agrega agua y roux de curry japonés; cocina a fuego lento hasta espesar y ablandar las verduras, 15 minutos.','Regresa el pollo para calentar y sirve sobre arroz.'], TRUE),
  ('r488', 'Teriyaki Shrimp Stir-Fry', 'Salteado de Camarón Teriyaki', NULL, 439, 47, 38, 11, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['shrimp','broccoli','bell_pepper','rice','soy_sauce','honey','garlic'], ARRAY['Whisk soy sauce, honey, garlic, and a splash of water for the sauce.','Stir-fry shrimp over high heat until pink, 3 minutes, then remove.','Stir-fry broccoli and bell pepper 3-4 minutes; return the shrimp and add the sauce.','Toss until glossy and serve over rice.'], ARRAY['Bate salsa de soya, miel, ajo y un chorrito de agua para la salsa.','Saltea los camarones a fuego alto hasta que estén rosados, 3 minutos, y retíralos.','Saltea el brócoli y el pimiento 3-4 minutos; regresa los camarones y añade la salsa.','Mezcla hasta que brille y sirve sobre arroz.'], TRUE),
  ('r489', 'Korean Gochujang Chicken Bowl', 'Bowl de Pollo Gochujang', NULL, 473, 49, 40, 13, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','rice','cucumber','carrot','gochujang','sesame_oil','garlic'], ARRAY['Coat sliced chicken thigh in gochujang, garlic, sesame oil, and honey.','Sear in a hot pan until sticky and cooked through, 7-8 minutes.','Slice cucumber and carrot into quick pickles with rice vinegar.','Serve the chicken over rice with the pickles and sesame seeds.'], ARRAY['Cubre el muslo de pollo en rodajas con gochujang, ajo, aceite de sésamo y miel.','Sella en sartén caliente hasta que esté pegajoso y cocido, 7-8 minutos.','Corta el pepino y la zanahoria en encurtidos rápidos con vinagre de arroz.','Sirve el pollo sobre arroz con los encurtidos y semillas de sésamo.'], TRUE),
  ('r490', 'Thai Green Curry Chicken Bowl', 'Bowl de Curry Verde Tailandés', NULL, 482, 42, 38, 18, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','bell_pepper','zucchini','coconut_milk','curry_paste'], ARRAY['Fry green curry paste in a little oil until fragrant, 1 minute.','Pour in the coconut milk and bring to a gentle simmer.','Add sliced chicken, bell pepper, and zucchini; simmer until cooked, 10 minutes.','Serve over jasmine rice with Thai basil.'], ARRAY['Fríe la pasta de curry verde en un poco de aceite hasta que aromatice, 1 minuto.','Vierte la leche de coco y lleva a fuego lento suave.','Agrega el pollo en rodajas, el pimiento y el calabacín; cocina hasta que estén listos, 10 minutos.','Sirve sobre arroz jazmín con albahaca tailandesa.'], TRUE),
  ('r491', 'Vietnamese Chicken Banh Mi Bowl', 'Bowl Vietnamita Banh Mi de Pollo', NULL, 452, 44, 42, 12, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','carrot','cucumber','garlic','soy_sauce'], ARRAY['Marinate chicken in soy sauce, garlic, honey, and lemongrass, 15 minutes.','Grill or sear the chicken until charred and cooked, 6-7 minutes, then slice.','Quick-pickle shredded carrot and cucumber in rice vinegar and a pinch of sugar.','Build a bowl of rice, chicken, pickles, cilantro, and sriracha mayo.'], ARRAY['Marina el pollo con salsa de soya, ajo, miel y hierba de limón, 15 minutos.','Asa o sella el pollo hasta dorar y cocinar, 6-7 minutos, y córtalo.','Encurte rápido la zanahoria y el pepino rallados en vinagre de arroz y una pizca de azúcar.','Arma un bowl de arroz, pollo, encurtidos, cilantro y mayonesa con sriracha.'], TRUE),
  ('r492', 'Sichuan Beef & Pepper Stir-Fry', 'Salteado de Carne y Pimientos Sichuan', NULL, 466, 46, 30, 18, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['lean_beef','bell_pepper','onion','garlic','soy_sauce','sesame_oil'], ARRAY['Toss sliced beef with a little soy sauce and cornstarch.','Sear the beef in a very hot wok until browned, 2 minutes, then remove.','Stir-fry bell pepper, onion, garlic, and Sichuan peppercorns, 3 minutes.','Return the beef, splash with soy sauce and sesame oil, and toss.'], ARRAY['Mezcla la carne en rodajas con un poco de salsa de soya y maicena.','Sella la carne en un wok muy caliente hasta dorar, 2 minutos, y retírala.','Saltea el pimiento, la cebolla, el ajo y la pimienta de Sichuan, 3 minutos.','Regresa la carne, añade salsa de soya y aceite de sésamo, y mezcla.'], TRUE),
  ('r493', 'Salmon Poke Bowl', 'Poke Bowl de Salmón', NULL, 511, 40, 45, 19, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','cucumber','avocado','edamame','soy_sauce','sesame_oil'], ARRAY['Dice sushi-grade salmon and toss with soy sauce and sesame oil.','Cook and cool sushi rice; slice cucumber and avocado.','Boil edamame 3 minutes and shell.','Arrange salmon and toppings over rice; finish with sesame seeds.'], ARRAY['Corta en cubos salmón calidad sushi y mézclalo con salsa de soya y aceite de sésamo.','Cocina y enfría arroz para sushi; corta el pepino y el aguacate.','Hierve el edamame 3 minutos y desgránalo.','Acomoda el salmón y los toppings sobre el arroz; termina con semillas de sésamo.'], TRUE),
  ('r494', 'Hawaiian Shrimp Poke Bowl', 'Poke Bowl de Camarón Hawaiano', NULL, 468, 44, 46, 12, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['shrimp','rice','cucumber','avocado','edamame','soy_sauce','onion'], ARRAY['Poach shrimp until just pink, 2 minutes, then chill in ice water.','Toss the shrimp with soy sauce, sesame oil, and green onion.','Cook sushi rice and let it cool slightly.','Top rice with shrimp, cucumber, avocado, and edamame.'], ARRAY['Escalfa los camarones hasta que estén rosados, 2 minutos, y enfríalos en agua con hielo.','Mezcla los camarones con salsa de soya, aceite de sésamo y cebollín.','Cocina el arroz para sushi y déjalo enfriar un poco.','Cubre el arroz con camarones, pepino, aguacate y edamame.'], TRUE),
  ('r495', 'Chicken Yakisoba Stir-Fry', 'Salteado de Yakisoba con Pollo', NULL, 486, 43, 47, 14, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','egg_noodles','cabbage','carrot','bell_pepper','soy_sauce'], ARRAY['Boil the yakisoba noodles briefly, then drain.','Stir-fry sliced chicken until cooked, 5 minutes.','Add cabbage, carrot, and bell pepper; stir-fry 3 minutes.','Toss in noodles and yakisoba (Worcestershire-soy) sauce until coated.'], ARRAY['Hierve brevemente los fideos yakisoba y escúrrelos.','Saltea el pollo en rodajas hasta cocinar, 5 minutos.','Agrega el repollo, la zanahoria y el pimiento; saltea 3 minutos.','Incorpora los fideos y la salsa yakisoba hasta cubrir.'], TRUE),
  ('r496', 'Korean Beef Japchae Bowl', 'Bowl Coreano de Japchae con Carne', NULL, 488, 42, 44, 16, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['lean_beef','glass_noodles','spinach','carrot','onion','soy_sauce','sesame_oil'], ARRAY['Boil glass noodles until chewy, drain, and cut.','Stir-fry the beef, then each vegetable separately in sesame oil.','Combine noodles, beef, and vegetables with soy sauce and a little honey.','Toss over heat 2 minutes and finish with sesame seeds.'], ARRAY['Hierve los fideos de cristal hasta que estén chiclosos, escurre y córtalos.','Saltea la carne y luego cada verdura por separado en aceite de sésamo.','Combina los fideos, la carne y las verduras con salsa de soya y un poco de miel.','Saltea todo junto 2 minutos y termina con semillas de sésamo.'], TRUE),
  ('r497', 'Miso Chicken Ramen Bowl', 'Ramen de Pollo con Miso', NULL, 457, 45, 40, 13, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','egg_noodles','eggs','spinach','mushroom','soy_sauce','onion'], ARRAY['Simmer chicken broth with miso paste and soy sauce, 5 minutes.','Poach sliced chicken in the broth until cooked, 6 minutes.','Cook ramen noodles separately and soft-boil an egg, 7 minutes.','Assemble noodles, broth, chicken, spinach, mushroom, egg, and green onion.'], ARRAY['Cocina a fuego lento caldo de pollo con pasta de miso y salsa de soya, 5 minutos.','Escalfa el pollo en rodajas en el caldo hasta cocinar, 6 minutos.','Cocina los fideos ramen aparte y prepara un huevo pasado por agua, 7 minutos.','Monta los fideos, el caldo, el pollo, la espinaca, el champiñón, el huevo y el cebollín.'], TRUE),
  ('r498', 'Teriyaki Tofu Rice Bowl', 'Bowl de Tofu Teriyaki', NULL, 480, 38, 46, 16, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['tofu','rice','broccoli','edamame','soy_sauce','honey','sesame_oil'], ARRAY['Press firm tofu, cube it, and pan-fry until golden on all sides, 8 minutes.','Add soy sauce and honey to glaze the tofu.','Steam broccoli and edamame until tender.','Serve over rice with sesame seeds and green onion.'], ARRAY['Prensa el tofu firme, córtalo en cubos y fríelo hasta dorar por todos lados, 8 minutos.','Agrega salsa de soya y miel para glasear el tofu.','Cocina al vapor el brócoli y el edamame hasta que estén tiernos.','Sirve sobre arroz con semillas de sésamo y cebollín.'], TRUE),
  ('r499', 'Thai Chicken Satay Bowl', 'Bowl Tailandés de Pollo Satay', NULL, 494, 45, 38, 18, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','cucumber','bell_pepper','peanut_butter','soy_sauce','garlic'], ARRAY['Marinate chicken strips in soy sauce, garlic, and curry powder, 15 minutes.','Grill or sear the skewered chicken until charred, 6 minutes.','Whisk peanut butter, soy sauce, lime, and water into a satay sauce.','Serve over rice with cucumber, bell pepper, and peanut sauce.'], ARRAY['Marina las tiras de pollo en salsa de soya, ajo y curry en polvo, 15 minutos.','Asa o sella el pollo en brochetas hasta dorar, 6 minutos.','Bate mantequilla de maní, salsa de soya, limón y agua para la salsa satay.','Sirve sobre arroz con pepino, pimiento y salsa de maní.'], TRUE),
  ('r500', 'Japanese Chicken Karaage Bowl', 'Bowl Japonés de Pollo Karaage', NULL, 505, 46, 42, 17, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','cabbage','soy_sauce','garlic'], ARRAY['Marinate chicken thigh chunks in soy sauce, grated ginger, and garlic, 20 minutes.','Dredge in potato starch and shallow-fry until golden and crisp, 4 minutes.','Drain on a rack and salt lightly.','Serve over rice with shredded cabbage and a wedge of lemon.'], ARRAY['Marina los trozos de muslo de pollo en salsa de soya, jengibre rallado y ajo, 20 minutos.','Rebózalos en fécula de papa y fríe hasta dorar y quedar crujientes, 4 minutos.','Escúrrelos en una rejilla y sala ligeramente.','Sirve sobre arroz con repollo rallado y un gajo de limón.'], TRUE),
  ('r501', 'Korean Dak Galbi Chicken Bowl', 'Bowl de Pollo Dak Galbi Coreano', NULL, 483, 47, 40, 15, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','cabbage','sweet_potato','gochujang','onion'], ARRAY['Marinate diced chicken thigh in gochujang, soy sauce, and garlic, 20 minutes.','Stir-fry the chicken with onion and sweet potato over high heat, 8 minutes.','Add cabbage and cook until wilted and the chicken is done.','Serve over rice with sesame seeds and green onion.'], ARRAY['Marina el muslo de pollo en cubos con gochujang, salsa de soya y ajo, 20 minutos.','Saltea el pollo con cebolla y batata a fuego alto, 8 minutos.','Agrega el repollo y cocina hasta marchitar y que el pollo esté listo.','Sirve sobre arroz con semillas de sésamo y cebollín.'], TRUE),
  ('r502', 'Shrimp Fried Rice Bowl', 'Bowl de Arroz Frito con Camarón', NULL, 477, 42, 48, 13, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['shrimp','rice','eggs','carrot','onion','soy_sauce','garlic'], ARRAY['Scramble the eggs in a hot wok and set aside.','Stir-fry shrimp until pink, then add carrot, onion, and garlic.','Add cold cooked rice and soy sauce; stir-fry until sizzling, 4 minutes.','Fold in the eggs and finish with green onion.'], ARRAY['Revuelve los huevos en un wok caliente y reserva.','Saltea los camarones hasta que estén rosados, luego agrega zanahoria, cebolla y ajo.','Añade arroz frío cocido y salsa de soya; saltea hasta que chisporrotee, 4 minutos.','Incorpora los huevos y termina con cebollín.'], TRUE),
  ('r503', 'Beef Chow Fun Noodles', 'Fideos Chow Fun con Carne', NULL, 508, 44, 47, 16, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['lean_beef','rice_noodles','bean_sprouts','onion','soy_sauce','sesame_oil'], ARRAY['Toss sliced beef with soy sauce and a little cornstarch.','Sear the beef in a hot wok, 2 minutes, then remove.','Stir-fry wide rice noodles with onion and bean sprouts, adding dark soy sauce.','Return the beef, toss with sesame oil, and serve.'], ARRAY['Mezcla la carne en rodajas con salsa de soya y un poco de maicena.','Sella la carne en un wok caliente, 2 minutos, y retírala.','Saltea los fideos anchos de arroz con cebolla y germinados, agregando salsa de soya oscura.','Regresa la carne, mezcla con aceite de sésamo y sirve.'], TRUE),
  ('r504', 'Chicken Chow Mein', 'Chow Mein de Pollo', NULL, 482, 45, 44, 14, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','egg_noodles','cabbage','carrot','soy_sauce','garlic'], ARRAY['Boil chow mein noodles until just tender, then drain.','Stir-fry sliced chicken with garlic until cooked, 5 minutes.','Add cabbage and carrot; stir-fry 3 minutes.','Toss in noodles and soy sauce until everything is coated.'], ARRAY['Hierve los fideos chow mein hasta que estén tiernos y escúrrelos.','Saltea el pollo en rodajas con ajo hasta cocinar, 5 minutos.','Agrega el repollo y la zanahoria; saltea 3 minutos.','Incorpora los fideos y la salsa de soya hasta cubrir todo.'], TRUE),
  ('r505', 'Nasi Goreng Chicken Bowl', 'Bowl de Nasi Goreng con Pollo', NULL, 491, 43, 46, 15, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','eggs','carrot','garlic','soy_sauce'], ARRAY['Stir-fry diced chicken with garlic and chili paste until cooked.','Add cold rice and sweet soy sauce (kecap manis); stir-fry until fragrant.','Push aside and fry an egg until crispy-edged.','Serve the fried rice topped with the egg and sliced carrot.'], ARRAY['Saltea el pollo en cubos con ajo y pasta de chile hasta cocinar.','Agrega arroz frío y salsa de soya dulce (kecap manis); saltea hasta que aromatice.','Aparta y fríe un huevo con bordes crujientes.','Sirve el arroz frito coronado con el huevo y zanahoria en rodajas.'], TRUE),
  ('r506', 'Sweet & Sour Chicken Bowl', 'Bowl de Pollo Agridulce', NULL, 480, 44, 49, 12, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','bell_pepper','pineapple','onion','soy_sauce'], ARRAY['Sear bite-sized chicken until golden, 6 minutes.','Stir-fry bell pepper, onion, and pineapple, 3 minutes.','Add a sauce of ketchup, rice vinegar, soy sauce, and a little honey; simmer to thicken.','Toss the chicken to coat and serve over rice.'], ARRAY['Sella el pollo en trozos hasta dorar, 6 minutos.','Saltea el pimiento, la cebolla y la piña, 3 minutos.','Agrega una salsa de ketchup, vinagre de arroz, salsa de soya y un poco de miel; cocina hasta espesar.','Mezcla el pollo para cubrir y sirve sobre arroz.'], TRUE),
  ('r507', 'Ginger Sesame Chicken Stir-Fry', 'Salteado de Pollo al Jengibre y Sésamo', NULL, 462, 48, 36, 14, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','broccoli','carrot','rice','soy_sauce','sesame_oil','garlic'], ARRAY['Stir-fry sliced chicken in sesame oil until golden, 6 minutes.','Add broccoli, carrot, grated ginger, and garlic; stir-fry 4 minutes.','Splash in soy sauce and a little honey; toss to glaze.','Serve over rice with toasted sesame seeds.'], ARRAY['Saltea el pollo en rodajas en aceite de sésamo hasta dorar, 6 minutos.','Agrega brócoli, zanahoria, jengibre rallado y ajo; saltea 4 minutos.','Añade salsa de soya y un poco de miel; mezcla para glasear.','Sirve sobre arroz con semillas de sésamo tostadas.'], TRUE),
  ('r508', 'Thai Turkey Larb Lettuce Cups', 'Larb Tailandés de Pavo en Lechuga', NULL, 423, 46, 26, 15, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','lettuce','onion','lemon','soy_sauce','garlic'], ARRAY['Brown ground turkey with garlic over high heat until crisp, 6 minutes.','Off the heat, toss with lime juice, fish sauce (or soy), chili, and sliced shallot.','Fold in fresh mint and cilantro.','Spoon into crisp lettuce cups and serve.'], ARRAY['Dora el pavo molido con ajo a fuego alto hasta que esté crujiente, 6 minutos.','Fuera del fuego, mezcla con jugo de limón, salsa de pescado (o soya), chile y chalota en rodajas.','Incorpora menta y cilantro frescos.','Sirve en hojas de lechuga crujientes.'], TRUE),
  ('r509', 'Beef Gyudon Bowl', 'Bowl de Carne Gyudon', NULL, 517, 45, 46, 17, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['lean_beef','rice','onion','eggs','soy_sauce','honey'], ARRAY['Simmer onion in dashi, soy sauce, and a little honey until soft, 5 minutes.','Add thin-sliced beef and cook in the broth until just done, 3 minutes.','Pour beaten egg over the top and cover until barely set.','Slide over a bowl of hot rice and top with green onion.'], ARRAY['Cocina la cebolla en dashi, salsa de soya y un poco de miel hasta ablandar, 5 minutos.','Agrega la carne en lonjas finas y cocínala en el caldo hasta que esté lista, 3 minutos.','Vierte huevo batido encima y tapa hasta que apenas cuaje.','Sirve sobre un bowl de arroz caliente y corona con cebollín.'], TRUE),
  ('r510', 'Deconstructed Salmon Sushi Bowl', 'Bowl Deconstruido de Sushi de Salmón', NULL, 500, 41, 48, 16, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','cucumber','avocado','soy_sauce','sesame_oil'], ARRAY['Season warm sushi rice with rice vinegar and let it cool.','Sear or bake the salmon, then flake into big pieces.','Slice cucumber and avocado.','Top rice with salmon, vegetables, crumbled nori, soy sauce, and sesame oil.'], ARRAY['Sazona el arroz para sushi tibio con vinagre de arroz y déjalo enfriar.','Sella u hornea el salmón y desmenúzalo en trozos grandes.','Corta el pepino y el aguacate.','Cubre el arroz con salmón, verduras, nori desmenuzado, salsa de soya y aceite de sésamo.'], TRUE),
  ('r511', 'Korean Tuna Kimbap Bowl', 'Bowl Coreano de Kimbap con Atún', NULL, 460, 43, 45, 12, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','rice','spinach','carrot','sesame_oil','soy_sauce'], ARRAY['Season the rice with sesame oil and a pinch of salt.','Mix drained tuna with a spoon of light mayo and sriracha.','Blanch the spinach and saute julienned carrot briefly.','Layer rice, tuna, vegetables, and torn nori in a bowl.'], ARRAY['Sazona el arroz con aceite de sésamo y una pizca de sal.','Mezcla el atún escurrido con una cucharada de mayonesa ligera y sriracha.','Escalda la espinaca y saltea brevemente la zanahoria en juliana.','Acomoda arroz, atún, verduras y nori troceado en un bowl.'], TRUE),
  ('r512', 'Spicy Shrimp Ramen Bowl', 'Ramen Picante de Camarón', NULL, 461, 44, 42, 13, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['shrimp','egg_noodles','spinach','eggs','garlic','soy_sauce'], ARRAY['Simmer broth with garlic, soy sauce, and a spoon of chili paste, 5 minutes.','Poach shrimp in the broth until pink, 2 minutes.','Cook ramen noodles and soft-boil an egg.','Build the bowl with noodles, spicy broth, shrimp, spinach, and egg.'], ARRAY['Cocina el caldo con ajo, salsa de soya y una cucharada de pasta de chile, 5 minutos.','Escalfa los camarones en el caldo hasta que estén rosados, 2 minutos.','Cocina los fideos ramen y prepara un huevo pasado por agua.','Arma el bowl con fideos, caldo picante, camarones, espinaca y huevo.'], TRUE),
  ('r513', 'Singapore Chili Shrimp Bowl', 'Bowl de Camarón al Chili de Singapur', NULL, 466, 45, 40, 14, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['shrimp','rice','tomato','garlic','eggs','soy_sauce'], ARRAY['Fry garlic, ginger, and chili paste in oil until fragrant.','Add a sauce of ketchup, tomato, and soy sauce; simmer 3 minutes.','Add shrimp and cook until pink and coated, 4 minutes.','Swirl in beaten egg and serve over rice.'], ARRAY['Fríe ajo, jengibre y pasta de chile en aceite hasta que aromatice.','Agrega una salsa de ketchup, tomate y salsa de soya; cocina 3 minutos.','Añade los camarones y cocina hasta que estén rosados y cubiertos, 4 minutos.','Incorpora huevo batido y sirve sobre arroz.'], TRUE),
  ('r514', 'Chicken Oyakodon Bowl', 'Bowl de Oyakodon de Pollo', NULL, 503, 47, 45, 15, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','rice','onion','eggs','soy_sauce','honey'], ARRAY['Simmer sliced onion in dashi, soy sauce, and honey, 4 minutes.','Add bite-sized chicken thigh and cook through, 6 minutes.','Pour beaten egg over the top and cover until just set.','Slide over hot rice and finish with green onion.'], ARRAY['Cocina la cebolla en rodajas en dashi, salsa de soya y miel, 4 minutos.','Agrega el muslo de pollo en trozos y cocínalo, 6 minutos.','Vierte huevo batido encima y tapa hasta que apenas cuaje.','Sirve sobre arroz caliente y termina con cebollín.'], TRUE),
  ('r515', 'Hoisin Chicken Lettuce Wraps', 'Wraps de Lechuga con Pollo Hoisin', NULL, 413, 46, 28, 13, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','lettuce','mushroom','onion','garlic','soy_sauce'], ARRAY['Stir-fry ground chicken with garlic until cooked, 6 minutes.','Add diced mushroom, onion, and water chestnut; cook 3 minutes.','Stir in hoisin and soy sauce until sticky.','Spoon into lettuce cups and top with green onion.'], ARRAY['Saltea el pollo molido con ajo hasta cocinar, 6 minutos.','Agrega champiñón, cebolla y castaña de agua en cubos; cocina 3 minutos.','Incorpora salsa hoisin y salsa de soya hasta que esté pegajoso.','Sirve en hojas de lechuga y corona con cebollín.'], TRUE),
  ('r516', 'Kung Pao Shrimp', 'Camarones Kung Pao', NULL, 464, 44, 36, 16, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['shrimp','bell_pepper','peanuts','rice','soy_sauce','garlic'], ARRAY['Toss shrimp with a little cornstarch and soy sauce.','Stir-fry shrimp in a hot wok until pink, 2 minutes, then remove.','Fry dried chili, garlic, and ginger; add bell pepper and a sauce of soy, vinegar, and honey.','Return shrimp, fold in peanuts, and serve over rice.'], ARRAY['Mezcla los camarones con un poco de maicena y salsa de soya.','Saltea los camarones en un wok caliente hasta que estén rosados, 2 minutos, y retíralos.','Fríe chile seco, ajo y jengibre; agrega el pimiento y una salsa de soya, vinagre y miel.','Regresa los camarones, incorpora el maní y sirve sobre arroz.'], TRUE),
  ('r517', 'Korean Salmon & Kimchi Bowl', 'Bowl Coreano de Salmón y Kimchi', NULL, 498, 42, 42, 18, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','kimchi','spinach','sesame_oil','soy_sauce'], ARRAY['Pan-sear salmon until crisp-skinned and just cooked, 6 minutes.','Stir-fry kimchi in sesame oil until caramelized, 3 minutes.','Wilt spinach in the same pan with a splash of soy sauce.','Serve salmon over rice with kimchi, spinach, and sesame seeds.'], ARRAY['Sella el salmón hasta que la piel esté crujiente y apenas cocido, 6 minutos.','Saltea el kimchi en aceite de sésamo hasta caramelizar, 3 minutos.','Marchita la espinaca en la misma sartén con un chorrito de salsa de soya.','Sirve el salmón sobre arroz con kimchi, espinaca y semillas de sésamo.'], TRUE),
  ('r518', 'Thai Peanut Chicken Bowl', 'Bowl Tailandés de Pollo con Maní', NULL, 506, 46, 40, 18, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','broccoli','carrot','peanut_butter','soy_sauce'], ARRAY['Whisk peanut butter, soy sauce, lime, garlic, and warm water into a sauce.','Sear sliced chicken until cooked, 6 minutes.','Steam broccoli and carrot until crisp-tender.','Serve over rice, smothered in peanut sauce, with crushed peanuts.'], ARRAY['Bate mantequilla de maní, salsa de soya, limón, ajo y agua tibia para la salsa.','Sella el pollo en rodajas hasta cocinar, 6 minutos.','Cocina al vapor el brócoli y la zanahoria hasta que estén al dente.','Sirve sobre arroz, bañado en salsa de maní, con maní triturado.'], TRUE),
  ('r519', 'Cashew Chicken Stir-Fry', 'Salteado de Pollo con Anacardos', NULL, 487, 44, 35, 19, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','bell_pepper','onion','rice','soy_sauce','cashews','garlic'], ARRAY['Stir-fry sliced chicken until golden, 6 minutes, then remove.','Stir-fry bell pepper, onion, and garlic, 3 minutes.','Return the chicken with soy sauce, hoisin, and a splash of water; toss.','Fold in toasted cashews and serve over rice.'], ARRAY['Saltea el pollo en rodajas hasta dorar, 6 minutos, y retíralo.','Saltea el pimiento, la cebolla y el ajo, 3 minutos.','Regresa el pollo con salsa de soya, hoisin y un chorrito de agua; mezcla.','Incorpora los anacardos tostados y sirve sobre arroz.'], TRUE),
  ('r520', 'Vietnamese Lemongrass Chicken Bowl', 'Bowl Vietnamita de Pollo a la Hierba de Limón', NULL, 469, 47, 41, 13, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','cucumber','carrot','garlic','soy_sauce'], ARRAY['Marinate chicken thigh in lemongrass, garlic, soy sauce, and honey, 20 minutes.','Sear the chicken until caramelized and cooked, 8 minutes, then slice.','Quick-pickle carrot and cucumber in rice vinegar.','Serve over rice with the pickles and a drizzle of nuoc cham.'], ARRAY['Marina el muslo de pollo con hierba de limón, ajo, salsa de soya y miel, 20 minutos.','Sella el pollo hasta caramelizar y cocinar, 8 minutos, y córtalo.','Encurte rápido la zanahoria y el pepino en vinagre de arroz.','Sirve sobre arroz con los encurtidos y un chorrito de nuoc cham.'], TRUE),
  ('r521', 'Beef Kimchi Udon Stir-Fry', 'Salteado de Udon con Carne y Kimchi', NULL, 508, 43, 48, 16, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['lean_beef','udon_noodles','kimchi','spinach','soy_sauce','sesame_oil'], ARRAY['Sear sliced beef in a hot pan until browned, 2 minutes.','Add kimchi and stir-fry until fragrant, 2 minutes.','Toss in cooked udon noodles, soy sauce, and sesame oil.','Fold in spinach until wilted and serve.'], ARRAY['Sella la carne en rodajas en una sartén caliente hasta dorar, 2 minutos.','Agrega el kimchi y saltea hasta que aromatice, 2 minutos.','Incorpora los fideos udon cocidos, salsa de soya y aceite de sésamo.','Añade la espinaca hasta marchitar y sirve.'], TRUE),
  ('r522', 'Turkey & Edamame Teriyaki Bowl', 'Bowl Teriyaki de Pavo y Edamame', NULL, 478, 48, 40, 14, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','rice','edamame','carrot','soy_sauce','honey','garlic'], ARRAY['Brown ground turkey with garlic over high heat, 6 minutes.','Add soy sauce, honey, and grated ginger; simmer into a glaze.','Steam edamame and shredded carrot until tender.','Serve the teriyaki turkey over rice with the vegetables.'], ARRAY['Dora el pavo molido con ajo a fuego alto, 6 minutos.','Agrega salsa de soya, miel y jengibre rallado; cocina hasta glasear.','Cocina al vapor el edamame y la zanahoria rallada hasta que estén tiernos.','Sirve el pavo teriyaki sobre arroz con las verduras.'], TRUE),
  ('r523', 'Shrimp Egg Foo Young', 'Egg Foo Young de Camarón', NULL, 416, 42, 26, 16, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['shrimp','eggs','bean_sprouts','mushroom','onion','soy_sauce'], ARRAY['Beat the eggs and mix in chopped shrimp, bean sprouts, mushroom, and onion.','Pan-fry as thick omelette patties until golden, 3 minutes per side.','Simmer soy sauce and broth with a little cornstarch into a gravy.','Pour the gravy over the patties and serve.'], ARRAY['Bate los huevos y mezcla camarones picados, germinados, champiñón y cebolla.','Fríe como tortillas gruesas hasta dorar, 3 minutos por lado.','Cocina salsa de soya y caldo con un poco de maicena hasta formar una salsa.','Vierte la salsa sobre las tortillas y sirve.'], TRUE),
  ('r524', 'Thai Red Curry Shrimp Bowl', 'Bowl Tailandés de Curry Rojo con Camarón', NULL, 486, 41, 40, 18, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['shrimp','rice','bell_pepper','zucchini','coconut_milk','curry_paste'], ARRAY['Fry red curry paste in oil until fragrant, 1 minute.','Add coconut milk and bring to a simmer.','Add bell pepper and zucchini; simmer 5 minutes, then add the shrimp.','Cook until the shrimp are pink and serve over rice.'], ARRAY['Fríe la pasta de curry rojo en aceite hasta que aromatice, 1 minuto.','Agrega la leche de coco y lleva a fuego lento.','Añade el pimiento y el calabacín; cocina 5 minutos y agrega los camarones.','Cocina hasta que los camarones estén rosados y sirve sobre arroz.'], TRUE),
  ('r525', 'Gochujang Salmon Rice Bowl', 'Bowl de Salmón Gochujang', NULL, 506, 42, 44, 18, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','cucumber','carrot','gochujang','sesame_oil'], ARRAY['Brush salmon with a gochujang, soy, and honey glaze.','Bake at 400°F until flaky and caramelized, 12 minutes.','Slice cucumber and carrot into quick pickles.','Flake the salmon over rice with the pickles and sesame oil.'], ARRAY['Unta el salmón con un glaseado de gochujang, soya y miel.','Hornea a 200°C hasta que se desmenuce y caramelice, 12 minutos.','Corta el pepino y la zanahoria en encurtidos rápidos.','Desmenuza el salmón sobre arroz con los encurtidos y aceite de sésamo.'], TRUE),
  ('r526', 'Chinese Pepper Steak Bowl', 'Bowl de Bistec con Pimientos', NULL, 496, 46, 42, 16, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['lean_beef','bell_pepper','onion','rice','soy_sauce','garlic'], ARRAY['Toss sliced steak with soy sauce and cornstarch.','Sear the beef in a hot wok until browned, 2 minutes, then remove.','Stir-fry bell pepper, onion, and garlic, 3 minutes.','Return the beef with soy-oyster sauce and toss; serve over rice.'], ARRAY['Mezcla el bistec en rodajas con salsa de soya y maicena.','Sella la carne en un wok caliente hasta dorar, 2 minutos, y retírala.','Saltea el pimiento, la cebolla y el ajo, 3 minutos.','Regresa la carne con salsa de soya y ostión; mezcla y sirve sobre arroz.'], TRUE),
  ('r527', 'Thai Drunken Noodles (Pad Kee Mao)', 'Fideos Borrachos Tailandeses (Pad Kee Mao)', NULL, 503, 43, 49, 15, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice_noodles','bell_pepper','onion','soy_sauce','garlic','eggs'], ARRAY['Stir-fry garlic and chili, then add sliced chicken until cooked.','Push aside and scramble an egg in the pan.','Add wide rice noodles, soy sauce, and oyster sauce; toss over high heat.','Fold in bell pepper, onion, and Thai basil until wilted.'], ARRAY['Saltea ajo y chile, luego agrega el pollo en rodajas hasta cocinar.','Aparta y revuelve un huevo en la sartén.','Añade fideos anchos de arroz, salsa de soya y salsa de ostión; saltea a fuego alto.','Incorpora el pimiento, la cebolla y la albahaca tailandesa hasta marchitar.'], TRUE),
  ('r528', 'Indonesian Beef Rendang Bowl', 'Bowl Indonesio de Rendang de Carne', NULL, 503, 45, 38, 19, 75, 'High Protein', 'Alto en Proteína', 'high_protein', 'Hard', 'Difícil', 1, ARRAY['lean_beef','rice','onion','garlic','coconut_milk','curry_paste'], ARRAY['Blend onion, garlic, ginger, and chili into a spice paste.','Brown the beef chunks, then add the paste and coconut milk.','Simmer low and slow until the beef is tender and the sauce is dark and thick, 60 minutes.','Serve the rendang over rice.'], ARRAY['Licúa cebolla, ajo, jengibre y chile en una pasta de especias.','Dora los trozos de carne, luego agrega la pasta y la leche de coco.','Cocina a fuego lento hasta que la carne esté tierna y la salsa oscura y espesa, 60 minutos.','Sirve el rendang sobre arroz.'], TRUE),
  ('r529', 'Buffalo Chicken Collard Wraps', 'Wraps de Pollo Búfalo en Berza', NULL, 309, 42, 15, 9, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','collard_greens','greek_yogurt','hot_sauce','carrot','celery'], ARRAY['Grill or poach the chicken breast, then shred and toss with hot sauce and a spoon of Greek yogurt.','Blanch collard leaves for 20 seconds and pat dry so they roll without cracking.','Fill each leaf with buffalo chicken, shredded carrot, and celery matchsticks.','Roll tightly, slice in half, and serve with extra yogurt for dipping.'], ARRAY['Asa o cocina la pechuga, desmenúzala y mézclala con salsa picante y una cucharada de yogur griego.','Escalda las hojas de berza 20 segundos y sécalas para que se enrollen sin romperse.','Rellena cada hoja con el pollo búfalo, zanahoria rallada y palitos de apio.','Enrolla bien, corta por la mitad y sirve con más yogur para mojar.'], TRUE),
  ('r530', 'Thai Larb Chicken Lettuce Boats', 'Larb de Pollo Tailandés en Lechuga', NULL, 315, 38, 16, 11, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['ground_chicken','lettuce','lime','onion','mint','chili'], ARRAY['Brown the ground chicken in a dry hot pan until cooked, breaking it into small crumbles.','Off the heat, toss with lime juice, sliced onion, chopped mint, and chili flakes.','Spoon the larb into crisp lettuce cups.','Top with extra mint and serve right away.'], ARRAY['Dora el pollo molido en una sartén caliente y seca hasta cocerlo, desmenuzándolo fino.','Fuera del fuego, mézclalo con jugo de limón, cebolla en rodajas, menta picada y hojuelas de chile.','Sirve el larb en hojas de lechuga crujiente.','Corona con más menta y sirve enseguida.'], TRUE),
  ('r531', 'Korean Bulgogi Beef Ssam Wraps', 'Wraps Coreanos de Res Bulgogi (Ssam)', NULL, 349, 40, 18, 13, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lean_beef','lettuce','soy_sauce','garlic','sesame_oil','kimchi'], ARRAY['Marinate thinly sliced lean beef in soy sauce, minced garlic, and sesame oil for 10 minutes.','Sear over high heat for 2 to 3 minutes until the edges caramelize.','Pile the beef into lettuce leaves with a little kimchi.','Fold into wraps and eat by hand.'], ARRAY['Marina la carne magra en tiras finas con salsa de soya, ajo picado y aceite de sésamo por 10 minutos.','Séllala a fuego alto 2 a 3 minutos hasta que los bordes se caramelicen.','Coloca la carne en hojas de lechuga con un poco de kimchi.','Dobla en wraps y come con la mano.'], TRUE),
  ('r532', 'Pesto Chicken Zucchini Noodles', 'Fideos de Calabacín con Pollo al Pesto', NULL, 354, 41, 16, 14, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['zucchini','chicken_breast','basil','olive_oil','garlic','tomato','cheese'], ARRAY['Blend basil, garlic, olive oil, and a splash of water into a loose pesto.','Sear diced chicken breast until golden and cooked through, about 6 minutes.','Spiralize the zucchini and toss raw noodles in the hot pan for 1 minute to warm.','Fold in the pesto, chicken, and halved tomatoes, then finish with grated cheese.'], ARRAY['Licúa albahaca, ajo, aceite de oliva y un chorrito de agua hasta lograr un pesto ligero.','Sella el pollo en cubos hasta dorarlo y cocerlo, unos 6 minutos.','Haz fideos de calabacín y saltéalos crudos en la sartén caliente 1 minuto para entibiar.','Integra el pesto, el pollo y los tomates en mitades, y termina con queso rallado.'], TRUE),
  ('r533', 'Chicken Biryani Cauliflower Rice', 'Biryani de Pollo con Arroz de Coliflor', NULL, 356, 40, 22, 12, 35, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['cauliflower','chicken_breast','onion','tomato','greek_yogurt','garlic','cilantro'], ARRAY['Marinate cubed chicken in Greek yogurt, garlic, and 1 teaspoon garam masala for 15 minutes.','Sauté sliced onion and tomato until soft, then add the chicken and cook 8 minutes.','Pulse cauliflower into rice and stir it in with a splash of water; cover and steam 5 minutes.','Fluff, fold through chopped cilantro, and season with salt.'], ARRAY['Marina el pollo en cubos con yogur griego, ajo y 1 cucharadita de garam masala por 15 minutos.','Sofríe cebolla y tomate hasta ablandar, agrega el pollo y cocina 8 minutos.','Tritura la coliflor en arroz, incorpórala con un chorrito de agua, tapa y cuece al vapor 5 minutos.','Suelta con un tenedor, integra el cilantro picado y sazona con sal.'], TRUE),
  ('r534', 'Ahi Tuna Poke Salad Bowl', 'Bowl de Poke de Atún', NULL, 313, 40, 18, 9, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['tuna_steak','cucumber','edamame','soy_sauce','sesame_oil','seaweed'], ARRAY['Cut sushi-grade tuna into 2 cm cubes and toss with soy sauce and sesame oil.','Build a bowl of diced cucumber, shelled edamame, and torn seaweed.','Pile the marinated tuna on top.','Chill 5 minutes and serve cold.'], ARRAY['Corta el atún de calidad sushi en cubos de 2 cm y mézclalo con salsa de soya y aceite de sésamo.','Arma un bowl con pepino en cubos, edamame pelado y alga desmenuzada.','Coloca el atún marinado encima.','Enfría 5 minutos y sirve frío.'], TRUE),
  ('r536', 'Turkey Taco Cauliflower Rice Skillet', 'Sartén de Tacos de Pavo y Coliflor', NULL, 351, 38, 25, 11, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','cauliflower','bell_pepper','onion','salsa','black_beans'], ARRAY['Brown the ground turkey with taco seasoning until fully cooked.','Add diced bell pepper and onion; sauté until soft.','Stir in riced cauliflower and rinsed black beans; cook 5 minutes.','Fold through salsa and warm one more minute.'], ARRAY['Dora el pavo molido con sazón para tacos hasta cocerlo por completo.','Agrega pimiento y cebolla en cubos y sofríe hasta ablandar.','Incorpora la coliflor rallada y los frijoles negros enjuagados; cocina 5 minutos.','Integra la salsa y calienta un minuto más.'], TRUE),
  ('r537', 'Chicken Cobb Salad Bowl', 'Ensalada Cobb de Pollo', NULL, 355, 40, 15, 15, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','eggs','lettuce','tomato','avocado','cheese'], ARRAY['Grill the chicken breast and slice it into strips.','Hard-boil an egg for 9 minutes, then peel and quarter it.','Build a bed of chopped lettuce and arrange chicken, egg, tomato, avocado, and crumbled cheese in rows.','Drizzle with a light vinaigrette and serve.'], ARRAY['Asa la pechuga y córtala en tiras.','Hierve un huevo 9 minutos, pélalo y córtalo en cuartos.','Arma una base de lechuga picada y acomoda en filas el pollo, huevo, tomate, aguacate y queso desmenuzado.','Rocía con una vinagreta ligera y sirve.'], TRUE),
  ('r538', 'Chicken Shawarma Salad Bowl', 'Bowl de Ensalada de Pollo Shawarma', NULL, 348, 42, 18, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','lettuce','tomato','cucumber','greek_yogurt','garlic','lemon'], ARRAY['Toss chicken strips with cumin, paprika, and a pinch of cinnamon, then sear until charred.','Whisk Greek yogurt with grated garlic and lemon juice for a quick sauce.','Fill a bowl with chopped lettuce, tomato, and cucumber.','Top with the shawarma chicken and drizzle the garlic-yogurt sauce.'], ARRAY['Mezcla las tiras de pollo con comino, pimentón y una pizca de canela, y séllalas hasta dorar.','Bate el yogur griego con ajo rallado y jugo de limón para una salsa rápida.','Llena un bowl con lechuga, tomate y pepino picados.','Corona con el pollo shawarma y rocía la salsa de yogur y ajo.'], TRUE),
  ('r539', 'Tandoori Chicken Slaw Bowl', 'Bowl de Ensalada Tandoori de Pollo', NULL, 326, 43, 16, 10, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','cabbage','greek_yogurt','carrot','lemon','cilantro'], ARRAY['Coat chicken in Greek yogurt with tandoori spice and grill until lightly charred.','Shred cabbage and carrot and toss with lemon juice and salt for a quick slaw.','Slice the chicken and set it over the slaw.','Scatter cilantro and add a dollop of yogurt on top.'], ARRAY['Cubre el pollo con yogur griego y especias tandoori, y ásalo hasta que se dore.','Ralla repollo y zanahoria y mézclalos con jugo de limón y sal para una ensalada rápida.','Rebana el pollo y colócalo sobre la ensalada.','Esparce cilantro y añade una cucharada de yogur encima.'], TRUE),
  ('r540', 'Shakshuka with Egg Whites & Greens', 'Shakshuka de Claras con Verduras', NULL, 308, 30, 20, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['egg_whites','eggs','tomato','bell_pepper','onion','spinach','garlic'], ARRAY['Sauté onion, bell pepper, and garlic until soft, then add crushed tomato and simmer 8 minutes.','Stir in spinach until wilted and season with cumin and paprika.','Make wells and pour in egg whites plus one whole egg; cover and cook until just set.','Serve straight from the pan.'], ARRAY['Sofríe cebolla, pimiento y ajo hasta ablandar, agrega tomate triturado y cocina a fuego lento 8 minutos.','Incorpora la espinaca hasta marchitar y sazona con comino y pimentón.','Haz huecos y vierte las claras más un huevo entero; tapa y cocina hasta cuajar.','Sirve directo de la sartén.'], TRUE),
  ('r541', 'Sichuan Tofu & Green Bean Stir-Fry', 'Salteado de Tofu y Habichuelas Sichuan', NULL, 314, 29, 18, 14, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['tofu','green_beans','garlic','soy_sauce','sesame_oil','chili'], ARRAY['Press firm tofu, cube it, and pan-fry in sesame oil until crisp on all sides.','Add trimmed green beans and blister them over high heat for 4 minutes.','Toss in garlic and chili, then splash with soy sauce.','Stir-fry one more minute and serve hot.'], ARRAY['Prensa el tofu firme, córtalo en cubos y dóralo en aceite de sésamo hasta que quede crujiente.','Agrega las habichuelas y ampóllalas a fuego alto por 4 minutos.','Añade ajo y chile, luego un chorro de salsa de soya.','Saltea un minuto más y sirve caliente.'], TRUE),
  ('r542', 'Thai Peanut Chicken Zoodles', 'Fideos de Calabacín con Pollo y Maní', NULL, 358, 38, 20, 14, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['zucchini','chicken_breast','peanut_butter','soy_sauce','lime','carrot'], ARRAY['Whisk peanut butter, soy sauce, lime juice, and warm water into a pourable sauce.','Sear sliced chicken breast until cooked through.','Spiralize zucchini and grate carrot into ribbons.','Toss the raw zoodles, carrot, and chicken in the peanut sauce and serve.'], ARRAY['Bate mantequilla de maní, salsa de soya, jugo de limón y agua tibia hasta lograr una salsa fluida.','Sella el pollo en tiras hasta cocerlo por completo.','Haz fideos de calabacín y ralla la zanahoria en tiras.','Mezcla los fideos crudos, la zanahoria y el pollo con la salsa de maní y sirve.'], TRUE),
  ('r543', 'Blackened Salmon Kale Caesar', 'César de Kale con Salmón Blackened', NULL, 339, 36, 15, 15, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['salmon','kale','greek_yogurt','lemon','garlic','cheese'], ARRAY['Rub the salmon with Cajun spice and sear 3 minutes per side until blackened.','Whisk Greek yogurt with garlic, lemon, and grated cheese for a light Caesar dressing.','Massage torn kale with the dressing until it softens.','Flake the salmon over the kale and finish with more cheese.'], ARRAY['Unta el salmón con especias cajún y séllalo 3 minutos por lado hasta ennegrecer.','Bate yogur griego con ajo, limón y queso rallado para un aderezo César ligero.','Masajea el kale troceado con el aderezo hasta ablandarlo.','Desmenuza el salmón sobre el kale y termina con más queso.'], TRUE),
  ('r544', 'Shrimp Cauliflower Tabbouleh', 'Tabulé de Coliflor con Camarón', NULL, 307, 34, 18, 11, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cauliflower','shrimp','tomato','cucumber','lemon','olive_oil','parsley'], ARRAY['Pulse cauliflower into fine grains and toss raw with lemon juice and olive oil.','Sauté the shrimp 3 minutes until pink and opaque.','Fold diced tomato, cucumber, and plenty of chopped parsley into the cauliflower.','Top with the warm shrimp and season with salt.'], ARRAY['Tritura la coliflor en granos finos y mézclala cruda con jugo de limón y aceite de oliva.','Saltea los camarones 3 minutos hasta que estén rosados y opacos.','Integra tomate y pepino en cubos y abundante perejil picado a la coliflor.','Corona con los camarones tibios y sazona con sal.'], TRUE),
  ('r545', 'Chipotle Chicken Cauli Burrito Bowl', 'Bowl Burrito de Pollo Chipotle y Coliflor', NULL, 372, 40, 26, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','cauliflower','black_beans','salsa','avocado','lime','cilantro'], ARRAY['Rub chicken with chipotle powder and grill, then slice.','Warm riced cauliflower with lime juice and chopped cilantro.','Build a bowl with the cauli rice, black beans, and salsa.','Top with sliced chicken and cubed avocado.'], ARRAY['Unta el pollo con chipotle en polvo, ásalo y rebánalo.','Calienta la coliflor rallada con jugo de limón y cilantro picado.','Arma un bowl con la coliflor, frijoles negros y salsa.','Corona con el pollo en rodajas y aguacate en cubos.'], TRUE),
  ('r546', 'Thai Grilled Beef Nam Tok Salad', 'Ensalada Tailandesa de Res (Nam Tok)', NULL, 329, 38, 15, 13, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lean_beef','lettuce','cucumber','tomato','mint','lime','chili'], ARRAY['Grill the lean steak to medium-rare, rest 5 minutes, then slice thin.','Whisk lime juice, chili, and a splash of fish sauce into a dressing.','Toss lettuce, cucumber, tomato, and mint with the dressing.','Lay the beef over the top and spoon over the resting juices.'], ARRAY['Asa el bistec magro a término medio, deja reposar 5 minutos y rebánalo fino.','Bate jugo de limón, chile y un chorro de salsa de pescado para el aderezo.','Mezcla lechuga, pepino, tomate y menta con el aderezo.','Coloca la res encima y vierte los jugos del reposo.'], TRUE),
  ('r547', 'Savory Cottage Cheese Crunch Bowl', 'Bowl Salado de Requesón Crujiente', NULL, 264, 32, 16, 8, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','cucumber','tomato','bell_pepper','olive_oil'], ARRAY['Spoon cottage cheese into a bowl as the base.','Top with diced cucumber, tomato, and crunchy bell pepper.','Drizzle with olive oil and crack over black pepper.','Finish with a pinch of everything-bagel seasoning and serve.'], ARRAY['Coloca el requesón en un bowl como base.','Cubre con pepino, tomate y pimiento crujiente en cubos.','Rocía con aceite de oliva y agrega pimienta negra recién molida.','Termina con una pizca de sazón everything-bagel y sirve.'], TRUE),
  ('r548', 'Skinny Chicken Alfredo Zoodles', 'Fideos de Calabacín Alfredo de Pollo', NULL, 344, 43, 16, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['zucchini','chicken_breast','greek_yogurt','garlic','cheese'], ARRAY['Sear diced chicken with garlic until golden and cooked through.','Off the heat, stir in Greek yogurt and grated cheese to make a creamy sauce.','Add spiralized zucchini and toss over low heat for 1 to 2 minutes.','Season with black pepper and serve at once.'], ARRAY['Sella el pollo en cubos con ajo hasta dorarlo y cocerlo.','Fuera del fuego, integra yogur griego y queso rallado para una salsa cremosa.','Agrega los fideos de calabacín y saltea a fuego bajo 1 a 2 minutos.','Sazona con pimienta negra y sirve enseguida.'], TRUE),
  ('r549', 'Baja Cod Lettuce Tacos', 'Tacos de Bacalao Baja en Lechuga', NULL, 297, 36, 18, 9, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cod','lettuce','cabbage','lime','greek_yogurt','cilantro','salsa'], ARRAY['Season the cod with chili and cumin and pan-sear 3 minutes per side, then flake.','Mix Greek yogurt with lime juice and cilantro for a crema.','Shred cabbage and dress lightly with lime.','Fill lettuce leaves with cod, slaw, salsa, and a drizzle of crema.'], ARRAY['Sazona el bacalao con chile y comino, séllalo 3 minutos por lado y desmenúzalo.','Mezcla yogur griego con jugo de limón y cilantro para una crema.','Ralla el repollo y adóbalo ligeramente con limón.','Rellena hojas de lechuga con el bacalao, repollo, salsa y un chorrito de crema.'], TRUE),
  ('r550', 'Turkey Egg Roll in a Bowl', 'Bowl Estilo Rollito Primavera con Pavo', NULL, 316, 36, 16, 12, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','cabbage','carrot','garlic','soy_sauce','sesame_oil'], ARRAY['Brown the ground turkey with garlic in sesame oil until cooked.','Add shredded cabbage and carrot and stir-fry until wilted but still crisp.','Splash with soy sauce and toss to coat.','Finish with a few drops of sesame oil and serve in a bowl.'], ARRAY['Dora el pavo molido con ajo en aceite de sésamo hasta cocerlo.','Agrega repollo y zanahoria rallados y saltea hasta marchitar pero aún crujientes.','Añade un chorro de salsa de soya y mezcla para cubrir.','Termina con unas gotas de aceite de sésamo y sirve en un bowl.'], TRUE),
  ('r551', 'Red Lentil Dal with Spinach', 'Dal de Lentejas Rojas con Espinaca', NULL, 336, 30, 36, 8, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lentils','spinach','tomato','onion','garlic','greek_yogurt'], ARRAY['Sauté onion and garlic, then add cumin and turmeric and toast 30 seconds.','Add red lentils, chopped tomato, and water; simmer 15 minutes until creamy.','Stir in spinach until wilted and season with salt.','Serve topped with a spoon of Greek yogurt.'], ARRAY['Sofríe cebolla y ajo, agrega comino y cúrcuma y tuéstalos 30 segundos.','Añade lentejas rojas, tomate picado y agua; cocina a fuego lento 15 minutos hasta que espese.','Incorpora la espinaca hasta marchitar y sazona con sal.','Sirve con una cucharada de yogur griego encima.'], TRUE),
  ('r552', 'Cajun Shrimp & Cauliflower Grits', 'Camarones Cajún con Grits de Coliflor', NULL, 324, 38, 16, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','cauliflower','greek_yogurt','cheese','garlic','bell_pepper'], ARRAY['Steam cauliflower until very soft, then mash with Greek yogurt and cheese into creamy grits.','Toss shrimp with Cajun seasoning.','Sear the shrimp with garlic and diced bell pepper for 3 minutes.','Spoon the shrimp over the cauliflower grits and serve.'], ARRAY['Cuece la coliflor al vapor hasta ablandarla y májala con yogur griego y queso para unos grits cremosos.','Mezcla los camarones con sazón cajún.','Sella los camarones con ajo y pimiento en cubos por 3 minutos.','Sirve los camarones sobre los grits de coliflor.'], TRUE),
  ('r553', 'Greek Turkey Meatball Salad Bowl', 'Bowl de Albóndigas Griegas de Pavo', NULL, 340, 40, 18, 12, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['ground_turkey','lettuce','tomato','cucumber','greek_yogurt','onion','lemon'], ARRAY['Mix ground turkey with grated onion, oregano, and salt, then roll into small meatballs.','Bake at 200 C (400 F) for 15 minutes until browned.','Whisk Greek yogurt with lemon and a little grated cucumber for tzatziki.','Serve the meatballs over lettuce, tomato, and cucumber with the tzatziki.'], ARRAY['Mezcla el pavo molido con cebolla rallada, orégano y sal, y forma albóndigas pequeñas.','Hornéalas a 200 C (400 F) por 15 minutos hasta dorar.','Bate yogur griego con limón y un poco de pepino rallado para el tzatziki.','Sirve las albóndigas sobre lechuga, tomate y pepino con el tzatziki.'], TRUE),
  ('r554', 'Chinese Chopped Chicken Salad', 'Ensalada China de Pollo Picada', NULL, 362, 39, 20, 14, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','cabbage','carrot','sesame_oil','soy_sauce','almond'], ARRAY['Poach and shred the chicken breast.','Whisk sesame oil, soy sauce, and a splash of rice vinegar for the dressing.','Toss shredded cabbage, carrot, and chicken with the dressing.','Top with sliced almonds and serve.'], ARRAY['Cocina y desmenuza la pechuga de pollo.','Bate aceite de sésamo, salsa de soya y un chorro de vinagre de arroz para el aderezo.','Mezcla repollo y zanahoria rallados con el pollo y el aderezo.','Corona con almendras en láminas y sirve.'], TRUE),
  ('r555', 'Turkey Pizza Stuffed Portobellos', 'Portobellos Rellenos Estilo Pizza de Pavo', NULL, 322, 34, 15, 14, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['mushroom','ground_turkey','tomato','cheese','onion','garlic'], ARRAY['Scrape the gills from two large portobello caps and roast 8 minutes at 200 C (400 F).','Brown ground turkey with onion, garlic, and Italian herbs.','Fill the caps with a little tomato sauce, the turkey, and shredded cheese.','Bake 10 more minutes until the cheese melts and bubbles.'], ARRAY['Retira las laminillas de dos portobellos grandes y ásalos 8 minutos a 200 C (400 F).','Dora el pavo molido con cebolla, ajo y hierbas italianas.','Rellena los sombreros con un poco de salsa de tomate, el pavo y queso rallado.','Hornea 10 minutos más hasta que el queso se derrita y burbujee.'], TRUE),
  ('r556', 'Shrimp Pad Thai Zoodles', 'Pad Thai de Camarón con Calabacín', NULL, 341, 34, 22, 13, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['zucchini','shrimp','eggs','peanut_butter','lime','bean_sprouts'], ARRAY['Whisk peanut butter, lime juice, a splash of soy sauce, and water into a pad thai sauce.','Sear shrimp until pink, push aside, and scramble an egg in the pan.','Add spiralized zucchini and bean sprouts and toss for 1 minute.','Pour in the sauce, combine everything, and finish with lime.'], ARRAY['Bate mantequilla de maní, jugo de limón, un chorro de salsa de soya y agua para la salsa pad thai.','Sella los camarones hasta que estén rosados, apártalos y revuelve un huevo en la sartén.','Agrega los fideos de calabacín y los brotes de soya y saltea 1 minuto.','Vierte la salsa, integra todo y termina con limón.'], TRUE),
  ('r557', 'Kimchi Beef Cauliflower Bibimbap', 'Bibimbap de Coliflor con Kimchi y Res', NULL, 357, 39, 21, 13, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['cauliflower','lean_beef','kimchi','spinach','eggs','carrot','sesame_oil'], ARRAY['Toast riced cauliflower in a dry pan with a little sesame oil and set aside.','Sear thin lean beef with a splash of soy sauce until browned.','Quickly wilt spinach and warm shredded carrot in separate corners of the pan.','Arrange beef, vegetables, and kimchi over the cauliflower rice and top with a fried egg.'], ARRAY['Tuesta la coliflor rallada en una sartén seca con un poco de aceite de sésamo y reserva.','Sella la res magra en tiras finas con un chorro de salsa de soya hasta dorar.','Marchita rápido la espinaca y entibia la zanahoria rallada por separado.','Acomoda la res, las verduras y el kimchi sobre la coliflor y corona con un huevo frito.'], TRUE),
  ('r558', 'Sheet-Pan Harissa Chicken & Veg', 'Pollo Harissa y Vegetales a la Bandeja', NULL, 357, 42, 18, 13, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','zucchini','bell_pepper','onion','harissa','olive_oil','lemon'], ARRAY['Toss chicken breast with harissa, olive oil, and lemon juice.','Spread chopped zucchini, bell pepper, and onion on a lined sheet pan.','Nestle the chicken among the vegetables.','Roast at 220 C (425 F) for 22 minutes until the chicken is cooked and the veg is charred.'], ARRAY['Mezcla la pechuga con harissa, aceite de oliva y jugo de limón.','Esparce calabacín, pimiento y cebolla picados en una bandeja con papel.','Acomoda el pollo entre las verduras.','Asa a 220 C (425 F) por 22 minutos hasta que el pollo esté cocido y las verduras doradas.'], TRUE),
  ('r559', 'Mediterranean Tuna Zucchini Boats', 'Barcos de Calabacín con Atún Mediterráneo', NULL, 303, 36, 15, 11, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['zucchini','canned_tuna','tomato','onion','olive_oil','lemon','parsley'], ARRAY['Halve zucchini lengthwise and scoop out the centers to form boats.','Mix drained tuna with diced tomato, onion, olive oil, lemon, and parsley.','Pile the tuna filling into the zucchini boats.','Bake at 190 C (375 F) for 15 minutes until the zucchini is tender.'], ARRAY['Corta el calabacín a lo largo y retira el centro para formar barcos.','Mezcla el atún escurrido con tomate, cebolla, aceite de oliva, limón y perejil.','Rellena los barcos de calabacín con la mezcla de atún.','Hornea a 190 C (375 F) por 15 minutos hasta que el calabacín esté tierno.'], TRUE),
  ('r560', 'Chicken Fajita Lettuce Wraps', 'Wraps de Fajita de Pollo en Lechuga', NULL, 330, 42, 18, 10, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','bell_pepper','onion','lettuce','salsa','lime'], ARRAY['Slice chicken and toss with cumin, chili powder, and lime juice.','Sear the chicken with sliced bell pepper and onion until charred at the edges.','Spoon the fajita mix into sturdy lettuce leaves.','Top with salsa and an extra squeeze of lime.'], ARRAY['Rebana el pollo y mézclalo con comino, chile en polvo y jugo de limón.','Sella el pollo con pimiento y cebolla en tiras hasta dorar los bordes.','Sirve la mezcla de fajita en hojas de lechuga firmes.','Corona con salsa y un chorrito extra de limón.'], TRUE),
  ('r561', 'Salmon Cakes over Lemon Greens', 'Tortitas de Salmón sobre Verdes al Limón', NULL, 322, 33, 16, 14, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['salmon','cauliflower','eggs','lemon','spinach','dijon'], ARRAY['Mash canned salmon with an egg, fine cauliflower crumbs, dijon, and lemon zest.','Form into patties and pan-sear 3 minutes per side until golden.','Wilt spinach quickly and dress with lemon juice.','Set the salmon cakes over the lemon greens and serve.'], ARRAY['Maja el salmón enlatado con un huevo, migas finas de coliflor, dijon y ralladura de limón.','Forma tortitas y séllalas 3 minutos por lado hasta dorar.','Marchita la espinaca rápido y adóbala con jugo de limón.','Coloca las tortitas de salmón sobre los verdes al limón y sirve.'], TRUE),
  ('r562', 'Loaded Beef Taco Salad', 'Ensalada de Tacos de Res Cargada', NULL, 374, 38, 24, 14, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lean_beef','lettuce','tomato','black_beans','salsa','avocado','cheese'], ARRAY['Brown the lean beef with taco seasoning until cooked through.','Pile chopped lettuce into a wide bowl.','Top with the beef, black beans, tomato, and a little shredded cheese.','Finish with salsa and cubed avocado.'], ARRAY['Dora la carne magra con sazón para tacos hasta cocerla.','Coloca lechuga picada en un bowl amplio.','Corona con la carne, frijoles negros, tomate y un poco de queso rallado.','Termina con salsa y aguacate en cubos.'], TRUE),
  ('r563', 'Sambal Tempeh & Broccoli Stir-Fry', 'Salteado de Tempeh y Brócoli con Sambal', NULL, 326, 30, 20, 14, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['tempeh','broccoli','soy_sauce','garlic','sesame_oil','chili'], ARRAY['Cube tempeh and pan-fry in sesame oil until browned on all sides.','Add broccoli florets and a splash of water; cover and steam 3 minutes.','Stir in garlic, chili, and soy sauce for a quick sambal glaze.','Toss until everything is coated and serve hot.'], ARRAY['Corta el tempeh en cubos y dóralo en aceite de sésamo por todos lados.','Agrega floretes de brócoli y un chorrito de agua; tapa y cuece al vapor 3 minutos.','Incorpora ajo, chile y salsa de soya para un glaseado sambal rápido.','Mezcla hasta cubrir todo y sirve caliente.'], TRUE),
  ('r564', 'Turkey Zucchini Chili Bowl', 'Bowl de Chili de Pavo y Calabacín', NULL, 355, 38, 26, 11, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','zucchini','tomato','bell_pepper','onion','black_beans'], ARRAY['Brown the ground turkey with onion and bell pepper.','Stir in chili powder, cumin, and crushed tomato; simmer 10 minutes.','Add diced zucchini and black beans and cook 8 more minutes.','Season with salt and serve in a bowl.'], ARRAY['Dora el pavo molido con cebolla y pimiento.','Incorpora chile en polvo, comino y tomate triturado; cocina a fuego lento 10 minutos.','Agrega calabacín en cubos y frijoles negros y cocina 8 minutos más.','Sazona con sal y sirve en un bowl.'], TRUE),
  ('r565', 'Spinach Feta Egg White Frittata', 'Frittata de Claras con Espinaca y Feta', NULL, 288, 30, 15, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['egg_whites','eggs','spinach','feta','tomato','onion'], ARRAY['Sauté onion and spinach in an oven-safe pan until the spinach wilts.','Whisk egg whites with one whole egg and pour over the vegetables.','Scatter halved tomatoes and crumbled feta on top.','Finish under the broiler for 4 minutes until set and golden.'], ARRAY['Sofríe cebolla y espinaca en una sartén apta para horno hasta que la espinaca se marchite.','Bate las claras con un huevo entero y viértelas sobre las verduras.','Esparce tomates en mitades y feta desmenuzado por encima.','Termina bajo el broiler 4 minutos hasta cuajar y dorar.'], TRUE),
  ('r566', 'Chicken Pho Zoodle Bowl', 'Bowl de Pho de Pollo con Calabacín', NULL, 296, 38, 18, 8, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['zucchini','chicken_breast','onion','ginger','lime','cilantro','bean_sprouts'], ARRAY['Simmer chicken broth with charred onion, sliced ginger, and a star anise for 15 minutes.','Poach the chicken breast in the broth, then remove and slice.','Place spiralized zucchini and bean sprouts in a bowl and ladle the hot broth over to soften.','Top with the chicken, cilantro, and a squeeze of lime.'], ARRAY['Cocina caldo de pollo con cebolla dorada, jengibre en rodajas y un anís estrella por 15 minutos.','Escalfa la pechuga en el caldo, retírala y rebánala.','Coloca fideos de calabacín y brotes de soya en un bowl y vierte el caldo caliente para ablandarlos.','Corona con el pollo, cilantro y un chorrito de limón.'], TRUE),
  ('r567', 'Chili-Lime Shrimp Slaw', 'Ensalada de Repollo con Camarón y Limón', NULL, 276, 35, 16, 8, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','cabbage','carrot','lime','cilantro','greek_yogurt'], ARRAY['Toss shrimp with chili powder and sear 3 minutes until pink.','Whisk Greek yogurt with lime juice and a pinch of chili for the dressing.','Combine shredded cabbage, carrot, and cilantro with the dressing.','Top the slaw with the warm shrimp and serve.'], ARRAY['Mezcla los camarones con chile en polvo y séllalos 3 minutos hasta que estén rosados.','Bate yogur griego con jugo de limón y una pizca de chile para el aderezo.','Combina repollo y zanahoria rallados y cilantro con el aderezo.','Corona la ensalada con los camarones tibios y sirve.'], TRUE),
  ('r568', 'Roast Beef Horseradish Collard Wraps', 'Wraps de Roast Beef en Hoja de Berza', NULL, 293, 38, 15, 9, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lean_beef','collard_greens','greek_yogurt','cucumber','tomato'], ARRAY['Blanch collard leaves 20 seconds and pat dry.','Mix Greek yogurt with prepared horseradish and a pinch of salt.','Spread the sauce on each leaf and layer with lean roast beef, cucumber, and tomato.','Roll up tightly and slice into pinwheels.'], ARRAY['Escalda las hojas de berza 20 segundos y sécalas.','Mezcla yogur griego con rábano picante y una pizca de sal.','Unta la salsa en cada hoja y coloca roast beef magro, pepino y tomate.','Enrolla bien y corta en espirales.'], TRUE),
  ('r569', 'Teriyaki Chicken Cauliflower Rice', 'Pollo Teriyaki con Arroz de Coliflor', NULL, 354, 42, 24, 10, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','cauliflower','broccoli','soy_sauce','honey','ginger'], ARRAY['Simmer soy sauce, honey, and grated ginger into a glossy teriyaki glaze.','Sear diced chicken until cooked, then toss in the glaze to coat.','Steam broccoli and quickly toast riced cauliflower in a dry pan.','Serve the teriyaki chicken over the cauliflower rice with the broccoli.'], ARRAY['Cocina salsa de soya, miel y jengibre rallado hasta lograr un glaseado teriyaki brillante.','Sella el pollo en cubos hasta cocerlo y báñalo en el glaseado.','Cuece el brócoli al vapor y tuesta la coliflor rallada en una sartén seca.','Sirve el pollo teriyaki sobre la coliflor con el brócoli.'], TRUE),
  ('r570', 'BBQ Chicken Crunch Salad', 'Ensalada Crujiente de Pollo BBQ', NULL, 362, 40, 28, 10, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','lettuce','corn','black_beans','tomato','greek_yogurt'], ARRAY['Grill the chicken and toss it with a spoon of barbecue sauce.','Thin Greek yogurt with a little water and herbs for a ranch-style dressing.','Build a bowl of chopped lettuce, corn, black beans, and tomato.','Top with the BBQ chicken and drizzle the ranch dressing.'], ARRAY['Asa el pollo y mézclalo con una cucharada de salsa barbacoa.','Aclara el yogur griego con un poco de agua y hierbas para un aderezo estilo ranch.','Arma un bowl con lechuga picada, maíz, frijoles negros y tomate.','Corona con el pollo BBQ y rocía el aderezo ranch.'], TRUE),
  ('r571', 'Curried Chicken Salad Lettuce Wraps', 'Wraps de Ensalada de Pollo al Curry', NULL, 341, 40, 16, 13, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','greek_yogurt','celery','almond','lettuce','grape'], ARRAY['Dice cooked chicken breast and place it in a bowl.','Mix in Greek yogurt, curry powder, diced celery, and halved grapes.','Fold in a handful of sliced almonds.','Spoon the curried chicken salad into lettuce leaves and wrap.'], ARRAY['Pica la pechuga cocida y colócala en un bowl.','Mezcla yogur griego, curry en polvo, apio en cubos y uvas en mitades.','Integra un puñado de almendras en láminas.','Sirve la ensalada de pollo al curry en hojas de lechuga y envuelve.'], TRUE),
  ('r572', 'Turkey Zucchini Lasagna Roll-Ups', 'Rollitos de Lasaña de Calabacín y Pavo', NULL, 333, 38, 16, 13, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['zucchini','ground_turkey','cottage_cheese','tomato','cheese','garlic'], ARRAY['Slice zucchini lengthwise into thin ribbons and pat dry.','Brown ground turkey with garlic and stir in half the tomato sauce.','Spread cottage cheese on each ribbon, add turkey, and roll up.','Set rolls in the remaining sauce, top with cheese, and bake 15 minutes at 200 C (400 F).'], ARRAY['Corta el calabacín a lo largo en tiras finas y sécalas.','Dora el pavo molido con ajo e integra la mitad de la salsa de tomate.','Unta requesón en cada tira, agrega el pavo y enrolla.','Coloca los rollitos en la salsa restante, cubre con queso y hornea 15 minutos a 200 C (400 F).'], TRUE),
  ('r573', 'Cuban Ropa Vieja Lettuce Cups', 'Copas de Ropa Vieja Cubana en Lechuga', NULL, 341, 38, 18, 13, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lean_beef','bell_pepper','onion','tomato','lettuce','garlic'], ARRAY['Sear thin strips of lean beef until browned, then set aside.','Sauté bell pepper, onion, and garlic with cumin until soft.','Return the beef with crushed tomato and simmer 10 minutes until saucy.','Spoon the ropa vieja into lettuce cups and serve.'], ARRAY['Sella tiras finas de carne magra hasta dorar y reserva.','Sofríe pimiento, cebolla y ajo con comino hasta ablandar.','Regresa la carne con tomate triturado y cocina a fuego lento 10 minutos hasta espesar.','Sirve la ropa vieja en copas de lechuga y sirve.'], TRUE),
  ('r574', 'Lemon Garlic Shrimp & Asparagus', 'Camarones al Ajillo con Espárragos', NULL, 302, 37, 16, 10, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','asparagus','garlic','lemon','olive_oil','tomato'], ARRAY['Heat olive oil and sauté minced garlic until fragrant.','Add asparagus and cherry tomatoes and cook 3 minutes.','Toss in the shrimp and cook 3 minutes until pink.','Finish with lemon juice and zest, then serve.'], ARRAY['Calienta aceite de oliva y sofríe el ajo picado hasta que aromatice.','Agrega los espárragos y los tomates cherry y cocina 3 minutos.','Incorpora los camarones y cocina 3 minutos hasta que estén rosados.','Termina con jugo y ralladura de limón, y sirve.'], TRUE),
  ('r575', 'Moroccan Chicken Cauliflower Couscous', 'Cuscús de Coliflor con Pollo Marroquí', NULL, 355, 40, 24, 11, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','cauliflower','chickpeas','onion','tomato','cilantro'], ARRAY['Brown chicken pieces with onion, cumin, cinnamon, and paprika.','Add tomato and chickpeas with a splash of water and simmer 12 minutes.','Toast riced cauliflower in a dry pan to make couscous.','Spoon the Moroccan chicken over the cauliflower couscous and scatter cilantro.'], ARRAY['Dora los trozos de pollo con cebolla, comino, canela y pimentón.','Agrega tomate y garbanzos con un chorrito de agua y cocina a fuego lento 12 minutos.','Tuesta la coliflor rallada en una sartén seca para hacer el cuscús.','Sirve el pollo marroquí sobre el cuscús de coliflor y esparce cilantro.'], TRUE),
  ('r576', 'Unstuffed Cabbage Roll Bowl', 'Bowl de Repollo Relleno Deshecho', NULL, 340, 38, 20, 12, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','cabbage','tomato','cauliflower','onion','garlic'], ARRAY['Brown the ground turkey with onion and garlic until cooked.','Add chopped cabbage and crushed tomato; simmer 12 minutes until the cabbage softens.','Stir in riced cauliflower and cook 5 more minutes.','Season with paprika and salt and serve in a bowl.'], ARRAY['Dora el pavo molido con cebolla y ajo hasta cocerlo.','Agrega repollo picado y tomate triturado; cocina a fuego lento 12 minutos hasta ablandar el repollo.','Incorpora la coliflor rallada y cocina 5 minutos más.','Sazona con pimentón y sal y sirve en un bowl.'], TRUE),
  ('r577', 'Tom Kha Gai Chicken Soup', 'Sopa Tom Kha Gai de Pollo', NULL, 332, 38, 18, 12, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','mushroom','coconut_milk','lime','cilantro','ginger'], ARRAY['Simmer 2 cups chicken broth with sliced ginger and a squeeze of lime for 5 minutes.','Add sliced chicken breast and mushrooms; cook 8 minutes until the chicken is done.','Stir in light coconut milk and warm through without boiling, about 2 minutes.','Finish with lime juice and fresh cilantro, then serve hot.'], ARRAY['Hierve 2 tazas de caldo de pollo con jengibre en rodajas y un chorrito de limón por 5 minutos.','Agrega la pechuga de pollo en tiras y los hongos; cocina 8 minutos hasta que el pollo esté listo.','Incorpora la leche de coco ligera y calienta sin hervir, unos 2 minutos.','Termina con jugo de limón y cilantro fresco, y sirve caliente.'], TRUE),
  ('r578', 'Chicken Pozole Rojo', 'Pozole Rojo de Pollo', NULL, 361, 36, 34, 9, 35, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','hominy','tomato','onion','garlic','lime'], ARRAY['Blend tomatoes, onion, garlic and a dried chili into a smooth red sauce.','Simmer the sauce with 3 cups broth and shredded chicken breast for 15 minutes.','Add drained hominy and cook another 10 minutes until the flavors meld.','Serve topped with shredded cabbage, radish and a squeeze of lime.'], ARRAY['Licúa tomates, cebolla, ajo y un chile seco hasta lograr una salsa roja.','Cocina la salsa con 3 tazas de caldo y pechuga de pollo deshebrada por 15 minutos.','Añade el maíz pozolero escurrido y cocina 10 minutos más.','Sirve con repollo rallado, rábano y un chorrito de limón.'], TRUE),
  ('r579', 'Italian Wedding Soup with Turkey', 'Sopa Italiana con Albóndigas de Pavo', NULL, 335, 35, 24, 11, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['ground_turkey','spinach','carrot','onion','pasta','garlic'], ARRAY['Roll ground turkey with garlic and pepper into small meatballs.','Simmer the meatballs in 3 cups broth with diced carrot and onion for 12 minutes.','Add a handful of small pasta and cook until tender, about 8 minutes.','Stir in spinach until wilted and serve hot.'], ARRAY['Forma albondiguitas con el pavo molido, ajo y pimienta.','Cocina las albóndigas en 3 tazas de caldo con zanahoria y cebolla por 12 minutos.','Agrega un puñado de pasta pequeña y cocina hasta que ablande, unos 8 minutos.','Incorpora la espinaca hasta marchitar y sirve caliente.'], TRUE),
  ('r580', 'Korean Spicy Beef Soup (Yukgaejang)', 'Sopa Coreana de Res Picante', NULL, 341, 40, 16, 13, 35, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['lean_beef','mushroom','egg','onion','garlic','bean_sprouts'], ARRAY['Simmer lean beef strips in 3 cups broth with garlic for 20 minutes until tender.','Stir in gochugaru chili flakes, mushrooms and bean sprouts; cook 8 minutes.','Add sliced scallion and drizzle in beaten egg to form ribbons.','Season with soy sauce and serve piping hot.'], ARRAY['Cocina las tiras de res en 3 tazas de caldo con ajo por 20 minutos hasta ablandar.','Agrega hojuelas de chile gochugaru, hongos y brotes de soya; cocina 8 minutos.','Añade cebollín y vierte el huevo batido para formar hilos.','Sazona con salsa de soya y sirve bien caliente.'], TRUE),
  ('r581', 'Vietnamese Beef Pho', 'Pho de Res Vietnamita', NULL, 351, 34, 38, 7, 45, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Hard', 'Difícil', 1, ARRAY['lean_beef','rice_noodles','onion','ginger','cilantro','bean_sprouts'], ARRAY['Char onion and ginger, then simmer in 3 cups broth with star anise for 20 minutes.','Soak rice noodles in hot water until soft, then divide into a bowl.','Lay thin raw beef slices over the noodles.','Pour the boiling broth over to cook the beef; top with herbs and bean sprouts.'], ARRAY['Tuesta cebolla y jengibre, y hierve en 3 tazas de caldo con anís estrellado por 20 minutos.','Remoja los fideos de arroz en agua caliente hasta ablandar y colócalos en un bowl.','Acomoda láminas finas de res cruda sobre los fideos.','Vierte el caldo hirviendo para cocinar la res; corona con hierbas y brotes de soya.'], TRUE),
  ('r582', 'Salmon Kimchi Stew', 'Guiso de Salmón y Kimchi', NULL, 318, 33, 15, 14, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['salmon','kimchi','tofu','zucchini','onion','garlic'], ARRAY['Simmer kimchi with garlic and 2 cups broth for 8 minutes to build flavor.','Add cubed tofu, sliced zucchini and onion; cook 5 minutes.','Nestle salmon chunks into the stew and simmer 6 minutes until just cooked.','Adjust seasoning with a splash of soy sauce and serve hot.'], ARRAY['Cocina el kimchi con ajo y 2 tazas de caldo por 8 minutos para concentrar el sabor.','Agrega el tofu en cubos, el calabacín y la cebolla; cocina 5 minutos.','Coloca los trozos de salmón en el guiso y cocina 6 minutos hasta que estén tiernos.','Ajusta la sal con un chorrito de salsa de soya y sirve caliente.'], TRUE),
  ('r583', 'Mexican Caldo de Res', 'Caldo de Res', NULL, 362, 35, 33, 10, 40, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lean_beef','potato','carrot','cabbage','corn','tomato'], ARRAY['Simmer lean beef in 4 cups broth with tomato for 25 minutes until tender.','Add potato, carrot and corn; cook 15 minutes until the vegetables soften.','Stir in cabbage wedges and cook 5 more minutes.','Serve with lime and chopped cilantro.'], ARRAY['Cocina la res en 4 tazas de caldo con tomate por 25 minutos hasta ablandar.','Agrega papa, zanahoria y maíz; cocina 15 minutos hasta que ablanden.','Añade trozos de repollo y cocina 5 minutos más.','Sirve con limón y cilantro picado.'], TRUE),
  ('r585', 'Manhattan Cod Chowder', 'Chowder de Bacalao Manhattan', NULL, 311, 34, 28, 7, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['cod','potato','tomato','carrot','onion','celery'], ARRAY['Sauté onion, carrot and celery in a splash of olive oil for 5 minutes.','Add diced tomato, potato and 3 cups broth; simmer 15 minutes until the potato is tender.','Add cubed cod and cook gently 6 minutes until it flakes.','Season with thyme and pepper, then serve.'], ARRAY['Sofríe cebolla, zanahoria y apio en un poco de aceite de oliva por 5 minutos.','Agrega tomate, papa y 3 tazas de caldo; cocina 15 minutos hasta ablandar la papa.','Añade el bacalao en cubos y cocina suave 6 minutos hasta que se desmenuce.','Sazona con tomillo y pimienta, y sirve.'], TRUE),
  ('r586', 'Spanish Shrimp and Bean Stew', 'Guiso de Camarones y Habichuelas', NULL, 337, 36, 28, 9, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','white_beans','tomato','spinach','garlic','onion'], ARRAY['Sauté garlic and onion in olive oil until soft, about 4 minutes.','Add tomato and smoked paprika; cook 3 minutes into a fragrant sofrito.','Stir in white beans and 1 cup broth; simmer 8 minutes.','Add shrimp and spinach; cook 4 minutes until the shrimp turn pink.'], ARRAY['Sofríe ajo y cebolla en aceite de oliva hasta ablandar, unos 4 minutos.','Agrega tomate y pimentón ahumado; cocina 3 minutos hasta formar un sofrito.','Incorpora las habichuelas blancas y 1 taza de caldo; cocina 8 minutos.','Añade los camarones y la espinaca; cocina 4 minutos hasta que los camarones estén rosados.'], TRUE),
  ('r587', 'Hot and Sour Chicken Soup', 'Sopa Agripicante de Pollo', NULL, 302, 35, 18, 10, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','mushroom','tofu','egg','soy_sauce','vinegar'], ARRAY['Simmer 3 cups broth with sliced chicken and mushrooms for 8 minutes.','Add tofu strips, soy sauce and rice vinegar; season with white pepper.','Stir in a cornstarch slurry to lightly thicken the broth.','Drizzle in beaten egg while stirring to form ribbons, then serve.'], ARRAY['Cocina 3 tazas de caldo con pollo en tiras y hongos por 8 minutos.','Agrega tiras de tofu, salsa de soya y vinagre de arroz; sazona con pimienta blanca.','Incorpora una mezcla de maicena para espesar ligeramente el caldo.','Vierte el huevo batido mientras revuelves para formar hilos, y sirve.'], TRUE),
  ('r588', 'Ginger Chicken Congee', 'Congee de Pollo y Jengibre', NULL, 342, 32, 40, 6, 40, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','ginger','scallion','garlic','cilantro'], ARRAY['Combine rice, ginger, garlic and 5 cups broth in a pot.','Simmer gently 30 minutes, stirring, until the rice breaks down into porridge.','Add shredded chicken breast and cook 5 minutes to heat through.','Top with scallion and cilantro and serve warm.'], ARRAY['Combina arroz, jengibre, ajo y 5 tazas de caldo en una olla.','Cocina a fuego lento 30 minutos, revolviendo, hasta que el arroz se deshaga en papilla.','Agrega pollo deshebrado y cocina 5 minutos para calentar.','Corona con cebollín y cilantro, y sirve tibio.'], TRUE),
  ('r589', 'Yucatan Lime Chicken Soup', 'Sopa de Lima Yucateca', NULL, 333, 37, 26, 9, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','lime','tomato','tortilla','onion','garlic'], ARRAY['Simmer chicken breast in 3 cups broth with onion and garlic for 15 minutes, then shred.','Add tomato and a generous squeeze of lime; simmer 8 minutes.','Crisp tortilla strips in a dry pan until golden.','Return the chicken to the pot, then serve topped with tortilla strips.'], ARRAY['Cocina la pechuga en 3 tazas de caldo con cebolla y ajo por 15 minutos y deshébrala.','Agrega tomate y un buen chorro de limón; cocina 8 minutos.','Dora tiras de tortilla en un sartén seco hasta que queden crujientes.','Regresa el pollo a la olla y sirve con las tiras de tortilla.'], TRUE),
  ('r590', 'Cioppino Seafood Stew', 'Cioppino de Mariscos', NULL, 312, 40, 20, 8, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['shrimp','cod','mussels','tomato','garlic','onion'], ARRAY['Sauté garlic and onion in olive oil, then add tomato and a pinch of chili.','Pour in 2 cups broth and simmer 10 minutes to build the base.','Add cod and mussels; cook 5 minutes until the mussels open.','Stir in shrimp and cook 3 minutes until pink; finish with parsley.'], ARRAY['Sofríe ajo y cebolla en aceite de oliva, luego agrega tomate y una pizca de chile.','Vierte 2 tazas de caldo y cocina 10 minutos para formar la base.','Agrega el bacalao y los mejillones; cocina 5 minutos hasta que abran.','Incorpora los camarones y cocina 3 minutos hasta que estén rosados; termina con perejil.'], TRUE),
  ('r591', 'Turkey Albondigas Soup', 'Sopa de Albóndigas de Pavo', NULL, 339, 34, 26, 11, 35, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['ground_turkey','rice','zucchini','carrot','tomato','onion'], ARRAY['Mix ground turkey with a spoonful of raw rice and form small meatballs.','Simmer tomato, onion and carrot in 3 cups broth for 8 minutes.','Drop in the meatballs and cook 12 minutes until the rice is tender.','Add zucchini and cook 5 more minutes, then serve with cilantro.'], ARRAY['Mezcla el pavo molido con una cucharada de arroz crudo y forma albóndigas pequeñas.','Cocina tomate, cebolla y zanahoria en 3 tazas de caldo por 8 minutos.','Agrega las albóndigas y cocina 12 minutos hasta que el arroz esté tierno.','Añade el calabacín y cocina 5 minutos más; sirve con cilantro.'], TRUE),
  ('r592', 'Moroccan Fish Tagine', 'Tagine de Pescado Marroquí', NULL, 350, 35, 30, 10, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['cod','chickpeas','tomato','bell_pepper','garlic','cilantro'], ARRAY['Make a chermoula with cilantro, garlic, cumin and lemon; coat the cod.','Layer tomato, bell pepper and chickpeas in a pot with a splash of broth.','Set the cod on top, cover, and simmer 15 minutes until the fish is flaky.','Spoon the sauce over the fish and serve warm.'], ARRAY['Prepara una chermoula con cilantro, ajo, comino y limón; cubre el bacalao.','Acomoda tomate, pimiento y garbanzos en una olla con un poco de caldo.','Coloca el bacalao encima, tapa y cocina 15 minutos hasta que el pescado se desmenuce.','Baña el pescado con la salsa y sirve tibio.'], TRUE),
  ('r593', 'Egg White Shakshuka', 'Shakshuka de Claras de Huevo', NULL, 282, 30, 18, 10, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['egg_whites','eggs','tomato','bell_pepper','onion','spinach'], ARRAY['Sauté onion and bell pepper until soft, about 6 minutes.','Add tomato, paprika and cumin; simmer into a thick sauce, 8 minutes.','Stir in spinach, then make wells and pour in egg whites plus one whole egg.','Cover and cook 5 minutes until the whites set; serve from the pan.'], ARRAY['Sofríe cebolla y pimiento hasta ablandar, unos 6 minutos.','Agrega tomate, pimentón y comino; cocina hasta espesar, 8 minutos.','Incorpora espinaca, haz huecos y vierte las claras con un huevo entero.','Tapa y cocina 5 minutos hasta que cuajen las claras; sirve en el sartén.'], TRUE),
  ('r594', 'Broccoli Feta Egg White Frittata', 'Frittata de Claras, Brócoli y Feta', NULL, 287, 32, 15, 11, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['egg_whites','broccoli','cheese','onion','garlic'], ARRAY['Sauté broccoli, onion and garlic in an oven-safe skillet for 5 minutes.','Pour in seasoned egg whites and scatter crumbled feta on top.','Cook on the stove 3 minutes until the edges set.','Finish under the broiler 4 minutes until puffed and golden.'], ARRAY['Sofríe brócoli, cebolla y ajo en un sartén apto para horno por 5 minutos.','Vierte las claras sazonadas y esparce feta desmenuzado por encima.','Cocina en la estufa 3 minutos hasta que cuajen los bordes.','Termina bajo el broiler 4 minutos hasta que esponje y dore.'], TRUE),
  ('r595', 'Smoked Salmon Egg White Frittata', 'Frittata de Claras y Salmón Ahumado', NULL, 308, 35, 15, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['egg_whites','salmon','spinach','onion','dill'], ARRAY['Wilt spinach with onion in an oven-safe skillet, about 4 minutes.','Pour in seasoned egg whites and lay smoked salmon pieces on top.','Cook 3 minutes until the base sets, then sprinkle with dill.','Broil 4 minutes until just set and serve.'], ARRAY['Marchita la espinaca con cebolla en un sartén apto para horno, unos 4 minutos.','Vierte las claras sazonadas y coloca trozos de salmón ahumado encima.','Cocina 3 minutos hasta que cuaje la base y espolvorea eneldo.','Hornea bajo el broiler 4 minutos hasta cuajar y sirve.'], TRUE),
  ('r596', 'Egg White Ranchero Scramble', 'Revoltillo Ranchero de Claras', NULL, 312, 32, 28, 8, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['egg_whites','salsa','black_beans','bell_pepper','tortilla','onion'], ARRAY['Warm black beans with a spoonful of salsa in a small pan.','Scramble egg whites with bell pepper and onion until just set.','Warm a tortilla and pile on the eggs and beans.','Top with extra salsa and cilantro to serve.'], ARRAY['Calienta las habichuelas negras con una cucharada de salsa en un sartén pequeño.','Revuelve las claras con pimiento y cebolla hasta cuajar.','Calienta una tortilla y coloca encima los huevos y las habichuelas.','Corona con más salsa y cilantro para servir.'], TRUE),
  ('r597', 'Denver Egg White Omelette', 'Omelette Denver de Claras', NULL, 295, 34, 15, 11, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['egg_whites','turkey_breast','bell_pepper','onion','cheese'], ARRAY['Sauté diced turkey, bell pepper and onion until softened, 5 minutes.','Pour seasoned egg whites over the filling in a nonstick pan.','Cook until nearly set, then add cheese and fold in half.','Slide onto a plate once the cheese melts and serve.'], ARRAY['Sofríe pavo en cubos, pimiento y cebolla hasta ablandar, 5 minutos.','Vierte las claras sazonadas sobre el relleno en un sartén antiadherente.','Cocina hasta casi cuajar, agrega queso y dobla a la mitad.','Pasa al plato cuando el queso se derrita y sirve.'], TRUE),
  ('r598', 'Egg White Caprese Frittata', 'Frittata Caprese de Claras', NULL, 296, 31, 16, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['egg_whites','tomato','cheese','basil','olive_oil'], ARRAY['Heat a drizzle of olive oil in an oven-safe skillet.','Pour in seasoned egg whites and dot with tomato slices and mozzarella.','Cook 3 minutes until the edges set.','Broil 4 minutes, then finish with fresh basil.'], ARRAY['Calienta un chorrito de aceite de oliva en un sartén apto para horno.','Vierte las claras sazonadas y coloca rodajas de tomate y mozzarella.','Cocina 3 minutos hasta que cuajen los bordes.','Hornea bajo el broiler 4 minutos y termina con albahaca fresca.'], TRUE),
  ('r599', 'Korean Egg White Roll (Gyeran-mari)', 'Rollo de Claras Coreano', NULL, 261, 29, 16, 9, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['egg_whites','eggs','carrot','spinach','scallion'], ARRAY['Whisk egg whites with one egg, minced carrot, spinach and scallion.','Pour a thin layer into a nonstick pan over low heat.','As it sets, roll it to one side, then add more egg and repeat.','Slice the finished roll into rounds and serve.'], ARRAY['Bate las claras con un huevo, zanahoria picada, espinaca y cebollín.','Vierte una capa fina en un sartén antiadherente a fuego bajo.','Al cuajar, enróllalo hacia un lado, agrega más huevo y repite.','Corta el rollo en rueditas y sirve.'], TRUE),
  ('r600', 'Spanish Egg White Tortilla', 'Tortilla Española de Claras', NULL, 330, 30, 30, 10, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['egg_whites','potato','onion','olive_oil'], ARRAY['Simmer thin potato and onion slices in a little olive oil until tender, 12 minutes.','Drain, then fold the potatoes into seasoned egg whites.','Cook the mixture in a nonstick pan 4 minutes until the base sets.','Flip with a plate and cook 3 more minutes; serve in wedges.'], ARRAY['Cocina rodajas finas de papa y cebolla en poco aceite de oliva hasta ablandar, 12 minutos.','Escurre y mezcla las papas con las claras sazonadas.','Cocina la mezcla en un sartén antiadherente 4 minutos hasta que cuaje la base.','Voltea con un plato y cocina 3 minutos más; sirve en triángulos.'], TRUE),
  ('r601', 'Cajun Blackened Tilapia', 'Tilapia Cajún Ennegrecida', NULL, 362, 38, 30, 10, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['tilapia','sweet_potato','broccoli','olive_oil','garlic'], ARRAY['Rub tilapia fillets with a Cajun spice blend.','Roast cubed sweet potato at 425F for 20 minutes, adding broccoli halfway.','Sear the tilapia in a hot skillet 3 minutes per side until blackened.','Plate the fish with the roasted vegetables.'], ARRAY['Unta los filetes de tilapia con mezcla de especias cajún.','Asa la batata en cubos a 425F por 20 minutos, agregando brócoli a la mitad.','Sella la tilapia en un sartén caliente 3 minutos por lado hasta ennegrecer.','Sirve el pescado con los vegetales asados.'], TRUE),
  ('r602', 'Mediterranean Baked Cod', 'Bacalao al Horno Mediterráneo', NULL, 359, 37, 28, 11, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cod','tomato','quinoa','spinach','olive_oil','garlic'], ARRAY['Cook quinoa in broth until fluffy, about 15 minutes.','Set cod in a baking dish and top with tomato, garlic and olives.','Bake at 400F for 15 minutes until the fish flakes.','Wilt spinach into the quinoa and serve alongside the cod.'], ARRAY['Cocina la quinoa en caldo hasta que esté esponjosa, unos 15 minutos.','Coloca el bacalao en una fuente y cúbrelo con tomate, ajo y aceitunas.','Hornea a 400F por 15 minutos hasta que el pescado se desmenuce.','Marchita la espinaca en la quinoa y sirve junto al bacalao.'], TRUE),
  ('r603', 'Garlic Shrimp and Asparagus Skillet', 'Camarones al Ajillo con Espárragos', NULL, 330, 38, 22, 10, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','asparagus','quinoa','garlic','olive_oil','lemon'], ARRAY['Cook quinoa until fluffy and set aside.','Sear asparagus in olive oil for 4 minutes, then remove.','Sauté shrimp with garlic 3 minutes until pink.','Return the asparagus, add lemon juice, and serve over the quinoa.'], ARRAY['Cocina la quinoa hasta que esté esponjosa y reserva.','Saltea los espárragos en aceite de oliva por 4 minutos y retira.','Sofríe los camarones con ajo 3 minutos hasta que estén rosados.','Regresa los espárragos, agrega jugo de limón y sirve sobre la quinoa.'], TRUE),
  ('r604', 'Teriyaki Salmon with Broccoli', 'Salmón Teriyaki con Brócoli', NULL, 373, 34, 30, 13, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['salmon','broccoli','rice','soy_sauce','honey','garlic'], ARRAY['Whisk soy sauce, honey and garlic into a teriyaki glaze.','Brush over the salmon and bake at 400F for 12 minutes.','Steam broccoli until crisp-tender, about 5 minutes.','Serve salmon and broccoli over a small scoop of rice.'], ARRAY['Mezcla salsa de soya, miel y ajo para el glaseado teriyaki.','Unta el salmón y hornea a 400F por 12 minutos.','Cocina el brócoli al vapor hasta que esté firme pero tierno, unos 5 minutos.','Sirve el salmón y el brócoli sobre una porción pequeña de arroz.'], TRUE),
  ('r605', 'Ginger Soy Steamed Sea Bass', 'Corvina al Vapor con Jengibre', NULL, 325, 36, 25, 9, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['sea_bass','rice','spinach','ginger','soy_sauce','scallion'], ARRAY['Place sea bass on a heatproof plate and top with ginger slivers.','Steam over boiling water for 10 minutes until opaque.','Heat soy sauce with scallion and pour over the fish.','Serve with steamed rice and wilted spinach.'], ARRAY['Coloca la corvina en un plato resistente al calor y cúbrela con tiras de jengibre.','Cocina al vapor sobre agua hirviendo por 10 minutos hasta que esté opaca.','Calienta la salsa de soya con cebollín y viértela sobre el pescado.','Sirve con arroz al vapor y espinaca marchitada.'], TRUE),
  ('r606', 'Pan-Seared Scallops with Cauliflower', 'Vieiras con Puré de Coliflor', NULL, 298, 34, 18, 10, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['scallops','cauliflower','garlic','spinach','olive_oil'], ARRAY['Steam cauliflower until soft, then blend with garlic into a smooth puree.','Pat scallops dry and season with salt and pepper.','Sear in a hot skillet 2 minutes per side until golden.','Spoon the puree onto a plate, add wilted spinach, and top with scallops.'], ARRAY['Cocina la coliflor al vapor hasta ablandar y licúala con ajo hasta lograr un puré.','Seca las vieiras y sazónalas con sal y pimienta.','Séllalas en un sartén caliente 2 minutos por lado hasta dorar.','Coloca el puré en el plato, añade espinaca y corona con las vieiras.'], TRUE),
  ('r607', 'Grilled Swordfish with Chimichurri', 'Pez Espada con Chimichurri', NULL, 374, 40, 22, 14, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['swordfish','quinoa','bell_pepper','olive_oil','garlic','parsley'], ARRAY['Blend parsley, garlic, olive oil and vinegar into a chimichurri.','Grill swordfish over high heat 4 minutes per side.','Char bell pepper strips on the grill until softened.','Serve fish and peppers over quinoa, spooned with chimichurri.'], ARRAY['Licúa perejil, ajo, aceite de oliva y vinagre para el chimichurri.','Asa el pez espada a fuego alto 4 minutos por lado.','Asa tiras de pimiento en la parrilla hasta ablandar.','Sirve el pescado y los pimientos sobre quinoa con el chimichurri.'], TRUE),
  ('r608', 'Tandoori Baked Fish', 'Pescado Tandoori al Horno', NULL, 288, 38, 16, 8, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cod','greek_yogurt','tomato','cucumber','garlic','lemon'], ARRAY['Mix greek yogurt with tandoori spices, garlic and lemon.','Coat the cod and marinate 15 minutes.','Bake at 425F for 14 minutes until the fish flakes.','Serve with a cucumber and tomato salad on the side.'], ARRAY['Mezcla el yogur griego con especias tandoori, ajo y limón.','Cubre el bacalao y marina 15 minutos.','Hornea a 425F por 14 minutos hasta que el pescado se desmenuce.','Sirve con una ensalada de pepino y tomate al lado.'], TRUE),
  ('r609', 'Steamed Mussels in Tomato Broth', 'Mejillones en Caldo de Tomate', NULL, 316, 33, 28, 8, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['mussels','tomato','garlic','onion','whole_grain_bread','parsley'], ARRAY['Sauté garlic and onion in olive oil until soft.','Add tomato and 1 cup broth; simmer 8 minutes.','Add mussels, cover, and steam 5 minutes until they open.','Sprinkle with parsley and serve with toasted whole-grain bread.'], ARRAY['Sofríe ajo y cebolla en aceite de oliva hasta ablandar.','Agrega tomate y 1 taza de caldo; cocina 8 minutos.','Añade los mejillones, tapa y cocina al vapor 5 minutos hasta que abran.','Espolvorea perejil y sirve con pan integral tostado.'], TRUE),
  ('r610', 'Grilled Mahi Mahi with Mango Salsa', 'Dorado con Salsa de Mango', NULL, 360, 38, 34, 8, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['mahi_mahi','mango','rice','bell_pepper','lime','cilantro'], ARRAY['Dice mango, bell pepper and cilantro; toss with lime for a salsa.','Season the mahi mahi and grill 4 minutes per side.','Cook a small portion of rice until fluffy.','Top the fish with mango salsa and serve over the rice.'], ARRAY['Pica mango, pimiento y cilantro; mezcla con limón para la salsa.','Sazona el dorado y ásalo 4 minutos por lado.','Cocina una porción pequeña de arroz hasta que esté esponjoso.','Corona el pescado con la salsa de mango y sirve sobre arroz.'], TRUE),
  ('r611', 'Lemon Pepper Baked Snapper', 'Pargo al Limón y Pimienta', NULL, 315, 37, 26, 7, 35, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['red_snapper','potato','asparagus','lemon','olive_oil','garlic'], ARRAY['Toss potato wedges with olive oil and roast at 425F for 20 minutes.','Season the snapper with lemon, pepper and garlic.','Add the snapper and asparagus to the pan and roast 12 more minutes.','Finish with a squeeze of lemon and serve.'], ARRAY['Mezcla gajos de papa con aceite de oliva y asa a 425F por 20 minutos.','Sazona el pargo con limón, pimienta y ajo.','Agrega el pargo y los espárragos a la bandeja y asa 12 minutos más.','Termina con un chorrito de limón y sirve.'], TRUE),
  ('r612', 'Chipotle Lime Shrimp Skillet', 'Camarones al Chipotle y Limón', NULL, 336, 36, 30, 8, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','black_beans','bell_pepper','salsa','lime','cilantro'], ARRAY['Toss shrimp with chipotle powder and lime juice.','Sauté bell pepper in a hot skillet for 4 minutes.','Add the shrimp and cook 3 minutes until pink.','Stir in warmed black beans and salsa; finish with cilantro.'], ARRAY['Mezcla los camarones con chipotle en polvo y jugo de limón.','Saltea el pimiento en un sartén caliente por 4 minutos.','Agrega los camarones y cocina 3 minutos hasta que estén rosados.','Incorpora las habichuelas negras tibias y la salsa; termina con cilantro.'], TRUE),
  ('r613', 'Ahi Tuna Poke Bowl', 'Poke Bowl de Atún', NULL, 388, 35, 35, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['tuna','rice','cucumber','avocado','soy_sauce','edamame'], ARRAY['Cube sushi-grade tuna and toss with soy sauce and sesame oil.','Cook rice, then cool slightly and add to a bowl.','Arrange tuna, cucumber, avocado and edamame over the rice.','Drizzle with extra soy sauce and sprinkle with sesame seeds.'], ARRAY['Corta el atún de calidad sushi en cubos y mézclalo con salsa de soya y aceite de sésamo.','Cocina el arroz, enfríalo un poco y colócalo en un bowl.','Acomoda atún, pepino, aguacate y edamame sobre el arroz.','Rocía más salsa de soya y espolvorea semillas de sésamo.'], TRUE),
  ('r614', 'Salmon Avocado Poke Bowl', 'Poke Bowl de Salmón y Aguacate', NULL, 394, 33, 34, 14, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','cucumber','avocado','soy_sauce','sesame_oil'], ARRAY['Cube sushi-grade salmon and marinate in soy sauce and sesame oil.','Cook rice and let it cool to warm.','Fill a bowl with rice and top with salmon, cucumber and avocado.','Finish with scallion and a sprinkle of sesame seeds.'], ARRAY['Corta el salmón de calidad sushi en cubos y marínalo en salsa de soya y aceite de sésamo.','Cocina el arroz y déjalo enfriar a temperatura tibia.','Llena un bowl con arroz y corona con salmón, pepino y aguacate.','Termina con cebollín y semillas de sésamo.'], TRUE),
  ('r615', 'Mexican Shrimp Aguachile', 'Aguachile de Camarón', NULL, 298, 36, 16, 10, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['shrimp','cucumber','lime','onion','avocado','cilantro'], ARRAY['Butterfly raw shrimp and cover with plenty of fresh lime juice.','Blend cucumber, cilantro and serrano chili into a green sauce.','Pour the sauce over the shrimp and rest 10 minutes to ''cook''.','Add sliced onion and avocado and serve chilled.'], ARRAY['Abre los camarones crudos por la mitad y cúbrelos con abundante jugo de limón.','Licúa pepino, cilantro y chile serrano hasta lograr una salsa verde.','Vierte la salsa sobre los camarones y deja reposar 10 minutos para que se ''cocinen''.','Agrega cebolla en rodajas y aguacate, y sirve bien frío.'], TRUE),
  ('r616', 'Ecuadorian Shrimp Ceviche', 'Ceviche de Camarón Ecuatoriano', NULL, 282, 35, 22, 6, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','tomato','onion','lime','cilantro','orange'], ARRAY['Poach shrimp for 2 minutes, then chill in ice water.','Mix lime juice, orange juice and a little tomato sauce for the base.','Combine shrimp with diced tomato, onion and cilantro.','Chill 20 minutes and serve with the citrus broth.'], ARRAY['Escalda los camarones por 2 minutos y enfríalos en agua con hielo.','Mezcla jugo de limón, jugo de naranja y un poco de salsa de tomate para la base.','Combina los camarones con tomate, cebolla y cilantro.','Enfría 20 minutos y sirve con el caldo cítrico.'], TRUE),
  ('r617', 'Seared Tuna Tataki Bowl', 'Bowl de Atún Tataki', NULL, 385, 34, 33, 13, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['tuna','rice','cucumber','soy_sauce','scallion','sesame_oil'], ARRAY['Sear a tuna steak 45 seconds per side over high heat, keeping the center rare.','Rest briefly, then slice thinly.','Whisk soy sauce, sesame oil and a little citrus into a ponzu.','Fan the tuna over rice with cucumber and drizzle with ponzu.'], ARRAY['Sella un filete de atún 45 segundos por lado a fuego alto, dejando el centro crudo.','Deja reposar un momento y córtalo en láminas finas.','Mezcla salsa de soya, aceite de sésamo y un poco de cítrico para el ponzu.','Acomoda el atún sobre arroz con pepino y rocía con el ponzu.'], TRUE),
  ('r618', 'Scallop Ceviche', 'Ceviche de Vieiras', NULL, 281, 32, 18, 9, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['scallops','lime','cucumber','tomato','avocado','cilantro'], ARRAY['Slice raw scallops thinly and cover with lime juice.','Let sit 15 minutes until the scallops turn opaque.','Fold in diced cucumber, tomato and cilantro.','Top with avocado and serve cold.'], ARRAY['Corta las vieiras crudas en láminas finas y cúbrelas con jugo de limón.','Deja reposar 15 minutos hasta que se tornen opacas.','Incorpora pepino, tomate y cilantro picados.','Corona con aguacate y sirve frío.'], TRUE),
  ('r619', 'Savory Cottage Cheese Bowl', 'Bowl Salado de Requesón', NULL, 273, 32, 16, 9, 5, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','cucumber','tomato','olive_oil','garlic'], ARRAY['Spoon cottage cheese into a bowl.','Top with diced cucumber and tomato.','Drizzle with olive oil and rub in a little grated garlic.','Season with black pepper and everything-bagel spice, then serve.'], ARRAY['Coloca el requesón en un bowl.','Cubre con pepino y tomate picados.','Rocía con aceite de oliva y añade un poco de ajo rallado.','Sazona con pimienta negra y condimento everything, y sirve.'], TRUE),
  ('r620', 'Whipped Cottage Cheese with Tomatoes', 'Requesón Batido con Tomates', NULL, 322, 30, 28, 10, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','tomato','whole_grain_bread','olive_oil','garlic'], ARRAY['Blend cottage cheese until smooth and whipped.','Roast halved tomatoes with garlic and olive oil at 400F for 15 minutes.','Spread the whipped cottage cheese on a plate.','Top with the roasted tomatoes and serve with toasted bread.'], ARRAY['Licúa el requesón hasta dejarlo cremoso y batido.','Asa tomates cortados a la mitad con ajo y aceite de oliva a 400F por 15 minutos.','Extiende el requesón batido en un plato.','Cubre con los tomates asados y sirve con pan integral tostado.'], TRUE),
  ('r621', 'Cottage Cheese Marinara Bowl', 'Bowl de Requesón a la Marinara', NULL, 306, 34, 20, 10, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','tomato','zucchini','cheese','garlic'], ARRAY['Simmer tomato with garlic and herbs into a quick marinara, 10 minutes.','Slice zucchini into ribbons and sauté 3 minutes until just tender.','Warm cottage cheese gently in a bowl.','Top with zucchini, marinara and a sprinkle of parmesan.'], ARRAY['Cocina tomate con ajo y hierbas hasta formar una marinara rápida, 10 minutos.','Corta el calabacín en tiras y saltéalo 3 minutos hasta que esté tierno.','Calienta suavemente el requesón en un bowl.','Corona con calabacín, marinara y un poco de parmesano.'], TRUE),
  ('r622', 'Greek Yogurt Tuna Dip Plate', 'Plato de Atún con Yogur Griego', NULL, 320, 40, 22, 8, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','canned_tuna','cucumber','carrot','whole_grain_bread','lemon'], ARRAY['Mix canned tuna with greek yogurt, lemon and black pepper.','Cut cucumber and carrot into sticks for dipping.','Toast whole-grain bread and slice into strips.','Serve the tuna dip with the vegetables and toast.'], ARRAY['Mezcla el atún enlatado con yogur griego, limón y pimienta negra.','Corta pepino y zanahoria en bastones para mojar.','Tuesta el pan integral y córtalo en tiras.','Sirve el dip de atún con los vegetales y las tostadas.'], TRUE),
  ('r623', 'Za''atar Greek Yogurt Chickpea Bowl', 'Bowl de Yogur con Garbanzos y Za''atar', NULL, 339, 30, 30, 11, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','chickpeas','cucumber','tomato','olive_oil','lemon'], ARRAY['Spread seasoned greek yogurt across the base of a bowl.','Toss chickpeas with za''atar and warm them in a skillet.','Top the yogurt with chickpeas, cucumber and tomato.','Drizzle with olive oil and lemon and serve.'], ARRAY['Extiende el yogur griego sazonado en la base de un bowl.','Mezcla los garbanzos con za''atar y caliéntalos en un sartén.','Cubre el yogur con garbanzos, pepino y tomate.','Rocía con aceite de oliva y limón, y sirve.'], TRUE),
  ('r624', 'Tzatziki Greek Yogurt Salmon Plate', 'Plato de Salmón con Tzatziki', NULL, 349, 38, 20, 13, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','salmon','cucumber','whole_grain_bread','dill','lemon'], ARRAY['Grate cucumber and stir into greek yogurt with dill and lemon for tzatziki.','Season the salmon and bake at 400F for 12 minutes.','Toast whole-grain bread.','Flake the salmon over the tzatziki and serve with the toast.'], ARRAY['Ralla pepino y mézclalo con yogur griego, eneldo y limón para el tzatziki.','Sazona el salmón y hornéalo a 400F por 12 minutos.','Tuesta el pan integral.','Desmenuza el salmón sobre el tzatziki y sirve con las tostadas.'], TRUE),
  ('r625', 'Cajun Chicken & Dirty Rice Bowl', 'Bowl de Pollo Cajún con Arroz', NULL, 592, 44, 68, 16, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','bell_pepper','onion','cajun_seasoning','olive_oil'], ARRAY['Season diced chicken breast with cajun seasoning and sear in olive oil over medium-high heat for 6-7 minutes until cooked through.','Add chopped onion and bell pepper; cook 4 minutes until softened.','Stir in cooked rice with a splash of water, tossing 2 minutes to coat everything in the spices.','Serve hot in a bowl, adjusting salt and cajun heat to taste.'], ARRAY['Sazona el pollo en cubos con condimento cajún y dóralo en aceite de oliva a fuego medio-alto por 6-7 minutos hasta cocer.','Agrega la cebolla y el pimiento picados; cocina 4 minutos hasta ablandar.','Incorpora el arroz cocido con un chorrito de agua, mezclando 2 minutos para cubrir todo con las especias.','Sirve caliente en un bowl y ajusta la sal y el picante cajún al gusto.'], TRUE),
  ('r626', 'Hawaiian Huli Huli Chicken Bowl', 'Bowl de Pollo Huli Huli Hawaiano', NULL, 574, 42, 70, 14, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','pineapple','soy_sauce','honey','garlic'], ARRAY['Whisk soy sauce, honey, minced garlic and pineapple juice into a huli huli glaze.','Grill or pan-sear chicken thighs over medium-high heat 5-6 minutes per side, brushing with glaze, until 165°F.','Char pineapple chunks 2 minutes per side until caramelized.','Slice chicken and serve over rice with pineapple and extra glaze.'], ARRAY['Bate salsa de soya, miel, ajo picado y jugo de piña para el glaseado huli huli.','Asa los muslos de pollo a fuego medio-alto 5-6 minutos por lado, pincelando con el glaseado, hasta 74°C.','Dora los trozos de piña 2 minutos por lado hasta caramelizar.','Rebana el pollo y sírvelo sobre arroz con la piña y glaseado extra.'], TRUE),
  ('r627', 'Buffalo Chicken Rice Bowl', 'Bowl de Arroz y Pollo Búfalo', NULL, 578, 46, 58, 18, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','hot_sauce','greek_yogurt','celery','carrot'], ARRAY['Grill or bake chicken breast until 165°F, then dice and toss with buffalo hot sauce.','Stir Greek yogurt with a pinch of salt for a quick creamy ranch drizzle.','Build the bowl over rice with sliced celery and shredded carrot.','Top with the buffalo chicken and drizzle the yogurt ranch.'], ARRAY['Asa u hornea la pechuga hasta 74°C, luego pícala y mézclala con salsa buffalo.','Mezcla el yogur griego con una pizca de sal para un aderezo ranch cremoso.','Arma el bowl sobre arroz con apio en rodajas y zanahoria rallada.','Corona con el pollo buffalo y rocía el ranch de yogur.'], TRUE),
  ('r628', 'Honey Garlic Salmon Rice Bowl', 'Bowl de Salmón con Miel y Ajo', NULL, 588, 40, 62, 20, 18, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','honey','garlic','soy_sauce','broccoli'], ARRAY['Whisk honey, soy sauce and minced garlic into a glaze.','Sear salmon skin-side down 4 minutes, flip, add glaze and cook 3 minutes, spooning sauce over.','Steam broccoli florets 4 minutes until bright and tender-crisp.','Serve salmon and broccoli over rice, drizzling the pan glaze on top.'], ARRAY['Bate miel, salsa de soya y ajo picado para el glaseado.','Sella el salmón con la piel hacia abajo 4 minutos, voltéalo, añade el glaseado y cocina 3 minutos bañándolo con la salsa.','Cocina el brócoli al vapor 4 minutos hasta que quede verde y tierno-crujiente.','Sirve el salmón y el brócoli sobre arroz y rocía el glaseado de la sartén.'], TRUE),
  ('r629', 'Miso Glazed Salmon Rice Bowl', 'Bowl de Salmón Glaseado al Miso', NULL, 575, 41, 60, 19, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','miso_paste','honey','sesame_oil','spinach'], ARRAY['Mix miso paste, honey and a splash of water into a glaze.','Brush over salmon and broil 8-9 minutes until caramelized and just cooked.','Wilt spinach in a drop of sesame oil for 2 minutes.','Serve salmon and spinach over rice with any remaining glaze.'], ARRAY['Mezcla la pasta de miso, miel y un chorrito de agua para el glaseado.','Pincela el salmón y ásalo al broiler 8-9 minutos hasta caramelizar y quedar apenas cocido.','Saltea la espinaca en unas gotas de aceite de sésamo por 2 minutos.','Sirve el salmón y la espinaca sobre arroz con el glaseado restante.'], TRUE),
  ('r630', 'Gochujang Chicken Rice Bowl', 'Bowl de Pollo al Gochujang', NULL, 571, 45, 64, 15, 18, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','rice','gochujang','sesame_oil','cucumber','garlic'], ARRAY['Toss sliced chicken thigh with gochujang and minced garlic.','Stir-fry in sesame oil over high heat 6-7 minutes until glazed and cooked through.','Slice cucumber for a cool crunchy topping.','Pile chicken over rice and finish with the cucumber.'], ARRAY['Mezcla el muslo de pollo en tiras con gochujang y ajo picado.','Saltéalo en aceite de sésamo a fuego alto 6-7 minutos hasta glasear y cocer.','Corta el pepino en rodajas para un topping fresco y crujiente.','Coloca el pollo sobre arroz y termina con el pepino.'], TRUE),
  ('r631', 'Indonesian Nasi Goreng with Chicken', 'Nasi Goreng Indonesio con Pollo', NULL, 580, 43, 66, 16, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','eggs','soy_sauce','garlic','carrot'], ARRAY['Scramble a beaten egg in a hot wok, then set aside.','Stir-fry diced chicken and garlic in a little oil until cooked, 6 minutes.','Add cold cooked rice, grated carrot and soy sauce; toss over high heat 3 minutes.','Fold the egg back in and top with a second fried egg if desired.'], ARRAY['Revuelve un huevo batido en un wok caliente y resérvalo.','Saltea el pollo en cubos y el ajo en un poco de aceite hasta cocer, 6 minutos.','Añade el arroz cocido frío, la zanahoria rallada y la salsa de soya; saltea a fuego alto 3 minutos.','Incorpora el huevo y corona con un segundo huevo frito si deseas.'], TRUE),
  ('r632', 'Char Siu Pork Rice Bowl', 'Bowl de Cerdo Char Siu', NULL, 597, 44, 67, 17, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['pork_tenderloin','rice','honey','soy_sauce','garlic','broccoli'], ARRAY['Coat pork tenderloin in honey, soy sauce and garlic and marinate 15 minutes.','Roast at 425°F for 18-20 minutes, basting once, until 145°F, then rest and slice.','Steam broccoli 4 minutes until tender-crisp.','Serve sliced pork over rice with broccoli and drizzle pan juices.'], ARRAY['Cubre el lomo de cerdo con miel, salsa de soya y ajo y marina 15 minutos.','Hornéalo a 220°C por 18-20 minutos, bañándolo una vez, hasta 63°C; reposa y rebana.','Cocina el brócoli al vapor 4 minutos hasta tierno-crujiente.','Sirve el cerdo sobre arroz con brócoli y rocía los jugos.'], TRUE),
  ('r633', 'Hawaiian Loco Moco Rice Bowl', 'Bowl de Loco Moco Hawaiano', NULL, 617, 47, 60, 21, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_beef','rice','eggs','mushroom','onion','soy_sauce'], ARRAY['Form lean beef into a patty and sear 3-4 minutes per side; set aside.','Sauté sliced mushroom and onion in the pan, then add soy sauce and water and simmer into a quick gravy, 4 minutes.','Fry an egg to your liking with a runny yolk.','Plate rice, top with the patty, gravy and egg.'], ARRAY['Forma una hamburguesa con la res magra y séllala 3-4 minutos por lado; resérvala.','Saltea el hongo y la cebolla en la sartén, añade salsa de soya y agua y cocina una salsa rápida, 4 minutos.','Fríe un huevo a tu gusto con la yema líquida.','Sirve el arroz, coloca la hamburguesa, la salsa y el huevo.'], TRUE),
  ('r634', 'Japanese Chicken Katsu Curry', 'Curry Japonés de Pollo Katsu', NULL, 618, 42, 72, 18, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','panko','curry_powder','carrot','onion'], ARRAY['Coat chicken breast in panko and pan-fry in a little oil 3-4 minutes per side until golden and 165°F.','Sauté onion and carrot, stir in curry powder, then add water and simmer into a thick sauce, 8 minutes.','Slice the crispy katsu.','Serve rice topped with katsu and ladle the curry sauce alongside.'], ARRAY['Empaniza la pechuga en panko y fríela en poco aceite 3-4 minutos por lado hasta dorar y 74°C.','Saltea cebolla y zanahoria, añade curry en polvo, luego agua y cocina una salsa espesa, 8 minutos.','Rebana el katsu crujiente.','Sirve el arroz con el katsu encima y la salsa de curry al lado.'], TRUE),
  ('r635', 'Beef Gyudon Rice Bowl', 'Bowl de Res Gyudon', NULL, 602, 45, 65, 18, 18, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['lean_beef','rice','onion','soy_sauce','ginger','eggs'], ARRAY['Simmer thinly sliced onion in soy sauce, grated ginger and water for 4 minutes.','Add thin strips of lean beef and simmer 4-5 minutes until just cooked.','Slide in a beaten egg and cover 1 minute to softly set.','Spoon the beef and broth over a bowl of rice.'], ARRAY['Cocina la cebolla en rodajas finas en salsa de soya, jengibre rallado y agua por 4 minutos.','Añade tiras finas de res magra y cocina 4-5 minutos hasta apenas cocer.','Vierte un huevo batido y tapa 1 minuto para cuajar suavemente.','Sirve la res y el caldo sobre un bowl de arroz.'], TRUE),
  ('r636', 'Chicken & Egg Oyakodon', 'Oyakodon de Pollo y Huevo', NULL, 585, 46, 62, 17, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','eggs','onion','soy_sauce','green_onion'], ARRAY['Simmer sliced onion in soy sauce and water 3 minutes.','Add bite-size chicken thigh and cook 6 minutes until done.','Pour beaten eggs over the top and cover 1-2 minutes until just set.','Slide over rice and scatter with sliced green onion.'], ARRAY['Cocina la cebolla en rodajas en salsa de soya y agua 3 minutos.','Añade el muslo de pollo en trozos y cocina 6 minutos hasta cocer.','Vierte los huevos batidos por encima y tapa 1-2 minutos hasta cuajar.','Sirve sobre arroz y esparce cebollín en rodajas.'], TRUE),
  ('r637', 'Kung Pao Chicken Rice Bowl', 'Bowl de Pollo Kung Pao', NULL, 576, 44, 64, 16, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','peanuts','bell_pepper','soy_sauce','garlic'], ARRAY['Toss diced chicken breast with a splash of soy sauce and sear in a hot wok 6 minutes until browned.','Add bell pepper, garlic and dried chilies and stir-fry 2 minutes.','Pour in a soy-vinegar sauce and toss 2 minutes until glossy, then stir in peanuts.','Serve over rice.'], ARRAY['Mezcla el pollo en cubos con un chorrito de salsa de soya y séllalo en un wok caliente 6 minutos hasta dorar.','Añade pimiento, ajo y chiles secos y saltea 2 minutos.','Vierte una salsa de soya y vinagre y saltea 2 minutos hasta que brille, luego incorpora el maní.','Sirve sobre arroz.'], TRUE),
  ('r638', 'Sweet Chili Shrimp Rice Bowl', 'Bowl de Camarón con Chili Dulce', NULL, 558, 40, 68, 14, 15, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['shrimp','rice','bell_pepper','garlic','sweet_chili_sauce','broccoli'], ARRAY['Sauté garlic in a hot pan, then add shrimp and cook 2 minutes per side until pink.','Add bell pepper and broccoli and stir-fry 3 minutes.','Toss with sweet chili sauce until everything is coated and glossy.','Serve over rice.'], ARRAY['Saltea el ajo en una sartén caliente, añade el camarón y cocina 2 minutos por lado hasta que estén rosados.','Agrega el pimiento y el brócoli y saltea 3 minutos.','Mezcla con salsa de chili dulce hasta cubrir todo y que brille.','Sirve sobre arroz.'], TRUE),
  ('r639', 'Spicy Tuna Poke Rice Bowl', 'Bowl de Atún Picante Poke', NULL, 544, 42, 58, 16, 15, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['tuna','rice','avocado','soy_sauce','sesame_oil','cucumber'], ARRAY['Cube sushi-grade tuna and toss with soy sauce and sesame oil.','Spread cooked rice in a bowl and let it cool slightly.','Top with the tuna, sliced avocado and cucumber.','Finish with a little extra soy sauce and a pinch of chili if you like heat.'], ARRAY['Corta el atún de calidad sushi en cubos y mézclalo con salsa de soya y aceite de sésamo.','Extiende el arroz cocido en un bowl y déjalo entibiar.','Corona con el atún, aguacate en rodajas y pepino.','Termina con un poco más de salsa de soya y una pizca de chili si te gusta el picante.'], TRUE),
  ('r640', 'Puerto Rican Arroz con Pollo', 'Arroz con Pollo Puertorriqueño', NULL, 588, 45, 66, 16, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','sofrito','bell_pepper','peas','olive_oil'], ARRAY['Brown chicken thighs in olive oil, then remove.','Sauté sofrito and bell pepper in the same pot 3 minutes.','Stir in rice, peas and water, nestle the chicken back in, and simmer covered 20 minutes until rice is tender.','Fluff and rest 5 minutes before serving.'], ARRAY['Dora los muslos de pollo en aceite de oliva y retíralos.','Sofríe el sofrito y el pimiento en la misma olla 3 minutos.','Añade el arroz, los guisantes y agua, coloca el pollo de nuevo y cocina tapado 20 minutos hasta que el arroz esté tierno.','Suelta con un tenedor y reposa 5 minutos antes de servir.'], TRUE),
  ('r641', 'Cuban Ropa Vieja with Yellow Rice', 'Ropa Vieja con Arroz Amarillo', NULL, 593, 46, 64, 17, 95, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Hard', 'Difícil', 1, ARRAY['lean_beef','rice','bell_pepper','onion','tomato','garlic'], ARRAY['Sear lean beef, then braise with tomato, onion, bell pepper and garlic in a little water, covered, 1.5 hours until shreddable.','Shred the beef and simmer uncovered 5 minutes to thicken the sauce.','Cook rice with a pinch of turmeric for color.','Serve the ropa vieja over the yellow rice.'], ARRAY['Sella la res magra y guísala con tomate, cebolla, pimiento y ajo en un poco de agua, tapada, 1.5 horas hasta deshebrar.','Deshebra la carne y cocina destapado 5 minutos para espesar la salsa.','Cocina el arroz con una pizca de cúrcuma para dar color.','Sirve la ropa vieja sobre el arroz amarillo.'], TRUE),
  ('r642', 'West African Jollof Rice with Chicken', 'Arroz Jollof con Pollo', NULL, 579, 43, 68, 15, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','tomato','onion','bell_pepper','olive_oil'], ARRAY['Blend tomato, onion and bell pepper into a smooth base and fry in olive oil 8 minutes until reduced.','Stir in rice and water, then lay seasoned chicken thighs on top.','Cover and simmer 25 minutes until rice is tender and chicken is cooked.','Fluff and serve, letting the smoky bottom layer mix in.'], ARRAY['Licúa tomate, cebolla y pimiento en una base suave y fríela en aceite de oliva 8 minutos hasta reducir.','Añade el arroz y agua, luego coloca los muslos de pollo sazonados encima.','Tapa y cocina 25 minutos hasta que el arroz esté tierno y el pollo cocido.','Suelta y sirve, integrando la capa ahumada del fondo.'], TRUE),
  ('r643', 'Chicken & Shrimp Jambalaya', 'Jambalaya de Pollo y Camarón', NULL, 580, 47, 62, 16, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','shrimp','rice','bell_pepper','onion','cajun_seasoning'], ARRAY['Brown diced chicken with cajun seasoning, then add onion and bell pepper and cook 4 minutes.','Stir in rice and water and simmer covered 15 minutes.','Nestle in the shrimp and cook 5 minutes until pink and rice is tender.','Rest 5 minutes and fluff before serving.'], ARRAY['Dora el pollo en cubos con condimento cajún, añade cebolla y pimiento y cocina 4 minutos.','Incorpora el arroz y agua y cocina tapado 15 minutos.','Coloca los camarones y cocina 5 minutos hasta que estén rosados y el arroz tierno.','Reposa 5 minutos y suelta antes de servir.'], TRUE),
  ('r644', 'Chicken & Shrimp Paella', 'Paella de Pollo y Camarón', NULL, 575, 46, 64, 15, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Hard', 'Difícil', 1, ARRAY['chicken_thigh','shrimp','rice','peas','bell_pepper','saffron'], ARRAY['Brown chicken thighs in a wide pan, then set aside.','Toast rice with saffron and bell pepper 2 minutes, then add water and the chicken.','Simmer undisturbed 15 minutes, then add shrimp and peas and cook 5 minutes more.','Rest 5 minutes to form the socarrat before serving.'], ARRAY['Dora los muslos de pollo en una sartén ancha y resérvalos.','Tuesta el arroz con azafrán y pimiento 2 minutos, luego añade agua y el pollo.','Cocina sin remover 15 minutos, añade camarón y guisantes y cocina 5 minutos más.','Reposa 5 minutos para formar el socarrat antes de servir.'], TRUE),
  ('r645', 'Pork Carnitas Burrito Bowl', 'Bowl Burrito de Carnitas de Cerdo', NULL, 602, 44, 66, 18, 50, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['pork_tenderloin','rice','black_beans','salsa','avocado','lime'], ARRAY['Simmer pork tenderloin with lime, salt and a little water, covered, 40 minutes until tender.','Shred and crisp under the broiler 4 minutes for caramelized edges.','Warm black beans and layer over rice.','Build the bowl with carnitas, salsa and sliced avocado.'], ARRAY['Cocina el lomo de cerdo con limón verde, sal y un poco de agua, tapado, 40 minutos hasta ablandar.','Deshebra y dóralo bajo el broiler 4 minutos para bordes caramelizados.','Calienta los frijoles negros y colócalos sobre el arroz.','Arma el bowl con las carnitas, salsa y aguacate en rodajas.'], TRUE),
  ('r646', 'Al Pastor Pork Burrito Bowl', 'Bowl Burrito de Cerdo al Pastor', NULL, 597, 43, 68, 17, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['pork_tenderloin','rice','pineapple','black_beans','salsa','onion'], ARRAY['Marinate pork tenderloin with pineapple, salsa and spices 20 minutes.','Sear in a hot pan 8 minutes until charred and cooked, then dice.','Warm black beans and diced pineapple.','Layer over rice with the pork, beans, pineapple and onion.'], ARRAY['Marina el lomo de cerdo con piña, salsa y especias 20 minutos.','Séllalo en una sartén caliente 8 minutos hasta dorar y cocer, luego pícalo.','Calienta los frijoles negros y la piña picada.','Coloca sobre arroz el cerdo, los frijoles, la piña y la cebolla.'], TRUE),
  ('r647', 'Chipotle Shrimp Burrito Bowl', 'Bowl Burrito de Camarón Chipotle', NULL, 567, 41, 67, 15, 18, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['shrimp','rice','black_beans','corn','salsa','avocado'], ARRAY['Toss shrimp with a little chipotle salsa and sauté 2 minutes per side until pink.','Warm black beans and corn together in a pan.','Layer rice with the beans and corn.','Top with shrimp, extra salsa and sliced avocado.'], ARRAY['Mezcla los camarones con un poco de salsa chipotle y saltéalos 2 minutos por lado hasta que estén rosados.','Calienta juntos los frijoles negros y el maíz.','Coloca el arroz con los frijoles y el maíz.','Corona con el camarón, más salsa y aguacate en rodajas.'], TRUE),
  ('r648', 'Ground Turkey & Rice Burrito Bowl', 'Bowl Burrito de Pavo Molido', NULL, 584, 45, 65, 16, 18, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','rice','black_beans','corn','salsa','cheese'], ARRAY['Brown ground turkey with a pinch of cumin and chili powder, 7 minutes.','Stir in salsa and simmer 3 minutes.','Warm black beans and corn.','Build over rice and finish with shredded cheese.'], ARRAY['Dora el pavo molido con una pizca de comino y chile en polvo, 7 minutos.','Añade salsa y cocina 3 minutos.','Calienta los frijoles negros y el maíz.','Arma sobre arroz y termina con queso rallado.'], TRUE),
  ('r649', 'Carolina BBQ Pulled Chicken Plate', 'Pollo Deshebrado BBQ Carolina', NULL, 576, 48, 60, 16, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','bbq_sauce','corn','cabbage'], ARRAY['Simmer chicken breast in a little water 18 minutes, then shred with two forks.','Toss the shredded chicken with tangy BBQ sauce.','Toss shredded cabbage with a splash of vinegar for a quick slaw.','Plate the pulled chicken over rice with corn and slaw.'], ARRAY['Cocina la pechuga en un poco de agua 18 minutos, luego deshebra con dos tenedores.','Mezcla el pollo deshebrado con salsa BBQ.','Mezcla la col rallada con un chorrito de vinagre para una ensalada rápida.','Sirve el pollo deshebrado sobre arroz con maíz y ensalada de col.'], TRUE),
  ('r650', 'Smoky BBQ Beef Brisket Plate', 'Plato de Brisket de Res BBQ', NULL, 605, 46, 58, 21, 135, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Hard', 'Difícil', 1, ARRAY['lean_beef','sweet_potato','bbq_sauce','corn','onion'], ARRAY['Rub lean beef with smoked paprika and salt and sear on all sides.','Braise covered with a little water and BBQ sauce 2 hours until fork-tender, then slice.','Roast sweet potato cubes at 425°F for 25 minutes.','Plate the brisket with sweet potato, corn and charred onion.'], ARRAY['Frota la res magra con pimentón ahumado y sal y séllala por todos lados.','Guísala tapada con un poco de agua y salsa BBQ 2 horas hasta que esté tierna; rebana.','Asa los cubos de batata a 220°C por 25 minutos.','Sirve el brisket con batata, maíz y cebolla dorada.'], TRUE),
  ('r651', 'Honey BBQ Chicken & Sweet Potato Plate', 'Pollo BBQ con Batata y Miel', NULL, 566, 47, 63, 14, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','sweet_potato','bbq_sauce','honey','broccoli'], ARRAY['Whisk BBQ sauce with honey for a sticky glaze.','Bake chicken breast at 400°F for 20 minutes, brushing with glaze in the last 5.','Roast sweet potato wedges alongside 25 minutes until tender.','Steam broccoli 4 minutes and plate everything together.'], ARRAY['Bate salsa BBQ con miel para un glaseado pegajoso.','Hornea la pechuga a 200°C por 20 minutos, pincelando con glaseado en los últimos 5.','Asa las cuñas de batata al lado 25 minutos hasta ablandar.','Cocina el brócoli al vapor 4 minutos y sirve todo junto.'], TRUE),
  ('r652', 'Teriyaki Turkey Meatball Rice Bowl', 'Bowl de Albóndigas de Pavo Teriyaki', NULL, 575, 44, 66, 15, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','rice','teriyaki_sauce','broccoli','sesame_oil','garlic'], ARRAY['Mix ground turkey with garlic and a pinch of salt and roll into meatballs.','Bake at 400°F for 15 minutes until 165°F.','Toss the meatballs in teriyaki sauce simmered until glossy.','Serve over rice with sesame-oil-wilted broccoli.'], ARRAY['Mezcla el pavo molido con ajo y una pizca de sal y forma albóndigas.','Hornea a 200°C por 15 minutos hasta 74°C.','Cubre las albóndigas con salsa teriyaki cocida hasta brillar.','Sirve sobre arroz con brócoli salteado en aceite de sésamo.'], TRUE),
  ('r653', 'Korean BBQ Pork Rice Bowl', 'Bowl de Cerdo BBQ Coreano', NULL, 590, 43, 64, 18, 18, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['pork_tenderloin','rice','gochujang','soy_sauce','sesame_oil','green_onion'], ARRAY['Slice pork tenderloin thin and toss with gochujang, soy sauce and sesame oil.','Sear in a hot pan 6-7 minutes until caramelized and cooked.','Serve over rice.','Finish with sliced green onion.'], ARRAY['Corta el lomo de cerdo fino y mézclalo con gochujang, salsa de soya y aceite de sésamo.','Séllalo en una sartén caliente 6-7 minutos hasta caramelizar y cocer.','Sirve sobre arroz.','Termina con cebollín en rodajas.'], TRUE),
  ('r654', 'Maple BBQ Salmon Rice Plate', 'Plato de Salmón BBQ con Maple', NULL, 596, 40, 64, 20, 22, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon','rice','maple_syrup','bbq_sauce','asparagus'], ARRAY['Whisk maple syrup with BBQ sauce into a glaze.','Brush over salmon and bake at 400°F for 12 minutes until it flakes.','Roast asparagus alongside 10 minutes.','Serve salmon and asparagus over rice with the extra glaze.'], ARRAY['Bate el sirope de maple con salsa BBQ para un glaseado.','Pincela el salmón y hornéalo a 200°C por 12 minutos hasta que se desmenuce.','Asa los espárragos al lado 10 minutos.','Sirve el salmón y los espárragos sobre arroz con el glaseado extra.'], TRUE),
  ('r655', 'Lightened Cajun Chicken Alfredo', 'Alfredo de Pollo Cajún Ligero', NULL, 574, 45, 58, 18, 22, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','pasta','greek_yogurt','parmesan','cajun_seasoning','garlic'], ARRAY['Cook pasta until al dente and reserve a little pasta water.','Sear cajun-seasoned chicken breast 6 minutes, then slice.','Stir Greek yogurt, parmesan, garlic and pasta water into a creamy sauce off the heat.','Toss pasta and chicken in the sauce and serve.'], ARRAY['Cocina la pasta al dente y reserva un poco de su agua.','Dora la pechuga con condimento cajún 6 minutos y rebánala.','Fuera del fuego, mezcla yogur griego, parmesano, ajo y agua de pasta en una salsa cremosa.','Mezcla la pasta y el pollo en la salsa y sirve.'], TRUE),
  ('r656', 'Whole Wheat Turkey Bolognese', 'Boloñesa de Pavo Integral', NULL, 584, 44, 66, 16, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','pasta','tomato','onion','garlic','olive_oil'], ARRAY['Brown ground turkey with onion and garlic in olive oil, 8 minutes.','Add crushed tomato and simmer 15 minutes until thick.','Cook whole wheat pasta until al dente.','Toss pasta with the bolognese and serve.'], ARRAY['Dora el pavo molido con cebolla y ajo en aceite de oliva, 8 minutos.','Añade tomate triturado y cocina 15 minutos hasta espesar.','Cocina la pasta integral al dente.','Mezcla la pasta con la boloñesa y sirve.'], TRUE),
  ('r657', 'Tuna Arrabbiata Penne', 'Penne Arrabbiata con Atún', NULL, 566, 42, 68, 14, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','pasta','tomato','garlic','chili_flakes','olive_oil'], ARRAY['Sauté garlic and chili flakes in olive oil 1 minute.','Add crushed tomato and simmer 10 minutes into a spicy sauce.','Flake in the canned tuna and warm through.','Toss with cooked penne and serve.'], ARRAY['Saltea el ajo y las hojuelas de chile en aceite de oliva 1 minuto.','Añade tomate triturado y cocina 10 minutos en una salsa picante.','Desmenuza el atún y caliéntalo.','Mezcla con el penne cocido y sirve.'], TRUE),
  ('r658', 'Garlic Shrimp Scampi Linguine', 'Linguine con Camarón al Ajillo', NULL, 569, 40, 64, 17, 18, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['shrimp','pasta','garlic','lemon','olive_oil','parsley'], ARRAY['Cook linguine until al dente, reserving a little pasta water.','Sauté garlic in olive oil, add shrimp and cook 2 minutes per side.','Add lemon juice, parsley and pasta water to make a light sauce.','Toss the linguine through and serve.'], ARRAY['Cocina el linguine al dente y reserva un poco de su agua.','Saltea el ajo en aceite de oliva, añade el camarón y cocina 2 minutos por lado.','Agrega jugo de limón, perejil y agua de pasta para una salsa ligera.','Mezcla el linguine y sirve.'], TRUE),
  ('r659', 'Chicken Pasta Primavera', 'Pasta Primavera con Pollo', NULL, 564, 43, 62, 16, 22, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','pasta','zucchini','bell_pepper','broccoli','olive_oil'], ARRAY['Cook pasta until al dente.','Sauté diced chicken breast in olive oil 6 minutes until cooked.','Add zucchini, bell pepper and broccoli and cook 5 minutes until tender-crisp.','Toss with the pasta and a splash of pasta water, then serve.'], ARRAY['Cocina la pasta al dente.','Saltea el pollo en cubos en aceite de oliva 6 minutos hasta cocer.','Añade calabacín, pimiento y brócoli y cocina 5 minutos hasta tierno-crujiente.','Mezcla con la pasta y un chorrito de su agua, y sirve.'], TRUE),
  ('r660', 'Creamy Salmon & Spinach Pasta', 'Pasta Cremosa de Salmón y Espinaca', NULL, 584, 41, 60, 20, 22, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon','pasta','spinach','greek_yogurt','garlic','lemon'], ARRAY['Cook pasta until al dente, reserving pasta water.','Flake cooked salmon and set aside.','Wilt spinach with garlic, then stir in Greek yogurt, lemon and pasta water off the heat for a creamy sauce.','Fold in pasta and salmon and serve.'], ARRAY['Cocina la pasta al dente y reserva su agua.','Desmenuza el salmón cocido y resérvalo.','Saltea la espinaca con ajo, luego fuera del fuego mezcla yogur griego, limón y agua de pasta para una salsa cremosa.','Incorpora la pasta y el salmón y sirve.'], TRUE),
  ('r661', 'Lean Beef Ragu Pappardelle', 'Pappardelle con Ragú de Res', NULL, 598, 45, 64, 18, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_beef','pasta','tomato','onion','carrot','garlic'], ARRAY['Brown lean beef with onion, carrot and garlic in olive oil, 8 minutes.','Add crushed tomato and a splash of water and simmer 30 minutes until rich.','Cook pappardelle until al dente.','Toss the pasta in the ragu and serve.'], ARRAY['Dora la res magra con cebolla, zanahoria y ajo en aceite de oliva, 8 minutos.','Añade tomate triturado y un chorrito de agua y cocina 30 minutos hasta que quede sabroso.','Cocina el pappardelle al dente.','Mezcla la pasta en el ragú y sirve.'], TRUE),
  ('r662', 'High-Protein Baked Turkey Ziti', 'Ziti Horneado de Pavo Proteico', NULL, 585, 46, 62, 17, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','pasta','tomato','cottage_cheese','cheese','garlic'], ARRAY['Brown ground turkey with garlic, then stir in crushed tomato and simmer 10 minutes.','Mix cooked ziti with the sauce and cottage cheese.','Transfer to a dish, top with shredded cheese, and bake at 400°F for 15 minutes until bubbly.','Rest 5 minutes before serving.'], ARRAY['Dora el pavo molido con ajo, añade tomate triturado y cocina 10 minutos.','Mezcla el ziti cocido con la salsa y el queso cottage.','Pásalo a un molde, cubre con queso rallado y hornea a 200°C por 15 minutos hasta burbujear.','Reposa 5 minutos antes de servir.'], TRUE),
  ('r663', 'Chicken Vegetable Lo Mein', 'Lo Mein de Pollo y Vegetales', NULL, 571, 42, 67, 15, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','noodles','soy_sauce','carrot','bell_pepper','sesame_oil'], ARRAY['Cook noodles until just tender and drain.','Stir-fry diced chicken in sesame oil 6 minutes until cooked.','Add carrot and bell pepper and stir-fry 3 minutes.','Toss in noodles and soy sauce over high heat 2 minutes and serve.'], ARRAY['Cocina los fideos hasta que estén apenas tiernos y escúrrelos.','Saltea el pollo en cubos en aceite de sésamo 6 minutos hasta cocer.','Añade zanahoria y pimiento y saltea 3 minutos.','Incorpora los fideos y la salsa de soya a fuego alto 2 minutos y sirve.'], TRUE),
  ('r664', 'Shrimp Pad Thai', 'Pad Thai de Camarón', NULL, 576, 40, 68, 16, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['shrimp','rice_noodles','eggs','peanut_butter','bean_sprouts','lime'], ARRAY['Soak rice noodles in hot water until pliable, then drain.','Stir-fry shrimp 2 minutes, push aside, and scramble a beaten egg.','Add noodles, a peanut-butter-tamarind sauce and bean sprouts and toss 3 minutes.','Finish with lime and crushed peanuts.'], ARRAY['Remoja los fideos de arroz en agua caliente hasta que estén flexibles y escúrrelos.','Saltea el camarón 2 minutos, hazlo a un lado y revuelve un huevo batido.','Añade los fideos, una salsa de maní y tamarindo y los brotes de soya y saltea 3 minutos.','Termina con limón verde y maní triturado.'], TRUE),
  ('r665', 'Dan Dan Noodles with Ground Turkey', 'Fideos Dan Dan con Pavo Molido', NULL, 591, 43, 62, 19, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','noodles','peanut_butter','soy_sauce','sesame_oil','garlic'], ARRAY['Brown ground turkey with garlic until crisp, 7 minutes.','Whisk peanut butter, soy sauce, sesame oil and a little water into a sauce.','Cook noodles and drain.','Toss noodles in the sauce and top with the turkey.'], ARRAY['Dora el pavo molido con ajo hasta que esté crujiente, 7 minutos.','Bate mantequilla de maní, salsa de soya, aceite de sésamo y un poco de agua en una salsa.','Cocina los fideos y escúrrelos.','Mezcla los fideos en la salsa y corona con el pavo.'], TRUE),
  ('r666', 'High-Protein Chicken Mac & Cheese', 'Mac & Cheese de Pollo Proteico', NULL, 599, 47, 60, 19, 22, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','pasta','cheese','cottage_cheese','greek_yogurt','garlic'], ARRAY['Cook pasta until al dente.','Blend cottage cheese and Greek yogurt smooth, then melt in shredded cheese with garlic over low heat.','Fold in cooked diced chicken and the pasta.','Warm through until creamy and serve.'], ARRAY['Cocina la pasta al dente.','Licúa el queso cottage y el yogur griego, luego derrite el queso rallado con ajo a fuego bajo.','Incorpora el pollo cocido en cubos y la pasta.','Calienta hasta que quede cremoso y sirve.'], TRUE),
  ('r667', 'Tuscan Chicken Farro Bowl', 'Bowl Toscano de Pollo y Farro', NULL, 581, 44, 63, 17, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','farro','spinach','tomato','olive_oil','lemon'], ARRAY['Cook farro until tender, about 25 minutes, and drain.','Grill or sear chicken breast until 165°F, then slice.','Wilt spinach with olive oil and blister the tomato, finishing with lemon.','Build the bowl with farro, chicken and the greens.'], ARRAY['Cocina el farro hasta que esté tierno, unos 25 minutos, y escúrrelo.','Asa la pechuga hasta 74°C y rebánala.','Saltea la espinaca con aceite de oliva y dora el tomate, terminando con limón.','Arma el bowl con farro, pollo y las verduras.'], TRUE),
  ('r668', 'Beef & Barley Power Bowl', 'Bowl de Res y Cebada', NULL, 588, 45, 66, 16, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_beef','barley','mushroom','carrot','onion','garlic'], ARRAY['Simmer barley until tender, about 30 minutes, and drain.','Sear lean beef strips, then set aside.','Sauté mushroom, carrot, onion and garlic 6 minutes.','Combine barley, beef and vegetables and season to taste.'], ARRAY['Cocina la cebada hasta que esté tierna, unos 30 minutos, y escúrrela.','Sella las tiras de res magra y resérvalas.','Saltea hongo, zanahoria, cebolla y ajo 6 minutos.','Combina la cebada, la res y los vegetales y sazona al gusto.'], TRUE),
  ('r669', 'Lemon Herb Chicken Couscous Bowl', 'Bowl de Pollo al Limón con Cuscús', NULL, 559, 46, 60, 15, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','couscous','lemon','spinach','olive_oil','garlic'], ARRAY['Pour boiling water over couscous, cover 5 minutes, then fluff.','Sear chicken breast with garlic 6 minutes until cooked, then slice.','Wilt spinach in olive oil and brighten with lemon.','Combine couscous, chicken and spinach in a bowl.'], ARRAY['Vierte agua hirviendo sobre el cuscús, tapa 5 minutos y suéltalo.','Dora la pechuga con ajo 6 minutos hasta cocer y rebánala.','Saltea la espinaca en aceite de oliva y realza con limón.','Combina cuscús, pollo y espinaca en un bowl.'], TRUE),
  ('r670', 'Southwest Turkey Quinoa Bowl', 'Bowl Suroeste de Pavo y Quinoa', NULL, 568, 44, 62, 16, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','quinoa','black_beans','corn','salsa','avocado'], ARRAY['Cook quinoa until fluffy, about 15 minutes.','Brown ground turkey with cumin and chili powder, 7 minutes.','Warm black beans and corn.','Build the bowl with quinoa, turkey, beans, corn, salsa and avocado.'], ARRAY['Cocina la quinoa hasta que esté suelta, unos 15 minutos.','Dora el pavo molido con comino y chile en polvo, 7 minutos.','Calienta los frijoles negros y el maíz.','Arma el bowl con quinoa, pavo, frijoles, maíz, salsa y aguacate.'], TRUE),
  ('r671', 'Turkish Chicken Bulgur Pilaf', 'Pilaf Turco de Pollo y Bulgur', NULL, 571, 45, 64, 15, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','bulgur','tomato','onion','olive_oil','parsley'], ARRAY['Sauté onion in olive oil, add bulgur and toast 2 minutes.','Stir in chopped tomato and water and simmer covered 15 minutes until tender.','Sear chicken thigh until cooked, then slice.','Serve the pilaf topped with chicken and parsley.'], ARRAY['Saltea la cebolla en aceite de oliva, añade el bulgur y tuéstalo 2 minutos.','Incorpora tomate picado y agua y cocina tapado 15 minutos hasta ablandar.','Dora el muslo de pollo hasta cocer y rebánalo.','Sirve el pilaf con el pollo y perejil.'], TRUE),
  ('r672', 'Herbed Turkey & Wild Rice Bowl', 'Bowl de Pavo y Arroz Salvaje', NULL, 568, 46, 60, 16, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['turkey_breast','wild_rice','mushroom','spinach','onion','olive_oil'], ARRAY['Simmer wild rice until tender, about 40 minutes, and drain.','Sauté onion and mushroom in olive oil 6 minutes.','Add sliced turkey breast and warm through with dried herbs.','Stir in spinach to wilt, fold in the wild rice, and serve.'], ARRAY['Cocina el arroz salvaje hasta que esté tierno, unos 40 minutos, y escúrrelo.','Saltea la cebolla y el hongo en aceite de oliva 6 minutos.','Añade la pechuga de pavo en rodajas y caliéntala con hierbas secas.','Incorpora la espinaca hasta marchitar, agrega el arroz salvaje y sirve.'], TRUE),
  ('r673', 'Puerto Rican Arroz con Pollo Bowl', 'Bowl de Arroz con Pollo Boricua', NULL, 600, 44, 70, 16, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','sofrito','pigeon_peas','bell_pepper','tomato','olive_oil'], ARRAY['Brown seasoned chicken thigh in 1 tsp olive oil, 4 min per side, then set aside.','Saute sofrito, bell pepper and tomato 3 min, then stir in rice and pigeon peas.','Add 1 cup water, nestle chicken back in, cover and simmer 20 min until rice is tender.','Fluff with a fork and rest 5 min before serving.'], ARRAY['Dora el muslo de pollo sazonado en 1 cdta de aceite de oliva, 4 min por lado, y reserva.','Sofríe el sofrito, el pimiento y el tomate 3 min, luego agrega el arroz y los gandules.','Añade 1 taza de agua, coloca el pollo encima, tapa y cocina 20 min hasta que el arroz ablande.','Suelta el arroz con un tenedor y reposa 5 min antes de servir.'], TRUE),
  ('r674', 'Garlic Shrimp Mofongo Bowl', 'Mofongo con Camarones al Ajillo', NULL, 588, 40, 62, 20, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['shrimp','green_plantain','garlic','olive_oil','onion','cilantro'], ARRAY['Pan-fry green plantain chunks in 2 tsp oil until golden, about 8 min, then mash with garlic.','Saute onion and remaining garlic 2 min, add shrimp and cook 3 min until pink.','Press mofongo into a bowl, top with garlic shrimp and pan juices.','Finish with chopped cilantro and serve hot.'], ARRAY['Fríe los trozos de plátano verde en 2 cdtas de aceite hasta dorar, unos 8 min, y májalos con ajo.','Sofríe la cebolla y el ajo restante 2 min, agrega los camarones y cocina 3 min hasta que rosen.','Presiona el mofongo en un bowl y cubre con los camarones al ajillo y su jugo.','Termina con cilantro picado y sirve caliente.'], TRUE),
  ('r675', 'Venezuelan Pabellon Criollo Plate', 'Pabellón Criollo Venezolano', NULL, 605, 45, 68, 17, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Hard', 'Difícil', 1, ARRAY['lean_beef','rice','black_beans','plantain','onion','bell_pepper'], ARRAY['Simmer lean beef in water 40 min until fork-tender, then shred and reserve.','Saute onion and bell pepper 4 min, return shredded beef and cook 5 min.','Warm black beans and steamed rice while you pan-fry ripe plantain slices until caramelized.','Plate rice, beans, shredded beef and plantain side by side.'], ARRAY['Hierve la carne magra 40 min hasta que esté blanda, luego desméchala y reserva.','Sofríe la cebolla y el pimiento 4 min, regresa la carne mechada y cocina 5 min.','Calienta las caraotas y el arroz mientras doras las tajadas de plátano maduro.','Sirve arroz, caraotas, carne mechada y plátano uno al lado del otro.'], TRUE),
  ('r676', 'Reina Pepiada Chicken Arepas', 'Arepas Reina Pepiada', NULL, 589, 42, 58, 21, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['arepa_flour','chicken_breast','avocado','onion','cilantro','lime'], ARRAY['Mix arepa flour with warm water and a pinch of salt into a soft dough, then form 2 discs.','Cook arepas in a dry skillet 5 min per side, then finish in a 350F oven 10 min.','Shred cooked chicken and fold with mashed avocado, onion, cilantro and lime.','Split the arepas and stuff with the reina pepiada filling.'], ARRAY['Mezcla la harina de arepa con agua tibia y sal hasta una masa suave y forma 2 discos.','Cocina las arepas en sartén seco 5 min por lado y termina en horno a 175C por 10 min.','Desmenuza el pollo y mézclalo con aguacate majado, cebolla, cilantro y limón.','Abre las arepas y rellénalas con la mezcla reina pepiada.'], TRUE),
  ('r677', 'Cuban Ropa Vieja with Rice', 'Ropa Vieja Cubana con Arroz', NULL, 568, 46, 60, 16, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Hard', 'Difícil', 1, ARRAY['lean_beef','tomato','bell_pepper','onion','rice','olive_oil','garlic'], ARRAY['Simmer lean beef in water 40 min until it shreds easily, reserving 1/2 cup broth.','Saute onion, bell pepper and garlic in 1 tsp oil 5 min, then add tomato and cook 3 min.','Stir in shredded beef and reserved broth, simmer 10 min until saucy.','Serve the ropa vieja over steamed white rice.'], ARRAY['Hierve la carne magra 40 min hasta que se desmeche fácil, reservando 1/2 taza de caldo.','Sofríe cebolla, pimiento y ajo en 1 cdta de aceite 5 min, agrega el tomate y cocina 3 min.','Incorpora la carne mechada y el caldo, cocina 10 min hasta que espese.','Sirve la ropa vieja sobre arroz blanco.'], TRUE),
  ('r678', 'Dominican Pollo Guisado Plate', 'Pollo Guisado Dominicano', NULL, 571, 43, 66, 15, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','potato','tomato','sofrito','rice','black_beans'], ARRAY['Brown seasoned chicken thigh pieces in a pot 5 min, then stir in sofrito and tomato.','Add diced potato and 1 cup water, cover and simmer 25 min until chicken is tender.','Warm black beans and steamed rice separately.','Serve the stewed chicken over rice with beans on the side.'], ARRAY['Dora los trozos de muslo sazonados en una olla 5 min, luego agrega sofrito y tomate.','Añade la papa en cubos y 1 taza de agua, tapa y cocina 25 min hasta ablandar el pollo.','Calienta aparte las habichuelas negras y el arroz.','Sirve el pollo guisado sobre el arroz con las habichuelas al lado.'], TRUE),
  ('r679', 'Costa Rican Gallo Pinto with Eggs', 'Gallo Pinto con Huevos', NULL, 546, 38, 58, 18, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['rice','black_beans','eggs','onion','bell_pepper','cilantro'], ARRAY['Saute onion and bell pepper 3 min, then add cooked rice and black beans.','Fry the rice and beans 4 min until edges crisp, stirring in cilantro.','Push to one side and scramble or fry the eggs in the same pan.','Plate the gallo pinto with the eggs on top.'], ARRAY['Sofríe la cebolla y el pimiento 3 min, luego agrega el arroz cocido y las habichuelas negras.','Fríe el arroz con habichuelas 4 min hasta que doren los bordes e incorpora el cilantro.','Aparta a un lado y cocina los huevos revueltos o fritos en el mismo sartén.','Sirve el gallo pinto con los huevos encima.'], TRUE),
  ('r680', 'Bistec Encebollado with Rice & Beans', 'Bistec Encebollado con Habichuelas', NULL, 590, 45, 62, 18, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_beef','onion','garlic','rice','black_beans','olive_oil'], ARRAY['Marinate thin lean beef steaks in garlic, vinegar and salt 10 min.','Sear the steaks in 1 tsp oil 2 min per side, then remove.','Saute sliced onion 5 min until soft, return beef and any juices, simmer 3 min.','Serve smothered in onions over rice and black beans.'], ARRAY['Marina los bisteces finos de res en ajo, vinagre y sal por 10 min.','Sella los bisteces en 1 cdta de aceite 2 min por lado y retíralos.','Sofríe la cebolla en rodajas 5 min hasta ablandar, regresa la carne y su jugo, cocina 3 min.','Sirve cubierto de cebolla sobre arroz y habichuelas negras.'], TRUE),
  ('r681', 'Roast Pernil with Arroz con Gandules', 'Pernil con Arroz con Gandules', NULL, 612, 44, 64, 20, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Hard', 'Difícil', 1, ARRAY['pork_shoulder','rice','pigeon_peas','garlic','onion','olive_oil'], ARRAY['Rub trimmed pork shoulder with garlic, oregano and salt, then roast at 350F 35 min.','Saute onion and garlic 3 min, add rice, pigeon peas and 1 cup water.','Cover and simmer the rice 20 min until tender.','Slice the pernil and serve over the arroz con gandules.'], ARRAY['Unta la paleta de cerdo magra con ajo, orégano y sal, y asa a 175C por 35 min.','Sofríe cebolla y ajo 3 min, agrega el arroz, los gandules y 1 taza de agua.','Tapa y cocina el arroz 20 min hasta que ablande.','Rebana el pernil y sírvelo sobre el arroz con gandules.'], TRUE),
  ('r682', 'Honduran Baleadas with Eggs', 'Baleadas Hondureñas con Huevo', NULL, 581, 39, 68, 17, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['tortilla','black_beans','eggs','greek_yogurt','avocado','cheese'], ARRAY['Warm 2 flour tortillas in a dry skillet 30 sec per side.','Mash black beans into a thick refried paste and spread over each tortilla.','Scramble the eggs, then layer over the beans with a smear of greek yogurt.','Add avocado slices and crumbled cheese, fold and serve.'], ARRAY['Calienta 2 tortillas de harina en un sartén seco 30 seg por lado.','Maja las habichuelas negras en una pasta espesa y úntala en cada tortilla.','Revuelve los huevos y colócalos sobre las habichuelas con una cucharada de yogur griego.','Añade rebanadas de aguacate y queso desmenuzado, dobla y sirve.'], TRUE),
  ('r683', 'Brazilian Feijoada Bowl', 'Bowl de Feijoada Brasileña', NULL, 591, 45, 60, 19, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Hard', 'Difícil', 1, ARRAY['pork_tenderloin','black_beans','rice','onion','garlic','cilantro'], ARRAY['Brown cubed pork tenderloin in a pot 5 min, then add onion and garlic.','Stir in black beans with their liquid and 1/2 cup water, simmer 25 min until thick.','Season with bay and cilantro, mashing a few beans to thicken the stew.','Serve the feijoada over steamed white rice.'], ARRAY['Dora el lomo de cerdo en cubos en una olla 5 min, luego agrega cebolla y ajo.','Incorpora las habichuelas negras con su líquido y 1/2 taza de agua, cocina 25 min.','Sazona con laurel y cilantro, majando algunas habichuelas para espesar.','Sirve la feijoada sobre arroz blanco.'], TRUE),
  ('r684', 'Argentine Chimichurri Steak Bowl', 'Bowl de Bife con Chimichurri', NULL, 576, 47, 52, 20, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['flank_steak','rice','parsley','garlic','olive_oil','red_onion'], ARRAY['Blend parsley, garlic, 2 tsp olive oil and red wine vinegar into a loose chimichurri.','Season flank steak and grill over high heat 4 min per side for medium.','Rest the steak 5 min, then slice thin against the grain.','Serve over rice with sliced red onion and spoon chimichurri on top.'], ARRAY['Licua perejil, ajo, 2 cdtas de aceite y vinagre en un chimichurri suelto.','Sazona el bife de flanco y ásalo a fuego alto 4 min por lado para término medio.','Reposa el bife 5 min y córtalo fino en contra de la fibra.','Sirve sobre arroz con cebolla morada y cubre con chimichurri.'], TRUE),
  ('r685', 'Colombian Grilled Chicken Bandeja', 'Bandeja de Pollo a la Parrilla', NULL, 619, 46, 66, 19, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','kidney_beans','plantain','avocado','egg_whites'], ARRAY['Season and grill chicken breast 6 min per side until 165F, then slice.','Warm kidney beans and steamed rice while frying ripe plantain until golden.','Fry the egg whites in a nonstick pan until set.','Arrange chicken, rice, beans, plantain, egg and avocado on one platter.'], ARRAY['Sazona y asa la pechuga 6 min por lado hasta 74C y córtala.','Calienta los frijoles rojos y el arroz mientras fríes el plátano maduro hasta dorar.','Fríe las claras en un sartén antiadherente hasta cuajar.','Acomoda pollo, arroz, frijoles, plátano, huevo y aguacate en una bandeja.'], TRUE),
  ('r686', 'Latin Carne Guisada with Rice', 'Carne Guisada con Arroz', NULL, 594, 44, 64, 18, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_beef','potato','carrot','tomato','rice','sofrito'], ARRAY['Brown cubed lean beef in a pot 5 min, then stir in sofrito and tomato.','Add potato, carrot and 1 cup water, cover and simmer 30 min until beef is tender.','Uncover and reduce the gravy 5 min until it coats the beef.','Serve the carne guisada over steamed rice.'], ARRAY['Dora la carne magra en cubos en una olla 5 min, luego agrega sofrito y tomate.','Añade papa, zanahoria y 1 taza de agua, tapa y cocina 30 min hasta ablandar la carne.','Destapa y reduce la salsa 5 min hasta que cubra la carne.','Sirve la carne guisada sobre arroz.'], TRUE),
  ('r687', 'Grilled Chicken with Tostones', 'Pollo a la Parrilla con Tostones', NULL, 565, 45, 58, 17, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','green_plantain','black_beans','garlic','olive_oil','lime'], ARRAY['Marinate chicken breast in garlic, lime and salt, then grill 6 min per side.','Fry green plantain rounds in 2 tsp oil 3 min, flatten, then fry again until crisp.','Warm black beans with a clove of garlic.','Serve sliced chicken with tostones and beans, squeezing lime over the top.'], ARRAY['Marina la pechuga en ajo, limón y sal, y ásala 6 min por lado.','Fríe las ruedas de plátano verde en 2 cdtas de aceite 3 min, aplástalas y fríe otra vez.','Calienta las habichuelas negras con un diente de ajo.','Sirve el pollo en rebanadas con tostones y habichuelas, exprimiendo limón encima.'], TRUE),
  ('r688', 'Cuban Mojo Pork with Black Beans', 'Cerdo al Mojo con Frijoles Negros', NULL, 571, 44, 56, 19, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['pork_tenderloin','black_beans','rice','garlic','lime','olive_oil'], ARRAY['Marinate pork tenderloin in garlic, lime juice, orange and cumin 15 min.','Sear on all sides, then roast at 400F 15 min until 145F and rest 5 min.','Simmer black beans with garlic until creamy while rice steams.','Slice the mojo pork and serve over rice and beans.'], ARRAY['Marina el lomo de cerdo en ajo, jugo de limón, naranja y comino por 15 min.','Sella por todos lados y asa a 205C por 15 min hasta 63C, reposa 5 min.','Cocina los frijoles negros con ajo hasta cremosos mientras el arroz se cocina.','Rebana el cerdo al mojo y sirve sobre arroz y frijoles.'], TRUE),
  ('r689', 'Mexican Chicken Tinga Bowl', 'Bowl de Tinga de Pollo', NULL, 556, 43, 60, 16, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','tomato','chipotle','onion','rice','black_beans'], ARRAY['Poach chicken breast 15 min, then shred with two forks.','Blend tomato, chipotle and onion, then simmer the sauce 5 min.','Toss the shredded chicken in the tinga sauce and cook 5 min more.','Serve over rice with black beans.'], ARRAY['Cocina la pechuga en agua 15 min y desméchala con dos tenedores.','Licua tomate, chipotle y cebolla, y cocina la salsa 5 min.','Mezcla el pollo mechado en la salsa tinga y cocina 5 min más.','Sirve sobre arroz con frijoles negros.'], TRUE),
  ('r690', 'Peruvian Aji de Gallina Plate', 'Ají de Gallina Peruano', NULL, 587, 42, 62, 19, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','potato','rice','almond_milk','whole_grain_bread','aji_amarillo'], ARRAY['Poach and shred chicken breast, reserving 1/2 cup of the broth.','Soak torn bread in almond milk, then blend with aji amarillo and broth into a sauce.','Simmer the sauce 5 min, fold in the shredded chicken and warm through.','Serve over sliced boiled potato with rice on the side.'], ARRAY['Cocina y desmenuza la pechuga, reservando 1/2 taza del caldo.','Remoja el pan en la leche de almendra y licúalo con ají amarillo y caldo en una salsa.','Cocina la salsa 5 min, incorpora el pollo mechado y calienta bien.','Sirve sobre papa hervida en rodajas con arroz al lado.'], TRUE),
  ('r691', 'Brazilian Churrasco Chicken with Farofa', 'Pollo Churrasco con Farofa', NULL, 596, 46, 58, 20, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','black_beans','cassava_flour','garlic','olive_oil'], ARRAY['Season chicken breast with coarse salt and grill 6 min per side, then slice.','Toast cassava flour in 2 tsp oil with garlic 4 min until golden to make farofa.','Warm black beans and steamed rice.','Plate the churrasco chicken with rice, beans and a sprinkle of farofa.'], ARRAY['Sazona la pechuga con sal gruesa, ásala 6 min por lado y córtala.','Tuesta la harina de yuca en 2 cdtas de aceite con ajo 4 min hasta dorar para la farofa.','Calienta los frijoles negros y el arroz.','Sirve el pollo churrasco con arroz, frijoles y farofa espolvoreada.'], TRUE),
  ('r692', 'Chicken & Bean Pupusa Plate', 'Pupusas de Pollo y Frijol', NULL, 602, 40, 70, 18, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['masa_harina','chicken_breast','black_beans','cheese','cabbage','tomato'], ARRAY['Mix masa harina with warm water into a soft dough and divide into 3 balls.','Fill each with shredded chicken, refried black beans and cheese, then pat into discs.','Cook the pupusas in a dry skillet 4 min per side until spotted.','Top with quick cabbage curtido and a spoon of tomato salsa.'], ARRAY['Mezcla la masa harina con agua tibia en una masa suave y divide en 3 bolas.','Rellena cada una con pollo mechado, frijoles refritos y queso, y aplana en discos.','Cocina las pupusas en sartén seco 4 min por lado hasta dorar.','Cubre con curtido de repollo y una cucharada de salsa de tomate.'], TRUE),
  ('r693', 'Grilled Chicken Farro Salad', 'Ensalada de Farro con Pollo', NULL, 554, 44, 54, 18, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','farro','cherry_tomato','cucumber','feta','olive_oil','lemon'], ARRAY['Simmer farro in salted water 25 min until chewy, then drain and cool.','Grill seasoned chicken breast 6 min per side and slice.','Toss farro with cherry tomato, cucumber, feta, lemon and 2 tsp olive oil.','Top the salad with the sliced chicken.'], ARRAY['Cocina el farro en agua con sal 25 min hasta que esté firme, escurre y enfría.','Asa la pechuga sazonada 6 min por lado y córtala.','Mezcla el farro con tomatitos, pepino, feta, limón y 2 cdtas de aceite de oliva.','Corona la ensalada con el pollo en rebanadas.'], TRUE),
  ('r694', 'Turkish Beef & Bulgur Pilaf', 'Pilaf de Res y Bulgur', NULL, 582, 43, 62, 18, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_beef','bulgur','onion','tomato','chickpeas','olive_oil'], ARRAY['Brown lean ground beef with onion in 1 tsp oil 6 min, breaking it up.','Stir in tomato paste and chickpeas, then add bulgur and 1 cup water.','Cover and simmer 15 min until the bulgur absorbs the liquid.','Rest 5 min, fluff and serve.'], ARRAY['Dora la carne molida magra con cebolla en 1 cdta de aceite 6 min, desmenuzando.','Agrega pasta de tomate y garbanzos, luego el bulgur y 1 taza de agua.','Tapa y cocina 15 min hasta que el bulgur absorba el líquido.','Reposa 5 min, suelta con un tenedor y sirve.'], TRUE),
  ('r695', 'Chicken Shish Kebab with Bulgur', 'Shish Kebab de Pollo con Bulgur', NULL, 543, 46, 56, 15, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','bulgur','bell_pepper','onion','greek_yogurt','olive_oil'], ARRAY['Marinate cubed chicken in greek yogurt, garlic and paprika 15 min.','Thread onto skewers with bell pepper and onion, then grill 12 min, turning.','Simmer bulgur in salted water 15 min until tender.','Serve the skewers over the bulgur with a dollop of yogurt.'], ARRAY['Marina el pollo en cubos con yogur griego, ajo y pimentón por 15 min.','Ensarta en pinchos con pimiento y cebolla y asa 12 min, girando.','Cocina el bulgur en agua con sal 15 min hasta que ablande.','Sirve los pinchos sobre el bulgur con una cucharada de yogur.'], TRUE),
  ('r696', 'Harissa Chicken Couscous Traybake', 'Cuscús de Pollo con Harissa', NULL, 580, 45, 64, 16, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','couscous','harissa','zucchini','bell_pepper','olive_oil'], ARRAY['Toss chicken breast and chopped zucchini and bell pepper with harissa and 2 tsp oil.','Roast on a sheet pan at 425F 22 min until chicken hits 165F.','Pour boiling water over couscous, cover 5 min, then fluff.','Slice the chicken and serve over couscous with the roasted vegetables.'], ARRAY['Mezcla la pechuga con calabacín y pimiento picados, harissa y 2 cdtas de aceite.','Asa en bandeja a 220C por 22 min hasta que el pollo llegue a 74C.','Vierte agua hirviendo sobre el cuscús, tapa 5 min y suelta con tenedor.','Rebana el pollo y sirve sobre el cuscús con las verduras asadas.'], TRUE),
  ('r697', 'Falafel & Halloumi Mezze Bowl', 'Bowl Mezze de Falafel y Halloumi', NULL, 573, 36, 60, 21, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chickpeas','halloumi','couscous','cucumber','tahini','greek_yogurt'], ARRAY['Pulse chickpeas with garlic, herbs and cumin, form into patties and bake at 400F 20 min.','Sear halloumi slices in a dry pan 1 min per side until golden.','Steam couscous and whisk tahini with greek yogurt and lemon into a sauce.','Build the bowl with couscous, falafel, halloumi, cucumber and the tahini sauce.'], ARRAY['Tritura los garbanzos con ajo, hierbas y comino, forma tortitas y hornea a 205C 20 min.','Sella las rebanadas de halloumi en sartén seco 1 min por lado hasta dorar.','Cocina el cuscús y bate el tahini con yogur griego y limón en una salsa.','Arma el bowl con cuscús, falafel, halloumi, pepino y la salsa de tahini.'], TRUE),
  ('r698', 'Chicken Gyro Rice Bowl', 'Bowl de Gyro de Pollo', NULL, 577, 44, 62, 17, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','rice','greek_yogurt','cucumber','tomato','red_onion'], ARRAY['Marinate chicken thigh in lemon, garlic and oregano 15 min, then grill 6 min per side.','Grate cucumber and mix with greek yogurt and garlic for tzatziki.','Slice the chicken and serve over rice.','Top with tomato, red onion and a generous spoon of tzatziki.'], ARRAY['Marina el muslo en limón, ajo y orégano 15 min, luego ásalo 6 min por lado.','Ralla el pepino y mézclalo con yogur griego y ajo para el tzatziki.','Rebana el pollo y sírvelo sobre arroz.','Cubre con tomate, cebolla morada y una buena cucharada de tzatziki.'], TRUE),
  ('r699', 'Za''atar Salmon with Freekeh', 'Salmón al Za''atar con Freekeh', NULL, 577, 42, 55, 21, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon','freekeh','spinach','lemon','olive_oil','za_atar'], ARRAY['Simmer freekeh in salted water 20 min until tender, then stir in spinach to wilt.','Rub salmon fillet with za''atar and 1 tsp olive oil.','Roast the salmon at 400F 12 min until it flakes.','Serve the salmon over the freekeh with a squeeze of lemon.'], ARRAY['Cocina el freekeh en agua con sal 20 min hasta ablandar, luego integra la espinaca.','Unta el filete de salmón con za''atar y 1 cdta de aceite de oliva.','Asa el salmón a 205C por 12 min hasta que se desmenuce.','Sirve el salmón sobre el freekeh con un chorrito de limón.'], TRUE),
  ('r700', 'Lemon Herb Cod with Couscous', 'Bacalao al Limón con Cuscús', NULL, 538, 45, 58, 14, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['cod','couscous','lemon','spinach','olive_oil','garlic'], ARRAY['Season cod with lemon, garlic and herbs, then bake at 400F 14 min until opaque.','Pour boiling water over couscous, cover 5 min, then fluff with a fork.','Wilt spinach in 1 tsp oil with garlic 2 min and fold into the couscous.','Plate the cod over the couscous with a lemon wedge.'], ARRAY['Sazona el bacalao con limón, ajo y hierbas, y hornea a 205C 14 min hasta opaco.','Vierte agua hirviendo sobre el cuscús, tapa 5 min y suelta con un tenedor.','Saltea la espinaca en 1 cdta de aceite con ajo 2 min e intégrala al cuscús.','Sirve el bacalao sobre el cuscús con un gajo de limón.'], TRUE),
  ('r701', 'Chickpea Shakshuka with Pita', 'Shakshuka de Garbanzos con Pita', NULL, 559, 35, 62, 19, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['eggs','chickpeas','tomato','bell_pepper','onion','pita'], ARRAY['Saute onion and bell pepper 4 min, then add tomato, chickpeas, cumin and paprika.','Simmer the sauce 8 min until thick, then make wells with a spoon.','Crack 3 eggs into the wells, cover and cook 6 min until whites set.','Serve straight from the pan with warm pita for dipping.'], ARRAY['Sofríe cebolla y pimiento 4 min, luego agrega tomate, garbanzos, comino y pimentón.','Cocina la salsa 8 min hasta espesar y haz huecos con una cuchara.','Rompe 3 huevos en los huecos, tapa y cocina 6 min hasta cuajar las claras.','Sirve directo del sartén con pita tibia para mojar.'], TRUE),
  ('r702', 'Mediterranean Tuna & White Bean Bowl', 'Bowl de Atún y Habichuelas Blancas', NULL, 538, 44, 50, 18, 15, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','cannellini_beans','cherry_tomato','red_onion','olive_oil','lemon'], ARRAY['Drain and rinse cannellini beans and tip into a bowl.','Add flaked tuna, halved cherry tomato and thin-sliced red onion.','Dress with 2 tsp olive oil, lemon juice, salt and pepper.','Toss gently and let sit 5 min before eating.'], ARRAY['Escurre y enjuaga las habichuelas blancas y ponlas en un bowl.','Agrega el atún desmenuzado, tomatitos en mitades y cebolla morada en rodajas finas.','Adereza con 2 cdtas de aceite de oliva, jugo de limón, sal y pimienta.','Mezcla suave y deja reposar 5 min antes de comer.'], TRUE),
  ('r703', 'Turkish Lamb & Eggplant Pilaf', 'Pilaf de Cordero y Berenjena', NULL, 605, 44, 60, 21, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lamb','rice','eggplant','onion','tomato','olive_oil'], ARRAY['Brown lean ground lamb with onion 6 min, draining excess fat.','Add diced eggplant and tomato, cooking 5 min until the eggplant softens.','Stir in rice and 1 cup water, cover and simmer 18 min.','Rest 5 min, fluff and serve.'], ARRAY['Dora el cordero molido magro con cebolla 6 min, escurriendo el exceso de grasa.','Agrega berenjena y tomate en cubos, cocinando 5 min hasta ablandar la berenjena.','Incorpora el arroz y 1 taza de agua, tapa y cocina 18 min.','Reposa 5 min, suelta con un tenedor y sirve.'], TRUE),
  ('r704', 'Greek Shrimp Saganaki with Orzo', 'Orzo con Camarones Saganaki', NULL, 568, 42, 64, 16, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['shrimp','orzo','tomato','feta','garlic','olive_oil'], ARRAY['Boil orzo in salted water 9 min, then drain.','Saute garlic in 2 tsp oil 1 min, add tomato and simmer into a sauce 6 min.','Add shrimp and cook 3 min, then crumble feta on top and cover 2 min.','Fold the saganaki through the orzo and serve.'], ARRAY['Hierve el orzo en agua con sal 9 min y escúrrelo.','Sofríe el ajo en 2 cdtas de aceite 1 min, agrega tomate y cocina una salsa 6 min.','Añade los camarones y cocina 3 min, desmenuza feta encima y tapa 2 min.','Integra el saganaki con el orzo y sirve.'], TRUE),
  ('r705', 'Turkey Ragu over Creamy Polenta', 'Ragú de Pavo sobre Polenta', NULL, 557, 43, 58, 17, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','polenta','tomato','onion','garlic','olive_oil'], ARRAY['Brown ground turkey with onion and garlic in 1 tsp oil 6 min.','Add tomato and a pinch of oregano, simmering the ragu 12 min until thick.','Whisk polenta into simmering water 5 min until creamy.','Spoon the turkey ragu over the polenta.'], ARRAY['Dora el pavo molido con cebolla y ajo en 1 cdta de aceite 6 min.','Agrega tomate y una pizca de orégano, cocinando el ragú 12 min hasta espesar.','Bate la polenta en agua hirviendo 5 min hasta que quede cremosa.','Sirve el ragú de pavo sobre la polenta.'], TRUE),
  ('r706', 'Greek Turkey Keftedes Rice Bowl', 'Bowl de Keftedes de Pavo', NULL, 564, 45, 60, 16, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','rice','tomato','onion','mint','olive_oil'], ARRAY['Mix ground turkey with grated onion, mint, oregano and salt, then roll into meatballs.','Brown the keftedes in 2 tsp oil 8 min, turning until cooked through.','Warm steamed rice and a quick tomato salad.','Serve the keftedes over rice with the tomato on the side.'], ARRAY['Mezcla el pavo molido con cebolla rallada, menta, orégano y sal, y forma albóndigas.','Dora los keftedes en 2 cdtas de aceite 8 min, girando hasta cocer por dentro.','Calienta arroz y prepara una ensalada rápida de tomate.','Sirve los keftedes sobre arroz con el tomate al lado.'], TRUE),
  ('r707', 'Spanish Chickpea & Chorizo Stew', 'Garbanzos con Chorizo', NULL, 564, 38, 58, 20, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chickpeas','chorizo','spinach','tomato','onion','garlic'], ARRAY['Brown sliced chorizo in a dry pot 3 min to render its oil.','Add onion and garlic, cooking 3 min, then stir in tomato and smoked paprika.','Add chickpeas and 1/2 cup water, simmering 12 min until thick.','Stir in spinach until wilted and serve.'], ARRAY['Dora el chorizo en rodajas en una olla seca 3 min para soltar su aceite.','Agrega cebolla y ajo, cocina 3 min, luego incorpora tomate y pimentón ahumado.','Añade los garbanzos y 1/2 taza de agua, cocinando 12 min hasta espesar.','Integra la espinaca hasta marchitar y sirve.'], TRUE),
  ('r708', 'Lebanese Chicken Fattoush Bowl', 'Bowl de Fattoush con Pollo', NULL, 534, 43, 50, 18, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','pita','cucumber','tomato','lettuce','lemon','olive_oil'], ARRAY['Grill seasoned chicken breast 6 min per side, then slice.','Tear pita, toss with 1 tsp oil and bake at 400F 6 min until crisp.','Combine lettuce, cucumber and tomato with lemon, sumac and 1 tsp oil.','Top the salad with chicken and the crisp pita chips.'], ARRAY['Asa la pechuga sazonada 6 min por lado y córtala.','Rompe la pita, mezcla con 1 cdta de aceite y hornea a 205C 6 min hasta crujir.','Combina lechuga, pepino y tomate con limón, zumaque y 1 cdta de aceite.','Corona la ensalada con el pollo y los chips de pita crujientes.'], TRUE),
  ('r709', 'Egyptian Ful Medames with Eggs', 'Ful Medames con Huevos', NULL, 530, 36, 56, 18, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['fava_beans','eggs','tomato','garlic','olive_oil','pita'], ARRAY['Warm fava beans with garlic and cumin, mashing lightly to a chunky paste.','Stir in diced tomato and 1 tsp olive oil, then season with lemon.','Fry or boil 2 eggs to your liking.','Serve the ful topped with the eggs and warm pita.'], ARRAY['Calienta las habas con ajo y comino, majando ligero hasta una pasta rústica.','Integra tomate en cubos y 1 cdta de aceite de oliva, y sazona con limón.','Fríe o hierve 2 huevos a tu gusto.','Sirve el ful coronado con los huevos y pita tibia.'], TRUE),
  ('r710', 'Tuscan White Bean & Chicken Sausage', 'Alubias Toscanas con Salchicha', NULL, 555, 42, 54, 19, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_sausage','cannellini_beans','kale','tomato','garlic','olive_oil'], ARRAY['Brown sliced chicken sausage in 1 tsp oil 5 min, then remove.','Saute garlic 1 min, add tomato and cannellini beans with 1/2 cup water.','Simmer 8 min, then stir in chopped kale until wilted.','Return the sausage and warm through before serving.'], ARRAY['Dora la salchicha de pollo en rodajas en 1 cdta de aceite 5 min y retírala.','Sofríe el ajo 1 min, agrega tomate y alubias blancas con 1/2 taza de agua.','Cocina 8 min, luego integra la col rizada picada hasta marchitar.','Regresa la salchicha y calienta bien antes de servir.'], TRUE),
  ('r711', 'Sicilian Tuna Couscous', 'Cuscús Siciliano con Atún', NULL, 573, 43, 62, 17, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','couscous','tomato','olives','garlic','olive_oil'], ARRAY['Pour boiling water over couscous, cover 5 min, then fluff.','Saute garlic in 2 tsp oil 1 min, add tomato and olives, simmering 5 min.','Fold in flaked tuna and warm through 2 min.','Stir the sauce through the couscous and serve.'], ARRAY['Vierte agua hirviendo sobre el cuscús, tapa 5 min y suelta con un tenedor.','Sofríe el ajo en 2 cdtas de aceite 1 min, agrega tomate y aceitunas, cocina 5 min.','Integra el atún desmenuzado y calienta 2 min.','Mezcla la salsa con el cuscús y sirve.'], TRUE),
  ('r712', 'Piri Piri Chicken with Rice & Beans', 'Pollo Piri Piri con Habichuelas', NULL, 592, 46, 66, 16, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','kidney_beans','bell_pepper','garlic','paprika'], ARRAY['Blend garlic, paprika, chili and lemon into a piri piri marinade and coat the chicken 15 min.','Grill the chicken thighs 7 min per side until charred and 175F.','Warm rice and kidney beans with sauteed bell pepper.','Serve the piri piri chicken over the rice and beans.'], ARRAY['Licua ajo, pimentón, chile y limón en un adobo piri piri y cubre el pollo 15 min.','Asa los muslos 7 min por lado hasta que se doren y lleguen a 79C.','Calienta el arroz y los frijoles rojos con pimiento salteado.','Sirve el pollo piri piri sobre el arroz y los frijoles.'], TRUE),
  ('r713', 'Chipotle Steak Burrito Bowl', 'Bowl Burrito de Bistec Chipotle', NULL, 822, 52, 95, 26, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','rice','black_beans','bell_pepper','onion','salsa','avocado','cheese'], ARRAY['Season sliced steak with chipotle, cumin and salt; sear in a hot skillet with olive oil for 3-4 minutes.','Warm cooked rice with lime and cilantro; heat the black beans through.','Saute bell pepper and onion until charred, about 5 minutes.','Build the bowl with rice, beans, steak and peppers; top with salsa, avocado and shredded cheese.'], ARRAY['Sazona el bistec en tiras con chipotle, comino y sal; sellalo en un sarten caliente con aceite de oliva por 3-4 minutos.','Calienta el arroz cocido con limon y cilantro; calienta los frijoles negros.','Saltea el pimiento y la cebolla hasta dorar, unos 5 minutos.','Arma el bowl con arroz, frijoles, bistec y pimientos; corona con salsa, aguacate y queso rallado.'], TRUE),
  ('r714', 'Buffalo Chicken Burrito Bowl', 'Bowl Burrito de Pollo Buffalo', NULL, 788, 55, 88, 24, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['chicken_breast','rice','black_beans','cheese','greek_yogurt','hot_sauce','lettuce','tomato'], ARRAY['Toss cooked shredded chicken in buffalo hot sauce until fully coated.','Stir cooked rice with a squeeze of lime; warm the black beans.','Whisk greek yogurt with a little hot sauce for a creamy ranch-style drizzle.','Layer rice, beans, buffalo chicken, lettuce and tomato; top with cheese and the yogurt drizzle.'], ARRAY['Mezcla el pollo cocido y desmenuzado con salsa buffalo hasta cubrirlo bien.','Revuelve el arroz cocido con un chorrito de limon; calienta los frijoles negros.','Bate el yogur griego con un poco de salsa picante para un aderezo cremoso estilo ranch.','Coloca arroz, frijoles, pollo buffalo, lechuga y tomate; corona con queso y el aderezo de yogur.'], TRUE),
  ('r715', 'Barbacoa Beef Burrito Bowl', 'Bowl Burrito de Barbacoa de Res', NULL, 838, 50, 92, 30, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','rice','black_beans','onion','garlic','salsa','avocado','cheese'], ARRAY['Braise the beef with garlic, onion, chipotle and a splash of broth until fork-tender, about 30 minutes, then shred.','Cook rice and fold in lime and chopped cilantro.','Warm the black beans with a pinch of cumin.','Fill the bowl with rice, beans and barbacoa; top with salsa, avocado and cheese.'], ARRAY['Guisa la carne con ajo, cebolla, chipotle y un chorrito de caldo hasta que este suave, unos 30 minutos, y desmenuzala.','Cocina el arroz e incorpora limon y cilantro picado.','Calienta los frijoles negros con una pizca de comino.','Llena el bowl con arroz, frijoles y barbacoa; corona con salsa, aguacate y queso.'], TRUE),
  ('r716', 'Cilantro Lime Chicken Burrito', 'Burrito de Pollo con Cilantro y Limon', NULL, 817, 48, 100, 25, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['chicken_breast','tortilla','rice','black_beans','cheese','salsa','avocado','onion'], ARRAY['Grill seasoned chicken breast until 165F, about 6 minutes per side, then slice.','Toss warm rice with lime juice and plenty of chopped cilantro.','Warm a large flour tortilla and layer rice, beans, chicken, cheese and salsa.','Fold in the sides, roll tight, and sear seam-side down in a dry pan for 1-2 minutes.'], ARRAY['Asa la pechuga sazonada hasta 74C, unos 6 minutos por lado, y cortala en tiras.','Mezcla el arroz caliente con jugo de limon y bastante cilantro picado.','Calienta una tortilla de harina grande y coloca arroz, frijoles, pollo, queso y salsa.','Dobla los lados, enrolla apretado y sella con la union hacia abajo en un sarten seco por 1-2 minutos.'], TRUE),
  ('r717', 'Al Pastor Burrito Bowl', 'Bowl de Burrito al Pastor', NULL, 828, 46, 98, 28, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['pork_shoulder','rice','black_beans','onion','pineapple','salsa','avocado','cheese'], ARRAY['Marinate thin pork slices in achiote, chipotle, pineapple juice and garlic for 15 minutes.','Sear the pork hard in a hot skillet until caramelized, 5-6 minutes, then chop.','Char pineapple and onion in the same pan for 3 minutes.','Serve over cilantro-lime rice with black beans, salsa, avocado and cheese.'], ARRAY['Marina las laminas finas de cerdo con achiote, chipotle, jugo de pina y ajo por 15 minutos.','Sella el cerdo en un sarten bien caliente hasta caramelizar, 5-6 minutos, y picalo.','Dora la pina y la cebolla en el mismo sarten por 3 minutos.','Sirve sobre arroz con cilantro y limon, con frijoles negros, salsa, aguacate y queso.'], TRUE),
  ('r718', 'Smothered Beef Wet Burrito', 'Burrito Ahogado de Res con Queso', NULL, 854, 47, 90, 34, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','tortilla','black_beans','rice','cheese','tomato','onion','salsa'], ARRAY['Brown ground beef with onion, cumin and chili powder until cooked through, 6-8 minutes.','Roll the beef, rice and beans in a large tortilla and place seam-down in a baking dish.','Cover with warm red enchilada sauce and a thick layer of shredded cheese.','Bake at 400F for 12 minutes until the cheese is bubbling; top with salsa.'], ARRAY['Dora la carne molida con cebolla, comino y chile en polvo hasta cocer, 6-8 minutos.','Enrolla la carne, el arroz y los frijoles en una tortilla grande y colocala con la union hacia abajo en un molde.','Cubre con salsa roja de enchilada caliente y una capa gruesa de queso rallado.','Hornea a 200C por 12 minutos hasta que el queso burbujee; corona con salsa.'], TRUE),
  ('r719', 'Southwest Steak Breakfast Burrito', 'Burrito de Desayuno con Bistec', NULL, 765, 45, 72, 33, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['lean_beef','eggs','tortilla','potato','cheese','bell_pepper','onion','salsa'], ARRAY['Pan-fry diced potato until crisp, about 8 minutes, adding pepper and onion for the last 3.','Sear thin steak strips 2-3 minutes, then scramble the eggs soft in the same pan.','Pile steak, eggs, potatoes and cheese onto a warm tortilla.','Roll tightly and griddle seam-side down for 2 minutes; serve with salsa.'], ARRAY['Frie la papa en cubos hasta que este crujiente, unos 8 minutos, agregando pimiento y cebolla los ultimos 3.','Sella las tiras finas de bistec 2-3 minutos y revuelve los huevos suaves en el mismo sarten.','Coloca bistec, huevos, papas y queso sobre una tortilla caliente.','Enrolla apretado y dora con la union hacia abajo por 2 minutos; sirve con salsa.'], TRUE),
  ('r720', 'Double Beef Baked Ziti', 'Ziti al Horno con Doble Carne', NULL, 826, 54, 85, 30, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['pasta','lean_beef','tomato','cheese','cottage_cheese','garlic','onion','spinach'], ARRAY['Boil ziti until just under al dente, about 8 minutes, and drain.','Brown a double portion of beef with onion and garlic, then simmer in crushed tomato for 10 minutes.','Fold the pasta with the meat sauce, cottage cheese and wilted spinach.','Top with mozzarella and bake at 400F for 18 minutes until golden and bubbly.'], ARRAY['Hierve el ziti hasta casi al dente, unos 8 minutos, y escurrelo.','Dora una porcion doble de carne con cebolla y ajo, y cocina en tomate triturado por 10 minutos.','Mezcla la pasta con la salsa de carne, el queso cottage y la espinaca marchitada.','Cubre con mozzarella y hornea a 200C por 18 minutos hasta dorar y burbujear.'], TRUE),
  ('r721', 'Creamy Cajun Chicken Pasta', 'Pasta Cremosa de Pollo Cajun', NULL, 812, 52, 88, 28, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['pasta','chicken_breast','cheese','bell_pepper','onion','garlic','tomato','greek_yogurt'], ARRAY['Toss sliced chicken in Cajun seasoning and sear until cooked, about 6 minutes.','Cook penne until al dente and reserve a splash of pasta water.','Saute pepper, onion and garlic, then stir in greek yogurt, parmesan and a little tomato for a creamy sauce.','Fold in the pasta and chicken, loosening with pasta water; simmer 2 minutes.'], ARRAY['Mezcla el pollo en tiras con sazon cajun y sellalo hasta cocer, unos 6 minutos.','Cocina el penne al dente y reserva un poco del agua de coccion.','Saltea pimiento, cebolla y ajo; incorpora yogur griego, parmesano y un poco de tomate para una salsa cremosa.','Integra la pasta y el pollo, aflojando con el agua reservada; cocina 2 minutos.'], TRUE),
  ('r722', 'Buffalo Chicken Mac and Cheese', 'Macarrones con Queso y Pollo Buffalo', NULL, 816, 50, 82, 32, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['pasta','chicken_breast','cheese','almond_milk','greek_yogurt','hot_sauce','garlic','onion'], ARRAY['Boil macaroni until al dente and drain.','Toss cooked shredded chicken with buffalo hot sauce.','Make a quick cheese sauce with milk, cheddar, a spoon of greek yogurt and garlic over low heat.','Fold the pasta and buffalo chicken into the sauce; simmer 2 minutes until thick.'], ARRAY['Hierve los macarrones al dente y escurrelos.','Mezcla el pollo cocido y desmenuzado con salsa buffalo.','Prepara una salsa rapida de queso con leche, cheddar, una cucharada de yogur griego y ajo a fuego bajo.','Integra la pasta y el pollo buffalo en la salsa; cocina 2 minutos hasta espesar.'], TRUE),
  ('r723', 'Pulled Pork Mac and Cheese', 'Macarrones con Queso y Cerdo Desmenuzado', NULL, 842, 48, 86, 34, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['pasta','pork_shoulder','cheese','almond_milk','onion','garlic','tomato','bbq_sauce'], ARRAY['Simmer or reheat shredded pork tossed in a little barbecue sauce.','Cook macaroni al dente and drain.','Melt cheddar into warm milk with garlic to form a smooth sauce.','Combine the pasta and sauce, top with pulled pork, and broil 3 minutes until crusty.'], ARRAY['Calienta el cerdo desmenuzado mezclado con un poco de salsa barbacoa.','Cocina los macarrones al dente y escurrelos.','Derrite el cheddar en leche tibia con ajo hasta lograr una salsa suave.','Combina la pasta y la salsa, corona con el cerdo y gratina 3 minutos hasta dorar.'], TRUE),
  ('r724', 'Philly Cheesesteak Pasta', 'Pasta Estilo Philly Cheesesteak', NULL, 833, 50, 84, 33, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['pasta','lean_beef','cheese','bell_pepper','onion','mushroom','garlic','almond_milk'], ARRAY['Sear thin-sliced steak until browned, 3-4 minutes, and set aside.','Saute pepper, onion and mushroom until soft, about 5 minutes.','Stir in milk and provolone to melt into a creamy sauce.','Fold in the cooked pasta and steak; simmer 2 minutes and season with pepper.'], ARRAY['Sella el bistec en laminas finas hasta dorar, 3-4 minutos, y reserva.','Saltea pimiento, cebolla y champinon hasta ablandar, unos 5 minutos.','Incorpora leche y provolone hasta derretir en una salsa cremosa.','Integra la pasta cocida y el bistec; cocina 2 minutos y sazona con pimienta.'], TRUE),
  ('r725', 'Beef Stroganoff over Egg Noodles', 'Stroganoff de Res sobre Fideos', NULL, 804, 49, 80, 32, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','pasta','mushroom','onion','garlic','greek_yogurt','cheese','olive_oil'], ARRAY['Sear strips of beef in olive oil until browned, then remove.','Cook mushroom, onion and garlic until golden, about 6 minutes.','Stir in broth and greek yogurt to make a silky sauce; return the beef.','Serve over boiled egg noodles and simmer 2 minutes to thicken.'], ARRAY['Sella las tiras de res en aceite de oliva hasta dorar y retiralas.','Cocina champinon, cebolla y ajo hasta dorar, unos 6 minutos.','Incorpora caldo y yogur griego para una salsa sedosa; regresa la carne.','Sirve sobre fideos de huevo cocidos y cocina 2 minutos para espesar.'], TRUE),
  ('r726', 'Turkey Bolognese Penne Bake', 'Penne al Horno con Bolonesa de Pavo', NULL, 788, 53, 90, 24, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['pasta','ground_turkey','tomato','onion','garlic','carrot','cheese','spinach'], ARRAY['Soften onion, carrot and garlic, then brown the ground turkey.','Add crushed tomato and simmer the sauce for 15 minutes.','Toss with cooked penne and wilted spinach, then transfer to a baking dish.','Top with mozzarella and bake at 400F for 15 minutes until golden.'], ARRAY['Ablanda cebolla, zanahoria y ajo, luego dora el pavo molido.','Agrega tomate triturado y cocina la salsa por 15 minutos.','Mezcla con el penne cocido y la espinaca marchitada, y pasalo a un molde.','Cubre con mozzarella y hornea a 200C por 15 minutos hasta dorar.'], TRUE),
  ('r727', 'Spicy Vodka Rigatoni with Chicken', 'Rigatoni a la Vodka Picante con Pollo', NULL, 830, 48, 92, 30, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['pasta','chicken_breast','tomato','garlic','onion','cheese','greek_yogurt','olive_oil'], ARRAY['Sear seasoned chicken pieces until cooked, about 6 minutes, then set aside.','Saute garlic and onion, add tomato paste and a pinch of chili flakes; cook 3 minutes.','Stir in greek yogurt and parmesan for a creamy vodka-style sauce.','Toss with cooked rigatoni and the chicken; simmer 2 minutes.'], ARRAY['Sella los trozos de pollo sazonado hasta cocer, unos 6 minutos, y reserva.','Saltea ajo y cebolla, agrega pasta de tomate y una pizca de hojuelas de chile; cocina 3 minutos.','Incorpora yogur griego y parmesano para una salsa cremosa estilo vodka.','Mezcla con el rigatoni cocido y el pollo; cocina 2 minutos.'], TRUE),
  ('r728', 'Chili Mac Skillet', 'Sarten de Chili con Macarrones', NULL, 804, 50, 88, 28, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['pasta','lean_beef','black_beans','tomato','cheese','onion','garlic','bell_pepper'], ARRAY['Brown ground beef with onion, garlic and pepper in a deep skillet.','Stir in chili powder, cumin, crushed tomato and black beans.','Add dry macaroni and enough broth to cover; simmer 12 minutes until tender.','Top with shredded cheese and cover until melted.'], ARRAY['Dora la carne molida con cebolla, ajo y pimiento en un sarten hondo.','Incorpora chile en polvo, comino, tomate triturado y frijoles negros.','Agrega los macarrones secos y caldo suficiente para cubrir; cocina 12 minutos hasta ablandar.','Corona con queso rallado y tapa hasta derretir.'], TRUE),
  ('r729', 'Shrimp Scampi Linguine', 'Linguine con Camarones al Ajillo', NULL, 794, 45, 95, 26, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['pasta','shrimp','garlic','lemon','olive_oil','tomato','spinach','cheese'], ARRAY['Cook linguine until al dente and reserve some pasta water.','Saute garlic in olive oil, then add shrimp and cook 2-3 minutes until pink.','Deglaze with lemon juice and a splash of pasta water; add spinach to wilt.','Toss in the pasta with parmesan and season; serve right away.'], ARRAY['Cocina el linguine al dente y reserva algo del agua de coccion.','Saltea el ajo en aceite de oliva, agrega los camarones y cocina 2-3 minutos hasta que esten rosados.','Desglasa con jugo de limon y un poco del agua reservada; agrega espinaca para marchitar.','Integra la pasta con parmesano y sazona; sirve enseguida.'], TRUE),
  ('r730', 'Beef Birria Quesatacos', 'Quesatacos de Birria de Res', NULL, 826, 52, 78, 34, 45, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Hard', 'Dificil', 1, ARRAY['lean_beef','tortilla','cheese','onion','garlic','tomato','salsa','cilantro'], ARRAY['Braise beef with dried chiles, garlic, tomato and spices until tender, about 35 minutes; shred and reserve the consomme.','Dip corn tortillas in the red consomme and lay them on a hot griddle.','Fill with birria beef and cheese, fold, and crisp both sides until the cheese melts.','Serve with chopped onion, cilantro and a cup of consomme for dipping.'], ARRAY['Guisa la carne con chiles secos, ajo, tomate y especias hasta ablandar, unos 35 minutos; desmenuza y reserva el consome.','Pasa las tortillas de maiz por el consome rojo y colocalas en un comal caliente.','Rellena con la birria y queso, dobla y dora ambos lados hasta que el queso derrita.','Sirve con cebolla picada, cilantro y una taza de consome para mojar.'], TRUE),
  ('r731', 'Chicken Philly Cheesesteak Bowl', 'Bowl de Pollo Estilo Philly', NULL, 783, 55, 80, 27, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['chicken_breast','rice','cheese','bell_pepper','onion','mushroom','garlic','olive_oil'], ARRAY['Sear thin-sliced chicken in olive oil until browned, about 5 minutes.','Add pepper, onion and mushroom; cook until soft and caramelized.','Lay provolone over the top and cover until melted.','Spoon over warm rice and season with salt and pepper.'], ARRAY['Sella el pollo en laminas finas en aceite de oliva hasta dorar, unos 5 minutos.','Agrega pimiento, cebolla y champinon; cocina hasta ablandar y caramelizar.','Coloca provolone encima y tapa hasta derretir.','Sirve sobre arroz caliente y sazona con sal y pimienta.'], TRUE),
  ('r732', 'Philly Cheesesteak Stuffed Peppers', 'Pimientos Rellenos Philly Cheesesteak', NULL, 752, 50, 66, 32, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['bell_pepper','lean_beef','cheese','onion','mushroom','garlic','rice','tomato'], ARRAY['Halve the bell peppers and remove the seeds.','Sear thin steak with onion, mushroom and garlic until browned.','Mix the filling with a little cooked rice and stuff it into the peppers.','Top with provolone and bake at 400F for 20 minutes until tender.'], ARRAY['Corta los pimientos a la mitad y retira las semillas.','Sella el bistec fino con cebolla, champinon y ajo hasta dorar.','Mezcla el relleno con un poco de arroz cocido y rellena los pimientos.','Cubre con provolone y hornea a 200C por 20 minutos hasta ablandar.'], TRUE),
  ('r733', 'Bacon Smash Burger Bowl', 'Bowl de Hamburguesa con Tocino', NULL, 796, 48, 70, 36, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['lean_beef','bacon','cheese','potato','lettuce','tomato','onion','pickle'], ARRAY['Smash seasoned beef into thin patties and sear hard 2 minutes per side.','Crisp the bacon and melt cheese over the patties.','Roast or pan-fry diced potatoes until golden.','Build a bowl with potatoes, chopped burger, bacon, lettuce, tomato, onion and pickles; drizzle with burger sauce.'], ARRAY['Aplasta la carne sazonada en discos finos y sellalos 2 minutos por lado.','Dora el tocino y derrite el queso sobre las carnes.','Asa o frie las papas en cubos hasta dorar.','Arma un bowl con papas, hamburguesa picada, tocino, lechuga, tomate, cebolla y pepinillos; rocia con salsa de hamburguesa.'], TRUE),
  ('r734', 'Green Chile Smash Burger Plate', 'Plato de Hamburguesa con Chile Verde', NULL, 799, 47, 74, 35, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['lean_beef','cheese','potato','bell_pepper','onion','tomato','lettuce','salsa'], ARRAY['Smash beef into thin patties and sear until crusty, about 2 minutes per side.','Char green chiles (or peppers) and lay them over the patties with cheese to melt.','Crisp potato wedges in the oven at 425F for 20 minutes.','Plate the burgers and wedges with lettuce, tomato and salsa verde.'], ARRAY['Aplasta la carne en discos finos y sellalos hasta dorar, unos 2 minutos por lado.','Asa los chiles verdes (o pimientos) y colocalos sobre las carnes con queso para derretir.','Dora las papas en gajos al horno a 220C por 20 minutos.','Sirve las hamburguesas y las papas con lechuga, tomate y salsa verde.'], TRUE),
  ('r735', 'Turkey Smash Burger Plate', 'Plato de Hamburguesa de Pavo', NULL, 758, 50, 72, 30, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['ground_turkey','cheese','potato','lettuce','tomato','onion','whole_grain_bread','greek_yogurt'], ARRAY['Form seasoned ground turkey into thin patties.','Smash and sear on a hot griddle 3 minutes per side until cooked through; melt cheese on top.','Toast the buns and bake fries alongside.','Assemble with lettuce, tomato, onion and a yogurt-based special sauce.'], ARRAY['Forma discos finos con el pavo molido sazonado.','Aplasta y sella en una plancha caliente 3 minutos por lado hasta cocer; derrite queso encima.','Tuesta los panes y hornea papas al lado.','Arma con lechuga, tomate, cebolla y una salsa especial a base de yogur.'], TRUE),
  ('r736', 'Loaded Steak Nachos', 'Nachos Cargados de Bistec', NULL, 860, 46, 88, 36, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['tortilla_chips','lean_beef','cheese','black_beans','salsa','avocado','greek_yogurt','jalapeno'], ARRAY['Sear seasoned steak strips 3-4 minutes, then chop.','Spread tortilla chips on a tray and layer with cheese and black beans.','Bake at 400F for 6 minutes until the cheese melts.','Top with steak, salsa, avocado, jalapenos and a yogurt crema.'], ARRAY['Sella las tiras de bistec 3-4 minutos y picalas.','Extiende los totopos en una bandeja y cubre con queso y frijoles negros.','Hornea a 200C por 6 minutos hasta derretir el queso.','Corona con bistec, salsa, aguacate, jalapenos y crema de yogur.'], TRUE),
  ('r737', 'Buffalo Chicken Nachos', 'Nachos de Pollo Buffalo', NULL, 838, 48, 85, 34, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['tortilla_chips','chicken_breast','cheese','hot_sauce','greek_yogurt','tomato','onion','jalapeno'], ARRAY['Toss cooked shredded chicken in buffalo sauce.','Layer tortilla chips with cheese and the buffalo chicken.','Bake at 400F for 6-7 minutes until melted and bubbling.','Finish with tomato, onion, jalapenos and a drizzle of yogurt ranch.'], ARRAY['Mezcla el pollo cocido y desmenuzado con salsa buffalo.','Cubre los totopos con queso y el pollo buffalo.','Hornea a 200C por 6-7 minutos hasta derretir y burbujear.','Termina con tomate, cebolla, jalapenos y un chorrito de ranch de yogur.'], TRUE),
  ('r738', 'Beef Chorizo Nachos', 'Nachos de Chorizo de Res', NULL, 846, 44, 82, 38, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['tortilla_chips','chorizo','lean_beef','cheese','black_beans','salsa','avocado','onion'], ARRAY['Brown the beef and chorizo together until crisp, breaking it up, 6-8 minutes; drain excess fat.','Layer chips with cheese and the meat over a sheet pan.','Bake at 400F for 6 minutes until the cheese melts.','Top with black beans, salsa, avocado and onion.'], ARRAY['Dora la carne y el chorizo juntos hasta dorar, desmoronando, 6-8 minutos; escurre el exceso de grasa.','Cubre los totopos con queso y la carne sobre una bandeja.','Hornea a 200C por 6 minutos hasta derretir el queso.','Corona con frijoles negros, salsa, aguacate y cebolla.'], TRUE),
  ('r739', 'Cheesy Beef Taco Skillet', 'Sarten de Tacos de Res con Queso', NULL, 817, 50, 80, 33, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['lean_beef','tortilla','cheese','black_beans','tomato','onion','salsa','corn'], ARRAY['Brown beef with onion and taco seasoning in a large skillet.','Stir in black beans, corn and diced tomato.','Tuck torn tortilla pieces into the skillet and top with cheese.','Cover 5 minutes until melted; finish with salsa.'], ARRAY['Dora la carne con cebolla y sazon para tacos en un sarten grande.','Incorpora frijoles negros, maiz y tomate en cubos.','Coloca trozos de tortilla en el sarten y cubre con queso.','Tapa 5 minutos hasta derretir; termina con salsa.'], TRUE),
  ('r740', 'Beef Enchilada Skillet', 'Sarten de Enchiladas de Res', NULL, 816, 48, 84, 32, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','tortilla','cheese','tomato','onion','garlic','black_beans','salsa'], ARRAY['Brown beef with onion and garlic until cooked.','Add red enchilada sauce and black beans; simmer 5 minutes.','Fold in cut tortillas so they soak up the sauce.','Top with cheese and broil 4 minutes until bubbly.'], ARRAY['Dora la carne con cebolla y ajo hasta cocer.','Agrega salsa roja de enchilada y frijoles negros; cocina 5 minutos.','Incorpora las tortillas cortadas para que absorban la salsa.','Cubre con queso y gratina 4 minutos hasta burbujear.'], TRUE),
  ('r741', 'Sizzling Chicken Fajita Platter', 'Fajitas de Pollo a la Plancha', NULL, 782, 55, 82, 26, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['chicken_breast','bell_pepper','onion','tortilla','cheese','salsa','avocado','lime'], ARRAY['Toss sliced chicken with fajita spices and lime.','Sear on a screaming-hot skillet 5-6 minutes until charred.','Add strips of pepper and onion; cook until just softened.','Serve sizzling with warm tortillas, cheese, salsa and avocado.'], ARRAY['Mezcla el pollo en tiras con especias para fajita y limon.','Sella en un sarten bien caliente 5-6 minutos hasta dorar.','Agrega tiras de pimiento y cebolla; cocina hasta ablandar.','Sirve bien caliente con tortillas, queso, salsa y aguacate.'], TRUE),
  ('r742', 'Cheesy Beef Chimichanga Plate', 'Plato de Chimichanga de Res con Queso', NULL, 859, 46, 90, 35, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['tortilla','lean_beef','cheese','rice','black_beans','salsa','avocado','onion'], ARRAY['Brown beef with onion and Mexican spices.','Roll beef, rice, beans and cheese tightly in a large tortilla.','Pan-fry in a little oil, seam-side down, turning until golden and crisp all over.','Serve topped with salsa, cheese and avocado.'], ARRAY['Dora la carne con cebolla y especias mexicanas.','Enrolla carne, arroz, frijoles y queso apretado en una tortilla grande.','Frie en poco aceite, con la union hacia abajo, girando hasta dorar y quedar crujiente.','Sirve con salsa, queso y aguacate encima.'], TRUE),
  ('r744', 'General Tso''s Chicken Bowl', 'Bowl de Pollo General Tso', NULL, 826, 48, 100, 26, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','soy_sauce','garlic','honey','broccoli','sesame_oil','egg_whites'], ARRAY['Coat chicken chunks in a light egg-white and cornstarch batter.','Pan-fry until crisp and golden, about 6 minutes.','Simmer a sauce of soy, honey, garlic and chili until glossy, then toss the chicken to coat.','Serve over rice with steamed broccoli and sesame seeds.'], ARRAY['Cubre los trozos de pollo con una capa ligera de clara de huevo y maicena.','Frie hasta que esten crujientes y dorados, unos 6 minutos.','Cocina una salsa de soya, miel, ajo y chile hasta que brille, y bana el pollo.','Sirve sobre arroz con brocoli al vapor y ajonjoli.'], TRUE),
  ('r746', 'Gyudon Beef Rice Bowl', 'Bowl Japones de Res Gyudon', NULL, 803, 47, 102, 23, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['lean_beef','rice','onion','soy_sauce','eggs','honey','sesame_oil','garlic'], ARRAY['Simmer thin-sliced beef and onion in soy, honey and a little water for 8 minutes.','Let the beef soak up the sweet-savory sauce.','Pile it over a bowl of hot rice.','Top with a soft egg, green onion and a drizzle of sesame oil.'], ARRAY['Cocina la res en laminas finas y la cebolla en soya, miel y un poco de agua por 8 minutos.','Deja que la carne absorba la salsa agridulce.','Sirve sobre un bowl de arroz caliente.','Corona con un huevo suave, cebollin y un chorrito de aceite de sesamo.'], TRUE),
  ('r747', 'Hawaiian Loco Moco Bowl', 'Bowl Hawaiano Loco Moco', NULL, 846, 45, 90, 34, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['lean_beef','rice','eggs','onion','mushroom','garlic','soy_sauce','olive_oil'], ARRAY['Form seasoned beef into a thick patty and sear 3-4 minutes per side.','Make a brown gravy from the pan drippings with onion, mushroom and a splash of soy.','Fry an egg sunny-side up with a runny yolk.','Plate the patty over rice, smother with gravy and top with the egg.'], ARRAY['Forma una hamburguesa gruesa con la carne sazonada y sellala 3-4 minutos por lado.','Prepara una salsa oscura con los jugos del sarten, cebolla, champinon y un chorrito de soya.','Frie un huevo estrellado con la yema liquida.','Sirve la carne sobre arroz, bana con la salsa y corona con el huevo.'], TRUE),
  ('r748', 'Bibimbap Beef Rice Bowl', 'Bibimbap de Res en Bowl', NULL, 801, 48, 96, 25, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','rice','eggs','spinach','carrot','mushroom','soy_sauce','sesame_oil'], ARRAY['Marinate beef in soy, garlic and sesame oil, then sear 3 minutes.','Quickly saute separate piles of spinach, carrot and mushroom.','Arrange the beef and vegetables over rice in sections.','Top with a fried egg and a spoon of gochujang; mix before eating.'], ARRAY['Marina la res en soya, ajo y aceite de sesamo, luego sellala 3 minutos.','Saltea por separado la espinaca, la zanahoria y el champinon.','Acomoda la res y las verduras sobre el arroz en secciones.','Corona con un huevo frito y una cucharada de gochujang; mezcla antes de comer.'], TRUE),
  ('r749', 'Jerk Chicken Rice and Peas Bowl', 'Bowl de Pollo Jerk con Arroz y Habichuelas', NULL, 798, 50, 100, 22, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','black_beans','onion','garlic','bell_pepper','olive_oil','lime'], ARRAY['Rub chicken thighs with jerk seasoning and marinate 15 minutes.','Sear, then bake at 400F for 20 minutes until 175F.','Cook rice with kidney beans, a little coconut milk, garlic and thyme.','Serve the chicken over the rice and peas with a squeeze of lime.'], ARRAY['Unta los muslos con sazon jerk y marina 15 minutos.','Sellalos y hornea a 200C por 20 minutos hasta 80C.','Cocina el arroz con habichuelas, un poco de leche de coco, ajo y tomillo.','Sirve el pollo sobre el arroz con habichuelas y un chorrito de limon.'], TRUE),
  ('r750', 'Cajun Jambalaya with Chicken and Shrimp', 'Jambalaya Cajun con Pollo y Camaron', NULL, 792, 52, 92, 24, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','shrimp','rice','tomato','bell_pepper','onion','garlic','chorizo'], ARRAY['Brown the chicken and sausage in a heavy pot, then remove.','Cook the trinity of onion, pepper and celery with garlic and Cajun spice.','Add rice and tomato, return the meats, and simmer covered 18 minutes.','Stir in the shrimp for the last 4 minutes until pink.'], ARRAY['Dora el pollo y la salchicha en una olla pesada, luego retiralos.','Cocina la base de cebolla, pimiento y apio con ajo y sazon cajun.','Agrega arroz y tomate, regresa las carnes y cocina tapado 18 minutos.','Incorpora los camarones los ultimos 4 minutos hasta que esten rosados.'], TRUE),
  ('r751', 'Blackened Salmon Rice Bowl', 'Bowl de Salmon Ennegrecido con Arroz', NULL, 814, 48, 88, 30, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['salmon','rice','avocado','black_beans','corn','bell_pepper','lime','olive_oil'], ARRAY['Coat the salmon in Cajun blackening spice.','Sear in a hot cast-iron pan 3-4 minutes per side until charred and flaky.','Warm rice with lime and fold in black beans and corn.','Flake the salmon over the bowl and top with avocado and pepper.'], ARRAY['Cubre el salmon con especias cajun para ennegrecer.','Sellalo en un sarten de hierro caliente 3-4 minutos por lado hasta dorar y que se desmenuce.','Calienta el arroz con limon e incorpora frijoles negros y maiz.','Desmenuza el salmon sobre el bowl y corona con aguacate y pimiento.'], TRUE),
  ('r752', 'Firecracker Shrimp Rice Bowl', 'Bowl de Camarones Firecracker con Arroz', NULL, 782, 46, 100, 22, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['shrimp','rice','garlic','honey','soy_sauce','bell_pepper','onion','sesame_oil'], ARRAY['Sear the shrimp in a hot pan 2 minutes until pink, then remove.','Cook pepper and onion until crisp-tender.','Simmer a spicy sauce of chili, honey, garlic and soy until sticky.','Toss the shrimp back in to glaze; serve over rice with sesame oil.'], ARRAY['Sella los camarones en un sarten caliente 2 minutos hasta que esten rosados y retiralos.','Cocina el pimiento y la cebolla hasta que esten crujientes.','Cocina una salsa picante de chile, miel, ajo y soya hasta que quede pegajosa.','Regresa los camarones para glasear; sirve sobre arroz con aceite de sesamo.'], TRUE),
  ('r753', 'Beef and Broccoli Rice Bowl', 'Bowl de Res con Brocoli y Arroz', NULL, 796, 50, 95, 24, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['lean_beef','broccoli','rice','soy_sauce','garlic','sesame_oil','onion','honey'], ARRAY['Sear sliced beef in a hot wok until browned, 3 minutes, then remove.','Stir-fry broccoli and garlic with a splash of water until bright green.','Return the beef with a sauce of soy, honey and a little cornstarch slurry.','Toss until glossy and serve over rice with sesame oil.'], ARRAY['Sella la res en tiras en un wok caliente hasta dorar, 3 minutos, y retirala.','Saltea el brocoli y el ajo con un chorrito de agua hasta que esten verdes.','Regresa la carne con una salsa de soya, miel y un poco de maicena disuelta.','Mezcla hasta que brille y sirve sobre arroz con aceite de sesamo.'], TRUE),
  ('r754', 'Chicken Souvlaki Rice Bowl', 'Bowl de Pollo Souvlaki con Arroz', NULL, 794, 55, 85, 26, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Facil', 1, ARRAY['chicken_breast','rice','greek_yogurt','cucumber','tomato','onion','olive_oil','lemon'], ARRAY['Marinate chicken cubes in lemon, olive oil, garlic and oregano.','Thread on skewers and grill 8-10 minutes until charred and cooked.','Stir greek yogurt with grated cucumber and garlic for tzatziki.','Serve the chicken over rice with tomato, onion and the tzatziki.'], ARRAY['Marina los cubos de pollo en limon, aceite de oliva, ajo y oregano.','Ensartalos en pinchos y asalos 8-10 minutos hasta dorar y cocer.','Mezcla yogur griego con pepino rallado y ajo para el tzatziki.','Sirve el pollo sobre arroz con tomate, cebolla y el tzatziki.'], TRUE),
  ('r755', 'Beef Shepherd''s Pie', 'Pastel de Carne con Pure de Papa', NULL, 792, 48, 78, 32, 45, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','potato','carrot','onion','garlic','cheese','tomato','broccoli'], ARRAY['Brown beef with onion, carrot and garlic until cooked.','Stir in tomato paste and broth; simmer into a thick gravy.','Spread mashed potato over the meat and rough up the top with a fork.','Bake at 400F for 20 minutes until the top is golden.'], ARRAY['Dora la carne con cebolla, zanahoria y ajo hasta cocer.','Incorpora pasta de tomate y caldo; cocina hasta una salsa espesa.','Extiende el pure de papa sobre la carne y marca la superficie con un tenedor.','Hornea a 200C por 20 minutos hasta que la superficie este dorada.'], TRUE),
  ('r756', 'Million Dollar Baked Spaghetti', 'Espagueti al Horno Estilo Millonario', NULL, 830, 52, 88, 30, 45, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['pasta','lean_beef','tomato','cheese','cottage_cheese','garlic','onion','greek_yogurt'], ARRAY['Boil spaghetti and brown beef with onion and garlic in tomato sauce.','Mix cottage cheese, greek yogurt and a little cream cheese for the middle layer.','Layer half the pasta, the cheese mixture, then the rest of the pasta and meat sauce.','Top with mozzarella and bake at 375F for 25 minutes until bubbly.'], ARRAY['Hierve el espagueti y dora la carne con cebolla y ajo en salsa de tomate.','Mezcla queso cottage, yogur griego y un poco de queso crema para la capa del centro.','Coloca la mitad de la pasta, la mezcla de quesos, luego el resto de pasta y salsa de carne.','Cubre con mozzarella y hornea a 190C por 25 minutos hasta burbujear.'], TRUE),
  ('r757', 'French Dip Sandwich with Fries', 'Sandwich French Dip con Papas', NULL, 838, 50, 92, 30, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','whole_grain_bread','cheese','onion','garlic','potato','olive_oil','mushroom'], ARRAY['Sear thin roast beef and caramelize onions until deeply golden.','Simmer a quick au jus from beef broth, garlic and the pan drippings.','Pile beef and provolone on a toasted roll and melt under the broiler.','Bake fries at 425F for 20 minutes; serve the sandwich with au jus for dipping.'], ARRAY['Sella el rosbif fino y carameliza la cebolla hasta que este bien dorada.','Prepara un au jus rapido con caldo de res, ajo y los jugos del sarten.','Coloca la carne y el provolone en un pan tostado y gratina hasta derretir.','Hornea las papas a 220C por 20 minutos; sirve el sandwich con el au jus para mojar.'], TRUE),
  ('r758', 'Loaded Chili Cheese Fries Plate', 'Plato de Papas Fritas con Chili y Queso', NULL, 853, 46, 84, 37, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['potato','lean_beef','cheese','black_beans','tomato','onion','greek_yogurt','jalapeno'], ARRAY['Bake thick-cut fries at 425F for 25 minutes until crisp.','Simmer a quick beef chili with beans, tomato, onion and spices.','Pile the chili over the fries and blanket with shredded cheese.','Broil 3 minutes to melt; top with yogurt crema and jalapenos.'], ARRAY['Hornea las papas en bastones gruesos a 220C por 25 minutos hasta que esten crujientes.','Cocina un chili de res rapido con habichuelas, tomate, cebolla y especias.','Coloca el chili sobre las papas y cubrelas con queso rallado.','Gratina 3 minutos para derretir; corona con crema de yogur y jalapenos.'], TRUE),
  ('r759', 'Cuban Mojo Pork Bowl', 'Bowl de Cerdo Mojo Cubano', NULL, 822, 48, 90, 30, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['pork_shoulder','rice','black_beans','onion','garlic','lime','olive_oil','tomato'], ARRAY['Marinate pork in a mojo of citrus, garlic, cumin and oregano.','Roast at 350F until tender, then shred and crisp under the broiler.','Serve over rice with black beans.','Top with quick pickled onions and a squeeze of lime.'], ARRAY['Marina el cerdo en un mojo de citricos, ajo, comino y oregano.','Asa a 175C hasta que este suave, desmenuza y dora bajo el broiler.','Sirve sobre arroz con frijoles negros.','Corona con cebolla encurtida rapida y un chorrito de limon.'], TRUE),
  ('r760', 'Milanesa Torta Sandwich', 'Torta de Milanesa de Pollo', NULL, 868, 50, 95, 32, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','whole_grain_bread','cheese','avocado','tomato','lettuce','onion','eggs'], ARRAY['Pound chicken thin, bread in egg and breadcrumbs, and fry until golden, 3 minutes per side.','Toast a crusty roll and spread it with mashed avocado.','Layer the milanesa with cheese, tomato, lettuce and onion.','Press the torta closed and serve warm.'], ARRAY['Aplana el pollo fino, empanalo en huevo y pan rallado, y frie hasta dorar, 3 minutos por lado.','Tuesta un pan crujiente y untalo con aguacate machacado.','Coloca la milanesa con queso, tomate, lechuga y cebolla.','Cierra la torta presionando y sirvela caliente.'], TRUE),
  ('r761', 'Thai Peanut Chicken Noodle Bowl', 'Bowl Thai de Pollo con Maní', NULL, 830, 48, 92, 30, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','noodles','peanut_butter','soy_sauce','bell_pepper','garlic'], ARRAY['Cook noodles per package, then drain and set aside.','Whisk peanut butter, soy sauce and a splash of water into a smooth sauce.','Stir-fry sliced chicken breast and bell pepper with garlic over high heat for 6-7 minutes.','Toss noodles and sauce with the chicken and serve hot.'], ARRAY['Cocina los fideos según el paquete, escúrrelos y reserva.','Bate la mantequilla de maní, la salsa de soya y un chorrito de agua hasta lograr una salsa suave.','Saltea el pollo en tiras y el pimiento con ajo a fuego alto por 6-7 minutos.','Mezcla los fideos y la salsa con el pollo y sirve caliente.'], TRUE),
  ('r762', 'West African Peanut Chicken Stew', 'Estofado de Pollo con Maní Africano', NULL, 800, 50, 78, 32, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','peanut_butter','tomato','onion','sweet_potato','garlic'], ARRAY['Brown chicken thighs in a pot, then remove and set aside.','Saute onion and garlic, add diced tomato and cubed sweet potato.','Stir in peanut butter with 2 cups water and return the chicken.','Simmer covered for 25 minutes until thick and the sweet potato is tender.'], ARRAY['Dora los muslos de pollo en una olla, retíralos y reserva.','Sofríe la cebolla y el ajo, agrega el tomate picado y la batata en cubos.','Incorpora la mantequilla de maní con 2 tazas de agua y regresa el pollo.','Cocina a fuego lento tapado por 25 minutos hasta espesar y ablandar la batata.'], TRUE),
  ('r763', 'Kung Pao Chicken with Peanuts', 'Pollo Kung Pao con Maní', NULL, 800, 52, 85, 28, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','peanuts','rice','bell_pepper','soy_sauce','garlic'], ARRAY['Cook rice and keep warm.','Sear diced chicken breast in a hot wok for 5 minutes until golden.','Add bell pepper, garlic and peanuts; stir-fry 3 minutes.','Pour in soy sauce with a pinch of chili, toss 1 minute and serve over rice.'], ARRAY['Cocina el arroz y mantenlo caliente.','Sella el pollo en cubos en un wok caliente por 5 minutos hasta dorar.','Agrega el pimiento, el ajo y los maníes; saltea 3 minutos.','Añade la salsa de soya con una pizca de chile, mezcla 1 minuto y sirve sobre el arroz.'], TRUE),
  ('r764', 'Szechuan Peanut Beef Noodles', 'Fideos Szechuan de Res con Maní', NULL, 852, 46, 95, 32, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['lean_beef','noodles','peanut_butter','soy_sauce','sesame_oil','garlic'], ARRAY['Boil noodles until just tender, then drain.','Whisk peanut butter, soy sauce, sesame oil and water into a sauce.','Stir-fry beef strips with garlic over high heat for 4-5 minutes.','Toss noodles and beef in the peanut sauce and serve.'], ARRAY['Hierve los fideos hasta que estén tiernos y escurre.','Bate la mantequilla de maní, la salsa de soya, el aceite de sésamo y agua para la salsa.','Saltea las tiras de res con ajo a fuego alto por 4-5 minutos.','Mezcla los fideos y la res en la salsa de maní y sirve.'], TRUE),
  ('r765', 'Peanut Beef Satay Rice Bowl', 'Bowl de Res Satay con Maní', NULL, 822, 50, 88, 30, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['lean_beef','peanut_butter','rice','soy_sauce','bell_pepper','garlic'], ARRAY['Cook rice and set aside.','Grill seasoned beef strips 3-4 minutes per side.','Whisk peanut butter with soy sauce, garlic and water for satay sauce.','Serve beef and bell pepper over rice, drizzled with peanut sauce.'], ARRAY['Cocina el arroz y reserva.','Asa las tiras de res sazonadas 3-4 minutos por lado.','Bate la mantequilla de maní con salsa de soya, ajo y agua para la salsa satay.','Sirve la res y el pimiento sobre el arroz, rociado con salsa de maní.'], TRUE),
  ('r766', 'Gado-Gado Peanut Egg Plate', 'Plato Gado-Gado con Huevo y Maní', NULL, 772, 42, 70, 36, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['eggs','peanut_butter','potato','cucumber','spinach','carrot'], ARRAY['Boil eggs 9 minutes, then peel and halve.','Boil potato cubes and blanch carrot until tender.','Whisk peanut butter with warm water and a splash of soy for dressing.','Arrange eggs, potato, carrot, cucumber and spinach; pour peanut dressing over.'], ARRAY['Hierve los huevos 9 minutos, pélalos y córtalos por la mitad.','Hierve los cubos de papa y blanquea la zanahoria hasta que estén tiernos.','Bate la mantequilla de maní con agua tibia y un chorrito de soya para el aderezo.','Acomoda huevos, papa, zanahoria, pepino y espinaca; vierte el aderezo de maní encima.'], TRUE),
  ('r767', 'Almond Butter Protein Waffles', 'Waffles Proteicos de Almendra', NULL, 784, 45, 88, 28, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['oats','egg_whites','protein_powder','almond_butter','banana','honey'], ARRAY['Blend oats, egg whites, protein powder and banana into a batter.','Cook in a hot waffle iron for 4-5 minutes until crisp.','Top with almond butter and a drizzle of honey.'], ARRAY['Licúa la avena, las claras, la proteína y el guineo hasta formar una masa.','Cocina en una wafflera caliente por 4-5 minutos hasta que estén crujientes.','Cubre con mantequilla de almendra y un chorrito de miel.'], TRUE),
  ('r768', 'Chocolate Peanut Butter Protein Pancakes', 'Panqueques Proteicos de Maní y Chocolate', NULL, 774, 44, 82, 30, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','peanut_butter','eggs','banana','honey'], ARRAY['Blend oats, chocolate protein powder, eggs and banana until smooth.','Cook pancakes on a greased skillet 2 minutes per side.','Stack and spread peanut butter between the layers.','Drizzle with honey and serve warm.'], ARRAY['Licúa la avena, la proteína de chocolate, los huevos y el guineo hasta suavizar.','Cocina los panqueques en un sartén engrasado 2 minutos por lado.','Apila y unta mantequilla de maní entre las capas.','Rocía con miel y sirve caliente.'], TRUE),
  ('r769', 'Cashew Chicken Stir-Fry with Rice', 'Salteado de Pollo con Marañón y Arroz', NULL, 786, 48, 90, 26, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','cashews','rice','bell_pepper','soy_sauce','garlic'], ARRAY['Cook rice and keep warm.','Sear diced chicken breast in a hot wok 5-6 minutes.','Add bell pepper, garlic and cashews; stir-fry 3 minutes.','Splash in soy sauce, toss and serve over rice.'], ARRAY['Cocina el arroz y mantenlo caliente.','Sella el pollo en cubos en un wok caliente 5-6 minutos.','Agrega el pimiento, el ajo y los marañones; saltea 3 minutos.','Añade salsa de soya, mezcla y sirve sobre el arroz.'], TRUE),
  ('r770', 'Peanut Ginger Pork Rice Bowl', 'Bowl de Cerdo con Maní y Jengibre', NULL, 816, 46, 86, 32, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['pork','peanut_butter','rice','soy_sauce','ginger','bell_pepper'], ARRAY['Cook rice and set aside.','Stir-fry ground pork with garlic and grated ginger for 6 minutes.','Stir in peanut butter and soy sauce with a splash of water.','Add bell pepper, cook 2 minutes and serve over rice.'], ARRAY['Cocina el arroz y reserva.','Saltea la carne de cerdo con ajo y jengibre rallado por 6 minutos.','Incorpora la mantequilla de maní y la salsa de soya con un chorrito de agua.','Agrega el pimiento, cocina 2 minutos y sirve sobre el arroz.'], TRUE),
  ('r771', 'Almond-Crusted Chicken and Sweet Potato', 'Pollo con Costra de Almendra y Batata', NULL, 748, 52, 72, 28, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','almonds','sweet_potato','eggs','broccoli','olive_oil'], ARRAY['Preheat oven to 200C (400F).','Dip chicken breast in beaten egg, then press into crushed almonds.','Bake chicken and cubed sweet potato tossed in olive oil for 25 minutes.','Steam broccoli and serve alongside.'], ARRAY['Precalienta el horno a 200C (400F).','Pasa la pechuga por huevo batido y presiónala en almendras trituradas.','Hornea el pollo y la batata en cubos con aceite de oliva por 25 minutos.','Cocina el brócoli al vapor y sirve al lado.'], TRUE),
  ('r772', 'Spicy Peanut Shrimp Noodles', 'Fideos Picantes de Camarón y Maní', NULL, 806, 44, 90, 30, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['shrimp','noodles','peanut_butter','soy_sauce','bell_pepper','garlic'], ARRAY['Cook noodles until tender and drain.','Whisk peanut butter, soy sauce, water and chili flakes into a sauce.','Saute shrimp with garlic and bell pepper for 3-4 minutes until pink.','Toss noodles and shrimp in the spicy peanut sauce and serve.'], ARRAY['Cocina los fideos hasta que estén tiernos y escurre.','Bate la mantequilla de maní, la salsa de soya, agua y hojuelas de chile.','Saltea los camarones con ajo y pimiento por 3-4 minutos hasta que estén rosados.','Mezcla los fideos y los camarones en la salsa de maní picante y sirve.'], TRUE),
  ('r773', 'Peanut Butter Protein Mug Cake Bowl', 'Mug Cake Proteico de Maní', NULL, 714, 45, 75, 26, 8, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','peanut_butter','egg_whites','banana','honey'], ARRAY['Mash banana and mix with oats, protein powder, egg whites and peanut butter.','Microwave in a large mug or bowl for 90 seconds.','Drizzle with honey and eat warm.'], ARRAY['Machaca el guineo y mézclalo con avena, proteína, claras y mantequilla de maní.','Cocina en microondas en una taza grande o bol por 90 segundos.','Rocía con miel y come caliente.'], TRUE),
  ('r774', 'Chicken and Sausage Gumbo', 'Gumbo de Pollo y Salchicha', NULL, 790, 50, 80, 30, 45, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Hard', 'Difícil', 1, ARRAY['chicken_thigh','sausage','rice','bell_pepper','onion','tomato'], ARRAY['Brown sliced sausage and diced chicken thigh in a large pot.','Saute onion and bell pepper with the drippings until soft.','Add diced tomato and 2 cups water; simmer 20 minutes.','Serve the gumbo over cooked rice.'], ARRAY['Dora la salchicha en rodajas y el muslo de pollo en cubos en una olla grande.','Sofríe la cebolla y el pimiento con la grasa hasta ablandar.','Agrega el tomate picado y 2 tazas de agua; cocina a fuego lento 20 minutos.','Sirve el gumbo sobre arroz cocido.'], TRUE),
  ('r775', 'Beef and Black Bean Chili Mac', 'Chili Mac de Res y Frijoles Negros', NULL, 824, 48, 95, 28, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','black_beans','pasta','tomato','cheese','onion'], ARRAY['Cook pasta until al dente and drain.','Brown lean beef with onion in a pot for 6 minutes.','Add black beans and diced tomato; simmer 10 minutes with chili spices.','Stir in pasta and cheese until melted, then serve.'], ARRAY['Cocina la pasta al dente y escurre.','Dora la carne de res con cebolla en una olla por 6 minutos.','Agrega los frijoles negros y el tomate picado; cocina 10 minutos con especias de chili.','Incorpora la pasta y el queso hasta derretir y sirve.'], TRUE),
  ('r776', 'Coconut Chicken Korma with Rice', 'Korma de Pollo al Coco con Arroz', NULL, 846, 47, 88, 34, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','coconut_milk','rice','onion','garlic','tomato'], ARRAY['Cook rice and keep warm.','Saute onion and garlic, then add diced chicken breast and brown 5 minutes.','Stir in diced tomato and coconut milk with korma spices.','Simmer 15 minutes until creamy and serve over rice.'], ARRAY['Cocina el arroz y mantenlo caliente.','Sofríe la cebolla y el ajo, agrega el pollo en cubos y dora 5 minutos.','Incorpora el tomate picado y la leche de coco con especias korma.','Cocina a fuego lento 15 minutos hasta que esté cremoso y sirve sobre el arroz.'], TRUE),
  ('r777', 'Moroccan Beef and Chickpea Tagine', 'Tagine de Res y Garbanzos', NULL, 814, 46, 90, 30, 45, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','chickpeas','tomato','onion','sweet_potato','garlic'], ARRAY['Brown lean beef cubes with onion and garlic in a pot.','Add chickpeas, diced tomato and cubed sweet potato.','Season with cumin and cinnamon, then add 2 cups water.','Simmer covered 30 minutes until the beef is tender.'], ARRAY['Dora los cubos de res con cebolla y ajo en una olla.','Agrega los garbanzos, el tomate picado y la batata en cubos.','Sazona con comino y canela, luego añade 2 tazas de agua.','Cocina tapado a fuego lento 30 minutos hasta que la res esté tierna.'], TRUE),
  ('r778', 'Thai Green Chicken Curry Bowl', 'Bowl de Curry Verde Thai de Pollo', NULL, 820, 48, 85, 32, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','coconut_milk','rice','green_curry_paste','bell_pepper','spinach'], ARRAY['Cook rice and set aside.','Fry green curry paste in a pan for 1 minute until fragrant.','Add diced chicken thigh and brown, then pour in coconut milk.','Add bell pepper and spinach; simmer 12 minutes and serve over rice.'], ARRAY['Cocina el arroz y reserva.','Sofríe la pasta de curry verde en un sartén por 1 minuto hasta que suelte aroma.','Agrega el muslo de pollo en cubos y dora, luego vierte la leche de coco.','Añade el pimiento y la espinaca; cocina 12 minutos y sirve sobre el arroz.'], TRUE),
  ('r779', 'Irish Beef and Potato Stew', 'Estofado Irlandés de Res y Papa', NULL, 798, 50, 82, 30, 55, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','potato','carrot','onion','tomato','garlic'], ARRAY['Brown lean beef cubes in a pot, then remove.','Saute onion, carrot and garlic for 5 minutes.','Return beef with diced tomato, potato and 2 cups water.','Simmer covered 40 minutes until the beef is fork-tender.'], ARRAY['Dora los cubos de res en una olla y retíralos.','Sofríe la cebolla, la zanahoria y el ajo por 5 minutos.','Regresa la res con el tomate picado, la papa y 2 tazas de agua.','Cocina tapado a fuego lento 40 minutos hasta que la res esté muy tierna.'], TRUE),
  ('r780', 'Jamaican Curry Chicken with Rice', 'Pollo al Curry Jamaicano con Arroz', NULL, 798, 49, 92, 26, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','kidney_beans','onion','garlic','curry_powder'], ARRAY['Season chicken thighs with curry powder and brown in a pot.','Saute onion and garlic, then add 2 cups water.','Simmer chicken 25 minutes until tender.','Stir in kidney beans, warm through and serve over rice.'], ARRAY['Sazona los muslos de pollo con curry en polvo y dóralos en una olla.','Sofríe la cebolla y el ajo, luego agrega 2 tazas de agua.','Cocina el pollo a fuego lento 25 minutos hasta que esté tierno.','Incorpora los frijoles rojos, calienta y sirve sobre el arroz.'], TRUE),
  ('r781', 'Turkey and White Bean Chili', 'Chili de Pavo y Frijoles Blancos', NULL, 736, 52, 78, 24, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','white_beans','tomato','onion','bell_pepper','garlic'], ARRAY['Brown ground turkey with onion and garlic for 6 minutes.','Add bell pepper, white beans and diced tomato.','Season with cumin and chili powder, then add 1 cup water.','Simmer 20 minutes until thick and serve.'], ARRAY['Dora el pavo molido con cebolla y ajo por 6 minutos.','Agrega el pimiento, los frijoles blancos y el tomate picado.','Sazona con comino y chile en polvo, luego añade 1 taza de agua.','Cocina a fuego lento 20 minutos hasta espesar y sirve.'], TRUE),
  ('r782', 'Goan Coconut Shrimp Curry', 'Curry de Camarón al Coco (Goa)', NULL, 822, 44, 85, 34, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['shrimp','coconut_milk','rice','tomato','onion','garlic'], ARRAY['Cook rice and keep warm.','Saute onion and garlic, then add diced tomato.','Pour in coconut milk with curry spices and bring to a simmer.','Add shrimp and cook 5 minutes until pink; serve over rice.'], ARRAY['Cocina el arroz y mantenlo caliente.','Sofríe la cebolla y el ajo, luego agrega el tomate picado.','Vierte la leche de coco con especias de curry y lleva a fuego lento.','Agrega los camarones y cocina 5 minutos hasta que estén rosados; sirve sobre el arroz.'], TRUE),
  ('r783', 'Beef Rendang with Jasmine Rice', 'Rendang de Res con Arroz Jazmín', NULL, 850, 48, 88, 34, 75, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Hard', 'Difícil', 1, ARRAY['lean_beef','coconut_milk','rice','onion','garlic','ginger'], ARRAY['Cook rice and set aside.','Blend onion, garlic and ginger into a paste and fry 2 minutes.','Add lean beef cubes and coconut milk with rendang spices.','Simmer uncovered 60 minutes until the sauce is dark and thick.','Serve the rendang over jasmine rice.'], ARRAY['Cocina el arroz y reserva.','Licúa la cebolla, el ajo y el jengibre en una pasta y sofríe 2 minutos.','Agrega los cubos de res y la leche de coco con especias rendang.','Cocina destapado a fuego lento 60 minutos hasta que la salsa esté oscura y espesa.','Sirve el rendang sobre el arroz jazmín.'], TRUE),
  ('r784', 'Red Lentil Dhal with Spiced Beef', 'Dhal de Lentejas con Res Especiada', NULL, 796, 46, 90, 28, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lentils','lean_beef','tomato','onion','garlic','rice'], ARRAY['Cook rice and keep warm.','Simmer lentils with diced tomato and 2 cups water for 20 minutes.','Brown lean beef with onion, garlic and warm spices.','Stir the spiced beef into the dhal and serve over rice.'], ARRAY['Cocina el arroz y mantenlo caliente.','Cocina las lentejas con tomate picado y 2 tazas de agua por 20 minutos.','Dora la carne de res con cebolla, ajo y especias.','Incorpora la res especiada al dhal y sirve sobre el arroz.'], TRUE),
  ('r785', 'Ethiopian Berbere Beef Stew', 'Estofado Etíope de Res Berbere', NULL, 808, 50, 80, 32, 45, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lean_beef','berbere','tomato','onion','potato','garlic'], ARRAY['Saute onion and garlic in a pot until soft.','Add lean beef cubes and berbere spice, browning 5 minutes.','Stir in diced tomato, potato and 2 cups water.','Simmer covered 35 minutes until the beef is tender.'], ARRAY['Sofríe la cebolla y el ajo en una olla hasta ablandar.','Agrega los cubos de res y la especia berbere, dorando 5 minutos.','Incorpora el tomate picado, la papa y 2 tazas de agua.','Cocina tapado a fuego lento 35 minutos hasta que la res esté tierna.'], TRUE),
  ('r786', 'Chorizo and Chickpea Stew', 'Estofado de Chorizo y Garbanzos', NULL, 814, 45, 82, 34, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chorizo','chickpeas','tomato','onion','spinach','garlic'], ARRAY['Brown sliced chorizo in a pot to release the oil.','Saute onion and garlic in the chorizo oil.','Add chickpeas and diced tomato; simmer 15 minutes.','Stir in spinach until wilted and serve.'], ARRAY['Dora el chorizo en rodajas en una olla para soltar el aceite.','Sofríe la cebolla y el ajo en el aceite del chorizo.','Agrega los garbanzos y el tomate picado; cocina 15 minutos.','Incorpora la espinaca hasta marchitar y sirve.'], TRUE),
  ('r787', 'Cajun Red Beans and Rice with Sausage', 'Frijoles Rojos y Arroz con Salchicha', NULL, 820, 44, 98, 28, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['sausage','kidney_beans','rice','bell_pepper','onion','garlic'], ARRAY['Cook rice and keep warm.','Brown sliced sausage with onion, bell pepper and garlic.','Add kidney beans with 1 cup water and Cajun seasoning.','Simmer 20 minutes until creamy and serve over rice.'], ARRAY['Cocina el arroz y mantenlo caliente.','Dora la salchicha en rodajas con cebolla, pimiento y ajo.','Agrega los frijoles rojos con 1 taza de agua y sazón cajún.','Cocina a fuego lento 20 minutos hasta que esté cremoso y sirve sobre el arroz.'], TRUE),
  ('r788', 'Loaded Chorizo Breakfast Burrito', 'Burrito de Desayuno con Chorizo', NULL, 828, 46, 80, 36, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['eggs','chorizo','tortilla','potato','cheese','salsa'], ARRAY['Cook diced potato until crisp, then set aside.','Brown chorizo, then scramble the eggs into the pan.','Warm the tortilla and layer eggs, chorizo, potato and cheese.','Roll up tightly and top with salsa.'], ARRAY['Cocina la papa en cubos hasta que esté crujiente y reserva.','Dora el chorizo, luego revuelve los huevos en el sartén.','Calienta la tortilla y coloca huevos, chorizo, papa y queso.','Enrolla apretado y cubre con salsa.'], TRUE),
  ('r789', 'Sweet Potato Sausage Breakfast Hash', 'Hash de Batata y Salchicha', NULL, 794, 44, 78, 34, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['sausage','sweet_potato','eggs','bell_pepper','onion','spinach'], ARRAY['Pan-fry cubed sweet potato until tender, about 12 minutes.','Add sliced sausage, bell pepper and onion; cook 6 minutes.','Make wells and crack in the eggs, cover and cook 4 minutes.','Fold in spinach until wilted and serve.'], ARRAY['Fríe la batata en cubos hasta que esté tierna, unos 12 minutos.','Agrega la salchicha en rodajas, el pimiento y la cebolla; cocina 6 minutos.','Haz huecos y casca los huevos, tapa y cocina 4 minutos.','Incorpora la espinaca hasta marchitar y sirve.'], TRUE),
  ('r790', 'Cinnamon Roll Protein French Toast', 'Tostada Francesa Proteica de Canela', NULL, 792, 45, 90, 28, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['whole_grain_bread','eggs','protein_powder','cinnamon','honey','greek_yogurt'], ARRAY['Whisk eggs with protein powder and cinnamon into a custard.','Soak whole grain bread slices in the custard.','Cook on a greased skillet 2-3 minutes per side.','Top with a swirl of Greek yogurt and honey.'], ARRAY['Bate los huevos con proteína y canela para formar una mezcla.','Remoja las rebanadas de pan integral en la mezcla.','Cocina en un sartén engrasado 2-3 minutos por lado.','Cubre con un remolino de yogur griego y miel.'], TRUE),
  ('r791', 'Denver Omelette Breakfast Bowl', 'Bowl de Omelette Denver', NULL, 770, 48, 68, 34, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['eggs','ham','cheese','bell_pepper','onion','potato'], ARRAY['Pan-fry diced potato until golden, then set aside.','Saute ham, bell pepper and onion for 4 minutes.','Pour in beaten eggs and scramble until just set.','Top with cheese and the potato, then serve in a bowl.'], ARRAY['Fríe la papa en cubos hasta dorar y reserva.','Sofríe el jamón, el pimiento y la cebolla por 4 minutos.','Vierte los huevos batidos y revuelve hasta cuajar.','Cubre con queso y la papa, y sirve en un bol.'], TRUE),
  ('r792', 'Blueberry Protein Pancake Stack', 'Torre de Panqueques Proteicos con Berries', NULL, 786, 46, 92, 26, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','eggs','berries','banana','honey'], ARRAY['Blend oats, protein powder, eggs and banana into a batter.','Fold in berries and cook pancakes 2 minutes per side.','Stack the pancakes high.','Drizzle with honey and serve.'], ARRAY['Licúa la avena, la proteína, los huevos y el guineo en una masa.','Incorpora las berries y cocina los panqueques 2 minutos por lado.','Apila los panqueques bien altos.','Rocía con miel y sirve.'], TRUE),
  ('r793', 'Ham and Cheese Breakfast Quesadilla', 'Quesadilla de Desayuno con Jamón', NULL, 782, 47, 72, 34, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['eggs','ham','cheese','tortilla','bell_pepper','salsa'], ARRAY['Scramble eggs with diced bell pepper until just set.','Layer ham, cheese and eggs on half a tortilla.','Fold and cook in a dry pan 2 minutes per side until crisp.','Cut into wedges and serve with salsa.'], ARRAY['Revuelve los huevos con pimiento picado hasta cuajar.','Coloca jamón, queso y huevos en la mitad de una tortilla.','Dobla y cocina en un sartén seco 2 minutos por lado hasta dorar.','Corta en triángulos y sirve con salsa.'], TRUE),
  ('r794', 'Bacon Egg and Cheese Bagel Stack', 'Bagel de Tocino, Huevo y Queso', NULL, 794, 44, 78, 34, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['eggs','bacon','cheese','bagel','avocado'], ARRAY['Cook bacon until crisp, then set aside.','Fry the eggs to your liking in the bacon fat.','Toast the bagel halves.','Stack bacon, eggs, cheese and sliced avocado on the bagel.'], ARRAY['Cocina el tocino hasta que esté crujiente y reserva.','Fríe los huevos a tu gusto en la grasa del tocino.','Tuesta las mitades del bagel.','Apila tocino, huevos, queso y aguacate en rodajas en el bagel.'], TRUE),
  ('r795', 'Huevos Rancheros Power Plate', 'Plato de Huevos Rancheros', NULL, 784, 42, 82, 32, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['eggs','black_beans','tortilla','salsa','cheese','avocado'], ARRAY['Warm black beans in a pan with a pinch of cumin.','Fry the eggs sunny-side up.','Warm the tortillas and top with beans and eggs.','Spoon over salsa, then add cheese and sliced avocado.'], ARRAY['Calienta los frijoles negros en un sartén con una pizca de comino.','Fríe los huevos estrellados.','Calienta las tortillas y cubre con frijoles y huevos.','Agrega salsa, luego queso y aguacate en rodajas.'], TRUE),
  ('r796', 'Shakshuka with Crusty Bread', 'Shakshuka con Pan Crujiente', NULL, 766, 40, 75, 34, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['eggs','tomato','bell_pepper','onion','whole_grain_bread','garlic'], ARRAY['Saute onion, bell pepper and garlic until soft.','Add diced tomato and simmer into a thick sauce, 10 minutes.','Make wells and crack in the eggs; cover and cook 6 minutes.','Serve straight from the pan with whole grain bread.'], ARRAY['Sofríe la cebolla, el pimiento y el ajo hasta ablandar.','Agrega el tomate picado y cocina hasta espesar, 10 minutos.','Haz huecos y casca los huevos; tapa y cocina 6 minutos.','Sirve directo del sartén con pan integral.'], TRUE),
  ('r797', 'Turkey Sausage Breakfast Skillet', 'Sartén de Salchicha de Pavo', NULL, 742, 48, 70, 30, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','potato','eggs','bell_pepper','onion','cheese'], ARRAY['Pan-fry diced potato until golden, about 12 minutes.','Add ground turkey with onion and bell pepper; brown 6 minutes.','Make wells and crack in the eggs; cover and cook 4 minutes.','Top with cheese and serve from the skillet.'], ARRAY['Fríe la papa en cubos hasta dorar, unos 12 minutos.','Agrega el pavo molido con cebolla y pimiento; dora 6 minutos.','Haz huecos y casca los huevos; tapa y cocina 4 minutos.','Cubre con queso y sirve del sartén.'], TRUE),
  ('r798', 'Kimchi Breakfast Fried Rice', 'Arroz Frito de Desayuno con Kimchi', NULL, 780, 44, 88, 28, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['rice','kimchi','eggs','soy_sauce','sesame_oil','spinach'], ARRAY['Stir-fry chopped kimchi in sesame oil for 2 minutes.','Add cooked rice and soy sauce, frying 4 minutes.','Push aside and scramble the eggs into the pan.','Fold in spinach and the eggs with the rice and serve.'], ARRAY['Saltea el kimchi picado en aceite de sésamo por 2 minutos.','Agrega el arroz cocido y la salsa de soya, friendo 4 minutos.','Aparta y revuelve los huevos en el sartén.','Mezcla la espinaca y los huevos con el arroz y sirve.'], TRUE),
  ('r799', 'Savory Protein Oatmeal with Eggs', 'Avena Salada con Huevos', NULL, 738, 46, 80, 26, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['oats','eggs','cheese','spinach','egg_whites'], ARRAY['Cook oats with water until creamy, about 5 minutes.','Stir in egg whites and cheese until the oatmeal thickens.','Fry or poach the eggs and set on top.','Fold in spinach and serve savory and hot.'], ARRAY['Cocina la avena con agua hasta que esté cremosa, unos 5 minutos.','Incorpora las claras y el queso hasta espesar la avena.','Fríe o escalfa los huevos y colócalos encima.','Agrega la espinaca y sirve salada y caliente.'], TRUE),
  ('r800', 'Chicken Chilaquiles with Eggs', 'Chilaquiles de Pollo con Huevos', NULL, 800, 50, 78, 32, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','eggs','tortilla','salsa','cheese','black_beans'], ARRAY['Simmer shredded chicken breast in salsa for 5 minutes.','Cut tortillas into wedges and toast until crisp.','Toss the tortillas in the salsa with black beans.','Top with fried eggs and cheese, then serve.'], ARRAY['Cocina el pollo desmenuzado en salsa por 5 minutos.','Corta las tortillas en triángulos y tuéstalas hasta dorar.','Mezcla las tortillas en la salsa con los frijoles negros.','Cubre con huevos fritos y queso, y sirve.'], TRUE),
  ('r801', 'Chicken Caesar Wrap', 'Wrap de Pollo César', NULL, 440, 40, 34, 16, 8, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['tortilla','chicken_breast','lettuce','cheese','greek_yogurt','lemon'], ARRAY['Stir 3 tbsp greek yogurt with a squeeze of lemon and grated cheese for a quick Caesar dressing.','Toss chopped romaine and sliced cooked chicken breast in the dressing.','Pile onto a tortilla, roll tightly, and slice in half.'], ARRAY['Mezcla 3 cucharadas de yogur griego con un chorrito de limón y queso rallado para un aderezo César rápido.','Revuelve la lechuga romana picada y el pollo cocido en rebanadas con el aderezo.','Coloca sobre una tortilla, enrolla apretado y corta a la mitad.'], TRUE),
  ('r802', 'Buffalo Chicken Quesadilla', 'Quesadilla de Pollo Búfalo', NULL, 474, 42, 36, 18, 10, 'Quick', 'Rápido', 'quick_meals', 'Medium', 'Medio', 1, ARRAY['tortilla','chicken_breast','cheese','salsa','greek_yogurt'], ARRAY['Toss shredded cooked chicken with 2 tbsp hot salsa.','Lay chicken and cheese on half a tortilla, fold over.','Toast in a dry pan over medium heat 2 minutes per side until golden.','Slice into wedges and serve with greek yogurt for dipping.'], ARRAY['Mezcla el pollo cocido desmenuzado con 2 cucharadas de salsa picante.','Coloca el pollo y el queso sobre media tortilla y dóblala.','Tuesta en un sartén seco a fuego medio 2 minutos por lado hasta dorar.','Corta en triángulos y sirve con yogur griego para mojar.'], TRUE),
  ('r803', 'Spicy Tuna Salad Wrap', 'Wrap de Atún Picante', NULL, 375, 36, 33, 11, 7, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['tortilla','canned_tuna','greek_yogurt','salsa','lettuce'], ARRAY['Drain the canned tuna and mix with 2 tbsp greek yogurt and a spoon of salsa.','Spread over a tortilla and top with shredded lettuce.','Roll up tightly and cut in half.'], ARRAY['Escurre el atún de lata y mézclalo con 2 cucharadas de yogur griego y una cucharada de salsa.','Extiéndelo sobre una tortilla y cubre con lechuga picada.','Enrolla bien apretado y corta a la mitad.'], TRUE),
  ('r804', 'Turkey Hummus Wrap', 'Wrap de Pavo y Hummus', NULL, 396, 34, 38, 12, 6, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['tortilla','turkey_breast','hummus','spinach','tomato','cucumber'], ARRAY['Spread 3 tbsp hummus across a tortilla.','Layer deli turkey breast, spinach, sliced tomato and cucumber.','Roll tightly and slice on the diagonal.'], ARRAY['Unta 3 cucharadas de hummus sobre una tortilla.','Acomoda el pavo, la espinaca, el tomate y el pepino en rebanadas.','Enrolla apretado y corta en diagonal.'], TRUE),
  ('r805', 'Black Bean & Cheese Quesadilla', 'Quesadilla de Frijoles y Queso', NULL, 436, 28, 45, 16, 9, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['tortilla','black_beans','cheese','salsa','bell_pepper'], ARRAY['Mash half a cup of black beans and spread over a tortilla.','Top with cheese and diced bell pepper, then fold.','Toast in a dry pan 2 minutes per side until cheese melts.','Cut into wedges and serve with salsa.'], ARRAY['Machaca media taza de frijoles negros y extiéndela sobre una tortilla.','Cubre con queso y pimiento en cubitos, luego dobla.','Tuesta en un sartén seco 2 minutos por lado hasta que el queso se derrita.','Corta en triángulos y sirve con salsa.'], TRUE),
  ('r806', 'Shrimp Avocado Wrap', 'Wrap de Camarón y Aguacate', NULL, 386, 33, 32, 14, 8, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['tortilla','shrimp','avocado','lettuce','lemon','salsa'], ARRAY['Toss cooked, chilled shrimp with a squeeze of lemon and a spoon of salsa.','Mash avocado onto a tortilla and add shredded lettuce.','Add the shrimp, roll tightly, and halve.'], ARRAY['Mezcla los camarones cocidos y fríos con un chorrito de limón y una cucharada de salsa.','Machaca aguacate sobre una tortilla y añade lechuga picada.','Agrega los camarones, enrolla apretado y corta a la mitad.'], TRUE),
  ('r807', 'Egg & Cheese Breakfast Wrap', 'Wrap de Huevo y Queso', NULL, 393, 30, 30, 17, 8, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['tortilla','eggs','egg_whites','cheese','spinach','salsa'], ARRAY['Scramble 1 egg plus 3 egg whites with a handful of spinach over medium heat.','Sprinkle cheese on top and let it melt.','Spoon onto a tortilla, add salsa, and roll up.'], ARRAY['Revuelve 1 huevo con 3 claras y un puñado de espinaca a fuego medio.','Espolvorea queso encima y deja que se derrita.','Coloca sobre una tortilla, añade salsa y enrolla.'], TRUE),
  ('r808', 'Chicken Fajita Quesadilla', 'Quesadilla de Pollo a la Fajita', NULL, 465, 41, 37, 17, 12, 'Quick', 'Rápido', 'quick_meals', 'Medium', 'Medio', 1, ARRAY['tortilla','chicken_breast','cheese','bell_pepper','onion'], ARRAY['Sauté sliced bell pepper and onion in a hot pan for 3 minutes.','Add sliced cooked chicken to warm through.','Fill a folded tortilla with the mix and cheese.','Toast 2 minutes per side and slice into wedges.'], ARRAY['Saltea el pimiento y la cebolla en rebanadas en un sartén caliente por 3 minutos.','Agrega el pollo cocido en tiras para calentar.','Rellena una tortilla doblada con la mezcla y el queso.','Tuesta 2 minutos por lado y corta en triángulos.'], TRUE),
  ('r809', 'BBQ Chicken Ranch Wrap', 'Wrap de Pollo BBQ y Ranch', NULL, 455, 40, 40, 15, 8, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['tortilla','chicken_breast','cheese','greek_yogurt','lettuce','onion'], ARRAY['Toss shredded chicken with 2 tbsp barbecue sauce.','Whisk greek yogurt with a pinch of garlic and onion for quick ranch.','Layer chicken, cheese, lettuce and ranch on a tortilla.','Roll tightly and slice in half.'], ARRAY['Mezcla el pollo desmenuzado con 2 cucharadas de salsa barbacoa.','Bate el yogur griego con una pizca de ajo y cebolla para un ranch rápido.','Acomoda el pollo, el queso, la lechuga y el ranch sobre una tortilla.','Enrolla apretado y corta a la mitad.'], TRUE),
  ('r810', 'Southwest Turkey Quesadilla', 'Quesadilla de Pavo Suroeste', NULL, 448, 38, 38, 16, 11, 'Quick', 'Rápido', 'quick_meals', 'Medium', 'Medio', 1, ARRAY['tortilla','ground_turkey','cheese','black_beans','salsa'], ARRAY['Brown ground turkey with a spoon of salsa in a hot pan, 5 minutes.','Stir in black beans to warm through.','Fill a folded tortilla with the mix and cheese.','Toast 2 minutes per side and cut into wedges.'], ARRAY['Dora el pavo molido con una cucharada de salsa en un sartén caliente, 5 minutos.','Agrega los frijoles negros para calentar.','Rellena una tortilla doblada con la mezcla y el queso.','Tuesta 2 minutos por lado y corta en triángulos.'], TRUE),
  ('r811', 'Tuna Poke Bowl', 'Bowl Poke de Atún', NULL, 440, 38, 45, 12, 9, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','rice','avocado','cucumber','soy_sauce','sesame_oil'], ARRAY['Warm a cup of microwave rice and spoon into a bowl.','Toss drained tuna with soy sauce and a few drops of sesame oil.','Top the rice with tuna, sliced avocado and cucumber.'], ARRAY['Calienta una taza de arroz de microondas y ponlo en un bowl.','Mezcla el atún escurrido con salsa de soya y unas gotas de aceite de sésamo.','Cubre el arroz con el atún, el aguacate y el pepino en rebanadas.'], TRUE),
  ('r813', 'Tuna & Black Bean Power Bowl', 'Bowl de Atún y Frijoles Negros', NULL, 436, 40, 42, 12, 7, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','black_beans','corn','tomato','avocado','lemon'], ARRAY['Rinse black beans and corn, then add to a bowl.','Flake in drained tuna and add diced tomato and avocado.','Squeeze lemon over the top and toss gently.'], ARRAY['Enjuaga los frijoles negros y el maíz, y ponlos en un bowl.','Desmenuza el atún escurrido y añade el tomate y el aguacate en cubos.','Exprime limón por encima y mezcla con cuidado.'], TRUE),
  ('r815', 'Salmon Avocado Quinoa Bowl', 'Bowl de Salmón, Aguacate y Quinoa', NULL, 449, 34, 40, 17, 9, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['canned_salmon','quinoa','avocado','spinach','lemon','olive_oil'], ARRAY['Warm a cup of cooked quinoa and toss with baby spinach until wilted.','Flake in drained canned salmon and add sliced avocado.','Dress with lemon juice and a drizzle of olive oil.'], ARRAY['Calienta una taza de quinoa cocida y mézclala con espinaca hasta marchitar.','Desmenuza el salmón de lata escurrido y añade aguacate en rebanadas.','Adereza con jugo de limón y un chorrito de aceite de oliva.'], TRUE),
  ('r816', 'Curry Chicken Salad Bowl', 'Bowl de Ensalada de Pollo al Curry', NULL, 408, 38, 28, 16, 8, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','greek_yogurt','carrot','lettuce','lemon'], ARRAY['Mix greek yogurt with a teaspoon of curry powder and a squeeze of lemon.','Fold in diced cooked chicken and grated carrot.','Serve over a bed of chopped lettuce.'], ARRAY['Mezcla el yogur griego con una cucharadita de curry en polvo y un chorrito de limón.','Incorpora el pollo cocido en cubos y la zanahoria rallada.','Sirve sobre una cama de lechuga picada.'], TRUE),
  ('r817', 'Microwave Protein Oatmeal', 'Avena Proteica al Microondas', NULL, 418, 30, 52, 10, 5, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','almond_milk','banana','peanut_butter'], ARRAY['Combine oats and almond milk in a mug and microwave 90 seconds.','Stir in a scoop of protein powder until smooth.','Top with sliced banana and a spoon of peanut butter.'], ARRAY['Combina la avena y la leche de almendra en una taza y calienta 90 segundos.','Incorpora una medida de proteína en polvo hasta suavizar.','Cubre con banana en rebanadas y una cucharada de mantequilla de maní.'], TRUE),
  ('r818', 'Egg White Mug Scramble', 'Revuelto de Claras en Taza', NULL, 297, 28, 26, 9, 5, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['egg_whites','eggs','cheese','spinach','tomato','salsa'], ARRAY['Whisk 4 egg whites and 1 whole egg in a greased mug.','Stir in chopped spinach and diced tomato.','Microwave 60 seconds, stir, then 30 more seconds.','Top with cheese and a spoon of salsa.'], ARRAY['Bate 4 claras y 1 huevo entero en una taza engrasada.','Agrega espinaca picada y tomate en cubitos.','Calienta 60 segundos, revuelve y 30 segundos más.','Cubre con queso y una cucharada de salsa.'], TRUE),
  ('r819', 'Denver Omelette Mug', 'Omelette Denver en Taza', NULL, 337, 30, 25, 13, 6, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['eggs','egg_whites','cheese','bell_pepper','onion','turkey_breast'], ARRAY['Beat 2 eggs and 2 egg whites in a greased mug.','Stir in diced bell pepper, onion and chopped turkey breast.','Microwave 90 seconds until set, stirring once.','Top with cheese and let it melt.'], ARRAY['Bate 2 huevos y 2 claras en una taza engrasada.','Agrega pimiento y cebolla en cubitos y pavo picado.','Calienta 90 segundos hasta cuajar, revolviendo una vez.','Cubre con queso y deja que se derrita.'], TRUE),
  ('r820', 'Mug Pizza Omelette', 'Omelette Pizza en Taza', NULL, 384, 32, 28, 16, 6, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['eggs','cheese','tomato','turkey_breast','mushroom'], ARRAY['Beat 3 eggs in a greased mug with a spoon of tomato sauce.','Stir in chopped turkey breast and sliced mushroom.','Microwave 90 seconds until puffed and set.','Top with cheese and microwave 15 seconds to melt.'], ARRAY['Bate 3 huevos en una taza engrasada con una cucharada de salsa de tomate.','Agrega pavo picado y champiñones en rebanadas.','Calienta 90 segundos hasta que infle y cuaje.','Cubre con queso y calienta 15 segundos para derretir.'], TRUE),
  ('r821', 'PB Banana Protein Mug Cake', 'Mug Cake de Maní y Banana', NULL, 397, 30, 40, 13, 5, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['protein_powder','oats','banana','peanut_butter','egg_whites','almond_milk'], ARRAY['Mash half a banana in a mug, then stir in protein powder, oats and egg whites.','Add a splash of almond milk until batter is smooth.','Microwave 70 seconds until set.','Swirl a spoon of peanut butter on top.'], ARRAY['Machaca media banana en una taza y mezcla proteína en polvo, avena y claras.','Añade un chorrito de leche de almendra hasta que la masa quede suave.','Calienta 70 segundos hasta cuajar.','Añade encima una cucharada de mantequilla de maní.'], TRUE),
  ('r822', 'Cottage Cheese Protein Toast', 'Tostada Proteica de Requesón', NULL, 363, 32, 34, 11, 5, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['whole_grain_bread','cottage_cheese','tomato','cucumber','olive_oil'], ARRAY['Toast two slices of whole grain bread.','Spread thick with cottage cheese.','Top with sliced tomato and cucumber and a drizzle of olive oil.'], ARRAY['Tuesta dos rebanadas de pan integral.','Unta una capa gruesa de requesón.','Cubre con tomate y pepino en rebanadas y un chorrito de aceite de oliva.'], TRUE),
  ('r823', 'Smoked Salmon Avocado Toast', 'Tostada de Salmón y Aguacate', NULL, 394, 28, 30, 18, 6, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['whole_grain_bread','salmon','avocado','lemon','onion'], ARRAY['Toast two slices of whole grain bread.','Mash avocado with lemon and spread over the toast.','Lay smoked salmon on top and scatter thin onion slices.'], ARRAY['Tuesta dos rebanadas de pan integral.','Machaca el aguacate con limón y úntalo sobre la tostada.','Coloca el salmón ahumado encima y esparce cebolla en rebanadas finas.'], TRUE),
