  ('r827', 'Greek Yogurt Granola Crunch', 'Yogur Griego con Granola', NULL, 402, 30, 48, 10, 4, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','granola','berries','honey','chia_seeds'], ARRAY['Spoon a cup of greek yogurt into a bowl.','Layer granola, berries and a sprinkle of chia seeds.','Finish with a drizzle of honey.'], ARRAY['Sirve una taza de yogur griego en un bowl.','Añade capas de granola, berries y una pizca de semillas de chía.','Termina con un chorrito de miel.'], TRUE),
  ('r828', 'Egg White Breakfast Sandwich', 'Sándwich de Claras para Desayuno', NULL, 373, 32, 32, 13, 8, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['whole_grain_bread','egg_whites','eggs','cheese','spinach'], ARRAY['Scramble 1 egg and 3 egg whites with spinach in a small pan.','Toast two slices of whole grain bread.','Layer the eggs and cheese between the toast and press gently.'], ARRAY['Revuelve 1 huevo y 3 claras con espinaca en un sartén pequeño.','Tuesta dos rebanadas de pan integral.','Coloca los huevos y el queso entre las tostadas y presiona ligeramente.'], TRUE),
