  ('r832', 'Roast Beef Cheddar Roll-Ups', 'Rollitos de Roast Beef y Cheddar', NULL, 409, 38, 26, 17, 6, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['lean_beef','cheese','lettuce','tomato','whole_grain_bread'], ARRAY['Lay out slices of lean roast beef and top each with cheddar and lettuce.','Add a strip of tomato and roll each one up.','Serve with a slice of whole grain bread on the side.'], ARRAY['Extiende las rebanadas de roast beef y cubre cada una con cheddar y lechuga.','Añade una tira de tomate y enrolla cada una.','Sirve con una rebanada de pan integral al lado.'], TRUE),
  ('r834', 'Korean Beef Rice Bowl', 'Bowl de Res Coreana con Arroz', NULL, 487, 40, 48, 15, 13, 'Quick', 'Rápido', 'quick_meals', 'Medium', 'Medio', 1, ARRAY['lean_beef','rice','soy_sauce','sesame_oil','garlic','carrot'], ARRAY['Brown lean ground beef in a hot pan with minced garlic, 5 minutes.','Stir in soy sauce, a drop of sesame oil and a pinch of sweetener.','Serve over warm rice with grated carrot on top.'], ARRAY['Dora la carne de res molida en un sartén caliente con ajo picado, 5 minutos.','Agrega salsa de soya, una gota de aceite de sésamo y una pizca de endulzante.','Sirve sobre arroz caliente con zanahoria rallada encima.'], TRUE),
  ('r835', 'Teriyaki Chicken Rice Cup', 'Vaso de Pollo Teriyaki con Arroz', NULL, 458, 42, 50, 10, 9, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','soy_sauce','honey','broccoli'], ARRAY['Microwave broccoli florets with a splash of water for 2 minutes.','Toss diced cooked chicken with soy sauce and honey and warm through.','Layer rice, chicken and broccoli in a cup.'], ARRAY['Cocina el brócoli en el microondas con un chorrito de agua por 2 minutos.','Mezcla el pollo cocido en cubos con salsa de soya y miel y caliéntalo.','Coloca capas de arroz, pollo y brócoli en un vaso.'], TRUE),
  ('r836', 'Thai Peanut Chicken Wrap', 'Wrap de Pollo con Maní Thai', NULL, 441, 38, 34, 17, 8, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['tortilla','chicken_breast','peanut_butter','carrot','lettuce','soy_sauce'], ARRAY['Whisk peanut butter with soy sauce and a little warm water into a sauce.','Toss shredded chicken and grated carrot in the sauce.','Spread over a tortilla with lettuce, roll tightly and slice.'], ARRAY['Bate la mantequilla de maní con salsa de soya y un poco de agua tibia para una salsa.','Mezcla el pollo desmenuzado y la zanahoria rallada en la salsa.','Extiende sobre una tortilla con lechuga, enrolla apretado y corta.'], TRUE),
