  ('r846', 'Chipotle Chicken Rice Bowl', 'Bowl de Pollo Chipotle con Arroz', NULL, 482, 42, 47, 14, 9, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','black_beans','salsa','corn','avocado'], ARRAY['Warm rice, black beans and corn together in a bowl.','Toss diced chicken with a spoon of smoky chipotle salsa and add on top.','Finish with a few slices of avocado.'], ARRAY['Calienta el arroz, los frijoles negros y el maíz juntos en un bowl.','Mezcla el pollo en cubos con una cucharada de salsa chipotle ahumada y ponlo encima.','Termina con unas rebanadas de aguacate.'], TRUE),
  ('r847', 'Open-Faced Tuna Melt', 'Tuna Melt Abierto', NULL, 399, 36, 30, 15, 8, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['whole_grain_bread','canned_tuna','cheese','greek_yogurt','tomato'], ARRAY['Mix drained tuna with a spoon of greek yogurt.','Pile onto whole grain bread, add tomato slices and cheese.','Broil or air-fry 3 minutes until the cheese bubbles.'], ARRAY['Mezcla el atún escurrido con una cucharada de yogur griego.','Coloca sobre pan integral, añade rebanadas de tomate y queso.','Gratina o usa la freidora de aire 3 minutos hasta que el queso burbujee.'], TRUE),
  ('r848', 'Miso Salmon Rice Bowl', 'Bowl de Salmón Miso con Arroz', NULL, 459, 35, 46, 15, 12, 'Quick', 'Rápido', 'quick_meals', 'Medium', 'Medio', 1, ARRAY['salmon','rice','spinach','soy_sauce','sesame_oil','garlic'], ARRAY['Whisk a spoon of miso with soy sauce and brush over a salmon fillet.','Sear 3 minutes per side, adding garlic near the end.','Wilt spinach in the pan and serve over rice with a drop of sesame oil.'], ARRAY['Bate una cucharada de miso con salsa de soya y unta sobre un filete de salmón.','Sella 3 minutos por lado, añadiendo ajo al final.','Marchita la espinaca en el sartén y sirve sobre arroz con una gota de aceite de sésamo.'], TRUE),
  ('r849', 'Buffalo Shrimp Lettuce Wraps', 'Wraps de Lechuga con Camarón Búfalo', NULL, 348, 34, 26, 12, 9, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['shrimp','lettuce','salsa','greek_yogurt','cheese','carrot'], ARRAY['Toss cooked shrimp with hot salsa until well coated.','Whisk greek yogurt with a pinch of garlic for a cool drizzle.','Spoon shrimp into lettuce leaves with grated carrot, cheese and the drizzle.'], ARRAY['Mezcla los camarones cocidos con salsa picante hasta cubrir bien.','Bate el yogur griego con una pizca de ajo para un aderezo fresco.','Rellena hojas de lechuga con los camarones, zanahoria rallada, queso y el aderezo.'], TRUE),
  ('r850', 'Protein Pancake Mug', 'Mug Cake de Panqueque Proteico', NULL, 396, 32, 40, 12, 6, 'Quick', 'Rápido', 'quick_meals', 'Easy', 'Fácil', 1, ARRAY['protein_powder','oats','eggs','banana','almond_milk'], ARRAY['Blend oats, protein powder, 1 egg, half a banana and a splash of almond milk.','Pour into a greased mug and microwave 90 seconds until set.','Top with the remaining banana slices.'], ARRAY['Licúa avena, proteína en polvo, 1 huevo, media banana y un chorrito de leche de almendra.','Vierte en una taza engrasada y calienta 90 segundos hasta cuajar.','Cubre con las rebanadas de banana restantes.'], TRUE),
  ('r851', 'Shakshuka Eggs in Tomato Sauce', 'Shakshuka: Huevos en Salsa de Tomate', NULL, 400, 26, 38, 16, 25, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['eggs','tomato','onion','bell_pepper','garlic','whole_grain_bread','olive_oil'], ARRAY['Saute diced onion, bell pepper and garlic in olive oil until soft, about 6 minutes.','Add chopped tomato with a pinch of cumin and paprika; simmer 10 minutes until thick.','Make 3 wells, crack in the eggs, cover and cook 5 minutes until whites set.','Serve with toasted whole-grain bread for dipping.'], ARRAY['Sofríe la cebolla, el pimiento y el ajo picados en aceite de oliva hasta ablandar, unos 6 minutos.','Agrega el tomate picado con una pizca de comino y pimentón; cocina a fuego lento 10 minutos hasta espesar.','Haz 3 huecos, casca los huevos, tapa y cocina 5 minutos hasta que cuajen las claras.','Sirve con pan integral tostado para mojar.'], TRUE),
  ('r853', 'Egg Drop Soup with Rice', 'Sopa China de Huevo con Arroz', NULL, 394, 24, 52, 10, 20, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['eggs','rice','soy_sauce','garlic','onion'], ARRAY['Simmer 2 cups water with garlic, sliced onion and a splash of soy sauce for 5 minutes.','Beat 3 eggs and pour in a thin stream while stirring to form silky ribbons.','Cook 1 minute, then ladle the soup over a bowl of hot cooked rice.'], ARRAY['Hierve 2 tazas de agua con ajo, cebolla en rodajas y un chorrito de salsa de soya durante 5 minutos.','Bate 3 huevos y viértelos en hilo fino mientras remueves para formar hebras sedosas.','Cocina 1 minuto y sirve la sopa sobre un tazón de arroz caliente.'], TRUE),
  ('r855', 'Kimchi Fried Rice with Egg', 'Arroz Frito con Kimchi y Huevo', NULL, 438, 23, 55, 14, 15, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['rice','eggs','kimchi','soy_sauce','sesame_oil'], ARRAY['Fry chopped kimchi in sesame oil over high heat for 2 minutes.','Add day-old cold rice and soy sauce; stir-fry until sizzling and coated, 4 minutes.','Push rice aside, fry an egg in the pan, then serve it on top of the rice.'], ARRAY['Sofríe el kimchi picado en aceite de sésamo a fuego alto por 2 minutos.','Agrega arroz frío del día anterior y salsa de soya; saltea hasta que chisporrotee, 4 minutos.','Aparta el arroz, fríe un huevo en el sartén y sírvelo encima del arroz.'], TRUE),
  ('r856', 'Tuna Melt Toastie', 'Sándwich Caliente de Atún y Queso', NULL, 436, 35, 38, 16, 12, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','whole_grain_bread','cheese','onion'], ARRAY['Drain the tuna and mix with finely diced onion and a spoon of yogurt or mayo.','Pile onto whole-grain bread and top with a slice of cheese and a second slice of bread.','Toast in a dry pan, pressing down, 3 minutes per side until golden and melted.'], ARRAY['Escurre el atún y mézclalo con cebolla picada fina y una cucharada de yogur o mayonesa.','Coloca sobre pan integral, añade una lonja de queso y tapa con otra rebanada de pan.','Tuesta en un sartén seco, presionando, 3 minutos por lado hasta dorar y derretir.'], TRUE),
  ('r857', 'Turkey & Bean Chili', 'Chili de Pavo y Frijoles', NULL, 428, 38, 42, 12, 35, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 2, ARRAY['ground_turkey','black_beans','tomato','onion','bell_pepper','garlic'], ARRAY['Brown the ground turkey with onion, bell pepper and garlic in a pot, 8 minutes.','Stir in chili powder and cumin, then add chopped tomato and black beans.','Simmer 20 minutes until thick, stirring occasionally.','Season with salt and serve in bowls.'], ARRAY['Dora el pavo molido con cebolla, pimiento y ajo en una olla, 8 minutos.','Añade chili en polvo y comino, luego incorpora el tomate picado y los frijoles negros.','Cocina a fuego lento 20 minutos hasta espesar, removiendo de vez en cuando.','Sazona con sal y sirve en tazones.'], TRUE),
  ('r858', 'Lentil Bolognese with Pasta', 'Boloñesa de Lentejas con Pasta', NULL, 476, 28, 64, 12, 30, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['lentils','pasta','tomato','onion','garlic','olive_oil'], ARRAY['Saute onion and garlic in olive oil, then add cooked lentils and chopped tomato.','Simmer with oregano for 15 minutes until the sauce is rich and thick.','Meanwhile boil the pasta until al dente and drain.','Toss the pasta through the lentil sauce and serve.'], ARRAY['Sofríe cebolla y ajo en aceite de oliva, luego agrega las lentejas cocidas y el tomate picado.','Cocina a fuego lento con orégano por 15 minutos hasta que la salsa espese.','Mientras tanto, hierve la pasta al dente y escúrrela.','Mezcla la pasta con la salsa de lentejas y sirve.'], TRUE),
  ('r859', 'Sheet-Pan Chicken Thighs & Potatoes', 'Muslos de Pollo y Papas al Horno', NULL, 458, 34, 40, 18, 45, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','potato','carrot','garlic','olive_oil'], ARRAY['Heat oven to 220C (425F). Toss cubed potato and carrot with olive oil, garlic and salt on a sheet pan.','Nestle in the chicken thighs, skin up, and season well.','Roast 35 minutes until the chicken is 74C (165F) and the potatoes are crisp.','Rest 5 minutes before serving.'], ARRAY['Calienta el horno a 220C (425F). Mezcla la papa y la zanahoria en cubos con aceite, ajo y sal en una bandeja.','Acomoda los muslos de pollo con la piel hacia arriba y sazónalos bien.','Hornea 35 minutos hasta que el pollo llegue a 74C (165F) y las papas estén crujientes.','Deja reposar 5 minutos antes de servir.'], TRUE),
  ('r860', 'Turkey & Cabbage Skillet', 'Salteado de Pavo y Repollo', NULL, 411, 33, 36, 15, 20, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','cabbage','carrot','soy_sauce','garlic'], ARRAY['Brown the ground turkey with garlic in a hot skillet until no longer pink, 6 minutes.','Add shredded cabbage and carrot; stir-fry until wilted but still crisp, 5 minutes.','Splash in soy sauce, toss to coat and serve.'], ARRAY['Dora el pavo molido con ajo en un sartén caliente hasta que pierda el color rosado, 6 minutos.','Añade el repollo y la zanahoria rallados; saltea hasta marchitar pero aún crujientes, 5 minutos.','Agrega salsa de soya, mezcla para cubrir y sirve.'], TRUE),
  ('r861', 'Potato & Egg Breakfast Hash', 'Hash de Papa y Huevo', NULL, 416, 22, 46, 16, 25, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['potato','eggs','onion','bell_pepper','olive_oil'], ARRAY['Dice potato small and fry in olive oil until golden and tender, about 12 minutes.','Add onion and bell pepper and cook until soft, 5 minutes; season with paprika.','Make 2 wells, crack in the eggs, cover and cook until set, 4 minutes.'], ARRAY['Corta la papa en cubitos y fríela en aceite de oliva hasta dorar y ablandar, unos 12 minutos.','Añade cebolla y pimiento y cocina hasta suavizar, 5 minutos; sazona con pimentón.','Haz 2 huecos, casca los huevos, tapa y cocina hasta cuajar, 4 minutos.'], TRUE),
  ('r862', 'Chana Masala Chickpea Curry', 'Chana Masala: Curry de Garbanzos', NULL, 444, 24, 60, 12, 25, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['chickpeas','tomato','onion','garlic','rice'], ARRAY['Fry onion and garlic until deep golden, then add grated tomato and garam masala.','Cook down to a thick masala, 8 minutes, then stir in the chickpeas with a splash of water.','Simmer 10 minutes to meld, mashing a few chickpeas to thicken.','Serve over hot rice.'], ARRAY['Sofríe cebolla y ajo hasta dorar bien, luego agrega tomate rallado y garam masala.','Reduce hasta lograr una masala espesa, 8 minutos, e incorpora los garbanzos con un poco de agua.','Cocina a fuego lento 10 minutos, machacando algunos garbanzos para espesar.','Sirve sobre arroz caliente.'], TRUE),
  ('r863', 'Refried Bean Tacos', 'Tacos de Frijoles Refritos', NULL, 447, 24, 54, 15, 15, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['black_beans','tortilla','cheese','salsa','onion'], ARRAY['Mash the black beans in a pan with a little onion and their liquid until smooth and hot.','Warm the tortillas in a dry skillet until pliable.','Spread beans on each tortilla, top with cheese, salsa and diced onion, and fold.'], ARRAY['Machaca los frijoles negros en un sartén con un poco de cebolla y su líquido hasta que estén suaves y calientes.','Calienta las tortillas en un sartén seco hasta que estén flexibles.','Unta los frijoles en cada tortilla, cubre con queso, salsa y cebolla picada, y dobla.'], TRUE),
  ('r864', 'Banana Peanut Overnight Oats', 'Avena Nocturna de Plátano y Maní', NULL, 456, 22, 56, 16, 10, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['oats','banana','peanut_butter','almond_milk','chia_seeds'], ARRAY['Stir oats, chia seeds and almond milk together in a jar.','Swirl in the peanut butter and half a mashed banana.','Cover and refrigerate overnight; top with sliced banana before eating.'], ARRAY['Mezcla la avena, las semillas de chía y la leche de almendra en un frasco.','Incorpora la mantequilla de maní y medio plátano machacado.','Tapa y refrigera toda la noche; cubre con plátano en rodajas antes de comer.'], TRUE),
  ('r865', 'Sardines on Toast', 'Sardinas sobre Tostada', NULL, 426, 30, 36, 18, 8, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['sardines','whole_grain_bread','tomato','lemon','olive_oil'], ARRAY['Toast 2 slices of whole-grain bread and drizzle with olive oil.','Lay over sliced tomato, then the drained sardines.','Squeeze lemon over the top and season with black pepper.'], ARRAY['Tuesta 2 rebanadas de pan integral y rocíalas con aceite de oliva.','Coloca encima el tomate en rodajas y luego las sardinas escurridas.','Exprime limón por encima y sazona con pimienta negra.'], TRUE),
  ('r866', 'Spanish Potato Omelette', 'Tortilla Española de Papa', NULL, 409, 24, 40, 17, 30, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 2, ARRAY['potato','eggs','onion','olive_oil'], ARRAY['Slice potato thin and cook gently in olive oil with onion until soft, about 15 minutes.','Beat 5 eggs, fold in the drained potato and onion, and season with salt.','Pour into the pan and cook over low heat until nearly set, 6 minutes.','Flip with a plate and cook the other side 3 minutes; slice into wedges.'], ARRAY['Corta la papa en láminas finas y cocínala lento en aceite de oliva con cebolla hasta ablandar, unos 15 minutos.','Bate 5 huevos, incorpora la papa y la cebolla escurridas y sazona con sal.','Vierte en el sartén y cocina a fuego bajo hasta casi cuajar, 6 minutos.','Voltea con un plato y cocina el otro lado 3 minutos; corta en cuñas.'], TRUE),
  ('r867', 'Lentil Shepherd''s Pie', 'Pastel de Lentejas y Papa', NULL, 431, 25, 58, 11, 45, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 2, ARRAY['lentils','potato','carrot','onion','tomato'], ARRAY['Boil potato until tender, then mash with a splash of milk and salt.','Simmer cooked lentils with onion, carrot and chopped tomato until thick, 12 minutes.','Spread the lentil mix in a dish and top with the mash.','Bake at 200C (400F) for 20 minutes until golden on top.'], ARRAY['Hierve la papa hasta ablandar y machácala con un chorrito de leche y sal.','Cocina las lentejas con cebolla, zanahoria y tomate picado hasta espesar, 12 minutos.','Extiende la mezcla de lentejas en un molde y cubre con el puré.','Hornea a 200C (400F) por 20 minutos hasta dorar la superficie.'], TRUE),
  ('r868', 'Black Bean Veggie Burgers', 'Hamburguesas de Frijol Negro', NULL, 396, 22, 50, 12, 30, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 1, ARRAY['black_beans','oats','eggs','onion','garlic'], ARRAY['Mash the black beans, leaving some texture, and mix with grated onion and garlic.','Stir in oats and 1 beaten egg with cumin until the mix holds together.','Form 2 patties and chill 10 minutes to firm up.','Pan-fry in a little oil, 4 minutes per side, until crisp.'], ARRAY['Machaca los frijoles negros dejando algo de textura y mezcla con cebolla y ajo rallados.','Incorpora la avena y 1 huevo batido con comino hasta que la mezcla se una.','Forma 2 hamburguesas y enfría 10 minutos para que tomen firmeza.','Fríe en poco aceite, 4 minutos por lado, hasta que estén crujientes.'], TRUE),
  ('r870', 'Indian Egg Curry', 'Curry Indio de Huevo', NULL, 456, 24, 54, 16, 30, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['eggs','tomato','onion','garlic','rice'], ARRAY['Hard-boil 3 eggs, peel, and lightly brown them whole in a little oil.','Fry onion and garlic until golden, add grated tomato and curry spices; cook 8 minutes.','Return the eggs, add a splash of water and simmer 8 minutes.','Serve over hot rice.'], ARRAY['Hierve 3 huevos, pélalos y dóralos enteros en un poco de aceite.','Sofríe cebolla y ajo hasta dorar, agrega tomate rallado y especias de curry; cocina 8 minutos.','Regresa los huevos, añade un poco de agua y cocina a fuego lento 8 minutos.','Sirve sobre arroz caliente.'], TRUE),
  ('r871', 'Baked Beans on Toast', 'Frijoles Guisados sobre Tostada', NULL, 402, 23, 55, 10, 15, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['white_beans','whole_grain_bread','tomato','onion','garlic'], ARRAY['Saute onion and garlic, then add chopped tomato and cook to a sauce, 6 minutes.','Stir in the white beans with a pinch of smoked paprika and simmer 8 minutes.','Toast 2 slices of whole-grain bread and spoon the beans over the top.'], ARRAY['Sofríe cebolla y ajo, luego añade tomate picado y cocina hasta formar una salsa, 6 minutos.','Incorpora los frijoles blancos con una pizca de pimentón ahumado y cocina 8 minutos.','Tuesta 2 rebanadas de pan integral y sirve los frijoles encima.'], TRUE),
  ('r872', 'Ground Turkey Stuffed Peppers', 'Pimientos Rellenos de Pavo', NULL, 437, 34, 46, 13, 45, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 2, ARRAY['ground_turkey','bell_pepper','rice','tomato','onion'], ARRAY['Halve the bell peppers and remove the seeds.','Brown the turkey with onion, stir in cooked rice and chopped tomato, and season.','Spoon the filling into the peppers and set in a baking dish.','Bake at 190C (375F) for 25 minutes until the peppers are tender.'], ARRAY['Corta los pimientos por la mitad y retira las semillas.','Dora el pavo con cebolla, incorpora arroz cocido y tomate picado, y sazona.','Rellena los pimientos con la mezcla y colócalos en un molde.','Hornea a 190C (375F) por 25 minutos hasta que los pimientos estén tiernos.'], TRUE),
  ('r873', 'Rajma Kidney Bean Curry', 'Rajma: Curry de Frijoles Rojos', NULL, 438, 24, 63, 10, 30, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['kidney_beans','tomato','onion','garlic','rice'], ARRAY['Fry onion, garlic and ginger until soft, then add grated tomato and garam masala.','Cook to a thick gravy, 8 minutes, then add kidney beans and a cup of water.','Simmer 12 minutes, mashing some beans to thicken the sauce.','Serve over steamed rice.'], ARRAY['Sofríe cebolla, ajo y jengibre hasta ablandar, luego agrega tomate rallado y garam masala.','Cocina hasta lograr una salsa espesa, 8 minutos, y añade los frijoles rojos y una taza de agua.','Cocina a fuego lento 12 minutos, machacando algunos frijoles para espesar.','Sirve sobre arroz al vapor.'], TRUE),
  ('r874', 'Filipino Chicken Adobo', 'Adobo de Pollo Filipino', NULL, 478, 35, 44, 18, 40, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','soy_sauce','vinegar','garlic','rice'], ARRAY['Brown chicken thighs in a pot, skin down, until golden.','Add soy sauce, vinegar, crushed garlic, a bay leaf and pepper with a splash of water.','Simmer covered 25 minutes, then uncover and reduce the sauce to a glaze.','Serve over steamed rice.'], ARRAY['Dora los muslos de pollo en una olla, con la piel hacia abajo, hasta dorar.','Agrega salsa de soya, vinagre, ajo machacado, una hoja de laurel y pimienta con un poco de agua.','Cocina tapado 25 minutos, destapa y reduce la salsa hasta glasear.','Sirve sobre arroz al vapor.'], TRUE),
  ('r875', 'Cottage Cheese Protein Pancakes', 'Panqueques Proteicos de Requesón', NULL, 412, 32, 44, 12, 15, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','oats','eggs','banana'], ARRAY['Blend cottage cheese, oats, 2 eggs and half a banana into a smooth batter.','Cook spoonfuls on a nonstick pan over medium heat, 2 minutes per side.','Stack and top with the remaining sliced banana.'], ARRAY['Licúa el requesón, la avena, 2 huevos y medio plátano hasta lograr una masa suave.','Cocina cucharadas en un sartén antiadherente a fuego medio, 2 minutos por lado.','Apila y cubre con el resto del plátano en rodajas.'], TRUE),
  ('r876', 'Sweet Potato Black Bean Chili', 'Chili de Batata y Frijol Negro', NULL, 409, 22, 60, 9, 40, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 2, ARRAY['sweet_potato','black_beans','tomato','onion','bell_pepper'], ARRAY['Saute onion and bell pepper, then add cubed sweet potato and chili spices.','Pour in chopped tomato and a cup of water; simmer 20 minutes until the sweet potato is tender.','Stir in the black beans and cook 8 more minutes to thicken.','Season and serve in bowls.'], ARRAY['Sofríe cebolla y pimiento, luego añade la batata en cubos y especias de chili.','Vierte tomate picado y una taza de agua; cocina 20 minutos hasta que la batata esté tierna.','Incorpora los frijoles negros y cocina 8 minutos más para espesar.','Sazona y sirve en tazones.'], TRUE),
  ('r877', 'Spiced Lentil Tacos', 'Tacos de Lentejas Especiadas', NULL, 420, 24, 54, 12, 25, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['lentils','tortilla','salsa','onion','garlic'], ARRAY['Saute onion and garlic, then add cooked lentils with cumin, chili and smoked paprika.','Cook until dry and taco-like, mashing lightly, 8 minutes.','Warm the tortillas and fill with the lentils.','Top with salsa and diced onion.'], ARRAY['Sofríe cebolla y ajo, luego agrega las lentejas cocidas con comino, chili y pimentón ahumado.','Cocina hasta que estén secas tipo relleno de taco, machacando ligeramente, 8 minutos.','Calienta las tortillas y rellénalas con las lentejas.','Cubre con salsa y cebolla picada.'], TRUE),
  ('r878', 'Egg Salad Sandwich', 'Sándwich de Ensalada de Huevo', NULL, 375, 24, 36, 15, 15, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['eggs','whole_grain_bread','greek_yogurt','lettuce'], ARRAY['Hard-boil 3 eggs, cool under cold water, peel and chop.','Mix with Greek yogurt, a little mustard, salt and pepper.','Spread onto whole-grain bread, add lettuce and close the sandwich.'], ARRAY['Hierve 3 huevos, enfríalos en agua fría, pélalos y pícalos.','Mezcla con yogur griego, un poco de mostaza, sal y pimienta.','Unta sobre pan integral, añade lechuga y cierra el sándwich.'], TRUE),
  ('r879', 'Turkey Meatballs in Marinara', 'Albóndigas de Pavo en Marinara', NULL, 494, 38, 54, 14, 35, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 2, ARRAY['ground_turkey','pasta','tomato','garlic','onion'], ARRAY['Mix ground turkey with grated onion, garlic, salt and a little oat binder; roll into balls.','Brown the meatballs in a pan, then set aside.','Simmer chopped tomato with garlic into a marinara, return the meatballs and cook 12 minutes.','Serve over boiled pasta.'], ARRAY['Mezcla el pavo molido con cebolla y ajo rallados, sal y un poco de avena como ligante; forma bolitas.','Dora las albóndigas en un sartén y resérvalas.','Cocina el tomate picado con ajo hasta hacer una marinara, regresa las albóndigas y cocina 12 minutos.','Sirve sobre pasta hervida.'], TRUE),
  ('r880', 'Quinoa & Black Bean Bowl', 'Bowl de Quinoa y Frijol Negro', NULL, 434, 22, 55, 14, 25, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['quinoa','black_beans','corn','tomato','avocado'], ARRAY['Cook quinoa in salted water until fluffy, about 15 minutes.','Warm the black beans and corn with cumin.','Build a bowl with the quinoa, beans, corn and chopped tomato.','Top with sliced avocado and a squeeze of lime.'], ARRAY['Cocina la quinoa en agua con sal hasta que quede esponjosa, unos 15 minutos.','Calienta los frijoles negros y el maíz con comino.','Arma un bowl con la quinoa, los frijoles, el maíz y el tomate picado.','Cubre con aguacate en rodajas y un chorrito de limón.'], TRUE),
  ('r881', 'Tuna Potato Patties', 'Croquetas de Atún y Papa', NULL, 406, 30, 40, 14, 30, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 1, ARRAY['canned_tuna','potato','eggs','onion'], ARRAY['Boil and mash the potato, then cool slightly.','Mix in the drained tuna, 1 egg, finely diced onion and pepper.','Shape into 3 patties.','Pan-fry in a little oil, 4 minutes per side, until golden and crisp.'], ARRAY['Hierve y machaca la papa, luego deja enfriar un poco.','Mezcla con el atún escurrido, 1 huevo, cebolla picada fina y pimienta.','Forma 3 croquetas.','Fríe en poco aceite, 4 minutos por lado, hasta dorar y quedar crujientes.'], TRUE),
  ('r882', 'Peanut Noodles with Egg', 'Fideos con Salsa de Maní y Huevo', NULL, 478, 24, 55, 18, 20, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['pasta','peanut_butter','eggs','soy_sauce','garlic'], ARRAY['Whisk peanut butter, soy sauce, grated garlic and warm water into a smooth sauce.','Boil the pasta, drain, and toss with the peanut sauce.','Fry an egg and slide it on top of the noodles.'], ARRAY['Bate la mantequilla de maní, salsa de soya, ajo rallado y agua tibia hasta lograr una salsa suave.','Hierve la pasta, escúrrela y mézclala con la salsa de maní.','Fríe un huevo y colócalo encima de los fideos.'], TRUE),
  ('r883', 'Beans & Greens Skillet', 'Sartén de Frijoles y Espinaca', NULL, 372, 22, 44, 12, 15, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['white_beans','spinach','garlic','tomato','olive_oil'], ARRAY['Warm olive oil and sizzle the garlic until fragrant, 1 minute.','Add chopped tomato and the white beans; simmer 6 minutes to meld.','Fold in the spinach until wilted and season with salt and chili flakes.'], ARRAY['Calienta aceite de oliva y sofríe el ajo hasta que suelte aroma, 1 minuto.','Añade tomate picado y los frijoles blancos; cocina 6 minutos para integrar.','Incorpora la espinaca hasta marchitar y sazona con sal y hojuelas de chile.'], TRUE),
  ('r884', 'Tex-Mex Egg Migas', 'Migas Tex-Mex con Huevo', NULL, 417, 26, 40, 17, 15, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['eggs','tortilla','salsa','cheese','onion'], ARRAY['Cut the tortilla into strips and crisp them in a little oil.','Add diced onion and cook 2 minutes, then pour in 3 beaten eggs.','Scramble softly, fold in salsa and cheese, and serve.'], ARRAY['Corta la tortilla en tiras y dóralas en un poco de aceite.','Agrega cebolla picada y cocina 2 minutos, luego vierte 3 huevos batidos.','Revuelve suavemente, incorpora salsa y queso, y sirve.'], TRUE),
  ('r885', 'Turkey Picadillo with Rice', 'Picadillo de Pavo con Arroz', NULL, 486, 35, 55, 14, 30, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 2, ARRAY['ground_turkey','rice','tomato','potato','onion'], ARRAY['Brown the ground turkey with onion until cooked through.','Add diced potato, chopped tomato, cumin and a handful of olives; simmer 15 minutes.','Cook until the potato is tender and the sauce thick.','Serve over hot rice.'], ARRAY['Dora el pavo molido con cebolla hasta cocer por completo.','Añade papa en cubos, tomate picado, comino y un puñado de aceitunas; cocina 15 minutos.','Cocina hasta que la papa esté tierna y la salsa espesa.','Sirve sobre arroz caliente.'], TRUE),
  ('r886', 'Gallo Pinto with Egg', 'Gallo Pinto con Huevo', NULL, 444, 24, 60, 12, 20, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['rice','black_beans','eggs','onion','bell_pepper'], ARRAY['Saute onion and bell pepper until soft.','Add the black beans with a little of their liquid, then fold in cold cooked rice.','Fry until sizzling and well mixed, 5 minutes.','Top with a fried egg and serve.'], ARRAY['Sofríe cebolla y pimiento hasta ablandar.','Agrega los frijoles negros con un poco de su líquido y luego incorpora arroz frío cocido.','Sofríe hasta que chisporrotee y quede bien mezclado, 5 minutos.','Cubre con un huevo frito y sirve.'], TRUE),
  ('r887', 'Lentil Mujadara', 'Mujadara de Lentejas', NULL, 452, 24, 62, 12, 40, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 2, ARRAY['lentils','rice','onion','garlic','olive_oil'], ARRAY['Fry sliced onion in olive oil low and slow until deep brown and crispy; set half aside.','Add rice, cooked lentils, garlic and cumin to the pan with 2 cups water.','Cover and simmer 18 minutes until the rice is tender.','Top with the reserved crispy onions.'], ARRAY['Fríe la cebolla en rodajas en aceite de oliva a fuego bajo hasta dorar y quedar crujiente; aparta la mitad.','Añade arroz, lentejas cocidas, ajo y comino al sartén con 2 tazas de agua.','Tapa y cocina a fuego lento 18 minutos hasta que el arroz esté tierno.','Cubre con la cebolla crujiente reservada.'], TRUE),
  ('r888', 'Green Chilaquiles with Egg', 'Chilaquiles Verdes con Huevo', NULL, 437, 26, 45, 17, 20, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['tortilla','salsa','eggs','cheese','onion'], ARRAY['Cut tortillas into triangles and toast in a pan until crisp.','Pour in green salsa and toss quickly so the chips soften but stay a bit crunchy.','Top with a fried egg, crumbled cheese and sliced onion.'], ARRAY['Corta las tortillas en triángulos y tuéstalas en un sartén hasta que estén crujientes.','Vierte salsa verde y mezcla rápido para que los totopos se suavicen pero queden algo crujientes.','Cubre con un huevo frito, queso desmoronado y cebolla en rodajas.'], TRUE),
  ('r890', 'Chicken Thigh & Chickpea Stew', 'Guiso de Muslo de Pollo y Garbanzos', NULL, 456, 38, 40, 16, 40, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','chickpeas','tomato','onion','garlic'], ARRAY['Brown the chicken thighs, then set aside.','Saute onion and garlic, add chopped tomato and smoked paprika to make a sofrito.','Return the chicken, add chickpeas and a cup of water; simmer 25 minutes.','Season and serve hot.'], ARRAY['Dora los muslos de pollo y resérvalos.','Sofríe cebolla y ajo, añade tomate picado y pimentón ahumado para hacer un sofrito.','Regresa el pollo, agrega los garbanzos y una taza de agua; cocina a fuego lento 25 minutos.','Sazona y sirve caliente.'], TRUE),
  ('r891', 'Cheesy Savory Oat Bowl', 'Bowl de Avena Salada con Queso', NULL, 400, 24, 40, 16, 15, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['oats','eggs','cheese','spinach'], ARRAY['Cook oats in water with a pinch of salt until thick and creamy.','Stir in grated cheese and a handful of spinach until melted and wilted.','Top with a fried or poached egg and black pepper.'], ARRAY['Cocina la avena en agua con una pizca de sal hasta que quede espesa y cremosa.','Incorpora queso rallado y un puñado de espinaca hasta derretir y marchitar.','Cubre con un huevo frito o escalfado y pimienta negra.'], TRUE),
  ('r892', 'Charro Beans with Turkey', 'Frijoles Charros con Pavo', NULL, 422, 34, 40, 14, 30, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 2, ARRAY['black_beans','ground_turkey','tomato','onion','garlic'], ARRAY['Brown the ground turkey with onion and garlic in a pot.','Add chopped tomato and cook down for 5 minutes.','Tip in the black beans with their liquid and simmer 15 minutes until soupy-thick.','Season with cumin and serve in bowls.'], ARRAY['Dora el pavo molido con cebolla y ajo en una olla.','Añade tomate picado y cocina 5 minutos.','Agrega los frijoles negros con su líquido y cocina 15 minutos hasta espesar como caldo.','Sazona con comino y sirve en tazones.'], TRUE),
  ('r893', 'Egg Foo Young over Rice', 'Egg Foo Young sobre Arroz', NULL, 416, 24, 44, 16, 20, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 1, ARRAY['eggs','bell_pepper','onion','mushroom','rice'], ARRAY['Beat 3 eggs and stir in finely sliced bell pepper, onion and mushroom.','Fry as thick patties in a little oil, 2 minutes per side, until set and golden.','Make a quick sauce with soy sauce and a little cornstarch slurry.','Serve the patties over rice with the sauce spooned over.'], ARRAY['Bate 3 huevos e incorpora pimiento, cebolla y champiñón en rodajas finas.','Fríe como tortitas gruesas en poco aceite, 2 minutos por lado, hasta cuajar y dorar.','Prepara una salsa rápida con salsa de soya y un poco de maicena disuelta.','Sirve las tortitas sobre arroz con la salsa por encima.'], TRUE),
  ('r894', 'Turkey Sloppy Joes', 'Sloppy Joes de Pavo', NULL, 446, 34, 46, 14, 25, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','whole_grain_bread','tomato','onion','bell_pepper'], ARRAY['Brown the ground turkey with onion and bell pepper.','Stir in tomato sauce, a little mustard and a pinch of brown sugar; simmer 10 minutes.','Toast the bread or a bun and pile the saucy turkey on top.'], ARRAY['Dora el pavo molido con cebolla y pimiento.','Incorpora salsa de tomate, un poco de mostaza y una pizca de azúcar morena; cocina 10 minutos.','Tuesta el pan o un bollo y coloca encima el pavo en salsa.'], TRUE),
  ('r895', 'Canned Salmon Patties', 'Tortitas de Salmón en Lata', NULL, 407, 30, 38, 15, 25, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 1, ARRAY['canned_salmon','potato','eggs','onion'], ARRAY['Boil and mash the potato, then let it cool slightly.','Flake in the drained salmon and mix with 1 egg, diced onion and pepper.','Shape into 3 patties.','Pan-fry in a little oil, 4 minutes per side, until golden and crisp.'], ARRAY['Hierve y machaca la papa, luego deja enfriar un poco.','Desmenuza el salmón escurrido y mézclalo con 1 huevo, cebolla picada y pimienta.','Forma 3 tortitas.','Fríe en poco aceite, 4 minutos por lado, hasta dorar y quedar crujientes.'], TRUE),
  ('r896', 'Chickpea Salad Pita', 'Pita de Ensalada de Garbanzos', NULL, 396, 22, 50, 12, 12, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['chickpeas','whole_grain_bread','cucumber','tomato','lemon'], ARRAY['Lightly mash the chickpeas, leaving some whole.','Mix with diced cucumber, tomato, lemon juice, olive oil, salt and pepper.','Stuff into a warmed whole-grain pita and serve.'], ARRAY['Machaca ligeramente los garbanzos, dejando algunos enteros.','Mezcla con pepino y tomate picados, jugo de limón, aceite de oliva, sal y pimienta.','Rellena una pita integral tibia y sirve.'], TRUE),
  ('r897', 'Baked Oatmeal Protein Squares', 'Cuadros de Avena Proteica al Horno', NULL, 432, 22, 50, 16, 40, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 2, ARRAY['oats','eggs','banana','peanut_butter','almond_milk'], ARRAY['Mash the banana and whisk with 2 eggs, peanut butter and almond milk.','Stir in the oats and a pinch of baking powder and cinnamon.','Pour into a small lined dish and bake at 180C (350F) for 25 minutes.','Cool, then cut into squares.'], ARRAY['Machaca el plátano y bátelo con 2 huevos, mantequilla de maní y leche de almendra.','Incorpora la avena y una pizca de polvo de hornear y canela.','Vierte en un molde pequeño forrado y hornea a 180C (350F) por 25 minutos.','Deja enfriar y corta en cuadros.'], TRUE),
  ('r898', 'Enfrijoladas Bean Tortillas', 'Enfrijoladas', NULL, 451, 24, 55, 15, 20, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['black_beans','tortilla','cheese','onion','garlic'], ARRAY['Blend the black beans with garlic, a little onion and water into a smooth warm sauce.','Simmer the bean sauce 5 minutes to thicken.','Dip each tortilla in the sauce, fold, and plate.','Top with more sauce, crumbled cheese and diced onion.'], ARRAY['Licúa los frijoles negros con ajo, un poco de cebolla y agua hasta lograr una salsa suave y tibia.','Cocina la salsa de frijol 5 minutos para espesar.','Pasa cada tortilla por la salsa, dóblala y sírvela en el plato.','Cubre con más salsa, queso desmoronado y cebolla picada.'], TRUE),
  ('r899', 'Kedgeree Tuna Rice', 'Kedgeree: Arroz Curry con Atún', NULL, 464, 34, 55, 12, 30, 'Budget', 'Económico', 'budget', 'Medium', 'Medio', 2, ARRAY['canned_tuna','rice','eggs','onion','curry_powder'], ARRAY['Fry onion until soft, then stir in curry powder and cook 1 minute.','Add cooked rice and the flaked tuna; heat through gently.','Fold in chopped hard-boiled eggs and season.','Finish with a squeeze of lemon.'], ARRAY['Sofríe la cebolla hasta ablandar, incorpora el curry en polvo y cocina 1 minuto.','Agrega arroz cocido y el atún desmenuzado; calienta suavemente.','Incorpora huevos duros picados y sazona.','Termina con un chorrito de limón.'], TRUE),
  ('r900', 'Chili-Loaded Baked Potato', 'Papa al Horno con Chili', NULL, 471, 34, 50, 15, 45, 'Budget', 'Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['potato','ground_turkey','black_beans','cheese','salsa'], ARRAY['Bake the potato at 200C (400F) for 45 minutes until soft, or microwave 8 minutes.','Brown the ground turkey and simmer with black beans and chili spices, 10 minutes.','Split the potato open and pile in the chili.','Top with cheese and a spoon of salsa.'], ARRAY['Hornea la papa a 200C (400F) por 45 minutos hasta ablandar, o cocínala 8 minutos en el microondas.','Dora el pavo molido y cocínalo con frijoles negros y especias de chili, 10 minutos.','Abre la papa y rellénala con el chili.','Cubre con queso y una cucharada de salsa.'], TRUE),
  ('r901', 'Cinnamon Roll Baked Oats', 'Avena Horneada de Rollo de Canela', NULL, 419, 28, 52, 11, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','eggs','protein_powder','cinnamon','honey','almond_milk'], ARRAY['Preheat oven to 350°F (175°C) and grease a small baking dish.','Blend oats, almond milk, eggs, protein powder, and cinnamon until smooth.','Pour into the dish and swirl a little honey on top.','Bake 22-25 minutes until set and golden.'], ARRAY['Precalienta el horno a 175°C (350°F) y engrasa un molde pequeño.','Licúa la avena, la leche de almendras, los huevos, la proteína y la canela hasta suavizar.','Vierte en el molde y dibuja un poco de miel encima.','Hornea 22-25 minutos hasta que cuaje y se dore.'], TRUE),
  ('r902', 'Gingerbread Overnight Oats', 'Avena Nocturna de Jengibre', NULL, 393, 29, 49, 9, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','greek_yogurt','protein_powder','honey','cinnamon','ginger'], ARRAY['In a jar, stir oats, Greek yogurt, protein powder, cinnamon, and ground ginger.','Sweeten with honey and mix well.','Cover and refrigerate at least 6 hours or overnight.','Stir and serve cold.'], ARRAY['En un frasco, mezcla la avena, el yogur griego, la proteína, la canela y el jengibre.','Endulza con miel y mezcla bien.','Tapa y refrigera al menos 6 horas o toda la noche.','Revuelve y sirve frío.'], TRUE),
  ('r903', 'Pumpkin Spice Baked Oatmeal', 'Avena Horneada de Calabaza Especiada', NULL, 394, 26, 50, 10, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','pumpkin','eggs','protein_powder','cinnamon','almond_milk'], ARRAY['Preheat oven to 350°F (175°C).','Whisk oats, pumpkin puree, almond milk, eggs, protein powder, and cinnamon.','Pour into a greased ramekin.','Bake 25 minutes until firm and fragrant.'], ARRAY['Precalienta el horno a 175°C (350°F).','Bate la avena, el puré de calabaza, la leche de almendras, los huevos, la proteína y la canela.','Vierte en un ramekin engrasado.','Hornea 25 minutos hasta que esté firme y aromático.'], TRUE),
  ('r904', 'Tiramisu Overnight Oats', 'Avena Nocturna Tiramisú', NULL, 389, 32, 45, 9, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','greek_yogurt','protein_powder','cocoa_powder','coffee','honey'], ARRAY['Dissolve the coffee in a splash of warm water and let it cool.','Stir oats, Greek yogurt, protein powder, cocoa, honey, and coffee in a jar.','Cover and refrigerate overnight.','Dust with extra cocoa before serving.'], ARRAY['Disuelve el café en un poco de agua tibia y deja enfriar.','Mezcla en un frasco la avena, el yogur griego, la proteína, el cacao, la miel y el café.','Tapa y refrigera toda la noche.','Espolvorea más cacao antes de servir.'], TRUE),
  ('r905', 'Strawberry Cheesecake Baked Oats', 'Avena Horneada de Cheesecake de Fresa', NULL, 412, 30, 46, 12, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','cottage_cheese','eggs','strawberries','protein_powder','vanilla'], ARRAY['Preheat oven to 350°F (175°C).','Blend oats, cottage cheese, eggs, protein powder, and vanilla until smooth.','Fold in chopped strawberries and pour into a ramekin.','Bake 24 minutes until golden and set.'], ARRAY['Precalienta el horno a 175°C (350°F).','Licúa la avena, el requesón, los huevos, la proteína y la vainilla hasta suavizar.','Incorpora las fresas picadas y vierte en un ramekin.','Hornea 24 minutos hasta dorar y cuajar.'], TRUE),
  ('r906', 'Maple Pecan Overnight Oats', 'Avena Nocturna de Nuez Pecana y Maple', NULL, 440, 24, 50, 16, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','almond_milk','greek_yogurt','chia_seeds','pecans','maple_syrup'], ARRAY['Combine oats, almond milk, Greek yogurt, chia seeds, and maple syrup in a jar.','Stir well and cover.','Refrigerate at least 6 hours or overnight.','Top with toasted pecans before eating.'], ARRAY['Combina en un frasco la avena, la leche de almendras, el yogur griego, la chía y el maple.','Mezcla bien y tapa.','Refrigera al menos 6 horas o toda la noche.','Cubre con nueces pecanas tostadas antes de comer.'], TRUE),
  ('r907', 'Peach Cobbler Baked Oats', 'Avena Horneada de Melocotón', NULL, 437, 26, 54, 13, 28, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','peaches','eggs','protein_powder','cinnamon'], ARRAY['Preheat oven to 350°F (175°C).','Blend oats, eggs, protein powder, and cinnamon until smooth.','Fold in diced peaches and pour into a greased ramekin.','Bake 24 minutes until golden and set.'], ARRAY['Precalienta el horno a 175°C (350°F).','Licúa la avena, los huevos, la proteína y la canela hasta suavizar.','Incorpora el melocotón en cubos y vierte en un ramekin engrasado.','Hornea 24 minutos hasta dorar y cuajar.'], TRUE),
  ('r908', 'Matcha Coconut Overnight Oats', 'Avena Nocturna de Matcha y Coco', NULL, 414, 30, 42, 14, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','greek_yogurt','protein_powder','matcha','coconut','almond_milk'], ARRAY['Whisk matcha into the almond milk until lump-free.','Stir in oats, Greek yogurt, protein powder, and shredded coconut in a jar.','Cover and refrigerate overnight.','Top with extra coconut and serve cold.'], ARRAY['Bate el matcha con la leche de almendras hasta que no queden grumos.','Agrega en un frasco la avena, el yogur griego, la proteína y el coco rallado.','Tapa y refrigera toda la noche.','Cubre con más coco y sirve frío.'], TRUE),
  ('r909', 'Lemon Ricotta Protein Pancakes', 'Panqueques Proteicos de Ricotta y Limón', NULL, 398, 34, 34, 14, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['ricotta','eggs','oats','protein_powder','lemon','honey'], ARRAY['Blend ricotta, eggs, oats, protein powder, lemon zest, and juice into a batter.','Heat a nonstick pan over medium and lightly grease.','Cook pancakes 2 minutes per side until golden.','Drizzle with honey and serve.'], ARRAY['Licúa el ricotta, los huevos, la avena, la proteína, la ralladura y el jugo de limón.','Calienta un sartén antiadherente a fuego medio y engrasa.','Cocina los panqueques 2 minutos por lado hasta dorar.','Rocía con miel y sirve.'], TRUE),
  ('r910', 'Pumpkin Protein Waffles', 'Waffles Proteicos de Calabaza', NULL, 388, 30, 40, 12, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','pumpkin','eggs','protein_powder','cinnamon'], ARRAY['Blend oats, pumpkin, eggs, protein powder, and cinnamon until smooth.','Heat and grease a waffle iron.','Pour in the batter and cook 4-5 minutes until crisp.','Serve warm with a dollop of yogurt.'], ARRAY['Licúa la avena, la calabaza, los huevos, la proteína y la canela hasta suavizar.','Calienta y engrasa la waflera.','Vierte la mezcla y cocina 4-5 minutos hasta que estén crujientes.','Sirve tibios con una cucharada de yogur.'], TRUE),
  ('r911', 'Sweet Potato Protein Pancakes', 'Panqueques Proteicos de Batata', NULL, 386, 30, 44, 10, 18, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['sweet_potato','eggs','oats','protein_powder','cinnamon'], ARRAY['Mash cooked sweet potato and blend with eggs, oats, protein powder, and cinnamon.','Heat a nonstick pan over medium heat.','Cook pancakes 2-3 minutes per side until golden.','Stack and serve warm.'], ARRAY['Machaca la batata cocida y licúa con huevos, avena, proteína y canela.','Calienta un sartén antiadherente a fuego medio.','Cocina los panqueques 2-3 minutos por lado hasta dorar.','Apila y sirve tibios.'], TRUE),
  ('r912', 'Fluffy Japanese Souffle Pancakes', 'Panqueques Japoneses Esponjosos', NULL, 305, 24, 32, 9, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Hard', 'Difícil', 1, ARRAY['eggs','egg_whites','flour','greek_yogurt','honey'], ARRAY['Separate the eggs; whip the whites with honey to stiff peaks.','Whisk the yolks with flour and Greek yogurt, then gently fold in the whites.','Cook covered on low heat in rings, 4-5 minutes per side.','Plate carefully and serve immediately.'], ARRAY['Separa los huevos; bate las claras con miel a punto de nieve.','Mezcla las yemas con harina y yogur griego, luego integra las claras con suavidad.','Cocina tapados a fuego bajo en aros, 4-5 minutos por lado.','Emplata con cuidado y sirve de inmediato.'], TRUE),
  ('r913', 'Blueberry Buttermilk Protein Pancakes', 'Panqueques Proteicos de Arándanos', NULL, 398, 33, 44, 10, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','eggs','protein_powder','blueberries','greek_yogurt'], ARRAY['Blend oats, eggs, protein powder, and Greek yogurt into a batter.','Fold in the fresh blueberries.','Cook on a greased pan 2 minutes per side until bubbles set.','Serve warm.'], ARRAY['Licúa la avena, los huevos, la proteína y el yogur griego.','Incorpora los arándanos frescos.','Cocina en sartén engrasado 2 minutos por lado hasta que burbujeen.','Sirve tibios.'], TRUE),
  ('r914', 'Savory Cheddar Chive Waffles', 'Waffles Salados de Cheddar y Cebollín', NULL, 396, 30, 33, 16, 22, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','egg_whites','oats','cheese','chives'], ARRAY['Blend oats, eggs, and egg whites; stir in shredded cheese and chopped chives.','Heat and grease a waffle iron.','Cook 5 minutes until crisp and golden.','Serve with a fried egg if desired.'], ARRAY['Licúa la avena, los huevos y las claras; añade el queso rallado y el cebollín picado.','Calienta y engrasa la waflera.','Cocina 5 minutos hasta que estén crujientes y dorados.','Sirve con un huevo frito si deseas.'], TRUE),
  ('r915', 'Almond Butter Protein Pancake Stack', 'Panqueques Proteicos de Almendra', NULL, 452, 31, 46, 16, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','eggs','protein_powder','almond_butter','banana'], ARRAY['Mash the banana and blend with oats, eggs, protein powder, and almond butter.','Heat a nonstick pan over medium.','Cook pancakes 2 minutes per side until set.','Stack and drizzle with extra almond butter.'], ARRAY['Machaca el guineo y licúa con avena, huevos, proteína y mantequilla de almendra.','Calienta un sartén antiadherente a fuego medio.','Cocina los panqueques 2 minutos por lado.','Apila y rocía con más mantequilla de almendra.'], TRUE),
  ('r916', 'Tex-Mex Migas Scramble', 'Huevos Revueltos Migas Tex-Mex', NULL, 401, 28, 34, 17, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','tortilla','cheese','salsa','black_beans','bell_pepper'], ARRAY['Cut the tortilla into strips and crisp in a hot greased pan.','Add beaten eggs and diced bell pepper; scramble until just set.','Stir in cheese and warm black beans.','Top with salsa and serve.'], ARRAY['Corta la tortilla en tiras y dórala en un sartén caliente y engrasado.','Agrega los huevos batidos y el pimiento en cubos; revuelve hasta cuajar.','Integra el queso y los frijoles negros calientes.','Cubre con salsa y sirve.'], TRUE),
  ('r917', 'Denver Omelette with Toast', 'Omelette Denver con Tostada', NULL, 417, 34, 32, 17, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['eggs','ham','bell_pepper','onion','cheese','whole_grain_bread'], ARRAY['Saute diced ham, bell pepper, and onion in a pan.','Pour in the beaten eggs and cook until the edges set.','Add cheese, fold the omelette, and finish cooking.','Serve with toasted whole grain bread.'], ARRAY['Sofríe el jamón, el pimiento y la cebolla en cubos.','Vierte los huevos batidos y cocina hasta que los bordes cuajen.','Agrega queso, dobla el omelette y termina de cocinar.','Sirve con pan integral tostado.'], TRUE),
  ('r918', 'Mediterranean Egg White Omelette', 'Omelette Mediterráneo de Claras', NULL, 356, 32, 30, 12, 12, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['egg_whites','eggs','spinach','feta','tomato','whole_grain_bread'], ARRAY['Wilt spinach with diced tomato in a lightly greased nonstick pan.','Pour in whisked egg whites and whole eggs.','Crumble feta over the top and cook until set.','Fold and serve with toast.'], ARRAY['Marchita la espinaca con tomate en cubos en un sartén antiadherente engrasado.','Vierte las claras y los huevos batidos.','Desmorona feta encima y cocina hasta cuajar.','Dobla y sirve con tostada.'], TRUE),
  ('r919', 'Mushroom Swiss Frittata', 'Frittata de Champiñones y Queso Suizo', NULL, 397, 30, 31, 17, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['eggs','mushroom','cheese','potato','spinach','olive_oil'], ARRAY['Preheat oven to 375°F (190°C).','Saute mushrooms and diced potato in an oven-safe pan with olive oil.','Add spinach, pour in the beaten eggs, and top with cheese.','Bake 12-15 minutes until puffed and set.'], ARRAY['Precalienta el horno a 190°C (375°F).','Sofríe los champiñones y la papa en cubos en un sartén apto para horno con aceite.','Añade espinaca, vierte los huevos batidos y cubre con queso.','Hornea 12-15 minutos hasta que infle y cuaje.'], TRUE),
  ('r920', 'Goat Cheese & Chive Scramble', 'Huevos Revueltos con Queso de Cabra', NULL, 385, 28, 30, 17, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','goat_cheese','spinach','whole_grain_bread','chives'], ARRAY['Whisk the eggs and soft-scramble in a buttered pan over low heat.','Wilt in the spinach as the eggs set.','Fold in crumbled goat cheese and chives.','Serve over toasted whole grain bread.'], ARRAY['Bate los huevos y revuélvelos suavemente en un sartén con mantequilla a fuego bajo.','Marchita la espinaca mientras cuajan los huevos.','Integra el queso de cabra desmoronado y el cebollín.','Sirve sobre pan integral tostado.'], TRUE),
  ('r921', 'Kimchi Egg Scramble', 'Huevos Revueltos con Kimchi', NULL, 390, 26, 40, 14, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','kimchi','rice','sesame_oil','green_onion'], ARRAY['Saute chopped kimchi in sesame oil until fragrant.','Add the cooked rice and toss to warm through.','Push aside, scramble the eggs, then combine.','Garnish with green onion and serve.'], ARRAY['Sofríe el kimchi picado en aceite de sésamo hasta que suelte aroma.','Agrega el arroz cocido y saltea para calentar.','Aparta a un lado, revuelve los huevos y mezcla todo.','Decora con cebollín verde y sirve.'], TRUE),
  ('r922', 'Caprese Frittata', 'Frittata Caprese', NULL, 376, 28, 30, 16, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['eggs','tomato','cheese','potato','basil','olive_oil'], ARRAY['Preheat oven to 375°F (190°C).','Saute diced potato in an oven-safe pan with olive oil until tender.','Add sliced tomato, pour in the beaten eggs, and top with cheese.','Bake 12 minutes, then finish with fresh basil.'], ARRAY['Precalienta el horno a 190°C (375°F).','Sofríe la papa en cubos en un sartén apto para horno hasta ablandar.','Añade tomate en rodajas, vierte los huevos y cubre con queso.','Hornea 12 minutos y termina con albahaca fresca.'], TRUE),
  ('r923', 'Turkey & Potato Breakfast Hash', 'Papas con Pavo y Huevo', NULL, 412, 34, 33, 16, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','potato','bell_pepper','onion','eggs','paprika'], ARRAY['Brown ground turkey with paprika, onion, and bell pepper.','Add diced potato and cook until crisp and tender.','Make wells and crack in the eggs; cover until set.','Serve hot from the skillet.'], ARRAY['Dora el pavo molido con paprika, cebolla y pimiento.','Agrega la papa en cubos y cocina hasta que esté dorada y tierna.','Haz huecos y agrega los huevos; tapa hasta que cuajen.','Sirve caliente desde el sartén.'], TRUE),
  ('r924', 'Broccoli Cheddar Egg Muffins', 'Muffins de Huevo con Brócoli y Cheddar', NULL, 375, 30, 30, 15, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','egg_whites','broccoli','cheese','whole_grain_bread'], ARRAY['Preheat oven to 350°F (175°C) and grease a muffin tin.','Whisk eggs and egg whites; stir in chopped broccoli and cheese.','Divide the mixture into the muffin cups.','Bake 18-20 minutes until set; serve with toast.'], ARRAY['Precalienta el horno a 175°C (350°F) y engrasa un molde para muffins.','Bate los huevos y las claras; añade el brócoli picado y el queso.','Reparte la mezcla en los moldes.','Hornea 18-20 minutos hasta cuajar; sirve con tostada.'], TRUE),
  ('r925', 'Masala Egg Bhurji', 'Huevos Bhurji a la Masala', NULL, 392, 28, 34, 16, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','onion','tomato','bell_pepper','whole_grain_bread','turmeric'], ARRAY['Saute onion, tomato, and bell pepper with turmeric until soft.','Pour in the beaten eggs and scramble over medium heat.','Cook until fluffy and just set.','Serve with warm whole grain bread.'], ARRAY['Sofríe cebolla, tomate y pimiento con cúrcuma hasta ablandar.','Vierte los huevos batidos y revuelve a fuego medio.','Cocina hasta que estén esponjosos y apenas cuajados.','Sirve con pan integral tibio.'], TRUE),
  ('r926', 'Peanut Butter Banana Smoothie Bowl', 'Smoothie Bowl de Maní y Banana', NULL, 463, 32, 50, 15, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','banana','peanut_butter','protein_powder','granola'], ARRAY['Blend banana, Greek yogurt, peanut butter, and protein powder until thick.','Pour into a bowl.','Top with granola and banana slices.','Serve immediately.'], ARRAY['Licúa el guineo, el yogur griego, el maní y la proteína hasta espesar.','Vierte en un bowl.','Cubre con granola y rodajas de guineo.','Sirve de inmediato.'], TRUE),
  ('r927', 'Mango Coconut Smoothie Bowl', 'Smoothie Bowl de Mango y Coco', NULL, 436, 30, 52, 12, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','mango','protein_powder','coconut','granola'], ARRAY['Blend frozen mango, Greek yogurt, protein powder, and coconut until thick.','Spoon into a bowl.','Top with granola and shredded coconut.','Serve cold.'], ARRAY['Licúa el mango congelado, el yogur griego, la proteína y el coco hasta espesar.','Sirve en un bowl.','Cubre con granola y coco rallado.','Sirve frío.'], TRUE),
  ('r928', 'Mixed Berry Protein Smoothie Bowl', 'Smoothie Bowl Proteico de Frutos Rojos', NULL, 393, 32, 46, 9, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','berries','protein_powder','almond_milk','granola'], ARRAY['Blend mixed berries, Greek yogurt, protein powder, and almond milk.','Keep it thick and pour into a bowl.','Top with granola and extra berries.','Serve right away.'], ARRAY['Licúa los frutos rojos, el yogur griego, la proteína y la leche de almendras.','Mantén la mezcla espesa y viértela en un bowl.','Cubre con granola y más frutos rojos.','Sirve enseguida.'], TRUE),
  ('r929', 'Tropical Green Yogurt Bowl', 'Bowl Verde Tropical de Yogur', NULL, 384, 30, 48, 8, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','spinach','pineapple','protein_powder','granola'], ARRAY['Blend spinach, pineapple, Greek yogurt, and protein powder until smooth.','Pour into a bowl.','Top with granola and pineapple chunks.','Serve chilled.'], ARRAY['Licúa la espinaca, la piña, el yogur griego y la proteína hasta suavizar.','Vierte en un bowl.','Cubre con granola y trozos de piña.','Sirve frío.'], TRUE),
  ('r930', 'Cherry Almond Yogurt Bowl', 'Bowl de Yogur con Cereza y Almendra', NULL, 426, 31, 44, 14, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','cherries','almonds','protein_powder','honey'], ARRAY['Spoon Greek yogurt into a bowl and stir in the protein powder.','Top with cherries and sliced almonds.','Drizzle with honey.','Serve cold.'], ARRAY['Coloca yogur griego en un bowl e integra la proteína.','Cubre con cerezas y almendras en láminas.','Rocía con miel.','Sirve frío.'], TRUE),
  ('r931', 'Pina Colada Smoothie Bowl', 'Smoothie Bowl Piña Colada', NULL, 419, 27, 53, 11, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','pineapple','banana','coconut','protein_powder'], ARRAY['Blend pineapple, banana, Greek yogurt, coconut, and protein powder.','Pour into a bowl.','Top with toasted coconut.','Serve immediately.'], ARRAY['Licúa la piña, el guineo, el yogur griego, el coco y la proteína.','Vierte en un bowl.','Cubre con coco tostado.','Sirve de inmediato.'], TRUE),
  ('r932', 'Dragon Fruit Protein Bowl', 'Bowl Proteico de Pitahaya', NULL, 402, 30, 48, 10, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','dragon_fruit','protein_powder','granola','kiwi'], ARRAY['Blend dragon fruit, Greek yogurt, and protein powder until vibrant and thick.','Spoon into a bowl.','Top with granola and sliced kiwi.','Serve cold.'], ARRAY['Licúa la pitahaya, el yogur griego y la proteína hasta obtener una mezcla espesa.','Sirve en un bowl.','Cubre con granola y kiwi en rodajas.','Sirve frío.'], TRUE),
  ('r933', 'Pistachio Honey Yogurt Bowl', 'Bowl de Yogur con Pistacho y Miel', NULL, 440, 28, 46, 16, 7, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','pistachios','honey','granola','berries'], ARRAY['Add Greek yogurt to a bowl.','Top with granola, chopped pistachios, and fresh berries.','Drizzle generously with honey.','Serve immediately.'], ARRAY['Coloca yogur griego en un bowl.','Cubre con granola, pistachos picados y frutos rojos frescos.','Rocía con miel generosamente.','Sirve de inmediato.'], TRUE),
  ('r934', 'Whipped Feta & Tomato Toast', 'Tostada de Feta Batido y Tomate', NULL, 358, 24, 34, 14, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['feta','whole_grain_bread','tomato','olive_oil'], ARRAY['Blend feta with a splash of olive oil until whipped and creamy.','Toast the whole grain bread until crisp.','Spread the whipped feta over each slice.','Top with sliced tomato and a drizzle of olive oil.'], ARRAY['Licúa el feta con un chorrito de aceite de oliva hasta que quede cremoso.','Tuesta el pan integral hasta que esté crujiente.','Unta el feta batido sobre cada rebanada.','Cubre con tomate en rodajas y un chorrito de aceite.'], TRUE),
  ('r935', 'Egg Salad Protein Toast', 'Tostada de Ensalada de Huevo', NULL, 375, 28, 32, 15, 12, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','greek_yogurt','whole_grain_bread','chives'], ARRAY['Chop the hard-boiled eggs and mix with Greek yogurt and chives.','Season with salt and pepper.','Toast the whole grain bread.','Pile the egg salad onto the toast and serve.'], ARRAY['Pica los huevos duros y mezcla con yogur griego y cebollín.','Sazona con sal y pimienta.','Tuesta el pan integral.','Coloca la ensalada de huevo sobre la tostada y sirve.'], TRUE),
  ('r936', 'Turkey Bacon & Egg Toast', 'Tostada de Huevo y Tocino de Pavo', NULL, 410, 30, 32, 18, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['turkey_bacon','eggs','whole_grain_bread','avocado'], ARRAY['Crisp the turkey bacon in a pan; set aside.','Fry the eggs to your liking in the same pan.','Mash the avocado onto the toasted bread.','Top with eggs and turkey bacon; serve.'], ARRAY['Dora el tocino de pavo en un sartén y reserva.','Fríe los huevos al gusto en el mismo sartén.','Machaca el aguacate sobre el pan tostado.','Coloca los huevos y el tocino encima; sirve.'], TRUE),
  ('r937', 'Hummus & Egg Breakfast Toast', 'Tostada de Hummus y Huevo', NULL, 384, 24, 36, 16, 12, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['hummus','eggs','whole_grain_bread','tomato'], ARRAY['Toast the whole grain bread.','Spread a thick layer of hummus.','Top with sliced boiled or fried eggs and tomato.','Season and serve.'], ARRAY['Tuesta el pan integral.','Unta una capa gruesa de hummus.','Cubre con huevos hervidos o fritos en rodajas y tomate.','Sazona y sirve.'], TRUE),
  ('r938', 'Honey Almond Yogurt Toast', 'Tostada de Yogur, Almendra y Miel', NULL, 385, 26, 41, 13, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','whole_grain_bread','almonds','honey','cinnamon'], ARRAY['Toast the whole grain bread.','Spread a thick layer of Greek yogurt over each slice.','Top with sliced almonds and a dusting of cinnamon.','Drizzle with honey and serve.'], ARRAY['Tuesta el pan integral.','Unta una capa gruesa de yogur griego sobre cada rebanada.','Cubre con almendras en láminas y un toque de canela.','Rocía con miel y sirve.'], TRUE),
  ('r939', 'Southwest Breakfast Tacos', 'Tacos de Desayuno Southwest', NULL, 442, 28, 42, 18, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','tortilla','black_beans','cheese','salsa','avocado'], ARRAY['Warm the tortillas in a dry pan.','Scramble the eggs and warm the black beans.','Fill the tortillas with eggs, beans, cheese, and avocado.','Top with salsa and serve.'], ARRAY['Calienta las tortillas en un sartén seco.','Revuelve los huevos y calienta los frijoles negros.','Rellena las tortillas con huevo, frijoles, queso y aguacate.','Cubre con salsa y sirve.'], TRUE),
  ('r940', 'Chilaquiles with Fried Egg', 'Chilaquiles con Huevo Frito', NULL, 425, 26, 42, 17, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['eggs','tortilla','salsa','cheese','black_beans'], ARRAY['Cut the tortillas into triangles and toast until crisp.','Simmer them briefly in salsa until lightly softened.','Top with warm black beans and cheese.','Finish with a fried egg and serve immediately.'], ARRAY['Corta las tortillas en triángulos y tuéstalas hasta que estén crujientes.','Cocínalas brevemente en salsa hasta ablandar ligeramente.','Cubre con frijoles negros calientes y queso.','Termina con un huevo frito y sirve de inmediato.'], TRUE),
  ('r941', 'California Breakfast Wrap', 'Wrap de Desayuno California', NULL, 443, 32, 36, 19, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','tortilla','avocado','cheese','spinach','turkey_bacon'], ARRAY['Scramble the eggs and crisp the turkey bacon.','Warm the tortilla and layer spinach and cheese.','Add eggs, turkey bacon, and sliced avocado.','Roll up tightly, slice, and serve.'], ARRAY['Revuelve los huevos y dora el tocino de pavo.','Calienta la tortilla y coloca espinaca y queso.','Agrega huevo, tocino de pavo y aguacate en rodajas.','Enrolla firme, corta y sirve.'], TRUE),
  ('r942', 'Turkey Sausage Breakfast Burrito Bowl', 'Bowl Burrito con Salchicha de Pavo', NULL, 439, 34, 42, 15, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['eggs','turkey_sausage','sweet_potato','black_beans','salsa'], ARRAY['Roast the diced sweet potato until tender.','Brown the turkey sausage in a pan.','Scramble the eggs and warm the black beans.','Layer everything in a bowl and top with salsa.'], ARRAY['Asa la batata en cubos hasta ablandar.','Dora la salchicha de pavo en un sartén.','Revuelve los huevos y calienta los frijoles.','Acomoda todo en un bowl y cubre con salsa.'], TRUE),
  ('r943', 'Chorizo Sweet Potato Breakfast Taco', 'Taco de Desayuno con Chorizo y Batata', NULL, 424, 30, 40, 16, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['eggs','tortilla','ground_turkey','sweet_potato','salsa','paprika'], ARRAY['Roast diced sweet potato with paprika until crisp.','Brown the ground turkey as a chorizo-style filling.','Scramble the eggs and warm the tortillas.','Fill the tortillas with everything and top with salsa.'], ARRAY['Asa la batata en cubos con paprika hasta dorar.','Dora el pavo molido estilo chorizo.','Revuelve los huevos y calienta las tortillas.','Rellena las tortillas y cubre con salsa.'], TRUE),
  ('r944', 'Chocolate Peanut Butter Chia Pudding', 'Pudín de Chía con Chocolate y Maní', NULL, 410, 28, 34, 18, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['chia_seeds','almond_milk','protein_powder','peanut_butter','cocoa_powder'], ARRAY['Whisk almond milk, protein powder, cocoa, and peanut butter until smooth.','Stir in the chia seeds thoroughly.','Cover and refrigerate at least 4 hours or overnight.','Stir again and serve chilled.'], ARRAY['Bate la leche de almendras, la proteína, el cacao y el maní hasta suavizar.','Integra bien las semillas de chía.','Tapa y refrigera al menos 4 horas o toda la noche.','Revuelve otra vez y sirve frío.'], TRUE),
  ('r945', 'Vanilla Berry Chia Pudding', 'Pudín de Chía con Vainilla y Frutos Rojos', NULL, 381, 30, 36, 13, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['chia_seeds','greek_yogurt','protein_powder','berries','almond_milk','vanilla'], ARRAY['Whisk almond milk, Greek yogurt, protein powder, and vanilla.','Stir in the chia seeds.','Refrigerate at least 4 hours until thick.','Top with fresh berries and serve.'], ARRAY['Bate la leche de almendras, el yogur griego, la proteína y la vainilla.','Integra las semillas de chía.','Refrigera al menos 4 horas hasta espesar.','Cubre con frutos rojos frescos y sirve.'], TRUE),
  ('r946', 'Matcha Chia Pudding', 'Pudín de Chía con Matcha', NULL, 366, 26, 34, 14, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['chia_seeds','almond_milk','protein_powder','matcha','honey'], ARRAY['Whisk matcha into the almond milk until smooth.','Add protein powder and honey, then stir in the chia seeds.','Refrigerate at least 4 hours or overnight.','Stir and serve cold.'], ARRAY['Bate el matcha con la leche de almendras hasta suavizar.','Agrega proteína y miel, luego integra la chía.','Refrigera al menos 4 horas o toda la noche.','Revuelve y sirve frío.'], TRUE),
  ('r947', 'Coconut Mango Chia Pudding', 'Pudín de Chía con Coco y Mango', NULL, 399, 24, 42, 15, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['chia_seeds','almond_milk','protein_powder','mango','coconut'], ARRAY['Whisk almond milk, protein powder, and shredded coconut.','Stir in the chia seeds and refrigerate 4 hours.','Dice the mango.','Top the pudding with mango and serve.'], ARRAY['Bate la leche de almendras, la proteína y el coco rallado.','Integra la chía y refrigera 4 horas.','Pica el mango en cubos.','Cubre el pudín con mango y sirve.'], TRUE),
  ('r948', 'Savory Miso Oats with Soft Egg', 'Avena Salada de Miso con Huevo', NULL, 374, 22, 40, 14, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['oats','eggs','miso','spinach','sesame_oil'], ARRAY['Cook the oats with water until creamy.','Stir in the miso paste and wilt in the spinach.','Soft-boil or fry an egg.','Top the oats with the egg and a drizzle of sesame oil.'], ARRAY['Cocina la avena con agua hasta que esté cremosa.','Integra la pasta de miso y marchita la espinaca.','Prepara un huevo mollet o frito.','Coloca el huevo sobre la avena y rocía con aceite de sésamo.'], TRUE),
  ('r949', 'Quinoa Porridge with Almond Butter', 'Quinoa Cremosa con Mantequilla de Almendra', NULL, 448, 26, 50, 16, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['quinoa','almond_milk','protein_powder','almond_butter','banana'], ARRAY['Simmer the quinoa in almond milk until tender and creamy.','Stir in the protein powder off the heat.','Swirl in the almond butter.','Top with banana slices and serve warm.'], ARRAY['Cocina la quinoa en leche de almendras hasta que esté tierna y cremosa.','Integra la proteína fuera del fuego.','Añade la mantequilla de almendra.','Cubre con rodajas de guineo y sirve tibio.'], TRUE),
  ('r950', 'Mocha Protein Breakfast Smoothie', 'Batido Proteico de Café y Chocolate', NULL, 408, 35, 40, 12, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['protein_powder','greek_yogurt','banana','coffee','almond_milk','peanut_butter'], ARRAY['Brew and cool the coffee.','Blend coffee, protein powder, Greek yogurt, banana, peanut butter, and almond milk.','Blend with ice until smooth and frothy.','Pour into a glass and serve.'], ARRAY['Prepara el café y déjalo enfriar.','Licúa el café, la proteína, el yogur griego, el guineo, el maní y la leche de almendras.','Licúa con hielo hasta que quede suave y espumoso.','Sirve en un vaso y disfruta.'], TRUE),
  ('r951', 'Ranchero Bean & Egg Bake', 'Horneado de Huevo y Frijoles Ranchero', NULL, 417, 26, 40, 17, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['eggs','black_beans','salsa','cheese','bell_pepper','tortilla'], ARRAY['Preheat oven to 375°F (190°C).','Spread black beans and salsa in a small oven-safe dish with bell pepper.','Make wells, crack in the eggs, and top with cheese.','Bake 12-15 minutes until whites set; serve with warm tortillas.'], ARRAY['Precalienta el horno a 190°C (375°F).','Coloca los frijoles negros y la salsa en un molde apto para horno con pimiento.','Haz huecos, agrega los huevos y cubre con queso.','Hornea 12-15 minutos hasta que cuajen las claras; sirve con tortillas tibias.'], TRUE),
  ('r952', 'Korean Egg Rice Bowl (Gyeran Bap)', 'Bowl Coreano de Arroz con Huevo', NULL, 405, 22, 50, 13, 12, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','rice','soy_sauce','sesame_oil','green_onion'], ARRAY['Cook or reheat the rice until hot.','Fry the eggs in sesame oil, keeping the yolks runny.','Place the eggs over the rice in a bowl.','Drizzle with soy sauce, add green onion, and mix.'], ARRAY['Cocina o recalienta el arroz hasta que esté caliente.','Fríe los huevos en aceite de sésamo, dejando las yemas líquidas.','Coloca los huevos sobre el arroz en un bowl.','Rocía con salsa de soya, añade cebollín y mezcla.'], TRUE),
  ('r953', 'Mango Whey Recovery Smoothie', 'Batido de Recuperación de Mango', NULL, 414, 38, 52, 6, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','mango','banana','almond_milk','greek_yogurt','honey'], ARRAY['Add mango, banana, and Greek yogurt to a blender.','Pour in almond milk and add the protein powder and honey.','Blend on high for 45 seconds until smooth.','Pour into a glass and drink within 30 minutes of training.'], ARRAY['Agrega el mango, el guineo y el yogur griego a la licuadora.','Vierte la leche de almendras y añade la proteína en polvo y la miel.','Licúa a alta velocidad por 45 segundos hasta que quede suave.','Sirve en un vaso y bébelo dentro de los 30 minutos después de entrenar.'], TRUE),
  ('r954', 'Strawberry Banana Protein Shake', 'Batido de Proteína, Fresa y Guineo', NULL, 385, 40, 45, 5, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','strawberries','banana','almond_milk','greek_yogurt'], ARRAY['Combine strawberries, banana, and Greek yogurt in a blender.','Add almond milk and vanilla protein powder.','Blend until creamy, about 30 seconds.','Serve immediately over ice if desired.'], ARRAY['Combina las fresas, el guineo y el yogur griego en la licuadora.','Añade la leche de almendras y la proteína de vainilla.','Licúa hasta que quede cremoso, unos 30 segundos.','Sirve de inmediato con hielo si lo deseas.'], TRUE),
  ('r955', 'Blueberry Almond Recovery Smoothie', 'Batido de Recuperación de Arándano', NULL, 408, 36, 48, 8, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','blueberries','banana','almond_milk','oats','honey'], ARRAY['Add blueberries, banana, and oats to the blender.','Pour in almond milk, protein powder, and a drizzle of honey.','Blend on high until the oats are fully broken down.','Pour into a tall glass and enjoy.'], ARRAY['Agrega los arándanos, el guineo y la avena a la licuadora.','Vierte la leche de almendras, la proteína en polvo y un chorrito de miel.','Licúa a alta velocidad hasta que la avena se deshaga por completo.','Sirve en un vaso alto y disfruta.'], TRUE),
  ('r956', 'Pineapple Coconut Protein Blend', 'Batido de Proteína, Piña y Coco', NULL, 421, 35, 50, 9, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','pineapple','banana','coconut_milk','greek_yogurt'], ARRAY['Blend pineapple, banana, and Greek yogurt until smooth.','Add coconut milk and vanilla protein powder.','Blend again for 20 seconds.','Serve chilled for a tropical recovery drink.'], ARRAY['Licúa la piña, el guineo y el yogur griego hasta que quede suave.','Añade la leche de coco y la proteína de vainilla.','Vuelve a licuar por 20 segundos.','Sirve bien frío como bebida tropical de recuperación.'], TRUE),
  ('r957', 'Green Spinach Recovery Smoothie', 'Batido Verde de Recuperación', NULL, 387, 37, 44, 7, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','spinach','banana','almond_milk','greek_yogurt','honey'], ARRAY['Add a handful of spinach, banana, and Greek yogurt to the blender.','Pour in almond milk, protein powder, and honey.','Blend on high for 40 seconds until no leaf specks remain.','Drink right after your workout.'], ARRAY['Agrega un puñado de espinaca, el guineo y el yogur griego a la licuadora.','Vierte la leche de almendras, la proteína en polvo y la miel.','Licúa a alta velocidad por 40 segundos hasta que no queden trozos de hoja.','Bébelo justo después de tu entrenamiento.'], TRUE),
  ('r958', 'Peanut Butter Banana Power Shake', 'Batido de Maní y Guineo', NULL, 470, 40, 46, 14, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','peanut_butter','banana','almond_milk','oats'], ARRAY['Add banana, peanut butter, and oats to a blender.','Pour in almond milk and chocolate protein powder.','Blend until smooth and thick.','Serve immediately for a filling recovery shake.'], ARRAY['Agrega el guineo, la mantequilla de maní y la avena a la licuadora.','Vierte la leche de almendras y la proteína de chocolate.','Licúa hasta que quede suave y espeso.','Sirve de inmediato como batido de recuperación saciante.'], TRUE),
  ('r959', 'Triple Berry Protein Refresher', 'Refrescante de Proteína y Frutos Rojos', NULL, 369, 34, 47, 5, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','berries','banana','almond_milk','greek_yogurt'], ARRAY['Combine mixed berries, banana, and Greek yogurt in a blender.','Add almond milk and protein powder.','Blend until fully smooth.','Pour over ice and enjoy cold.'], ARRAY['Combina los frutos rojos, el guineo y el yogur griego en la licuadora.','Añade la leche de almendras y la proteína en polvo.','Licúa hasta que quede completamente suave.','Sirve sobre hielo y disfruta bien frío.'], TRUE),
  ('r960', 'Tropical Mango Pineapple Shake', 'Batido Tropical de Mango y Piña', NULL, 405, 35, 55, 5, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','mango','pineapple','almond_milk','greek_yogurt'], ARRAY['Add mango, pineapple, and Greek yogurt to the blender.','Pour in almond milk and vanilla protein powder.','Blend on high until smooth, about 30 seconds.','Serve chilled.'], ARRAY['Agrega el mango, la piña y el yogur griego a la licuadora.','Vierte la leche de almendras y la proteína de vainilla.','Licúa a alta velocidad hasta que quede suave, unos 30 segundos.','Sirve bien frío.'], TRUE),
  ('r961', 'Vanilla Almond Recovery Shake', 'Batido de Recuperación de Vainilla', NULL, 422, 42, 41, 10, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','banana','almond_milk','oats','honey'], ARRAY['Add banana and oats to a blender.','Pour in almond milk, vanilla protein powder, and honey.','Blend until smooth and creamy.','Serve immediately after training.'], ARRAY['Agrega el guineo y la avena a la licuadora.','Vierte la leche de almendras, la proteína de vainilla y la miel.','Licúa hasta que quede suave y cremoso.','Sirve de inmediato después de entrenar.'], TRUE),
  ('r962', 'Cinnamon Roll Protein Shake', 'Batido Proteico de Canela', NULL, 404, 40, 43, 8, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','banana','oats','almond_milk','cinnamon','honey'], ARRAY['Add banana, oats, and a pinch of cinnamon to the blender.','Pour in almond milk, vanilla protein powder, and honey.','Blend until smooth.','Dust with extra cinnamon and serve.'], ARRAY['Agrega el guineo, la avena y una pizca de canela a la licuadora.','Vierte la leche de almendras, la proteína de vainilla y la miel.','Licúa hasta que quede suave.','Espolvorea más canela y sirve.'], TRUE),
  ('r963', 'Cocoa Peanut Butter Recovery Shake', 'Batido de Recuperación de Cacao y Maní', NULL, 458, 41, 42, 14, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','cocoa_powder','peanut_butter','banana','almond_milk'], ARRAY['Add banana, cocoa powder, and peanut butter to a blender.','Pour in almond milk and chocolate protein powder.','Blend on high until rich and smooth.','Serve immediately.'], ARRAY['Agrega el guineo, el cacao en polvo y la mantequilla de maní a la licuadora.','Vierte la leche de almendras y la proteína de chocolate.','Licúa a alta velocidad hasta que quede rico y suave.','Sirve de inmediato.'], TRUE),
  ('r964', 'Mocha Banana Protein Smoothie', 'Batido Proteico de Café y Cacao', NULL, 391, 38, 44, 7, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','coffee','banana','almond_milk','cocoa_powder','honey'], ARRAY['Brew and cool a shot of coffee.','Add coffee, banana, and cocoa powder to a blender.','Pour in almond milk, chocolate protein powder, and honey.','Blend until smooth and serve over ice.'], ARRAY['Prepara y enfría un shot de café.','Agrega el café, el guineo y el cacao en polvo a la licuadora.','Vierte la leche de almendras, la proteína de chocolate y la miel.','Licúa hasta que quede suave y sirve sobre hielo.'], TRUE),
  ('r965', 'Cherry Almond Recovery Blend', 'Batido de Recuperación de Cereza', NULL, 409, 36, 46, 9, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','cherries','banana','almond_milk','greek_yogurt'], ARRAY['Add pitted cherries, banana, and Greek yogurt to the blender.','Pour in almond milk and vanilla protein powder.','Blend on high until smooth.','Serve cold to help muscle recovery.'], ARRAY['Agrega las cerezas sin semilla, el guineo y el yogur griego a la licuadora.','Vierte la leche de almendras y la proteína de vainilla.','Licúa a alta velocidad hasta que quede suave.','Sirve bien frío para ayudar a la recuperación muscular.'], TRUE),
  ('r966', 'Banana Bread Protein Oats', 'Avena Proteica de Pan de Guineo', NULL, 449, 34, 58, 9, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','banana','almond_milk','cinnamon','honey'], ARRAY['Cook oats with almond milk in a saucepan over medium heat for 4 minutes.','Mash in half a banana and a pinch of cinnamon.','Remove from heat and stir in protein powder until smooth.','Top with banana slices and a drizzle of honey.'], ARRAY['Cocina la avena con leche de almendras en una olla a fuego medio por 4 minutos.','Machaca medio guineo y una pizca de canela en la avena.','Retira del fuego e incorpora la proteína en polvo hasta que quede suave.','Cubre con rodajas de guineo y un chorrito de miel.'], TRUE),
  ('r967', 'Blueberry Protein Overnight Oats', 'Avena Nocturna de Arándano', NULL, 408, 32, 52, 8, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','blueberries','greek_yogurt','almond_milk','chia_seeds'], ARRAY['In a jar, combine oats, protein powder, and chia seeds.','Stir in Greek yogurt and almond milk until mixed.','Fold in blueberries and seal the jar.','Refrigerate overnight and eat cold in the morning.'], ARRAY['En un frasco, combina la avena, la proteína en polvo y las semillas de chía.','Incorpora el yogur griego y la leche de almendras hasta mezclar.','Agrega los arándanos y cierra el frasco.','Refrigera toda la noche y come frío en la mañana.'], TRUE),
  ('r968', 'Peanut Butter Protein Oatmeal', 'Avena Proteica de Mantequilla de Maní', NULL, 478, 38, 50, 14, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','peanut_butter','banana','almond_milk'], ARRAY['Cook oats with almond milk over medium heat for 4 minutes.','Stir in peanut butter until melted through.','Remove from heat and mix in protein powder.','Top with banana slices and serve warm.'], ARRAY['Cocina la avena con leche de almendras a fuego medio por 4 minutos.','Incorpora la mantequilla de maní hasta que se derrita.','Retira del fuego y mezcla la proteína en polvo.','Cubre con rodajas de guineo y sirve caliente.'], TRUE),
  ('r969', 'Apple Cinnamon Protein Oats', 'Avena Proteica de Manzana y Canela', NULL, 419, 33, 56, 7, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','apple','almond_milk','cinnamon','honey'], ARRAY['Dice half an apple and simmer with oats and almond milk for 5 minutes.','Add a pinch of cinnamon while cooking.','Remove from heat and stir in protein powder.','Drizzle with honey and top with remaining apple.'], ARRAY['Pica media manzana y cocínala con la avena y la leche de almendras por 5 minutos.','Añade una pizca de canela mientras se cocina.','Retira del fuego e incorpora la proteína en polvo.','Rocía con miel y cubre con el resto de la manzana.'], TRUE),
  ('r970', 'Strawberry Protein Baked Oats', 'Avena Horneada de Fresa', NULL, 437, 35, 54, 9, 25, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['oats','protein_powder','strawberries','egg_whites','almond_milk','honey'], ARRAY['Preheat oven to 350°F (175°C).','Blend oats, egg whites, almond milk, protein powder, and honey.','Fold in chopped strawberries and pour into a ramekin.','Bake for 18 minutes until set, then cool slightly and serve.'], ARRAY['Precalienta el horno a 175°C (350°F).','Licúa la avena, las claras de huevo, la leche de almendras, la proteína y la miel.','Agrega las fresas picadas y vierte en un molde individual.','Hornea por 18 minutos hasta que cuaje, deja reposar y sirve.'], TRUE),
  ('r971', 'Chocolate Banana Protein Oats', 'Avena Proteica de Chocolate y Guineo', NULL, 428, 34, 55, 8, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','cocoa_powder','banana','almond_milk'], ARRAY['Cook oats with almond milk and cocoa powder for 4 minutes.','Mash in half a banana.','Remove from heat and stir in chocolate protein powder.','Top with banana slices and serve warm.'], ARRAY['Cocina la avena con leche de almendras y cacao en polvo por 4 minutos.','Machaca medio guineo en la avena.','Retira del fuego e incorpora la proteína de chocolate.','Cubre con rodajas de guineo y sirve caliente.'], TRUE),
  ('r972', 'Mango Coconut Protein Oats', 'Avena Proteica de Mango y Coco', NULL, 446, 32, 57, 10, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['oats','protein_powder','mango','coconut_milk','honey'], ARRAY['Cook oats with coconut milk over medium heat for 4 minutes.','Remove from heat and stir in protein powder.','Top with diced mango.','Drizzle with honey and serve.'], ARRAY['Cocina la avena con leche de coco a fuego medio por 4 minutos.','Retira del fuego e incorpora la proteína en polvo.','Cubre con mango picado.','Rocía con miel y sirve.'], TRUE),
  ('r973', 'Teriyaki Chicken Recovery Bowl', 'Bowl de Recuperación de Pollo Teriyaki', NULL, 505, 46, 60, 9, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','teriyaki_sauce','broccoli','sesame_oil'], ARRAY['Cook rice according to package directions.','Slice chicken breast and sauté in sesame oil over medium-high heat for 6 minutes.','Add teriyaki sauce and steamed broccoli, tossing to coat.','Serve chicken and broccoli over rice.'], ARRAY['Cocina el arroz según las instrucciones del paquete.','Corta la pechuga de pollo y saltéala en aceite de sésamo a fuego medio-alto por 6 minutos.','Añade la salsa teriyaki y el brócoli al vapor, mezclando para cubrir.','Sirve el pollo y el brócoli sobre el arroz.'], TRUE),
  ('r974', 'Honey Garlic Chicken Rice Bowl', 'Bowl de Pollo con Miel y Ajo', NULL, 502, 45, 58, 10, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','honey','garlic','soy_sauce','broccoli'], ARRAY['Cook rice and set aside.','Sauté diced chicken in a hot pan for 6 minutes until golden.','Add minced garlic, honey, and soy sauce; simmer until glossy.','Serve over rice with steamed broccoli.'], ARRAY['Cocina el arroz y reserva.','Saltea el pollo en cubos en una sartén caliente por 6 minutos hasta dorar.','Añade el ajo picado, la miel y la salsa de soya; cocina hasta que espese y brille.','Sirve sobre el arroz con brócoli al vapor.'], TRUE),
  ('r975', 'Pineapple Chicken Fried Rice', 'Arroz Frito con Pollo y Piña', NULL, 515, 42, 62, 11, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','pineapple','egg_whites','soy_sauce','green_onion'], ARRAY['Use cold cooked rice for best texture.','Sauté diced chicken in a wok over high heat for 5 minutes.','Push chicken aside, scramble egg whites, then add rice and pineapple.','Season with soy sauce and green onion; stir-fry 3 more minutes.'], ARRAY['Usa arroz cocido y frío para mejor textura.','Saltea el pollo en cubos en un wok a fuego alto por 5 minutos.','Aparta el pollo, cocina las claras de huevo, luego añade el arroz y la piña.','Sazona con salsa de soya y cebollín; sofríe 3 minutos más.'], TRUE),
  ('r976', 'Korean Gochujang Chicken Rice', 'Arroz con Pollo al Gochujang', NULL, 502, 44, 59, 10, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','gochujang','sesame_oil','garlic','spinach'], ARRAY['Cook rice and set aside.','Sauté sliced chicken in sesame oil for 6 minutes.','Stir in gochujang and minced garlic until the chicken is coated.','Serve over rice with a side of wilted spinach.'], ARRAY['Cocina el arroz y reserva.','Saltea el pollo en tiras en aceite de sésamo por 6 minutos.','Incorpora el gochujang y el ajo picado hasta cubrir el pollo.','Sirve sobre el arroz con espinaca salteada al lado.'], TRUE),
  ('r977', 'Lemon Herb Chicken Rice Plate', 'Plato de Pollo al Limón y Hierbas', NULL, 489, 47, 55, 9, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','lemon','garlic','olive_oil','asparagus'], ARRAY['Cook rice and set aside.','Season chicken with garlic, lemon juice, salt, and pepper.','Sear in olive oil over medium heat for 6 minutes per side.','Serve sliced over rice with roasted asparagus.'], ARRAY['Cocina el arroz y reserva.','Sazona el pollo con ajo, jugo de limón, sal y pimienta.','Dóralo en aceite de oliva a fuego medio por 6 minutos por lado.','Sirve en rodajas sobre el arroz con espárragos asados.'], TRUE),
  ('r978', 'Sesame Ginger Chicken Bowl', 'Bowl de Pollo con Sésamo y Jengibre', NULL, 507, 45, 57, 11, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','ginger','sesame_oil','soy_sauce','broccoli'], ARRAY['Cook rice and set aside.','Sauté grated ginger in sesame oil for 30 seconds.','Add sliced chicken and cook for 6 minutes, then add soy sauce.','Serve over rice with steamed broccoli.'], ARRAY['Cocina el arroz y reserva.','Saltea el jengibre rallado en aceite de sésamo por 30 segundos.','Añade el pollo en tiras y cocina 6 minutos, luego agrega la salsa de soya.','Sirve sobre el arroz con brócoli al vapor.'], TRUE),
  ('r979', 'Sweet Chili Chicken Rice Bowl', 'Bowl de Pollo con Chile Dulce', NULL, 501, 44, 61, 9, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','sweet_chili_sauce','bell_pepper','green_onion'], ARRAY['Cook rice and set aside.','Sauté diced chicken and bell pepper for 7 minutes.','Stir in sweet chili sauce until everything is glazed.','Serve over rice and top with green onion.'], ARRAY['Cocina el arroz y reserva.','Saltea el pollo en cubos y el pimiento por 7 minutos.','Incorpora la salsa de chile dulce hasta glasear todo.','Sirve sobre el arroz y cubre con cebollín.'], TRUE),
  ('r980', 'Cilantro Lime Chicken Rice', 'Arroz con Pollo, Cilantro y Limón', NULL, 498, 46, 56, 10, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','lime','cilantro','garlic','olive_oil'], ARRAY['Cook rice and toss with lime juice and chopped cilantro.','Season chicken with garlic, salt, and pepper.','Sear in olive oil for 6 minutes per side, then slice.','Serve chicken over the cilantro-lime rice.'], ARRAY['Cocina el arroz y mézclalo con jugo de limón verde y cilantro picado.','Sazona el pollo con ajo, sal y pimienta.','Dóralo en aceite de oliva por 6 minutos por lado y córtalo.','Sirve el pollo sobre el arroz con cilantro y limón.'], TRUE),
  ('r982', 'Turkey Teriyaki Rice Bowl', 'Bowl de Pavo Teriyaki con Arroz', NULL, 493, 44, 59, 9, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','rice','teriyaki_sauce','broccoli','green_onion'], ARRAY['Cook rice and set aside.','Brown ground turkey in a pan over medium-high heat for 7 minutes.','Stir in teriyaki sauce and steamed broccoli.','Serve over rice and garnish with green onion.'], ARRAY['Cocina el arroz y reserva.','Dora el pavo molido en una sartén a fuego medio-alto por 7 minutos.','Incorpora la salsa teriyaki y el brócoli al vapor.','Sirve sobre el arroz y decora con cebollín.'], TRUE),
  ('r983', 'Honey Banana Protein Bowl', 'Bowl Proteico de Guineo y Miel', NULL, 412, 33, 52, 8, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','protein_powder','banana','honey','granola'], ARRAY['Stir protein powder into Greek yogurt until smooth.','Spoon into a bowl.','Top with banana slices and a sprinkle of granola.','Drizzle with honey and serve.'], ARRAY['Mezcla la proteína en polvo con el yogur griego hasta que quede suave.','Sirve en un bowl.','Cubre con rodajas de guineo y un poco de granola.','Rocía con miel y sirve.'], TRUE),
  ('r984', 'Berry Greek Yogurt Recovery Cup', 'Vaso de Yogur Griego y Frutos Rojos', NULL, 370, 34, 45, 6, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','protein_powder','berries','honey','chia_seeds'], ARRAY['Whisk protein powder into Greek yogurt.','Layer half into a cup, then add mixed berries.','Add the rest of the yogurt and top with more berries.','Sprinkle chia seeds and drizzle honey.'], ARRAY['Bate la proteína en polvo con el yogur griego.','Coloca la mitad en un vaso y añade los frutos rojos.','Agrega el resto del yogur y cubre con más frutos rojos.','Espolvorea semillas de chía y rocía con miel.'], TRUE),
  ('r985', 'Honey Almond Protein Toast', 'Tostada Proteica de Almendra y Miel', NULL, 446, 32, 48, 14, 8, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['whole_grain_bread','greek_yogurt','protein_powder','almond_butter','honey','banana'], ARRAY['Toast two slices of whole grain bread.','Mix protein powder into Greek yogurt and spread over the toast.','Spread a thin layer of almond butter on top.','Add banana slices and drizzle with honey.'], ARRAY['Tuesta dos rebanadas de pan integral.','Mezcla la proteína en polvo con el yogur griego y úntalo sobre el pan.','Unta una capa fina de mantequilla de almendras encima.','Añade rodajas de guineo y rocía con miel.'], TRUE),
  ('r986', 'Banana Honey Rice Bowl', 'Bowl de Arroz Dulce con Guineo', NULL, 455, 30, 68, 7, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['rice','protein_powder','banana','honey','almond_milk','cinnamon'], ARRAY['Warm cooked rice with a splash of almond milk.','Stir in protein powder and a pinch of cinnamon.','Top with banana slices.','Drizzle with honey and serve warm.'], ARRAY['Calienta el arroz cocido con un chorrito de leche de almendras.','Incorpora la proteína en polvo y una pizca de canela.','Cubre con rodajas de guineo.','Rocía con miel y sirve caliente.'], TRUE),
  ('r987', 'Strawberry Cottage Cheese Bowl', 'Bowl de Queso Cottage y Fresa', NULL, 350, 32, 42, 6, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','strawberries','honey','granola','chia_seeds'], ARRAY['Add cottage cheese to a bowl.','Top with sliced strawberries and granola.','Sprinkle chia seeds over the top.','Drizzle with honey and serve.'], ARRAY['Coloca el queso cottage en un bowl.','Cubre con fresas en rodajas y granola.','Espolvorea semillas de chía por encima.','Rocía con miel y sirve.'], TRUE),
  ('r988', 'Peach Greek Yogurt Protein Bowl', 'Bowl de Yogur Griego y Melocotón', NULL, 378, 35, 46, 6, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','protein_powder','peach','honey','granola'], ARRAY['Stir protein powder into Greek yogurt until smooth.','Spoon into a bowl and top with sliced peach.','Add a spoonful of granola.','Drizzle with honey and serve.'], ARRAY['Mezcla la proteína en polvo con el yogur griego hasta que quede suave.','Sirve en un bowl y cubre con melocotón en rodajas.','Añade una cucharada de granola.','Rocía con miel y sirve.'], TRUE),
  ('r989', 'Tropical Yogurt Recovery Parfait', 'Parfait Tropical de Yogur', NULL, 395, 33, 50, 7, 8, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','protein_powder','mango','pineapple','granola','honey'], ARRAY['Mix protein powder into Greek yogurt.','Layer yogurt, mango, and pineapple in a glass.','Repeat the layers and top with granola.','Finish with a drizzle of honey.'], ARRAY['Mezcla la proteína en polvo con el yogur griego.','Coloca capas de yogur, mango y piña en un vaso.','Repite las capas y cubre con granola.','Termina con un chorrito de miel.'], TRUE),
  ('r990', 'Blueberry Cottage Cheese Bowl', 'Bowl de Queso Cottage y Arándano', NULL, 350, 33, 41, 6, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','blueberries','honey','oats','cinnamon'], ARRAY['Spoon cottage cheese into a bowl.','Top with blueberries and a sprinkle of raw oats.','Dust with cinnamon.','Drizzle with honey and serve.'], ARRAY['Sirve el queso cottage en un bowl.','Cubre con arándanos y un poco de avena cruda.','Espolvorea canela.','Rocía con miel y sirve.'], TRUE),
  ('r991', 'Acai Protein Recovery Bowl', 'Bowl de Recuperación de Açaí', NULL, 425, 32, 54, 9, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['acai','protein_powder','banana','almond_milk','granola','berries'], ARRAY['Blend acai, banana, protein powder, and almond milk into a thick puree.','Pour into a bowl.','Top with granola and mixed berries.','Serve immediately with a spoon.'], ARRAY['Licúa el açaí, el guineo, la proteína en polvo y la leche de almendras hasta obtener un puré espeso.','Vierte en un bowl.','Cubre con granola y frutos rojos.','Sirve de inmediato con una cuchara.'], TRUE),
  ('r992', 'Raspberry Honey Yogurt Bowl', 'Bowl de Yogur con Frambuesa y Miel', NULL, 366, 34, 44, 6, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','protein_powder','raspberries','honey','chia_seeds'], ARRAY['Whisk protein powder into Greek yogurt until smooth.','Spoon into a bowl and top with raspberries.','Sprinkle with chia seeds.','Drizzle with honey and serve.'], ARRAY['Bate la proteína en polvo con el yogur griego hasta que quede suave.','Sirve en un bowl y cubre con frambuesas.','Espolvorea semillas de chía.','Rocía con miel y sirve.'], TRUE),
  ('r993', 'Egg White Fried Rice', 'Arroz Frito con Claras de Huevo', NULL, 424, 33, 55, 8, 15, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['egg_whites','rice','soy_sauce','green_onion','sesame_oil','carrot'], ARRAY['Heat sesame oil in a wok over high heat.','Add diced carrot and cook for 2 minutes.','Push aside, scramble egg whites, then add cold rice.','Season with soy sauce, toss for 3 minutes, and top with green onion.'], ARRAY['Calienta el aceite de sésamo en un wok a fuego alto.','Añade la zanahoria en cubos y cocina por 2 minutos.','Aparta, cocina las claras de huevo, luego añade el arroz frío.','Sazona con salsa de soya, sofríe 3 minutos y cubre con cebollín.'], TRUE),
  ('r994', 'Egg White & Sweet Potato Plate', 'Plato de Claras y Batata', NULL, 383, 32, 48, 7, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['egg_whites','sweet_potato','spinach','olive_oil','garlic'], ARRAY['Roast cubed sweet potato at 400°F (205°C) for 20 minutes.','Sauté garlic and spinach in olive oil until wilted.','Scramble egg whites in the same pan.','Plate the egg whites with sweet potato and spinach.'], ARRAY['Asa la batata en cubos a 205°C (400°F) por 20 minutos.','Saltea el ajo y la espinaca en aceite de oliva hasta marchitar.','Cocina las claras de huevo en la misma sartén.','Sirve las claras con la batata y la espinaca.'], TRUE),
  ('r995', 'Savory Egg White Rice Bowl', 'Bowl Salado de Arroz y Claras', NULL, 416, 34, 52, 8, 15, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['egg_whites','rice','spinach','soy_sauce','sesame_oil','garlic'], ARRAY['Cook rice and set aside.','Sauté garlic and spinach in sesame oil for 2 minutes.','Scramble egg whites in the pan until just set.','Serve over rice with a splash of soy sauce.'], ARRAY['Cocina el arroz y reserva.','Saltea el ajo y la espinaca en aceite de sésamo por 2 minutos.','Cocina las claras de huevo en la sartén hasta que cuajen.','Sirve sobre el arroz con un chorrito de salsa de soya.'], TRUE),
  ('r996', 'Egg White Veggie Rice Scramble', 'Revoltillo de Claras con Arroz', NULL, 404, 33, 50, 8, 15, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['egg_whites','rice','bell_pepper','onion','tomato','olive_oil'], ARRAY['Cook rice and set aside.','Sauté diced bell pepper, onion, and tomato in olive oil for 4 minutes.','Add egg whites and scramble until set.','Fold in the rice and cook for 2 more minutes.'], ARRAY['Cocina el arroz y reserva.','Saltea el pimiento, la cebolla y el tomate en aceite de oliva por 4 minutos.','Añade las claras de huevo y revuelve hasta que cuajen.','Incorpora el arroz y cocina 2 minutos más.'], TRUE),
  ('r997', 'Shrimp Fried Rice Recovery Bowl', 'Bowl de Arroz Frito con Camarones', NULL, 473, 40, 58, 9, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['shrimp','rice','egg_whites','soy_sauce','green_onion','sesame_oil'], ARRAY['Use cold cooked rice for the best texture.','Sauté shrimp in sesame oil over high heat for 3 minutes, then set aside.','Scramble egg whites, add rice, and stir-fry for 3 minutes.','Return shrimp, season with soy sauce, and top with green onion.'], ARRAY['Usa arroz cocido y frío para mejor textura.','Saltea los camarones en aceite de sésamo a fuego alto por 3 minutos y reserva.','Cocina las claras de huevo, añade el arroz y sofríe por 3 minutos.','Devuelve los camarones, sazona con salsa de soya y cubre con cebollín.'], TRUE),
  ('r998', 'Tuna & Rice Recovery Bowl', 'Bowl de Atún y Arroz', NULL, 456, 42, 54, 8, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','rice','soy_sauce','cucumber','sesame_oil','green_onion'], ARRAY['Cook rice and let it cool slightly.','Drain canned tuna and flake it over the rice.','Add sliced cucumber and green onion.','Drizzle with soy sauce and sesame oil.'], ARRAY['Cocina el arroz y déjalo entibiar.','Escurre el atún enlatado y desmenúzalo sobre el arroz.','Añade pepino en rodajas y cebollín.','Rocía con salsa de soya y aceite de sésamo.'], TRUE),
  ('r999', 'Salmon Rice Power Bowl', 'Bowl de Poder con Salmón y Arroz', NULL, 487, 38, 50, 15, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['salmon','rice','broccoli','soy_sauce','sesame_oil'], ARRAY['Cook rice and set aside.','Season salmon and pan-sear in sesame oil for 4 minutes per side.','Steam broccoli until tender.','Flake salmon over rice, add broccoli, and drizzle with soy sauce.'], ARRAY['Cocina el arroz y reserva.','Sazona el salmón y dóralo en aceite de sésamo por 4 minutos por lado.','Cocina el brócoli al vapor hasta que esté tierno.','Desmenuza el salmón sobre el arroz, añade el brócoli y rocía con salsa de soya.'], TRUE),
  ('r1000', 'Ground Turkey Sweet Potato Hash', 'Hash de Pavo y Batata', NULL, 468, 44, 46, 12, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','sweet_potato','bell_pepper','onion','olive_oil'], ARRAY['Dice sweet potato and sauté in olive oil for 8 minutes until tender.','Add bell pepper and onion; cook for 4 minutes.','Push aside and brown the ground turkey for 7 minutes.','Combine everything, season, and serve hot.'], ARRAY['Pica la batata y saltéala en aceite de oliva por 8 minutos hasta que esté tierna.','Añade el pimiento y la cebolla; cocina por 4 minutos.','Aparta y dora el pavo molido por 7 minutos.','Combina todo, sazona y sirve caliente.'], TRUE),
  ('r1001', 'Honey Soy Salmon Rice Bowl', 'Bowl de Salmón con Miel y Soya', NULL, 511, 38, 56, 15, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['salmon','rice','honey','soy_sauce','garlic','broccoli'], ARRAY['Cook rice and set aside.','Whisk honey, soy sauce, and minced garlic into a glaze.','Pan-sear salmon for 4 minutes per side, brushing with the glaze.','Serve over rice with steamed broccoli.'], ARRAY['Cocina el arroz y reserva.','Bate la miel, la salsa de soya y el ajo picado hasta formar un glaseado.','Dora el salmón por 4 minutos por lado, untándolo con el glaseado.','Sirve sobre el arroz con brócoli al vapor.'], TRUE),
  ('r1002', 'Maple Protein Pancakes', 'Panqueques Proteicos con Arce', NULL, 442, 36, 52, 10, 15, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['oats','protein_powder','egg_whites','banana','maple_syrup'], ARRAY['Blend oats, protein powder, egg whites, and banana into a batter.','Heat a nonstick pan over medium heat.','Pour small rounds and cook 2 minutes per side.','Stack and top with a drizzle of maple syrup.'], ARRAY['Licúa la avena, la proteína en polvo, las claras de huevo y el guineo hasta formar una masa.','Calienta una sartén antiadherente a fuego medio.','Vierte porciones pequeñas y cocina 2 minutos por lado.','Apila y cubre con un chorrito de sirope de arce.'], TRUE)
